window.HADITH_CACHE["abu-dawud_6"] = {"3001":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ وَحَبِيبٍ الْمُعَلِّمِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَجُوزُ لِامْرَأَةٍ أَمْرٌ فِي مَالِهَا إِذَا مَلَكَ زَوْجُهَا عِصْمَتَهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Daud bin Abu Hindun] dan [Habib Al Mu'allim] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang wanita tidak boleh membelanjakan hartanya jika suaminya telah menikahinya.\""},"3002":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ حَدَّثَنَا حُسَيْنٌ عَنْ عَمْرِو بْنِ شُعَيْبٍ أَنَّ أَبَاهُ أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَجُوزُ لِامْرَأَةٍ عَطِيَّةٌ إِلَّا بِإِذْنِ زَوْجِهَا","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Husain] dari ['Amru bin Syu'aib] bahwa [Ayahnya] telah mengabarkan kepadanya dari [Abdullah bin 'Amru] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh seorang wanita memberikan suatu pemberian kecuali dengan seizing suaminya.\""},"3003":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَى جَائِزَةٌحَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [An Nadlr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"'Umra itu dibolehkan.\" Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam seperti itu.\" "},"3004":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ الْعُمْرَى لِمَنْ وُهِبَتْ لَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Aban] dari [Yahya] dari [Abu Salamah] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"'Umra itu untuk orang yang diberi.\" "},"3005":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ الْحَرَّانِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ أَخْبَرَنِي الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أُعْمِرَ عُمْرَى فَهِيَ لَهُ وَلِعَقِبِهِ يَرِثُهَا مَنْ يَرِثُهُ مِنْ عَقِبِهِحَدَّثَنَا أَحْمَدُ بْنُ أَبِي الْحَوَارِيِّ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ وَعُرْوَةَ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ أَبُو دَاوُد وَهَكَذَا رَوَاهُ اللَّيْثُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ","id":"Telah menceritakan kepada kami [Mu`ammal bin Al Fadlal Al Kharrani] telah menceritakan kepada kami [Muhammad bin Syu'aib] telah mengabarkan kepadaku [Al Auza'i] dari [Az Zuhri] dari ['Urwah] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diberi 'Umra, maka ia akan menjadi miliknya dan milik keturunannya. Dan keturunannya akan mewarisinya.\" Telah menceritakan kepada kami [Ahmad bin Abu Al Hawari] telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Az Zuhri] dari [Abu Salamah] dan ['Urwah] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam dengan maknanya.\" Abu Daud berkata, \"Seperti inilah [Al Laits] meriwayatkannya dari [Az Zuhri] dari [Abu Salamah] dari [Jabir].\" "},"3006":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا بِشْرُ بْنُ عُمَرَ حَدَّثَنَا مَالِكٌ يَعْنِي ابْنَ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا رَجُلٍ أُعْمِرَ عُمْرَى لَهُ وَلِعَقِبِهِ فَإِنَّهَا لِلَّذِي يُعْطَاهَا لَا تَرْجِعُ إِلَى الَّذِي أَعْطَاهَا لِأَنَّهُ أَعْطَى عَطَاءً وَقَعَتْ فِيهِ الْمَوَارِيثُحَدَّثَنَا حَجَّاجُ بْنُ أَبِي يَعْقُوبَ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ أَبُو دَاوُد وَكَذَلِكَ رَوَاهُ عَقِيلٌ عَنْ ابْنِ شِهَابٍ وَيَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ ابْنِ شِهَابٍ وَاخْتُلِفَ عَلَى الْأَوْزَاعِيِّ فِي لَفْظِهِ عَنْ ابْنِ شِهَابٍ وَرَوَاهُ فُلَيْحُ بْنُ سُلَيْمَانَ مِثْلَ حَدِيثِ مَالِكٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] dan [Muhammad bin Al Mutsanna] mereka berkata; telah menceritakan kepada kami [Bisyr bin Umar] telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Abu Salamah] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lelaki mana saja yang diberi umra, maka ia akan menjadi miliknya dan milik keturunannya. Yakni, ia akan menjadi milik orang yang diserahi, dan tidak kembali kepada orang yang memberinya, karena dia telah memberikan suatu pemberian yang padanya berlaku hukum waris.\" Telah menceritakan kepada kami [Hajjaj bin Abu Ya'qub] telah menceritakan kepada kami [Ya'qub] telah menceritakan kepada kami [Ayahku] dari [Shalih] dari [Ibnu Syihab] dengan sanad dan maknanya.\" Abu Daud berkata, \" [Aqil] juga menceritakan dari [Ibnu Syihab] dan [Yazid bin Abu Habib] dari [Ibnu Syihab]. Dan telah diperselisihkan pada lafazh [Al Auza'i] dari [Ibnu Syihab] dan hadits tersebut telah diriwayatkan oleh [Fulaih bin Sulaiman] seperti hadits Malik.\" "},"3007":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَإِنَّمَا الْعُمْرَى الَّتِي أَجَازَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَقُولَ هِيَ لَكَ وَلِعَقِبِكَ فَأَمَّا إِذَا قَالَ هِيَ لَكَ مَا عِشْتَ فَإِنَّهَا تَرْجِعُ إِلَى صَاحِبِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Jabir bin Abdullah] ia berkata, \"Sesungguhnya 'Umra yang diperbolehkan Rasulullah shallallahu 'alaihi wasallam adalah dengan mengatakan, 'Barang tersebut untukmu dan untuk orang setelahmu'. Adapun jika ia mengatakan, 'Barang tersebut untukmu selama hidupmu', maka pemberian tersebut akan kembali kepada pemiliknya.\" "},"3008":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُرْقِبُوا وَلَا تُعْمِرُوا فَمَنْ أُرْقِبَ شَيْئًا أَوْ أُعْمِرَهُ فَهُوَ لِوَرَثَتِهِ","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari ['Atha] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah memberikan Ruqba atau Umra. Barangsiapa diberi Ruqba atau Umra maka hal tersebut untuk para pewarisnya.\" "},"3009":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاِويَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبٍ يَعْنِي ابْنَ أَبِي ثَابِتٍ عَنْ حُمَيْدٍ الْأَعْرَجِ عَنْ طَارِقٍ الْمَكِّيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي امْرَأَةٍ مِنْ الْأَنْصَارِ أَعْطَاهَا ابْنُهَا حَدِيقَةً مِنْ نَخْلٍ فَمَاتَتْ فَقَالَ ابْنُهَا إِنَّمَا أَعْطَيْتُهَا حَيَاتَهَا وَلَهُ إِخْوَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ لَهَا حَيَاتَهَا وَمَوْتَهَا قَالَ كُنْتُ تَصَدَّقْتُ بِهَا عَلَيْهَا قَالَ ذَلِكَ أَبْعَدُ لَكَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Humaid Al A'raj] dari [Thariq Al Makki] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memutuskan mengenai seorang wanita anshar yang telah diberi kebun kurma oleh anaknya kemudian wanita tersebut meninggal, lalu anaknya berkata, 'Sesungguhnya aku memberinya selama hidupnya' -Dan orang tersebut memiliki beberapa orang saudara-. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kebun tersebut miliknya selama hidup dan matinya.\" Orang tersebut berkata, \"Dahulu aku mensedekahkan kebun tersebut kepadanya.\" Maka beliau bersabda: \"Yang demikian itu lebih tidak mungkin kembali kepadamu.\""},"3010":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا دَاوُدُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعُمْرَى جَائِزَةٌ لِأَهْلِهَا وَالرُّقْبَى جَائِزَةٌ لِأَهْلِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Daud] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Umra adalah diperbolehkan bagi pemiliknya, dan ruqba diperbolehkan bagi pemiliknya.\" "},"3011":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ قَالَ قَرَأْتُ عَلَى مَعْقِلٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ حُجْرٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْمَرَ شَيْئًا فَهُوَ لِمُعْمَرِهِ مَحْيَاهُ وَمَمَاتَهُ وَلَا تُرْقِبُوا فَمَنْ أَرْقَبَ شَيْئًا فَهُوَ سَبِيلُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] ia berkata; aku membacakan riwayat di hadapan [Ma'qil] dari ['Amru bin Dinar] dari [Thawus] dari [Hujr] dari [Zaid bin Tsabit] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memberikan sesuatu dengan cara 'umra maka sesuatu tersebut untuk orang yang diberinya selama hidup dan matinya. Dan janganlah engkau memberikan sesuatu dengan cara ruqba, Barangsiapa memberikan sesuatu secara ruqba maka ia punya hak untuk mewariskannya.\" "},"3012":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ عَنْ عُبَيْدِ اللَّهِ بْنِ مُوسَى عَنْ عُثْمَانَ بْنِ الْأَسْوَدِ عَنْ مُجَاهِدٍ قَالَالْعُمْرَى أَنْ يَقُولَ الرَّجُلُ لِلرَّجُلِ هُوَ لَكَ مَا عِشْتَ فَإِذَا قَالَ ذَلِكَ فَهُوَ لَهُ وَلِوَرَثَتِهِ وَالرُّقْبَى هُوَ أَنْ يَقُولَ الْإِنْسَانُ هُوَ لِلْآخِرِ مِنِّي وَمِنْكَ","id":"Telah menceritakan kepada kami [Abdullah bin Al Jarrah] dari ['Ubaidullah bin Musa] dari [Utsman bin Al Aswad] dari [Mujahid] ia berkata, \"Umra adalah seseorang berkata kepada orang lain, 'Sesuatu tersebut untukmu selama engkau hidup. ' Maka apabila ia mengucapkan hal tersebut sesuatu tersebut miliknya dan milik para pewarisnya. Ruqba adalah seseorang berkata, 'Sesuatu tersebut milik orang yang meninggalnya paling akhir antara aku dan kamu. '"},"3013":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا يَحْيَى عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَى الْيَدِ مَا أَخَذَتْ حَتَّى تُؤَدِّيَ ثُمَّ إِنَّ الْحَسَنَ نَسِيَ فَقَالَ هُوَ أَمِينُكَ لَا ضَمَانَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad] telah menceritakan kepada kami [Yahya] dari [Ibnu Abu 'Arubah] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tangan bertanggung jawab atas apa yang ia ambil hingga ia menunaikannya, -kemudian Al Hasan lupa lanjutannya-. Lantas ia menyebutkan, \"…. dia adalah orang yang engkau percayai, tidak ada tanggung jawab atasnya.\""},"3014":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ مُحَمَّدٍ وَسَلَمَةُ بْنُ شَبِيبٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أُمَيَّةَ بْنِ صَفْوَانَ بْنِ أُمَيَّةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعَارَ مِنْهُ أَدْرَاعًا يَوْمَ حُنَيْنٍ فَقَالَ أَغَصْبٌ يَا مُحَمَّدُ فَقَالَ لَا بَلْ عَمَقٌ مَضْمُونَةٌقَالَ أَبُو دَاوُد وَهَذِهِ رِوَايَةُ يَزِيدَ بِبَغْدَادَ وَفِي رِوَايَتِهِ بِوَاسِطٍ تَغَيُّرٌ عَلَى غَيْرِ هَذَا","id":"Telah menceritakan kepada kami [Al Hasan bin Muhammad] dan [Salamah bin Syabib] mereka berkata; telah menceritakan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Syarik] dari [Abdul Aziz bin Rufai'] dari [Umayyah bin Shafwan bin Umayyah] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah meminjam beberapa baju besi saat perang Hunain, lalu ia berkata, \"Apakah ini suatu perampasan wahai Muhammad!\" Beliau menjawab: \"Tidak, melainkan pinjaman yang akan dijamin.\" Abu Daud berkata, \"Ini adalah riwayat Yazid di Baghdad, ketika berada di Wasith pada periwayatannya terjadi perubahan dan tidak seperti itu.\""},"3015":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ أُنَاسٍ مِنْ آلِ عَبدِ اللَّهِ بْنِ صَفْوَانَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا صَفْوَانُ هَلْ عِنْدَكَ مِنْ سِلَاحٍ قَالَ عَوَرً أَمْ غَصْبًا قَالَ لَا بَلْ عَوَرً فَأَعَارَهُ مَا بَيْنَ الثَّلَاثِينَ إِلَى الْأَرْبَعِينَ دِرْعًا وَغَزَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُنَيْنًا فَلَمَّا هُزِمَ الْمُشْرِكُونَ جُمِعَتْ دُرُوعُ صَفْوَانَ فَفَقَدَ مِنْهَا أَدْرَاعًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِصَفْوَانَ إِنَّا قَدْ فَقَدْنَا مِنْ أَدْرَاعِكَ أَدْرَاعًا فَهَلْ نَغْرَمُ لَكَ قَالَ لَا يَا رَسُولَ اللَّهِ لِأَنَّ فِي قَلْبِي الْيَوْمَ مَا لَمْ يَكُنْ يَوْمَئِذٍقَالَ أَبُو دَاوُد وَكَانَ أَعَارَهُ قَبْلَ أَنْ يُسْلِمَ ثُمَّ أَسْلَمَ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ رُفَيْعٍ عَنْ عَطَاءٍ عَنْ نَاسٍ مِنْ آلِ صَفْوَانَ قَالَ اسْتَعَارَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Abdul Aziz bin Rufai'] dari [beberapa orang dari keluarga Abdullah bin Shafwan] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Shafwan, apakah engkau memiliki senjata?\" Shafwan menjawab, \"Sebagai pinjaman atau perampasan?\" Beliau menjawab: \"Bukan perampasan, melainkan peminjaman.\" Kemudian ia meminjamkan kepada beliau antara tiga puluh hingga empat puluh baju besi. Kemudian Rasulullah shallallahu 'alaihi wasallam memerangi Hunain. Ketika orang-orang musyrik dapat dikalahkan, maka baju-baju besi milik Shafwan dikumpulkan, namun beliau kehilangan beberapa baju zirah. Rasulullah shallallahu 'alaihi wasallam kemudian berkata kepada Shafwan: \"Sesungguhnya kami kehilangan sebagian baju besimu, apakah kami menanggung untukmu?\" Shafwan menjawab, \"Tidak, wahai Rasulullah! Karena dalam hatiku pada hari ini terdapat sesuatu yang tidak ada pada saat itu.\" Abu Daud berkata, \" Ia memberi pinjaman itu sebelum ia masuk Islam.\" Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Al Ahwash] telah menceritakan kepada kami [Abdul Aziz bin Rufai'] dari ['Atha] dari [beberapa orang keluarga Shafwan] ia berkata, \"Nabi shallallahu 'alaihi wasallam meminjam….. kemudian ia menyebutkan maknanya.\""},"3016":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ الْحَوْطِيُّ حَدَّثَنَا ابْنُ عَيَّاشٍ عَنْ شُرَحْبِيلَ بْنِ مُسْلِمٍ قَالَ سَمِعْتُ أَبَا أُمَامَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ أَعْطَى كُلَّ ذِي حَقٍّ حَقَّهُ فَلَا وَصِيَّةَ لِوَارِثٍ وَلَا تُنْفِقُ الْمَرْأَةُ شَيْئًا مِنْ بَيْتِهَا إِلَّا بِإِذْنِ زَوْجِهَا فَقِيلَ يَا رَسُولَ اللَّهِ وَلَا الطَّعَامَ قَالَ ذَاكَ أَفْضَلُ أَمْوَالِنَا ثُمَّ قَالَ الْعَوَرُ مُؤَدَّاةٌ وَالْمِنْحَةُ مَرْدُودَةٌ وَالدَّيْنُ مَقْضِيٌّ وَالزَّعِيمُ غَارِمٌ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah Al Hauthi] telah menceritakan kepada kami [Ibnu 'Ayyasy] dari [Syurahbil bin Muslim] ia berkata; saya mendengar [Abu Umamah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah Azza wa Jalla telah memberikan hak kepada setiap yang memiliki hak, maka tidak ada wasiat bagi pewaris. Dan tidak boleh seorang wanita menginfakkan sesuatu dari rumahnya kecuali dengan seizin suaminya.\" Kemudian beliau ditanya, \"Wahai Rasulullah, tidak juga dengan makanan?\" Beliau menjawab: \"Itu adalah harta kita yang terbaik.\" Kemudian beliau mengatakan: \"Pinjaman harus dikembalikan kepada pemiliknya, sesuatu yang diberikan agar diambil manfaatnya dikembalikan kepada pemiliknya, hutang harus dibayar, dan penanggung jawab adalah orang yang bertanggung jawab.\""},"3017":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُسْتَمِرِّ الْعُصْفُرِيُّ حَدَّثَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَتَتْكَ رُسُلِي فَأَعْطِهِمْ ثَلَاث��ينَ دِرْعًا وَثَلَاثِينَ بَعِيرًا قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَعَوَرٌ مَضْمُونَةٌ أَوْ عَوَرٌ مُؤَدَّاةٌ قَالَ بَلْ مُؤَدَّاةٌقَالَ أَبُو دَاوُد حَبَّانُ خَالُ هِلَالٍ الرَّائِيِّ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mustamir Al 'Ushfuri] telah menceritakan kepada kami [Habban bin Hilal] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari ['Atha bin Abu Rabah] dari [Shafwan bin Ya'la] dari [Ayahnya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Apabila para utusanku datang kepadamu, maka berikan kepada mereka tiga puluh baju besi dan tiga puluh unta!\" Ya'la berkata, \"Aku lalu berkata, \"Wahai Rasulullah, apakah hal itu sebagai pinjaman yang akan mendapat jaminan atau pinjaman yang akan dikembalikan kepada pemiliknya?\" Beliau menjawab: \"Bahkan pinjaman yang akan dikembalikan kepada pemiliknya.\" Abu Daud berkata, \"Habban adalah paman (dari pihak ibu) Hilal Ar Rai.\""},"3018":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا خَالِدٌ عَنْ حُمَيْدٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَ بَعْضِ نِسَائِهِ فَأَرْسَلَتْ إِحْدَى أُمَّهَاتِ الْمُؤْمِنِينَ مَعَ خَادِمِهَا قَصْعَةً فِيهَا طَعَامٌ قَالَ فَضَرَبَتْ بِيَدِهَا فَكَسَرَتْ الْقَصْعَةَ قَالَ ابْنُ الْمُثَنَّى فَأَخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكِسْرَتَيْنِ فَضَمَّ إِحْدَاهُمَا إِلَى الْأُخْرَى فَجَعَلَ يَجْمَعُ فِيهَا الطَّعَامَ وَيَقُولُ غَارَتْ أُمُّكُمْ زَادَ ابْنُ الْمُثَنَّى كُلُوا فَأَكَلُوا حَتَّى جَاءَتْ قَصْعَتُهَا الَّتِي فِي بَيْتِهَا ثُمَّ رَجَعْنَا إِلَى لَفْظِ حَدِيثِ مُسَدَّدٍ قَالَ كُلُوا وَحَبَسَ الرَّسُولَ وَالْقَصْعَةَ حَتَّى فَرَغُوا فَدَفَعَ الْقَصْعَةَ الصَّحِيحَةَ إِلَى الرَّسُولِ وَحَبَسَ الْمَكْسُورَةَ فِي بَيْتِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Khalid] dari [Humaid] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah berada di rumah sebagian isterinya, kemudian salah seorang Ummul mukminin menyuruh pelayannya mengirimkan sebuah nampan yang berisi makanan.\" Anas berkata, \"Kemudian isteri beliau memukul nampan tersebut dengan tangannya hingga pecah.\" Ibnu Al Mutsanna menyebutkan, \"Nabi shallallahu 'alaihi wasallam mengambil dua pecahan tersebut dan menggabungkan sebagian dengan yang lainnya, kemudian mengembalikan makanan pada tempatnya (semula) seraya berkata: \"Ibu kalian sedang cemburu.\" Ibnu Al Mutsanna menambahkan, \"Makanlah.\" Kemudian mereka makan hingga datang nampan yang ada di rumah isteri beliau tersebut. Kemudian kita kembali kepada lafazh hadits Musaddad, beliau bersabda: \"Makanlah!\" Dan beliau menahan utusan dan nampan tersebut hingga mereka selesai lalu beliau menyerahkan nampan yang tidak pecah kepada utusan tersebut, dan beliau menahan nampan yang pecah di rumahnya.\""},"3019":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي فُلَيْتٌ الْعَامِرِيُّ عَنْ جَسْرَةَ بِنْتِ دَجَاجَةَ قَالَتْ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَامَا رَأَيْتُ صَانِعًا طَعَامًا مِثْلَ صَفِيَّةَ صَنَعَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا فَبَعَثَتْ بِهِ فَأَخَذَنِي أَفْكَلٌ فَكَسَرْتُ الْإِنَاءَ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا كَفَّارَةُ مَا صَنَعْتُ قَالَ إِنَاءٌ مِثْلُ إِنَاءٍ وَطَعَامٌ مِثْلُ طَعَامٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Fulait Al 'Amiri] dari [Jasrah binti Dajajah] ia berkata, \" [Aisyah] radliallahu 'anha berkata, \"Aku tidak melihat pembuat makanan seperti Shafiyyah, ia membuat makanan untuk Rasulullah shallallahu 'alaihi wasallam lalu mengirimkannya kepada beliau. Maka aku merasa gemetar, hingga aku pun memecahkan bejana tersebut. Kemudian aku katakan, \"Wahai Rasulullah, apa hukuman dari apa yang telah aku perbuat?\" Beliau menjawab: \"Bejana yang sama, dan makanan yang sama.\""},"3020":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ مُحَيِّصَةَ عَنْ أَبِيهِأَنَّ نَاقَةً لِلْبَرَاءِ بْنِ عَازِبٍ دَخَلَتْ حَائِطَ رَجُلٍ فَأَفْسَدَتْهُ عَلَيْهِمْ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَهْلِ الْأَمْوَالِ حِفْظَهَا بِالنَّهَارِ وَعَلَى أَهْلِ الْمَوَاشِي حِفْظَهَا بِاللَّيْلِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit Al Marwazi] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Haram bin Muhayyishah] dari [Ayahnya] bahwa unta Al Bara bin 'Azib masuk ke dalam kebun seorang laki-laki lalu merusaknya. Kemudian Rasulullah shallallahu 'alaihi wasallam mewajibkan atas pemilik harta (kebun) agar menjaganya pada siang hari, dan bagi pemilik hewan agar menjaganya pada malam hari.\""},"3021":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا الْفِرْيَابِيُّ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ حَرَامِ بْنِ مُحَيِّصَةَ الْأَنْصَارِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَتْ لَهُ نَاقَةٌ ضَارِيَةٌ فَدَخَلَتْ حَائِطًا فَأَفْسَدَتْ فِيهِ فَكُلِّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا فَقَضَى أَنَّ حِفْظَ الْحَوَائِطِ بِالنَّهَارِ عَلَى أَهْلِهَا وَأَنَّ حِفْظَ الْمَاشِيَةِ بِاللَّيْلِ عَلَى أَهْلِهَا وَأَنَّ عَلَى أَهْلِ الْمَاشِيَةِ مَا أَصَابَتْ مَاشِيَتُهُمْ بِاللَّيْلِ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] telah menceritakan kepada kami [Al Firyabi] dari [Al Auza'i] dari [Az Zuhri] dari [Haram bin Muhayyishah Al Anshari] dari [Al Bara bin 'Azib] ia berkata, \"Dahulu ia memiliki seekor unta yang biasa makan tanaman orang lain. Lalu unta tersebut memasuki sebuah kebun dan merusak apa yang ada di dalamnya. Kemudian Rasulullah shallallahu 'alaihi wasallam diberi kabar tentang hal itu, maka beliau pun memberi putusan bahwa penjagaan kebun pada siang hari menjadi tanggung jawab pemiliknya, dan penjagaan hewan pada malam hari menjadi tanggung jawab pemiliknya, serta pemilik hewan bertanggung jawab atas apa yang dirusak hewan tersebut pada malam hari.\""},"3022":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَمْرُو بْنُ أَبِي عَمْرٍو عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ وَلِيَ الْقَضَاءَ فَقَدْ ذُبِحَ بِغَيْرِ سِكِّينٍ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepada kami [Fudlail bin Sulaiman] telah menceritakan kepada kami ['Amru bin Abu 'Amru] dari [Sa'id Al Maqburi] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjabat sebagai hakim, maka sungguh ia telah disembelih tanpa menggunakan pisau.\""},"3023":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا بِشْرُ بْنُ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ عَنْ عُثْمَانَ بْنِ مُحَمَّدٍ الْأَخْنَسِيِّ عَنْ الْمَقْبُرِيِّ وَالْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جُعِلَ قَاضِيًا بَيْنَ النَّاسِ فَقَدْ ذُبِحَ بِغَيْرِ سِكِّينٍ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepada kami [Bisyr bin Umar] dari [Abdullah bin Ja'far] dari [Utsman bin Muhammad Al Akhnasi] dari [Al Maqburi] serta [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa dijadikan sebagai hakim di antara manusia, maka sungguh ia telah disembelih tanpa menggunakan pisau.\""},"3024":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَسَّانَ السَّمْتِيُّ حَدَّثَنَا خَلَفُ بْنُ خَلِيفَةَ عَنْ أَبِي هَاشِمٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْقُضَاةُ ثَلَاثَةٌ وَاحِدٌ فِي الْجَنَّةِ وَاثْنَانِ فِي النَّارِ فَأَمَّا الَّذِي فِي الْجَنَّةِ فَرَجُلٌ عَرَفَ الْحَقَّ فَقَضَى بِهِ وَرَجُلٌ عَرَفَ الْحَقَّ فَجَارَ فِي الْحُكْمِ فَهُوَ فِي النَّارِ وَرَجُلٌ قَضَى لِلنَّاسِ عَلَى جَهْلٍ فَهُوَ فِي النَّارِقَالَ أَبُو دَاوُد وَهَذَا أَصَحُّ شَيْءٍ فِيهِ يَعْنِي حَدِيثَ ابْنِ بُرَيْدَةَ الْقُضَاةُ ثَلَاثَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Hassan As Samti] telah menceritakan kepada kami [Khalaf bin Khalifah] dari [Abu Hasyim] dari [Ibnu Buraidah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Hakim itu ada tiga; satu orang di Surga dan dua orang berada di Neraka. Yang berada di surga adalah seorang laki-laki yang mengetahui kebenaran lalu menghukumi dengannya, seorang laki-laki yang mengetahui kebenaran lalu berlaku lalim dalam berhukum maka ia berada di Neraka, dan orang yang memberikan keputusan untuk manusia di atas kebodohan maka ia berada di Neraka.\" Abu Daud berkata, \"Hadits ini adalah yang paling shahih dalam hal tersebut, yaitu Hadits Ibnu Buraidah yang mengatakan; Hakim ada tiga….\""},"3025":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ أَخْبَرَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ أَبِي قَيْسٍ مَوْلَى عَمْرِو بْنِ الْعَاصِ عَنْ عَمْرِو بْنِ الْعَاصِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَكَمَ الْحَاكِمُ فَاجْتَهَدَ فَأَصَابَ فَلَهُ أَجْرَانِ وَإِذَا حَكَمَ فَاجْتَهَدَ فَأَخْطَأَ فَلَهُ أَجْرٌفَحَدَّثْتُ بِهِ أَبَا بَكْرِ بْنِ حَزْمٍ فَقَالَ هَكَذَا حَدَّثَنِي أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] telah mengabarkan kepadaku [Yazid bin Abdullah bin Al Had] dari [Muhammad bin Ibrahim] dari [Busr bin Sa'id] dari [Abu Qais] mantan budak 'Amru bin Al 'Ash dari ['Amru bin Al 'Ash] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seorang hakim berhukum lalu berijtihad dan benar maka baginya dua pahala, dan apabila ia berhukum lalu berijtihad dan salah maka baginya satu pahala.\" Lalu aku menceritakannya kepada [Abu Bakar bin Hazm], kemudian ia berkata, \"Seperti inilah [Abu Salamah] menceritakan kepadaku dari [Abu Hurairah].\""},"3026":{"ar":"حَدَّثَنَا عَبَّاسٌ الْعَنْبَرِيُّ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا مُلَازِمُ بْنُ عَمْرٍو حَدَّثَنِي مُوسَى بْنُ نَجْدَةَ عَنْ جَدِّهِ يَزِيدُ بْنُ عَبْدِ الرَّحْمَنِ وَهُوَ أَبُو كَثِيرٍ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ طَلَبَ قَضَاءَ الْمُسْلِمِينَ حَتَّى يَنَالَهُ ثُمَّ غَلَبَ عَدْلُهُ جَوْرَهُ فَلَهُ الْجَنَّةُ وَمَنْ غَلَبَ جَوْرُهُ عَدْلَهُ فَلَهُ النَّارُ","id":"Telah menceritakan kepada kami [Abbas Al 'Anbari] telah menceritakan kepada kami [Umar bin Yunus] telah menceritakan kepada kami [Mulazim bin 'Amru] telah menceritakan kepadaku [Musa bin Najdah] dari kakeknya [Yazid bin Abdurrahman Abu Katsir] ia berkata; telah menceritakan kepadaku [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menginginkan untuk menjadi hakim, kemudian keadilannya mengalahkan kelalimannya maka baginya Surga, dan Barangsiapa yang kelalimannya mengalahkan keadilannya maka baginya Neraka.\""},"3027":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ بْنِ أَبِي يَحْيَى الرَّمْلِيُّ حَدَّثَنَا زَيْدُ بْنُ أَبِي الزَّرْقَاءِ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ وَمَنْ لَمْ يَحْكُمْ بِمَا أَنْزَلَ اللَّهُ فَأُولَئِكَ هُمْ الْكَافِرُونَ إِلَى قَوْلِهِ الْفَاسِقُونَ }هَؤُلَاءِ الْآيَاتِ الثَّلَاثِ نَزَلَتْ فِي الْيَهُودِ خَاصَّةً فِي قُرَيْظَةَ وَالنَّضِيرِ","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah bin Abu Yahya Ar Ramli] telah menceritakan kepada kami [Zaid bin Abu Az Zarqa`] telah menceritakan kepada kami [Ibnu Az Zinad] dari [Ayahnya] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas] ia membaca ayat: '(Barangsiapa yang tidak memutuskan menurut apa yang diturunkan Allah, maka mereka itu adalah orang-orang yang kafir) ' hingga firman Allah: '(…… orang-orang yang fasik) ' (Qs. Al Maidah: 44-47). ketiga ayat tersebut turun mengenai orang-orang Yahudi, khususnya orang-orang Bani Quraizhah dan An Nazlir.\""},"3028":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ رَجَاءٍ الْأَنْصَارِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بِشْرٍ الْأَنْصَارِيِّ الْأَزْرَقِ قَالَدَخَلَ رَجُلَانِ مِنْ أَبْوَابِ كِنْدَةَ وَأَبُو مَسْعُودٍ الْأَنْصَارِيُّ جَالِسٌ فِي حَلْقَةٍ فَقَالَا أَلَا رَجُلٌ يُنَفِّذُ بَيْنَنَا فَقَالَ رَجُلٌ مِنْ الْحَلْقَةِ أَنَا فَأَخَذَ أَبُو مَسْعُودٍ كَفًّا مِنْ حَصًى فَرَمَاهُ بِهِ وَقَالَ مَهْ إِنَّهُ كَانَ يُكْرَهُ التَّسَرُّعُ إِلَى الْحُكْمِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala`] dan [Muhammad bin Al Mutsanna] mereka berkata; telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Raja Al Anshari] dari [Abdurrahman bin Bisyr Al Anshari Al Azraq] ia berkata, \"Dua orang lelaki masuk dari beberapa pintu Kindah, sementara Abu Mas'ud Al Anshari sedang duduk di antara sekumpulan orang. Keduanya lalu berkata, \"Adakah seseorang yang memberikan keputusan di antara kami? Kemudian seorang laki-laki dari sekumpulan orang itu yang berkata, \"Aku.\" [Abu Mas'ud] kemudian mengambil segenggam kerikil lalu melemparkannya kepada orang tersebut seraya berkata, \"Tahanlah! Sesungguhnya terburu-buru dalam memberikan keputusan itu dibenci.\""},"3029":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا إِسْرَائِيلُ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ بِلَالٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ طَلَبَ الْقَضَاءَ وَاسْتَعَانَ عَلَيْهِ وُكِلَ إِلَيْهِ وَمَنْ لَمْ يَطْلُبْهُ وَلَمْ يَسْتَعِنْ عَلَيْهِ أَنْزَلَ اللَّهُ مَلَكًا يُسَدِّدُهُو قَالَ وَكِيعٌ عَنْ إِسْرَائِيلَ عَنْ عَبْدِ الْأَعْلَى عَنْ بِلَالِ بْنِ أَبِي مُوسَى عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و قَالَ أَبُو عَوَانَةَ عَنْ عَبْدِ الْأَعْلَى عَنْ بِلَالِ بْنِ مِرْدَاسٍ الْفَزَارِيِّ عَنْ خَيْثَمَةَ الْبَصْرِيِّ عَنْ أَنَسٍ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Israil] telah menceritakan kepada kami [Abdul A'la] dari [Bilal] dari [Anas bin Malik] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menginginkan untuk menjadi hakim dan ia meminta pertolongan untuk mendapatkannya, maka segala urusannya akan diserahkan kepadanya, sedangkan orang yang tidak menginginkannya dan tidak meminta pertolongan untuk mendapatkannya, maka Allah menurunkan Malaikat untuk meluruskannya.\" [Waki'] berkata dari [Israil] dari [Abul A'la] dari [Bilal bin Abu Musa] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, dan [Abu 'Awanah] berkata dari [Abdul A'la] dari [Bilal bin Mirdas Al Fazari] dari [Khaitsamah Al Anshari] dari [Anas].\""},"3030":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ حَدَّثَنِي أَبُو بُرْدَةَ قَالَ قَالَ أَبُو مُوسَىقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ نَسْتَعْمِلَ أَوْ لَا نَسْتَعْمِلُ عَلَى عَمَلِنَا مَنْ أَرَادَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Qurrah bin Khalid] telah menceritakan kepada kami [Humaid bin Hilal] telah menceritakan kepadaku [Abu Burdah] ia berkata, [Abu Musa] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Kami tidak akan memberikan jabatan untuk mengurusi suatu pekerjaan kami kepada orang yang menginginkannya.\""},"3031":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّاشِي وَالْمُرْتَشِي","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Al Harits bin Abdurrahman] dari [Abu Salamah] dari [Abdullah bin 'Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat orang yang memberi uang sogokan dan orang yang menerimanya.\""},"3032":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ حَدَّثَنِي قَيْسٌ قَالَ حَدَّثَنِي عَدِيُّ بْنُ عُمَيْرَةَ الْكِنْدِيُّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا أَيُّهَا النَّاسُ مَنْ عُمِّلَ مِنْكُمْ لَنَا عَلَى عَمَلٍ فَكَتَمَنَا مِنْهُ مِخْيَطًا فَمَا فَوْقَهُ فَهُوَ غُلٌّ يَأْتِي بِهِ يَوْمَ الْقِيَامَةِ فَقَامَ رَجُلٌ مِنْ الْأَنْصَارِ أَسْوَدُ كَأَنِّي أَنْظُرُ إِلَيْهِ فَقَالَ يَا رَسُولَ اللَّهِ اقْبَلْ عَنِّي عَمَلَكَ قَالَ وَمَا ذَاكَ قَالَ سَمِعْتُكَ تَقُولُ كَذَا وَكَذَا قَالَ وَأَنَا أَقُولُ ذَلِكَ مَنْ اسْتَعْمَلْنَاهُ عَلَى عَمَلٍ فَلْيَأْتِ بِقَلِيلِهِ وَكَثِيرِهِ فَمَا أُوتِيَ مِنْهُ أَخَذَهُ وَمَا نُهِيَ عَنْهُ انْتَهَى","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Isma'il bin Abu Khalid] telah menceritakan kepadaku [Qais] ia berkata; telah menceritakan kepadaku [Adi bin 'Umairah Al Kindi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai para manusia, barangsiapa yang di antara kalian diserahi jabatan untuk mengurus pekerjaan, kemudian menyembunyikan sebuah jarum atau lebih dari itu dari kami, maka hal itu adalah sebuah pengkhianatan yang akan ia bawa pada Hari Kiamat.\" Kemudian seorang laki-laki anshar berkulit hitam berdiri seakan aku pernah melihatnya, lalu ia berkata, \"Wahai Rasulullah, terimalah dariku pekerjaan anda! Beliau bersabda: \"Apakah itu?\" laki-laki itu menjawab, \"Saya mendengar anda mengatakan demikian dan demikian.\" Beliau bersabda: \"Dan aku katakan: Barangsiapa yang kami beri jabatan untuk melakukan suatu pekerjaan maka hendaknya ia melakukan yang sedikit dan yang banyak! Lalu apa yang diberikan kepadanya boleh ia mengambilnya, dan apa yang dilarang darinya maka ia tinggalkan.\""},"3033":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ أَخْبَرَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ حَنَشٍ عَنْ عَلِيٍّ عَلَيْهِ السَّلَام قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْيَمَنِ قَاضِيًا فَقُلْتُ يَا رَسُولَ اللَّهِ تُرْسِلُنِي وَأَنَا حَدِيثُ السِّنِّ وَلَا عِلْمَ لِي بِالْقَضَاءِ فَقَالَ إِنَّ اللَّهَ سَيَهْدِي قَلْبَكَ وَيُثَبِّتُ لِسَانَكَ فَإِذَا جَلَسَ بَيْنَ يَدَيْكَ الْخَصْمَانِ فَلَا تَقْضِيَنَّ حَتَّى تَسْمَعَ مِنْ الْآخَرِ كَمَا سَمِعْتَ مِنْ الْأَوَّلِ فَإِنَّهُ أَحْرَى أَنْ يَتَبَيَّنَ لَكَ الْقَضَاءُ قَالَ فَمَا زِلْتُ قَاضِيًا أَوْ مَا شَكَكْتُ فِي قَضَاءٍ بَعْدُ","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] ia berkata; telah mengabarkan kepada kami [Syarik] dari [Simak] dari [Hanasy] dari [Ali] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutusku ke Yaman sebagai hakim, lalu kami katakan, \"Wahai Rasulullah, apakah anda akan mengutusku sementara saya masih muda dan tidak memiliki ilmu mengenai peradilan?\" Kemudian beliau bersabda: \"Sesungguhnya Allah akan memberi petunjuk kepada hatimu, dan meneguhkan lisanmu. Apabila ada dua orang yang berseteru duduk di hadapanmu maka janganlah engkau memberikan keputusan hingga engkau mendengar dari orang yang lain, sebagaimana engkau mendengar dari orang yang pertama, karena sesungguhnya keputusan akan lebih jelas bagimu.\" Ali berkata, \"Setelah itu aku tetap menjadi hakim atau aku tidak merasa ragu dalam memberikan keputusan.\""},"3034":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا أَنَا بَشَرٌ وَإِنَّكُمْ تَخْتَصِمُونَ إِلَيَّ وَلَعَلَّ بَعْضَكُمْ أَنْ يَكُونَ أَلْحَنَ بِحُجَّتِهِ مِنْ بَعْضٍ فَأَقْضِيَ لَهُ عَلَى نَحْوِ مَا أَسْمَعُ مِنْهُ فَمَنْ قَضَيْتُ لَهُ مِنْ حَقِّ أَخِيهِ بِشَيْءٍ فَلَا يَأْخُذْ مِنْهُ شَيْئًا فَإِنَّمَا أَقْطَعُ لَهُ قِطْعَةً مِنْ النَّارِحَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ مَوْلَى أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلَانِ يَخْتَصِمَانِ فِي مَوَارِيثَ لَهُمَا لَمْ تَكُنْ لَهُمَا بَيِّنَةٌ إِلَّا دَعْوَاهُمَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ فَبَكَى الرَّجُلَانِ وَقَالَ كُلُّ وَاحِدٍ مِنْهُمَا حَقِّي لَكَ فَقَالَ لَهُمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا إِذْ فَعَلْتُمَا مَا فَعَلْتُمَا فَاقْتَسِمَا وَتَوَخَّيَا الْحَقَّ ثُمَّ اسْتَهَمَا ثُمَّ تَحَالَّا حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى حَدَّثَنَا أُسَامَةُ عَنْ عَبْدِ اللَّهِ بْنِ رَافِعٍ قَالَ سَمِعْتُ أُمَّ سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ قَالَ يَخْتَصِمَانِ فِي مَوَارِيثَ وَأَشْيَاءَ قَدْ دَرَسَتْ فَقَالَ إِنِّي إِنَّمَا أَقْضِي بَيْنَكُمْ بِرَأْيِي فِيمَا لَمْ يُنْزَلْ عَلَيَّ فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari ['Urwah] dari [Zainab binti Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku hanyalah seorang manusia, dan kalian mengadukan permasalahannya kepadaku. Bisa jadi sebagian kalian lebih pandai dalam berdalih dari sebagian yang lain, sehingga aku memberikan keputusan untuknya sesuai dengan apa yang aku dengar darinya. Maka barangsiapa yang aku berikan suatu keputusan baginya dengan mengambil hak dari saudaranya maka janganlah ia mengambil sedikitpun darinya, karena sesungguhnya aku potongkan (api) baginya dari potongan (api) Neraka.\" Telah menceritakan kepada kami [Ar Rabi' bin Nafi' Abu Taubah] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Usamah bin Zaid] dari [Abdullah bin Rafi'] mantan budak Ummu Salamah, dari [Ummu Salamah] ia berkata, \"Dua orang laki-laki berselisih mengenai warisan mereka berdua, sementara mereka tidak memiliki bukti kecuali pengakuan mereka saja. Lalu Nabi shallallahu 'alaihi wasallam bersabda…lalu ia menyebutkan sebagaimana hadits tersebut. Kedua laki-laki tersebut kemudian menangis, lalu setiap dari mereka berkata, 'Hakku untukmu. ' Kemudian Nabi shallallahu 'alaihi wasallam berkata kepada mereka berdua: \"Adapun apabila kalian berdua melakukan apa yang telah kalian lakukan, maka bagi dan berusahalah untuk bersikap benar (adil).\" Kemudian mereka mengundi mana bagian mereka, dan mereka saling menghalalkan untuk yang lainnya.\" Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] telah mengabarkan kepada kami [Isa] telah menceritakan kepada kami [Usamah] dari [Abdullah bin Rafi'] ia berkata, \"Aku mendengar [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam sebagaimana dalam hadits tersebut. Ia berkata, \"Mereka berdua berseteru mengenai harta warisan dan beberapa perkara yang telah usang. Kemudian beliau bersabda: \"Aku memberi putusan untuk kalian berdasarkan pendapatku semata, sesuatu yang aku belum mendapatkan wahyu tentangnya.\""},"3035":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ أَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُقَالَ وَهُوَ عَلَى الْمِنْبَرِ يَا أَيُّهَا النَّاسُ إِنَّ الرَّأْيَ إِنَّمَا كَانَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُصِيبًا لِأَنَّ اللَّهَ كَانَ يُرِيهِ وَإِنَّمَا هُوَ مِنَّا الظَّنُّ وَالتَّكَلُّفُ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri] telah mengabarkan kepada kami [Ibnu Wahb] dari [Yunus bin Yazid] dari [Ibnu Syihab] bahwa [Umar bin Al Khathab] radliallahu 'anhu berada di atas mimbar dan berkata, \"Wahai para manusia, sesungguhnya jika pendapat itu berasal dari Rasulullah shallallahu 'alaihi wasallam maka ia benar adanya, sebab Allah memperlihatkan kepadanya, dan pendapat yang berasal dari kita hanyalah prasangka dan takalluf (membebani diri).\""},"3036":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ الضَّبِّيُّ أَخْبَرَنَا مُعَاذُ بْنُ مُعَاذٍ قَالَأَخْبَرَنِي أَبُو عُثْمَانَ الشَّامِيُّ وَلَا إِخَالُنِي رَأَيْتُ شَأْمِيًّا أَفْضَلَ مِنْهُ يَعْنِي حُرَيْزَ بْنَ عُثْمَانَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah Adl Dalbbi] telah mengabarkan kepada kami [Mu'adz bin Mu'adz] ia berkata, \"Abu Utsman Asy Syami mengabarkan kepadaku, dan aku tidak pernah melihat orang yang Syam yang lebih baik darinya, yaitu Huraiz bin Utsman.\""},"3037":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مَنِيعٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا مُصْعَبُ بْنُ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْخَصْمَيْنِ يَقْعُدَانِ بَيْنَ يَدَيْ الْحَكَمِ","id":"Telah menceritakan kepada kami [Ahmad bin Mani'] telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah menceritakan kepada kami [Mush'ab bin Tsabit] dari [Abdullah bin Az Zubair] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memutuskan, bahwa dua orang yang saling berselisih hendaklah duduk di hadapan hakim.\""},"3038":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرَةَ عَنْ أَبِيهِأَنَّهُ كَتَبَ إِلَى ابْنِهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقْضِي الْحَكَمُ بَيْنَ اثْنَيْنِ وَهُوَ غَضْبَانُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abdul Malik bin 'Umair] ia berkata; telah menceritakan kepada kami [Abdurrahman bin Abu Bakrah] dari [Ayahnya] bahwa ia menulis surat kepada anaknya, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang hakim tidak boleh memberikan keputusan di antara dua orang sementara ia sedang dalam keadaan marah.\""},"3039":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ فَإِنْ جَاءُوكَ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ }فَنُسِخَتْ قَالَ{ فَاحْكُمْ بَيْنَهُمْ بِمَا أَنْزَلَ اللَّهُ }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepadaku [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Ayat: '(Jika mereka (orang Yahudi) datang kepadamu (untuk meminta putusan), maka putuskanlah (perkara itu) diantara mereka, atau berpalinglah dari mereka) ' (Qs. Al Maidah: 42), dihapus dan diganti dengan ayat: '(maka putuskanlah perkara mereka menurut apa yang Allah turunkan) ' (Qs. Al Maidah: 48). "},"3040":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ فَإِنْ جَاءُوكَ فَاحْكُمْ بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ }{ وَإِنْ حَكَمْتَ فَاحْكُمْ بَيْنَهُمْ بِالْقِسْطِ }الْآيَةُ قَالَ كَانَ بَنُو النَّضِيرِ إِذَا قَتَلُوا مِنْ بَنِي قُرَيْظَةَ أَدَّوْا نِصْفَ الدِّيَةِ وَإِذَا قَتَلَ بَنُو قُرَيْظَةَ مِنْ بَنِي النَّضِيرِ أَدَّوْا إِلَيْهِمْ الدِّيَةَ كَامِلَةً فَسَوَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Daud bin Al Hushain] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Tatkala turun ayat ini: '(Jika mereka (orang Yahudi) datang kepadamu (untuk meminta putusan), maka putuskanlah (perkara itu) diantara mereka, atau berpalinglah dari mereka; jika kamu berpaling dari mereka maka mereka tidak akan memberi mudharat kepadamu sedikitpun. Dan jika kamu memutuskan perkara mereka, maka putuskanlah (perkara itu) diantara mereka dengan adil) ' (Qs. Al Maidah: 42), Ibnu Abbas berkata, \"Dahulu jika orang-orang Bani An Nadlir membunuh orang dari Bani Quraizhah maka mereka memberikan setengah diyat (tebusan), dan apabila Bani Quraizhah membunuh sebagian orang dari Bani An Nazlir, maka mereka menunaikan diyat secara penuh. Lalu Rasulullah shallallahu 'alaihi wasallam menyamaratakan besaran diyat di antara mereka.\""},"3041":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ عَنْ شُعْبَةَ عَنْ أَبِي عَوْنٍ عَنْ الْحَارِثِ بْنِ عَمْرِو ابْنِ أَخِي الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أُنَاسٍ مِنْ أَهْلِ حِمْصَ مِنْ أَصْحَابِ مُعَاذِ بْنِ جَبَلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا أَرَادَ أَنْ يَبْعَثَ مُعَاذًا إِلَى الْيَمَنِ قَالَ كَيْفَ تَقْضِي إِذَا عَرَضَ لَكَ قَضَاءٌ قَالَ أَقْضِي بِكِتَابِ اللَّهِ قَالَ فَإِنْ لَمْ تَجِدْ فِي كِتَابِ اللَّهِ قَالَ فَبِسُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَإِنْ لَمْ تَجِدْ فِي سُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا فِي كِتَابِ اللَّهِ قَالَ أَجْتَهِدُ رَأْيِي وَلَا آلُو فَضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدْرَهُ وَقَالَ الْحَمْدُ لِلَّهِ الَّذِي وَفَّقَ رَسُولَ رَسُولِ اللَّهِ لِمَا يُرْضِي رَسُولَ اللَّهِحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنِي أَبُو عَوْنٍ عَنْ الْحَارِثِ بْنِ عَمْرٍو عَنْ نَاسٍ مِنْ أَصْحَابِ مُعَاذٍ عَنْ مُعَاذِ بْنِ جَبَلٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا بَعَثَهُ إِلَى الْيَمَنِ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] dari [Syu'bah] dari [Abu 'Aun] dari [Al Harits bin 'Amru] anak saudara Al Mughirah bin Syu'bah, dari [beberapa orang penduduk Himsh] yang merupakan sebagian dari sahabat Mu'adz bin Jabal. Bahwa Rasulullah shallallahu 'alaihi wasallam ketika akan mengutus Mu'adz bin Jabal ke Yaman beliau bersabda: \"Bagaimana engkau memberikan keputusan apabila ada sebuah peradilan yang dihadapkan kepadamu?\" Mu'adz menjawab, \"Saya akan memutuskan menggunakan Kitab Allah.\" Beliau bersabda: \"Seandainya engkau tidak mendapatkan dalam Kitab Allah?\" Mu'adz menjawab, \"Saya akan kembali kepada sunnah Rasulullah shallallahu 'alaihi wasallam.\" Beliau bersabda lagi: \"Seandainya engkau tidak mendapatkan dalam Sunnah Rasulullah shallallahu 'alaihi wasallam serta dalam Kitab Allah?\" Mu'adz menjawab, \"Saya akan berijtihad menggunakan pendapat saya, dan saya tidak akan mengurangi.\" Kemudian Rasulullah shallallahu 'alaihi wasallam menepuk dadanya dan berkata: \"Segala puji bagi Allah yang telah memberikan petunjuk kepada utusan Rasulullah untuk melakukan apa yang membuat senang Rasulullah.\" Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] telah menceritakan kepadaku [Abu 'Aun] dari [Al Harits bin 'Amru] dari [beberapa orang sahabat Mu'adz] dari [Mu'adz bin Jabal] bahwa Rasulullah shallallahu 'alaihi wasallam tatkala mengutusnya ke Yaman… kemudian ia menyebutkan maknanya.\""},"3042":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي سُلَيْمَانُ بْنُ بِلَالٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْوَاحِدِ الدِّمَشْقِيُّ حَدَّثَنَا مَرْوَانُ يَعْنِي ابْنَ مُحَمَّدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ أَوْ عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ شَكَّ الشَّيْخُ عَنْ كَثِيرِ بْنِ زَيْدٍ عَنْ الْوَلِيدِ بْنِ رَبَاحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصُّلْحُ جَائِزٌ بَيْنَ الْمُسْلِمِينَ زَادَ أَحْمَدُ إِلَّا صُلْحًا أَحَلَّ حَرَامًا أَوْ حَرَّمَ حَلَالًا وَزَادَ سُلَيْمَانُ بْنُ دَاوُدَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْلِمُونَ عَلَى شُرُوطِهِمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Sulaiman bin Bilal]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Abdul Wahid Ad Dimasyqi] telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sulaiman bin Bilal] atau [Abdul Aziz bin Muhammad] -Syeikh merasa ragu- dari [Katsir bin Zaid] dari [Al Walid bin Rabah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perjanjian damai diperbolehkan di antara orang-orang Muslim.\" Ahmad menambahkan, \"kecuali perjanjian damai yang menghalalkan sesuatu yang haram atau mengharamkan yang halal.\" Sedangkan [Sulaiman bin Daud] menambahkan, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang Muslim terikat di atas syarat-syarat mereka.\""},"3043":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ كَعْبِ بْنِ مَالِكٍ أَنَّ كَعْبَ بْنَ مَالِكٍ أَخْبَرَهُأَنَّهُ تَقَاضَى ابْنَ أَبِي حَدْرَدٍ دَيْنًا كَانَ عَلَيْهِ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ فَارْتَفَعَتْ أَصْوَاتُهُمَا حَتَّى سَمِعَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِهِ فَخَرَجَ إِلَيْهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى كَشَفَ سِجْفَ حُجْرَتِهِ وَنَادَى كَعْبَ بْنَ مَالِكٍ فَقَالَ يَا كَعْبُ فَقَالَ لَبَّيْكَ يَا رَسُولَ اللَّهِ فَأَشَارَ لَهُ بِيَدِهِ أَنْ ضَعْ الشَّطْرَ مِنْ دَيْنِكَ قَالَ كَعْبٌ قَدْ فَعَلْتُ يَا رَسُولَ اللَّهِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُمْ فَاقْضِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abdullah bin Ka'b bin Malik] bahwa [Ka'b bin Malik] mengabarkan kepadanya bahwa pada masa Rasulullah shallallahu 'alaihi wasallam ia pernah menuntut hutang kepada Ibnu Abu Hadrad di masjid, kemudian suara mereka meninggi hingga Rasulullah shallallahu 'alaihi wasallam mendengar mereka berdua dari dalam rumahnya. Rasulullah shallallahu 'alaihi wasallam lantas membuka tabir kamarnya dan keluar menemui mereka. Beliau memanggil Ka'b bin Malik dan berkata: \"Wahai Ka'b!\" Kemudian Ka'ab menjawab, \"Aku penuhi panggilanmu wahai Rasulullah.\" Lalu beliau memberikan isyarat kepadanya menggunakan tangannya: \"Gugurkanlah setengah hutangmu!\" Ka'b berkata, \"Aku telah melakukannya wahai Rasulullah.\" Nabi shallallahu 'alaihi wasallam kemudian bersabda: \"Berdiri dan bayarlah hutangmu kepadanya!\""},"3044":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْهَمَدَانِيُّ وأَحْمَدُ بْنُ السَّرْحِ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مَالِكُ بْنُ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ أَنَّ أَبَاهُ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ عُثْمَانَ بْنِ عَفَّانَ أَخْبَرَهُ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ أَبِي عَمْرَةَ الْأَنْصَارِيَّ أَخْبَرَهُ أَنَّ زَيْدَ بْنَ خَالِدٍ الْجُهَنِيَّ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا أُخْبِرُكُمْ بِخَيْرِ الشُّهَدَاءِ الَّذِي يَأْتِي بِشَهَادَتِهِ أَوْ يُخْبِرُ بِشَهَادَتِهِ قَبْلَ أَنْ يُسْأَلَهَا شَكَّ عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ أَيَّتَهُمَا قَالَقَالَ أَبُو دَاوُد قَالَ مَالِكٌ الَّذِي يُخْبِرُ بِشَهَادَتِهِ وَلَا يَعْلَمُ بِهَا الَّذِي هِيَ لَهُ قَالَ الْهَمَدَانِيُّ وَيَرْفَعُهَا إِلَى السُّلْطَانِ قَالَ ابْنُ السَّرْحِ أَوْ يَأْتِي بِهَا الْإِمَامَ وَالْإِخْبَارُ فِي حَدِيثِ الْهَمَدَانِيِّ قَالَ ابْنُ السَّرْحِ ابْنُ أَبِي عَمْرَةَ لَمْ يَقُلْ عَبْدَ الرَّحْمَنِ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al Hamdani] dan [Ahmad bin As Sarah] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Malik bin Anas] dari [Abdullah bin Abu Bakr] bahwa [Ayahnya] mengabarkan kepadanya bahwa [Abdullah bin 'Amru bin Utsman bin 'Affan] telah mengabarkan kepadanya, bahwa [Abdurrahman bin 'Amrah Al Anshari] mengabarkan kepadanya, bahwa [Zaid bin Khalid Al Juhani] mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah aku beritahukan kepada kalian tentang seorang saksi terbaik yang datang membawa kesaksiannya, atau memberi kabar mengenai kesaksiannya sebelum ia ditanya mengenainya.\" -Abdullah bin Abu Bakr merasa ragu manakah di antara keduanya yang beliau sebutkan-. Abu Daud berkata, \"Malik berkata, \"Yang mengabarkan kesaksiannya, sementara orang yang memilikinya (hak untuk diberi persaksian) tidak mengetahuinya.\" [Al Hamdani] berkata, \"Ia sampaikan kepada penguasa.\" [Ibnu As As Sarh] berkata, \"Atau ia datang membawanya kepada seorang imam.\" Bentuk pengabaran ada pada hadits Al Hamdani. Ibnu As As Sarh berkata, \"Ibnu Abu 'Amrah tidak menyebutkan nama Abdurrahman.\""},"3045":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عُمَارَةَ بْنِ غَزِيَّةَ عَنْ يَحْيَى بْنِ رَاشِدٍ قَالَجَلَسْنَا لِعَبْدِ اللَّهِ بْنِ عُمَرَ فَخَرَجَ إِلَيْنَا فَجَلَسَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَالَتْ شَفَاعَتُهُ دُونَ حَدٍّ مِنْ حُدُودِ اللَّهِ فَقَدْ ضَادَّ اللَّهَ وَمَنْ خَاصَمَ فِي بَاطِلٍ وَهُوَ يَعْلَمُهُ لَمْ يَزَلْ فِي سَخَطِ اللَّهِ حَتَّى يَنْزِعَ عَنْهُ وَمَنْ قَالَ فِي مُؤْمِنٍ مَا لَيْسَ فِيهِ أَسْكَنَهُ اللَّهُ رَدْغَةَ الْخَبَالِ حَتَّى يَخْرُجَ مِمَّا قَالَحَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ حَدَّثَنَا عَاصِمُ بْنُ مُحَمَّدِ بْنِ زَيْدٍ الْعُمَرِيُّ حَدَّثَنِي الْمُثَنَّى بْنُ يَزِيدٍ عَنْ مَطَرٍ الْوَرَّاقِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ وَمَنْ أَعَانَ عَلَى خُصُومَةٍ بِظُلْمٍ فَقَدْ بَاءَ بِغَضَبٍ مِنْ اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami ['Umarah bin Ghaziyyah] dari [Yahya bin Rasyid] ia berkata, \"Kami duduk menunggu Abdullah bin Umar, kemudian ia keluar dan duduk bersama kami, ia lalu berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang syafa'atnya menghalanginya dari mendapatkan hukuman di antara hukuman-hukuman Allah, maka sungguh ia telah menyelisihi Allah. Barangsiapa berseteru dalam kebatilan sementara ia mengetahuinya maka ia senantiasa berada dalam kemurkaan Allah hingga ia meninggalkannya. Dan barangsiapa mengatakan pada diri seorang mukmin sesuatu yang tidak ada padanya, maka Allah akan menempatkannya dalam perasan penduduk Neraka hingga ia keluar (meninggalkan) dari apa yang ia katakan.\" Telah menceritakan kepada kami [Ali bin Al Husain bin Ibrahim] telah menceritakan kepada kami [Umar bin Yunus] telah menceritakan kepada kami ['Ashim bin Muhammad bin Zaid Al 'Umari] telah menceritakan kepadaku [Al Mutsanna bin Yazid] dari [Mathar Al Warraq] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan maknanya. Ia menyebutkan, \"Barangsiapa memberikan pertolongan dalam sebuah perselisihan dengan kezhaliman maka sungguh ia telah kembali dengan membawa kemarahan Allah 'azza wajalla.\""},"3046":{"ar":"حَدَّثَنِي يَحْيَى بْنُ مُوسَى الْبَلْخِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنِي سُفْيَانُ يَعْنِي الْعُصْفُرِيَّ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ النُّعْمَانِ الْأَسَدِيِّ عَنْ خُرَيْمِ بْنِ فَاتِكٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ فَلَمَّا انْصَرَفَ قَامَ قَائِمًا فَقَالَ عُدِلَتْ شَهَادَةُ الزُّورِ بِالْإِشْرَاكِ بِاللَّهِ ثَلَاثَ مِرَارٍ ثُمَّ قَرَأَ{ فَاجْتَنِبُوا الرِّجْسَ مِنْ الْأَوْثَانِ وَاجْتَنِبُوا قَوْلَ الزُّورِ حُنَفَاءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِ }","id":"Telah menceritakan kepadaku [Yahya bin Musa Al Balkhi] telah menceritakan kepada kami [Muhammad bin 'Ubaid] telah menceritakan kepadaku [Sufyan Al 'Ushfuri] dari [Ayahnya] dari [Habib bin An Nu'man Al Asadi] dari [Khuraim bin Fatik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melakukan Shalat Subuh, selesai shalat beliau bangkit dan berkata: \"Persaksian palsu disamakan dengan perbuatan mensekutukan Allah.\" Beliau mengucapkannya sebanyak tiga kali. Kemudian beliau membaca ayat: '(Maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta dengan ikhlas kepada Allah) ' (Qs. Al Hajj: 30). "},"3047":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ مُوسَى عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَدَّ شَهَادَةَ الْخَائِنِ وَالْخَائِنَةِ وَذِي الْغِمْرِ عَلَى أَخِيهِ وَرَدَّ شَهَادَةَ الْقَانِعِ لِأَهْلِ الْبَيْتِ وَأَجَازَهَا لِغَيْرِهِمْقَالَ أَبُو دَاوُد الْغِمْرُ الْحِنَةُ وَالشَّحْنَاءُ وَالْقَانِعُ الْأَجِيرُ التَّابِعُ مِثْلُ الْأَجِيرِ الْخَاصِّ حَدَّثَنَا مُحَمَّدُ بْنُ خَلَفِ بْنِ طَارِقٍ الرَّازِيُّ حَدَّثَنَا زَيْدُ بْنُ يَحْيَى بْنِ عُبَيْدٍ الْخُزَاعِيُّ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ سُلَيْمَانَ بْنِ مُوسَى بِإِسْنَادِهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَجُوزُ شَهَادَةُ خَائِنٍ وَلَا خَائِنَةٍ وَلَا زَانٍ وَلَا زَانِيَةٍ وَلَا ذِي غِمْرٍ عَلَى أَخِيهِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Muhammad bin Rasyid] telah menceritakan kepada kami [Sulaiman bin Musa] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah menolak persaksian orang laki-laki dan perempuan yang berkhianat serta orang yang memiliki kedengkian terhadap saudaranya. Dan beliau menolak persaksian orang yang bekerja untuk penghuni rumah, dan beliau memperbolehkan persaksian tersebut untuk orang selain mereka.\" Abu Daud berkata, \"Al Ghimru adalah permusuhan dan kebencian, sedangkan Al Qani' adalah buruh yang mengikuti seperti buruh special.\" Telah menceritakan kepada kami [Muhammad bin Khalaf bin Thariq Ar Razi] telah menceritakan kepada kami [Zaid bin Yahya bin 'Ubaid Al Khuza'i] telah menceritakan kepada kami [Sa'id bin Abdul 'Aziz] dari [Sulaiman bin Musa] dengan sanadnya, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh persaksian seorang laki-laki dan wanita yang berkhianat, dan tidak pula laki-laki serta wanita pezina dan orang yang memiliki kedengkian terhadap saudaranya.\""},"3048":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سَعِيدٍ الْهَمَدَانِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ وَنَافِعُ بْنُ يَزِيدَ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَجُوزُ شَهَادَةُ بَدَوِيٍّ عَلَى صَاحِبِ قَرْيَةٍ","id":"Telah menceritakan kepada kami [Ahmad bin Sa'id Al Hamdani] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yahya bin Ayyub] serta [Nafi' bin Yazid] dari [Ibnu Al Had] dari [Muhammad bin 'Amru bin 'Atha] dari ['Atha bin Yasar] dari [Abu Hurairah] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Persaksian orang pelosok tidak berlaku untuk penduduk kota.\""},"3049":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ حَدَّثَنِي عُقْبَةُ بْنُ الْحَارِثِ وَحَدَّثَنِيهِ صَاحِبٌ لِي عَنْهُ وَأَنَا لِحَدِيثِ صَاحِبِي أَحْفَظُ قَالَتَزَوَّجْتُ أُمَّ يَحْيَى بِنْتَ أَبِي إِهَابٍ فَدَخَلَتْ عَلَيْنَا امْرَأَةٌ سَوْدَاءُ فَزَعَمَتْ أَنَّهَا أَرْضَعَتْنَا جَمِيعًا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَأَعْرَضَ عَنِّي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهَا لَكَاذِبَةٌ قَالَ وَمَا يُدْرِيكَ وَقَدْ قَالَتْ مَا قَالَتْ دَعْهَا عَنْكَحَدَّثَنَا أَحْمَدُ بْنُ أَبِي شُعَيْبٍ الْحَرَّانِيُّ حَدَّثَنَا الْحَارِثُ بْنُ عُمَيْرٍ الْبَصْرِيُّ ح و حَدَّثَنَا عُثْمُانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ كِلَاهُمَا عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُبَيْدِ بْنِ أَبِي مَرْيَمَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ وَقَدْ سَمِعْتُهُ مِنْ عُقْبَةَ وَلَكِنِّي لِحَدِيثِ عُبَيْدٍ أَحْفَظُ فَذَكَرَ مَعْنَاهُ قَالَ أَبُو دَاوُد نَظَرَ حَمَّادُ بْنُ زَيْدٍ إِلَى الْحَارِثِ بْنِ عُمَيْرٍ فَقَالَ هَذَا مِنْ ثِقَاتِ أَصْحَابِ أَيُّوبَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Ibnu Abu Mulaikah] telah menceritakan kepadaku ['Uqbah bin Al Harits] dan telah menceritakannya kepadaku [sahabatku], dan aku lebih hafal terhadap hadits sahabatku, ia berkata, \"Aku menikahi Ummu Yahya binti Abu Ihab, kemudian seorang wanita hitam datang kepadaku dan mengaku bahwa ia telah menyusui kami semua. Lalu aku datang kepada Nabi shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepadanya. Beliau pun berpaling dariku, lalu aku katakan, \"Wahai Rasulullah, sesungguhnya ia telah berdusta.\" Beliau bersabda: \"Bagaimana engkau mengetahui, sementara ia telah mengatakan apa yang telah ia katakan. Tinggalkan wanita (isterimu) tersebut!\" Telah menceritakan kepada kami [Ahmad bin Abu Syu'aib Al Harrani] telah menceritakan kepada kami [Al Harits bin 'Umair Al Bashri]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin 'Ulaiyyah] keduanya berasal dari [Ayyub] dari [Ibnu Abu Mulaikah] dari ['Ubaid bin Abu Maryam] dari ['Uqbah bin Al Harits] aku telah mendengarnya dari 'Uqbah, akan tetapi aku lebih hafal dengan hadits 'Ubaid…lalu ia menyebutkan maknanya.\" Abu Daud berkata; [Hammad bin Zaid] melihat kepada Al Harits bin 'Umair kemudian berkata, \"Orang ini termasuk di antara sahabat-sahabat Ayyub yang tsiqah.\""},"3050":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا زَكَرِيَّا عَنْ الشَّعْبِيِّأَنَّ رَجُلًا مِنْ الْمُسْلِمِينَ حَضَرَتْهُ الْوَفَاةُ بِدَقُوقَاءَ هَذِهِ وَلَمْ يَجِدْ أَحَدًا مِنْ الْمُسْلِمِينَ يُشْهِدُهُ عَلَى وَصِيَّتِهِ فَأَشْهَدَ رَجُلَيْنِ مِنْ أَهْلِ الْكِتَابِ فَقَدِمَا الْكُوفَةَ فَأَتَيَا أَبَا مُوسَى الْأَشْعَرِيَّ فَأَخْبَرَاهُ وَقَدِمَا بِتَرِكَتِهِ وَوَصِيَّتِهِ فَقَالَ الْأَشْعَرِيُّ هَذَا أَمْرٌ لَمْ يَكُنْ بَعْدَ الَّذِي كَانَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَحْلَفَهُمَا بَعْدَ الْعَصْرِ بِاللَّهِ مَا خَانَا وَلَا كَذَبَا وَلَا بَدَّلَا وَلَا كَتَمَا وَلَا غَيَّرَا وَإِنَّهَا لَوَصِيَّةُ الرَّجُلِ وَتَرِكَتُهُ فَأَمْضَى شَهَادَتَهُمَا","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Zakaria] dari [Asy Sya'bi] bahwa seorang muslim meninggal di Daquqa` (daerah antara Baghdad dan Irbil), dan tidak ada seseorang yang bisa menjadi saksi terhadap wasiatnya. Kemudian ada dua orang ahli kitab memberi persaksian hingga mereka pun datang ke Kufah menemui [Abu Musa Al Asy'ari] dan mengabarkan hal tersebut. keduanya datang dengan membawa harta warisan dan wasiat orang yang meninggal tersebut, Abu Musa Al Asy'ari lalu berkata, \"Ini adalah permasalahan yang belum pernah terjadi sejak zaman Rasulullah shallallahu 'alaihi wasallam.\" Lalu Abu Musa meminta mereka berdua agar bersumpah dengan nama Allah bahwa mereka tidak berkhianat, tidak berdusta, tidak mengganti, tidak menyembunyikan serta tidak merubah, dan bahwa wasiat dan harta wasiatnya itu adalah wasiat laki-laki tersebut. Abu Musa kemudian menerima persaksian mereka berdua.\""},"3051":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ مُحَمَّدِ بْنِ أَبِي الْقَاسِمِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَخَرَجَ رَجُلٌ مِنْ بَنِي سَهْمٍ مَعَ تَمِيمٍ الدَّارِيِّ وَعُدَيِّ بْنِ بَدَّاءٍ فَمَاتَ السَّهْمِيُّ بِأَرْضٍ لَيْسَ بِهَا مُسْلِمٌ فَلَمَّا قَدِمَا بِتَرِكَتِهِ فَقَدُوا جَامَ فِضَّةٍ مُخَوَّصًا بِالذَّهَبِ فَأَحْلَفَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ وُجِدَ الْجَامُ بِمَكَّةَ فَقَالُوا اشْتَرَيْنَاهُ مِنْ تَمِيمٍ وَعُدَيٍّ فَقَامَ رَجُلَانِ مِنْ أَوْلِيَاءِ السَّهْمِيِّ فَحَلَفَا لَشَهَادَتُنَا أَحَقُّ مِنْ شَهَادَتِهِمَا وَإِنَّ الْجَامَ لِصَاحِبِهِمْ قَالَ فَنَزَلَتْ فِيهِمْ{ يَا أَيُّهَا الَّذِينَ آمَنُوا شَهَادَةُ بَيْنِكُمْ إِذَا حَضَرَ أَحَدَكُمْ الْمَوْتُ }الْآيَةَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Ibnu Abu Zaidah] dari [Muhammad bin Abu Al Qasim] dari [Abdul Malik bin Sa'id bin Jubair] dari [Ayahnya] dari [Ibnu Abbas] ia berkata, \"Seorang laki-laki Bani Sahm keluar bersama Tamim Ad Dari dan 'Udai bin Badda, kemudian orang dari Bani Sahm tersebut meninggal di negeri yang tidak ada seorang Muslim pun di dalamnya. Kemudian tatkala mereka berdua datang dengan membawa harta warisannya mereka kehilangan gelas perak yang terukir dengan emas seperti daun kurma. Lalu Rasulullah shallallahu 'alaihi wasallam meminta mereka berdua agar bersumpah, dan gelas itu kemudian ditemukan di Makkah, keduanya lalu berkata, \"Kami membelinya dari Tamim dan 'Udai.\" Dua orang dari wali laki-laki Bani As Sahm kemudian berdiri dan bersumpah, 'Sungguh persaksian kami lebih berhak dari pada persaksian mereka berdua. ' Dan sesungguhnya gelas tersebut adalah milik sahabat mereka.\" Jubair berkata, \"Kemudian turunlah ayat: '(Hai orang-orang yang beriman, apabila salah seorang kamu menghadapi kematian, sedang dia akan berwasiat, maka hendaklah (wasiat itu) disaksikan oleh dua orang yang adil di antara kamu, atau dua orang yang berlainan agama dengan kamu, jika kamu dalam perjalanan di muka bumi lalu kamu ditimpa bahaya kematian. Kamu tahan kedua saksi itu sesudah sembahyang (untuk bersumpah), lalu mereka keduanya bersumpah dengan nama Allah, jika kamu ragu-ragu: \"(Demi Allah) kami tidak akan membeli dengan sumpah ini harga yang sedikit (untuk kepentingan seseorang), walaupun dia karib kerabat, dan tidak (pula) kami menyembunyikan persaksian Allah; sesungguhnya kami kalau demikian tentulah termasuk orang-orang yang berdosa) ' (Qs. Al Maidah: 106). "},"3052":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ أَنَّ الْحَكَمَ بْنَ نَافِعٍ حَدَّثَهُمْ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ أَنَّ عَمَّهُ حَدَّثَهُ وَهُوَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعَ فَرَسًا مِنْ أَعْرَابِيٍّ فَاسْتَتْبَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَقْضِيَهُ ثَمَنَ فَرَسِهِ فَأَسْرَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَشْيَ وَأَبْطَأَ الْأَعْرَابِيُّ فَطَفِقَ رِجَالٌ يَعْتَرِضُونَ الْأَعْرَابِيَّ فَيُسَاوِمُونَهُ بِالْفَرَسِ وَلَا يَشْعُرُونَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعَهُ فَنَادَى الْأَعْرَابِيُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ كُنْتَ مُبْتَاعًا هَذَا الْفَرَسِ وَإِلَّا بِعْتُهُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ سَمِعَ نِدَاءَ الْأَعْرَابِيِّ فَقَالَ أَوْ لَيْسَ قَدْ ابْتَعْتُهُ مِنْكَ فَقَالَ الْأَعْرَابِيُّ لَا وَاللَّهِ مَا بِعْتُكَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلَى قَدْ ابْتَعْتُهُ مِنْكَ فَطَفِقَ الْأَعْرَابِيُّ يَقُولُ هَلُمَّ شَهِيدًا فَقَالَ خُزَيْمَةُ بْنُ ثَابِتٍ أَنَا أَشْهَدُ أَنَّكَ قَدْ بَايَعْتَهُ فَأَقْبَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى خُزَيْمَةَ فَقَالَ بِمَ تَشْهَدُ فَقَالَ بِتَصْدِيقِكَ يَا رَسُولَ اللَّهِ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهَادَةَ خُزَيْمَةَ بِشَهَادَةِ رَجُلَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] bahwa [Al Hakam bin Nafi'] telah menceritakan kepada mereka, ia berkata; telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dari ['Umarah bin Khuzaimah] bahwa [pamannya] seorang sahabat Nabi shallallahu 'alaihi wasallam, telah menceritakan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam pernah membeli seekor kuda dari seorang Arab dusun, kemudian Nabi shallallahu 'alaihi wasallam meminta kepada Arab dusun tersebut untuk mengikutinya sehingga beliau bisa membayar kuda yang dibelinya. Rasulullah shallallahu 'alaihi wasallam berjalan cepat sementara orang Arab dusun tersebut berjalan lambat. Setelah itu orang-orang datang kepada Arab dusun itu dan menawar kudanya, dan mereka tidak mengetahui bahwa Nabi shallallahu 'alaihi wasallam telah membelinya. Arab dusun itu kemudian datang menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Apabila engkau membeli kuda ini maka belilah, jika tidak maka aku akan menjualnya.\" Saat mendengar panggilan Arab dusun itu Nabi shallallahu 'alaihi wasallam bangkit dan berkata: \"Bukankah aku telah membelinya darimu?\" Arab dusun itu menjawab, \"Demi Allah, tidak! Aku tidak menjualnya kepadamu.\" Nabi shallallahu 'alaihi wasallam lalu berkata: \"Benar, aku telah membelinya darimu.\" Maka Arab dusun itu pun berkata, \"Berikan kepadaku seorang saksi.\" Kemudian Khuzaimah bin Tsabit berkata, \"Aku bersaksi bahwa engkau telah menjualnya.\" Lalu Nabi shallallahu 'alaihi wasallam menghadap kepada ke arah Khuzaimah dan berkata: \"Dengan apakah engkau bersaksi?\" Khuzaimah menjawab, \"Dengan membenarkanmu wahai Rasulullah!\" Lalu Rasulullah shallallahu 'alaihi wasallam menjadikan persaksian Khuzaimah sama dengan persaksian dua orang.\""},"3053":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَالْحَسَنُ بْنُ عَلِيٍّ أَنَّ زَيْدَ بْنَ الْحُبَابِ حَدَّثَهُمْ حَدَّثَنَا سَيْفٌ الْمَكَّيُّ قَالَ عُثْمَانُ سَيْفُ بْنُ سُلَيْمَانَ عَنْ قَيْسِ بْنِ سَعْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِيَمِينٍ وَشَاهِدٍحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى وَسَلَمَةُ بْنُ شَبِيبٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مُحَمَّدُ بْنُ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ سَلَمَةُ فِي حَدِيثِهِ قَالَ عَمْرٌو فِي الْحُقُوقِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Al Hasan bin Ali] bahwa [Zaid bin Al Hubab] menceritakan kepada mereka, ia berkata; telah menceritakan kepada kami [Saiful Makki]. [Utsman Saif bin Sulaiman] berkata dari [Qais bin Sa'd] dari ['Amru bin Dinar] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam memberikan putusan dengan adanya sumpah dan seorang saksi.\" Telah menceritakan kepada kami [Muhammad bin Yahya] dan [Salamah bin Syabib] mereka berdua berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Muhammad bin Muslim] dari ['Amru bin Dinar] dengan sanad dan maknanya. Salamah menyebutkan dalam haditsnya; 'Amru berkata dalam masalah hak.\""},"3054":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي بَكْرٍ أَبُو مُصْعَبٍ الزُّهْرِيُّ حَدَّثَنَا الدَّرَاوَرْدِيُّ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْيَمِينِ مَعَ الشَّاهِدِقَالَ أَبُو دَاوُد وَزَادَنِي الرَّبِيعُ بْنُ سُلَيْمَانَ الْمُؤَذِّنُ فِي هَذَا الْحَدِيثِ قَالَ أَخْبَرَنِي الشَّافِعِيُّ عَنْ عَبْدِ الْعَزِيزِ قَالَ فَذَكَرْتُ ذَلِكَ لِسُهَيْلٍ فَقَالَ أَخْبَرَنِي رَبِيعَةُ وَهُوَ عِنْدِي ثِقَةٌ أَنِّي حَدَّثْتُهُ إِيَّاهُ وَلَا أَحْفَظُهُ قَالَ عَبْدُ الْعَزِيزِ وَقَدْ كَانَ أَصَابَتْ سُهَيْلًا عِلَّةٌ أَذْهَبَتْ بَعْضَ عَقْلِهِ وَنَسِيَ بَعْضَ حَدِيثِهِ فَكَانَ سُهَيْلٌ بَعْدُ يُحَدِّثُهُ عَنْ رَبِيعَةَ عَنْ أَبِيهِ حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ الْإِسْكَنْدَرَانِيُّ حَدَّثَنَا زِيَادٌ يَعْنِي ابْنَ يُونُسَ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ رَبِيعَةَ بِإِسْنَادِ أَبِي مُصْعَبٍ وَمَعْنَاهُ قَالَ سُلَيْمَانُ فَلَقِيتُ سُهَيْلًا فَسَأَلْتُهُ عَنْ هَذَا الْحَدِيثِ فَقَالَ مَا أَعْرِفُهُ فَقُلْتُ لَهُ إِنَّ رَبِيعَةَ أَخْبَرَنِي بِهِ عَنْكَ قَالَ فَإِنْ كَانَ رَبِيعَةُ أَخْبَرَكَ عَنِّي فَحَدِّثْ بِهِ عَنْ رَبِيعَةَ عَنِّي","id":"Telah menceritakan kepada kami [Ahmad bin Abu Bakr Abu Mush'ab Az Zuhri] dari [Rabi'ah bin Abu Abdurrahman] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam memberikan putusan dengan adanya sumpah dan satu orang saksi.\" Abu Daud berkata, \" [Ar Rabi' bin Sulaiman Al Muadzdzin] dalam haditsnya menambahkan kepadaku, ia berkata; telah mengabarkan kepadaku [Asy Syafi'i] dari [Abdul Aziz] ia berkata, \"Hal itu kemudian aku ceritakan kepada [Suhail], ia pun berkata; telah mengabarkan kepadaku [Rabi'ah] -dan ia menurutku adalah orang yang tsiqah- bahwa aku telah menceritakan hal tersebut kepadanya dan aku sudah tidak menghafalnya. Abdul Aziz berkata; Suhail telah terkena suatu penyakit yang menghilangkan sebagian ingatannya, hingga ia lupa sebagian haditsnya. Setelah itu ia menceritakan kepadanya dari Rabi'ah dari ayahnya.\" Telah menceritakan kepada kami [Muhammad bin Daud Al Iskandarani] telah menceritakan kepada kami [Ziyad bin Yunus] telah menceritakan kepadaku [Sulaiman bin Bilal] dari [Rabi'ah] dengan sanad Abu Mush'ab dan dengan maknanya. Sulaiman berkata, \"Kemudian aku bertemu dengan Suhail dan bertanya kepadanya mengenai hadits ini, lalu ia berkata, \"Aku tidak mengetahuinya.\" Lalu aku katakan kepadanya, \"Sesungguhnya Rabi'ah telah mengabarkannya kepadaku darimu.\" Ia berkata, \"Jika Rabi'ah pernah mengabarkan kepadamu dariku, maka ceritakan (riwayat) dari Rabi'ah dariku.\""},"3055":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا عَمَّارُ بْنُ شُعَيْثِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْبِ الْعَنْبَرِيُّ حَدَّثَنِي أَبِي قَالَ سَمِعْتُ جَدِّي الزُّبَيْبَ يَقُولُبَعَثَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَيْشًا إِلَى بَنِي الْعَنْبَرِ فَأَخَذُوهُمْ بِرُكْبَةَ مِنْ نَاحِيَةِ الطَّائِفِ فَاسْتَاقُوهُمْ إِلَى نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَكِبْتُ فَسَبَقْتُهُمْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ السَّلَامُ عَلَيْكَ يَا نَبِيَّ اللَّهِ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ أَتَانَا جُنْدُكَ فَأَخَذُونَا وَقَدْ كُنَّا أَسْلَمْنَا وَخَضْرَمْنَا آذَانَ النَّعَمِ فَلَمَّا قَدِمَ بَلْعَنْبَرِ قَالَ لِي نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكُمْ بَيِّنَةٌ عَلَى أَنَّكُمْ أَسْلَمْتُمْ قَبْلَ أَنْ تُؤْخَذُوا فِي هَذِهِ الْأَيَّامِ قُلْتُ نَعَمْ قَالَ مَنْ بَيِّنَتُكَ قُلْتُ سَمُرَةُ رَجُلٌ مِنْ بَنِي الْعَنْبَرِ وَرَجُلٌ آخَرُ سَمَّاهُ لَهُ فَشَهِدَ الرَّجُلُ وَأَبَى سَمُرَةُ أَنْ يَشْهَدَ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَبَى أَنْ يَشْهَدَ لَكَ فَتَحْلِفُ مَعَ شَاهِدِكَ الْآخَرِ قُلْتُ نَعَمْ فَاسْتَحْلَفَنِي فَحَلَفْتُ بِاللَّهِ لَقَدْ أَسْلَمْنَا يَوْمَ كَذَا وَكَذَا وَخَضْرَمْنَا آذَانَ النَّعَمِ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبُوا فَقَاسِمُوهُمْ أَنْصَافَ الْأَمْوَالِ وَلَا تَمَسُّوا ذَرَارِيَّهُمْ لَوْلَا أَنَّ اللَّهَ لَا يُحِبُّ ضَلَالَةَ نَمَل مَا رَزَيْنَاكُمْ عِقَالًا قَالَ الزُّبَيْبُ فَدَعَتْنِي أُمِّي فَقَالَتْ هَذَا الرَّجُلُ أَخَذَ زِرْبِيَّتِي فَانْصَرَفْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي فَأَخْبَرْتُهُ فَقَالَ لِي احْبِسْهُ فَأَخَذْتُ بِتَلْبِيبِهِ وَقُمْتُ مَعَهُ مَكَانَنَا ثُمَّ نَظَرَ إِلَيْنَا نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمَيْنِ فَقَالَ مَا تُرِيدُ بِأَسِيرِكَ فَأَرْسَلْتُهُ مِنْ يَدِي فَقَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِلرَّجُلِ رُدَّ عَلَى هَذَا زِرْبِيَّةَ أُمِّهِ الَّتِي أَخَذْتَ مِنْهَا فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّهَا خَرَجَتْ مِنْ يَدِي قَالَ فَاخْتَلَعَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيْفَ الرَّجُلِ فَأَعْطَانِيهِ وَقَالَ لِلرَّجُلِ اذْهَبْ فَزِدْهُ آصُعًا مِنْ طَعَامٍ قَالَ فَزَادَنِي آصُعًا مِنْ شَعِيرٍ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] telah menceritakan kepada kami ['Ammar bin Syu'aib bin Abdullah bin Az Zubaib Al 'Anbari] telah menceritakan kepadaku [Ayahku] ia berkata; aku mendengar kakekku [Az Zubaib] berkata, \"Nabi Allah shallallahu 'alaihi wasallam mengutus sepasukan menuju Bani Al 'Anbar, lalu pasukan tersebut menyerang mereka di Rukbah (bukit di Thaif) dari arah Thaif, pasukan itu kemudian menggiringnya menemui Nabi Allah shallallahu 'alaihi wasallam. Aku lantas mengendarai kuda dan mendahului mereka menuju Nabi shallallahu 'alaihi wasallam, dan aku ucapkan 'As salamu 'alaika wa rahmatullahi wa barakatuh wahai Nabi Allah! Pasukan anda telah datang dan menyerang kami, padahal kami telah masuk Islam dan telah memotong ujung telinga hewan-hewan ternak kami.\" Kemudian tatkala sampai di Bal'anbar Nabi Allah shallallahu 'alaihi wasallam berkata kepadaku: \"Apakah kalian memiliki bukti bahwa kalian telah masuk Islam sebelum diserang pada beberapa hari ini?\" Aku katakan, \"Ya.\" Beliau bertanya: \"Siapakah yang bisa menjadi saksi untukmu?\" Aku katakan, \"Samurah, seorang laki-laki dari Bani Al 'Anbar.\" Dan seorang laki-laki lain yang ia sebutkan. Kemudian laki-laki tersebut bersaksi sementara Samurah menolak untuk bersaksi. Nabi Allah shallallahu 'alaihi wasallam kemudian bersabda: \"Ia enggan bersaksi untukmu, maka engkau bisa bersumpah bersama saksimu yang lain.\" Aku katakan, \"Ya.\" Lalu beliau memintaku untuk bersumpah, maka aku bersumpah dengan nama Allah, 'Sungguh kami telah masuk Islam pada hari ini dan ini, dan kami telah memotong ujung telinga hewan-hewan ternak. ' Kemudian Nabi Allah shallallahu 'alaihi wasallam bersabda: \"Pergilah kalian dan bagilah untuk mereka separuh harta tersebut dan jangan kalian sentuh keturunan-keturunan mereka! Seandainya Allah tidak membenci hilangnya suatu amal maka kami tidak akan mengurangi kalian satu 'Iqalpun (tali unta).\" Az Zubaib berkata, \"Kemudian ibuku memanggilku dan berkata, \"Orang ini telah mengambil permadaniku.\" Lalu aku pergi menemui Nabi shallallahu 'alaihi wasallam dan mengabarkan hal tersebut, beliau pun berkata: \"Tahanlah dia!\" Lalu aku cengkeram bajunya, dan aku berdiri bersamanya di tempat kami. Kemudian Nabi shallallahu 'alaihi wasallam melihat kepada kami dalam keadaan berdiri, lalu beliau bersabda: \"Apa yang engkau kehendaki dengan tawananmu?\" Lalu aku melepaskannya, kemudian Nabi Allah shallallahu 'alaihi wasallam berdiri dan berkata kepada orang tersebut: \"Kembalikan kepada orang ini permadani milik ibunya yang telah engkau ambil!\" Orang tersebut berkata, \"Wahai Nabi Allah, sesungguhnya permadani tersebut telah hilang dari tanganku.\" Az Zubaib berkata, \"Kemudian Nabi Allah shallallahu 'alaihi wasallam melepas pedang laki-laki tersebut dan memberikannya kepadaku, kemudian beliau berkata kepada laki-laki itu: \"Pergi dan tambahlah beberapa sha' makanan!\" Az Zubaib berkata, \"Kemudian laki-laki itu menambahku beberapa sha' gandum.\""},"3056":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ الضَّرِيرُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا ابْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ أَبِي مُوسَى الْأَشْعَرِيِّأَنَّ رَجُلَيْنِ ادَّعَيَا بَعِيرًا أَوْ دَابَّةً إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَتْ لِوَاحِدٍ مِنْهُمَا بَيِّنَةٌ فَجَعَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَاحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ سَعِيدٍ بِإِسْنَادِهِ وَمَعْنَاهُ حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ بِمَعْنَى إِسْنَادِهِ أَنَّ رَجُلَيْنِ ادَّعَيَا بَعِيرًا عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ كُلُّ وَاحِدٍ مِنْهُمَا شَاهِدَيْنِ فَقَسَمَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا نِصْفَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Minhal Adl Dlarir] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ibnu Abu 'Arubah] dari [Qatadah] dari [Sa'id bin Abu Burdah] dari [Ayahnya] dari kakeknya [Abu Musa Al Asy'ari] bahwa ada dua orang laki-laki mengklaim seekor unta atau seekor hewan kepada Nabi shallallahu 'alaihi wasallam, sementara keduanya tidak memiliki bukti. Nabi shallallahu 'alaihi wasallam lalu membagi unta tersebut untuk keduanya.\" Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Sa'id] dengan sanad dan maknanya.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammam] dari [Qatadah] dengan makna sanadnya, bahwa dua orang yang mengklaim seekor unta pada zaman Nabi shallallahu 'alaihi wasallam, lalu keduanya mengirimkan dua orang saksi, Nabi shallallahu 'alaihi wasallam kemudian membagi unta tersebut untuk mereka berdua.\""},"3057":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمِنْهَالِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا ابْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ خِلَاسٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلَيْنِ اخْتَصَمَا فِي مَتَاعٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ لِوَاحِدٍ مِنْهُمَا بَيِّنَةٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَهِمَا عَلَى الْيَمِينِ مَا كَانَ أَحَبَّا ذَلِكَ أَوْ كَرِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Minhal] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ibnu Abu 'Arubah] dari [Qatadah] dari [Khilas] dari [Abu Rafi'] dari [Abu Hurairah] bahwa dua orang laki-laki mengadukan perselisihan tentang sebuah barang kepada Nabi shallallahu 'alaihi wasallam, sementara keduanya tidak memiliki bukti. Lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Undilah untuk melakukan sumpah!\" Baik keduanya menyukai hal tersebut atau membencinya.\""},"3058":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَسَلَمَةُ بْنُ شَبِيبٍ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَحْمَدُ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَرِهَ الِاثْنَانِ الْيَمِينَ أَوْ اسْتَحَبَّاهَا فَلْيَسْتَهِمَا عَلَيْهَا قَالَ سَلَمَةُ قَالَ أَخْبَرَنَا مَعْمَرٌ وَقَالَ إِذَا أُكْرِهَ الِاثْنَانِ عَلَى الْيَمِي��ِحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ بِإِسْنَادِ ابْنِ مِنْهَالٍ مِثْلَهُ قَالَ فِي دَابَّةٍ وَلَيْسَ لَهُمَا بَيِّنَةٌ فَأَمَرَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْتَهِمَا عَلَى الْيَمِينِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Salamah bin Syabib] mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] [Ahmad] berkata; telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila dua orang tidak senang bersumpah atau tidak menyukainya, maka hendaknya mereka berdua berundi untuk mendapatkannya.\" [Salamah] berkata; telah mengabarkan kepada kami [Ma'mar] dan ia berkata, \"Apabila dua orang dipaksa untuk bersumpah.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Khalid bin Al Harits] dari [Sa'id bin Abu 'Arubah] dengan sanad Ibnu Minhal, \n\n(Yaitu; dari [Qatadah] dari [Khilas] dari [Abu Rafi'] dari [Abu Hurairah]) seperti itu. Ia menyebutkan tentang seekor hewan dan mereka tidak memiliki bukti, lalu Rasulullah shallallahu 'alaihi wasallam memerintahkan mereka berdua agar mengundi untuk mendapatkan hewan tersebut.\""},"3059":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَكَتَبَ إِلَيَّ ابْنُ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِالْيَمِينِ عَلَى الْمُدَّعَى عَلَيْهِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Al Qa'nabi] telah menceritakan kepada kami [Nafi' bin Umar] dari [Ibnu Abu Mulaikah] ia berkata, \" [Ibnu Abbas] menulis surat kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam memberi putusan bahwa orang yang tertuduh harus bersumpah.\""},"3060":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِي يَحْيَى عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَعْنِي لِرَجُلٍ حَلَّفَهُ احْلِفْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ مَا لَهُ عِنْدَكَ شَيْءٌ يَعْنِي لِلْمُدَّعِيقَالَ أَبُو دَاوُد أَبُو يَحْيَى اسْمُهُ زِيَادٌ كُوفِيٌّ ثِقَةٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu Al Ahwash] telah menceritakan kepada kami ['Atha bin As Saib] dari [Abu Yahya] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam berkata kepada seorang laki-laki yang beliau perintahkan agar bersumpah: \"Bersumpahlah dengan nama Allah yang tidak ada tuhan yang berhak disembah melainkan Allah, bahwa ia tidak memiliki sesuatu yang diklaim ada padamu.\" Abu Daud berkata, \"Abu Yahya namanya Ziyad Kufi, ia adalah orang yang tsiqah.\""},"3061":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ الْأَشْعَثِ قَالَكَانَ بَيْنِي وَبَيْنَ رَجُلٍ مِنْ الْيَهُودِ أَرْضٌ فَجَحَدَنِي فَقَدَّمْتُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَكَ بَيِّنَةٌ قُلْتُ لَا قَالَ لِلْيَهُودِيِّ احْلِفْ قُلْتُ يَا رَسُولَ اللَّهِ إِذًا يَحْلِفُ وَيَذْهَبُ بِمَالِي فَأَنْزَلَ اللَّهُ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Al Asy'ats] ia berkata, \"Aku dan seorang laki-laki Yahudi berselisih atas sebuah lahan, kemudian ia mengingkariku. Maka aku pun datang menemui Nabi shallallahu 'alaihi wasallam dan mengadukan hal itu kepadanya, Nabi shallallahu 'alaihi wasallam lalu berkata kepadaku: \"Apakah engkau memiliki bukti?\" Aku menjawab, \"Tidak.\" Beliau bersabda kepada orang Yahudi tersebut: \"Bersumpahlah!\" Maka aku katakan, \"Wahai Rasulullah, jika demikian ia akan bersumpah dan membawa hartaku!\" Kemudian Allah menurunkan ayat: '(Sesungguhnya orang-orang yang menukar janji (nya dengan) Allah dan sumpah-sumpah mereka dengan harga yang sedikit…) ' (Qs. Ali Imran: 77) hingga akhir ayat.\""},"3062":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا الْفَرْيَابِيُّ حَدَّثَنَا الْحَارِثُ بْنُ سُلَيْمَانَ حَدَّثَنِي كُرْدُوسٌ عَنْ الْأَشْعَثِ بْنِ قَيْسٍأَنَّ رَجُلًا مِنْ كِنْدَةَ وَرَجُلًا مِنْ حَضْرَمَوْتَ اخْتَصَمَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَرْضٍ مِنْ الْيَمَنِ فَقَالَ الْحَضْرَمِيُّ يَا رَسُولَ اللَّهِ إِنَّ أَرْضِي اغْتَصَبَنِيهَا أَبُو هَذَا وَهِيَ فِي يَدِهِ قَالَ هَلْ لَكَ بَيِّنَةٌ قَالَ لَا وَلَكِنْ أُحَلِّفُهُ وَاللَّهِ مَا يَعْلَمُ أَنَّهَا أَرْضِي اغْتَصَبَنِيهَا أَبُوهُ فَتَهَيَّأَ الْكِنْدِيُّ يَعْنِي لِلْيَمِينِ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] telah menceritakan kepada kami [Al Faryabi] telah menceritakan kepada kami [Al Harits bin Sulaiman] telah menceritakan kepadaku [Kurdus] dari [Al Asy'ats bin Qais] bahwa seorang laki-laki dari Kindah dan seorang laki-laki dari Hadlramaut mengadukan perselisihan mereka tentang lahan yang ada di Yaman kepada Nabi shallallahu 'alaihi wasallam. Orang Hadlrami berkata, \"Wahai Rasulullah, sesungguhnya tanahku telah dirampas bapak orang ini. Dan tanah tersebut ada di tangannya.\" Beliau bersabda: \"Apakah engkau memiliki bukti?\" Aku katakan, \"Tidak, akan tetapi aku memintanya agar ia bersumpah. Demi Allah ia tidak mengetahui bahwa tanah tersebut adalah tanahku yang dirampas oleh bapaknya.\" Maka orang Kindah tersebut bersiap-siap untuk bersumpah…. Al Asy'ats lalu menyebutkan hadits tersebut.\""},"3063":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ عَلْقَمَةَ بْنِ وَائِلِ بْنِ حُجْرٍ الْحَضْرَمِيِّ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ مِنْ حَضْرَمَوْتَ وَرَجُلٌ مِنْ كِنْدَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ الْحَضْرَمِيُّ يَا رَسُولَ اللَّهِ إِنَّ هَذَا غَلَبَنِي عَلَى أَرْضٍ كَانَتْ لِأَبِي فَقَالَ الْكِنْدِيُّ هِيَ أَرْضِي فِي يَدِي أَزْرَعُهَا لَيْسَ لَهُ فِيهَا حَقٌّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْحَضْرَمِيِّ أَلَكَ بَيِّنَةٌ قَالَ لَا قَالَ فَلَكَ يَمِينُهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهُ فَاجِرٌ لَيْسَ يُبَالِي مَا حَلَفَ لَيْسَ يَتَوَرَّعُ مِنْ شَيْءٍ فَقَالَ لَيْسَ لَكَ مِنْهُ إِلَّا ذَلِكَ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari ['Alqamah bin Wail bin Hujr Al Hadlrami] dari [Ayahnya] ia berkata, \"Seorang laki-laki Hadlramaut dan seorang laki-laki dari Kindah datang kepada Rasulullah shallallahu 'alaihi wasallam. Orang Hadlramaut tersebut berkata, \"Wahai Rasulullah, sesungguhnya orang ini telah menguasai tanah yang dahulu adalah milik ayahku.\" Kemudian orang Kindi tersebut berkata, \"Tanah itu adalah tanahku, ia ada padaku dan aku yang menanaminya, dia tidak memiliki hak pada tanah tersebut!\" 'Alqamah bin Wail berkata, \"Kemudian Nabi shallallahu 'alaihi wasallam bertanya kepada orang Hadlrami, \"Apakah engkau memiliki bukti?\" Orang Hadlrami itu menjawab, \"Tidak.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Bagimu sumpahnya.\" Orang Hadlrami itu pun berkata, \"Wahai Rasulullah, dia itu orang yang suka berbuat dosa, dia tidak peduli dengan apa yang ia bersumpah atasnya! Ia tidak menjaga diri dari sesuatupun.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Engkau tidak bisa melakukan apapun kecuali hanya itu.\""},"3064":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ حَدَّثَنَا رَجُلٌ مِنْ مُزَيْنَةَ وَنَحْنُ عِنْدَ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي لِلْيَهُودِ أَنْشُدُكُمْ بِاللَّهِ الَّذِي أَنْزَلَ التَّوْرَاةَ عَلَى مُوسَى مَا تَجِدُونَ فِي التَّوْرَاةِ عَلَى مَنْ زَنَى وَسَاقَ الْحَدِيثَ فِي قِصَّةِ الرَّجْمِحَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى أَبُو الْأَصْبَغِ حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الزُّهْرِيِّ بِهَذَا الْحَدِيثِ وَبِإِسْنَادِهِ قَالَ حَدَّثَنِي رَجُلٌ مِنْ مُزْيَنَةَ مِمَّنْ كَانَ يَتَّبِعُ الْعِلْمَ وَيَعِيهِ يُحَدِّثُ سَعِيدَ بْنَ الْمُسَيِّبِ وَسَاقَ الْحَدِيثَ بِمَعْنَاهُ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ يَعْنِي لِابْنِ صُورِيَا أُذَكِّرُكُمْ بِاللَّهِ الَّذِي نَجَّاكُمْ مِنْ آلِ فِرْعَوْنَ وَأَقْطَعَكُمْ الْبَحْرَ وَظَلَّلَ عَلَيْكُمْ الْغَمَامَ وَأَنْزَلَ عَلَيْكُمْ الْمَنَّ وَالسَّلْوَى وَأَنْزَلَ عَلَيْكُمْ التَّوْرَاةَ عَلَى مُوسَى أَتَجِدُونَ فِي كِتَابِكُمْ الرَّجْمَ قَالَ ذَكَّرْتَنِي بِعَظِيمٍ وَلَا يَسَعُنِي أَنْ أَكْذِبَكَ وَسَاقَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah menceritakan kepada kami [seorang laki-laki Muzainah] -saat itu kami berada di sisi Sa'id bin Al Musayyab- dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam berkata kepada seorang Yahudi: \"Aku sumpahi kamu atas nama Allah yang telah menurunkan Taurat kepada Musa, hukuman apakah yang kalian dapatkan dalam Taurat terhadap orang yang berzina? Abu Hurairah menyebutkan terusan hadits tersebut dalam masalah rajam.\" Telah menceritakan kepada kami [Abdul Aziz bin Yahya Abu Al Ashbagh] telah menceritakan kepadaku [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Az Zuhri] dengan hadits ini dan dengan sanadnya. Ia berkata; telah menceritakan kepadaku [seorang laki-laki Muzainah] dari orang yang mengikuti ilmu dan memahaminya, ia menceritakan dari Sa'id bin Al Musayyab, lalu ia menyebutkan hadits tersebut dengan maknanya.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Ikrimah] bahwa Nabi shallallahu 'alaihi wasallam berkata kepada Ibnu Shuriya: \"Aku ingatkan kalian kepada Allah yang telah menyelamatkan kalian dari keluarga Fir'aun, membelah laut untuk kalian, menaungi kalian dengan awan, menurunkan Al Mann dan As Salwa kepada kalian, serta menurunkan Taurat kepada Musa. Apakah kalian mendapatkan rajam dalam Kitab kalian?\" Ibnu Shuriya menjawab, \"Engkau telah mengingatkan aku dengan sesuatu yang agung, tidak ada alasan bagiku untuk mendustaimu….. lalu ia menyebutkan hadits tersebut.\""},"3065":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ وَمُوسَى بْنُ مَرْوَانَ الرَّقِّيُّ قَالَا حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ سَيْفٍ عَنْ عَوْفِ بْنِ مَالِكٍ أَنَّهُ حَدَّثَهُمْأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بَيْنَ رَجُلَيْنِ فَقَالَ الْمَقْضِيُّ عَلَيْهِ لَمَّا أَدْبَرَ حَسْبِيَ اللَّهُ وَنِعْمَ الْوَكِيلُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَلُومُ عَلَى الْعَجْزِ وَلَكِنْ عَلَيْكَ بِالْكَيْسِ فَإِذَا غَلَبَكَ أَمْرٌ فَقُلْ حَسْبِيَ اللَّهُ وَنِعْمَ الْوَكِيلُ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah] dan [Musa bin Marwan Ar Raqqi] mereka berkata; telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Saif] dari ['Auf bin Malik] bahwa ia menceritakan kepada mereka, bahwa Nabi shallallahu 'alaihi wasallam telah memberikan keputusan di antara dua orang laki-laki, kemudian orang yang diputuskan atasnya ketika pergi mengatakan, \"Cukuplah Allah bagiku dan Dia adalah sebaik-baik pelindung.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah mencela kelemahan, hendaklah kalian berlaku bijak, jika kalian mendapati sesuatu yang kalian tidak sukai maka ucapkanlah: HASBIALLAHU WA NI'MAL WAKIL (Cukuplah Allah bagiku dan Dia adalah sebaik-baik pelindung).\""},"3066":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ وَبْرِ بْنِ أَبِي دُلَيْلَةَ عَنْ مُحَمَّدِ بْنِ مَيْمُونٍ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيُّ الْوَاجِدِ يُحِلُّ عِرْضَهُ وَعُقُوبَتَهُقَالَ ابْنُ الْمُبَارَكِ يُحِلُّ عِرْضُهُ يُغَلَّظُ لَهُ وَعُقُوبَتَهُ يُحْبَسُ لَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Wabr bin Abu Dulailah] dari [Muhammad bin Maimun] dari ['Amru bin Asy Syarid] dari [Ayahnya] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Orang mampu yang menunda pembayaran hutangnya, maka kehormatan dan hukuman telah halal untuknya.\" Ibnu Al Mubarak berkata, \"Halal kehormatannya maksudnya boleh untuk mengeraskan suara (mencela), dan halal hukumannya maksudnya adalah memenjarakannya.\""},"3067":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ أَسَدٍ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا هِرْمَاسُ بْنُ حَبِيبٍ رَجُلٌ مِنْ أَهْلِ الْبَادِيَةِ عَنْ أَبِيهِ عَنْ جَدَّهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِغَرِيمٍ لِي فَقَالَ لِي الْزَمْهُ ثُمَّ قَالَ لِي يَا أَخَا بَنِي تَمِيمٍ مَا تُرِيدُ أَنْ تَفْعَلَ بِأَسِيرِكَ","id":"Telah menceritakan kepada kami [Mu'adz bin Asad] telah menceritakan kepada kami [An Nadlr bin Syumail] telah mengabarkan kepada kami [Hirmas bin Habib] seorang laki-laki dari penduduk badui, dari [Ayahnya] dari [Kakeknya] ia berkata, \"Aku datang kepada Nabi shallallahu 'alaihi wasallam dengan membawa orang yang berhutang kepadaku, lalu beliau bersabda: \"Tetaplah bersamanya!\" Kemudian beliau bertanya: \"Wahai saudara Bani Tamim, apa yang engkau ingin engkau lakukan terhadap tawananmu?\""},"3068":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَبَسَ رَجُلًا فِي تُهْمَةٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] telah mengabarkan kepada kami [Abdurrazzaq] dari [Ma'mar] dari [Bahz bin Hakim] dari [Ayahnya] dari [Kakeknya] bahwa Nabi shallallahu 'alaihi wasallam menahan seorang laki-laki karena suatu tuduhan.\""},"3069":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ قُدَامَةَ وَمُؤَمَّلُ بْنُ هِشَامٍ قَالَ ابْنُ قُدَامَةَ حَدَّثَنِي إِسْمَعِيلُ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ ابْنُ قُدَامَةَ إِنَّ أَخَاهُ أَوْ عَمَّهُ وَقَالَ مُؤَمَّلٌإِنَّهُ قَامَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ فَقَالَ جِيرَانِي بِمَا أُخِذُوا فَأَعْرَضَ عَنْهُ مَرَّتَيْنِ ثُمَّ ذَكَرَ شَيْئًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلُّوا لَهُ عَنْ جِيرَانِهِلَمْ يَذْكُرْ مُؤَمَّلٌ وَهُوَ يَخْطُبُ","id":"Telah menceritakan kepada kami [Muhammad bin Qudamah] dan [Muammal bin Hisyam], [Ibnu Qudamah] berkata; telah menceritakan kepadaku [Isma'il] dari [Bahz bin Hakim] dari [Ayahnya] dari [kakeknya], Ibnu Qudamah berkata, \"Sesungguhnya saudaranya atau pamannya, sedangkan Mu`ammal berkata, \"Sesungguhnya ia bangkit menemui Nabi shallallahu 'alaihi wasallam saat beliau sedang berkhutbah. Lalu ia berkata, \"Karena apa para tetanggaku ditahan?\" kemudian beliau berpaling darinya sebanyak dua kali. Kemudian ia menyebutkan sesuatu, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Bebaskanlah para tetangganya!\" Namun Mu`ammal tidak menyebutkan lafadz, 'saat beliau sedang berkhutbah'.\""},"3070":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ حَدَّثَنَا عَمِّي حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ عَنْ أَبِي نُعَيْمٍ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ سَمِعَهُ يُحَدِّثُ قَالَأَرَدْتُ الْخُرُوجَ إِلَى خَيْبَرَ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمْتُ عَلَيْهِ وَقُلْتُ لَهُ إِنِّي أَرَدْتُ الْخُرُوجَ إِلَى خَيْبَرَ فَقَالَ إِذَا أَتَيْتَ وَكِيلِي فَخُذْ مِنْهُ خَمْسَةَ عَشَرَ وَسْقًا فَإِنْ ابْتَغَى مِنْكَ آيَةً فَضَعْ يَدَكَ عَلَى تَرْقُوَتِهِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Sa'dan bin Ibrahim] telah menceritakan kepada kami [Pamanku] telah menceritakan kepada kami [Ayahku] dari [Ibnu Ishaq] dari [Abu Nu'aim Wahb bin Kaisan] dari [Jabir bin Abdullah] bahwa ia mendengarnya menceritakan, ia berkata, \"Aku ingin pergi ke Khaibar, lalu aku datang menemui Rasulullah shallallahu 'alaihi wasallam, aku ucapkan salam kemudian berkata, \"Sesungguhnya aku ingin pergi ke Khaibar.\" Kemudian beliau bersabda: \"Apabila engkau datang kepada wakilku, maka ambillah darinya lima belas wasaq, dan apabila ia menginginkan tanda darimu maka letakkan tanganmu pada tulang bahunya!\" "},"3071":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْمُثَنَّى بْنُ سَعِيدٍ حَدَّثَنَا قَتَادَةُ عَنْ بُشَيْرِ بْنِ كَعْبٍ الْعَدَوِيِّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا تَدَارَأْتُمْ فِي طَرِيقٍ فَاجْعَلُوهُ سَبْعَةَ أَذْرُعٍ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Al Mutsanna bin Sa'id] telah menceritakan kepada kami [Qatadah] dari [Busyair bin Ka'b Al 'Adawi] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika kalian berselisih dengan (batas), maka jadikanlah jalan tersebut lebarnya adalah tujuh hasta!\""},"3072":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَابْنُ أَبِي خَلَفٍ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَأْذَنَ أَحَدُكُمْ أَخَاهُ أَنْ يَغْرِزَ خَشَبَةً فِي جِدَارِهِ فَلَا يَمْنَعُهُ فَنَكَّسُوا فَقَالَ مَا لِي أَرَاكُمْ قَدْ أَعْرَضْتُمْ لَأُلْقِيَنَّهَا بَيْنَ أَكْتَافِكُمْقَالَ أَبُو دَاوُد وَهَذَا حَدِيثُ ابْنُ أَبِي خَلَفٍ وَهُوَ أَتَمُّ","id":"Telah menceritakan kepada kami [Musaddad] dan [Ibnu Abu Khalaf] mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Al A'raj] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian meminta izin kepada saudaranya untuk meletakkan kayu pada dindingnya maka izinkanlah, lalu mereka mengiyakan dengan kepalanya. Lalu dia berkata; 'Kenapa saya masih melihat kalian menolaknya. Sungguh saya akan menyampaikan kepada mereka.\" Abu Daud berkata; Ini adalah hadits Ibnu Abu Khalaf, dan merupakan yang paling lengkap. "},"3073":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ لُؤْلُؤَةَ عَنْ أَبِي صِرْمَةَ قَالَ غَيْرَ قُتَيْبَةَ فِي هَذَا الْحَدِيثِ عَنْ أَبِي صِرْمَةَ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ ضَارَّ أَضَرَّ اللَّهُ بِهِ وَمَنْ شَاقَّ شَاقَّ اللَّهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Yahya] dari [Muhammad bin Yahya bin Habban] dari [Luluah] dari [Abu Shirmah] -selain Qutaibah telah menyebutkan hadits ini dari Shirmah- sahabat Nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa menimpakan madharat (keburukan) kepada orang lain maka Allah akan menimpakan madharat kepadanya, dan barangsiapa memperberat orang lain maka Allah akan memperberat dirinya.\""},"3074":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا وَاصِلٌ مَوْلَى أَبِي عُيَيْنَةَ قَالَ سَمِعْتُ أَبَا جَعْفَرٍ مُحَمَّدَ بْنَ عَلِيٍّ يُحَدِّثُ عَنْ سَمُرَةَ بْنِ جُنْدُبٍأَنَّهُ كَانَتْ لَهُ عَضُدٌ مِنْ نَخْلٍ فِي حَائِطِ رَجُلٍ مِنْ الْأَنْصَارِ قَالَ وَمَعَ الرَّجُلِ أَهْلُهُ قَالَ فَكَانَ سَمُرَةُ يَدْخُلُ إِلَى نَخْلِهِ فَيَتَأَذَّى بِهِ وَيَشُقُّ عَلَيْهِ فَطَلَبَ إِلَيْهِ أَنْ يَبِيعَهُ فَأَبَى فَطَلَبَ إِلَيْهِ أَنْ يُنَاقِلَهُ فَأَبَى فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَطَلَبَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعَهُ فَأَبَى فَطَلَبَ إِلَيْهِ أَنْ يُنَاقِلَهُ فَأَبَى قَالَ فَهِبْهُ لَهُ وَلَكَ كَذَا وَكَذَا أَمْرًا رَغَّبَهُ فِيهِ فَأَبَى فَقَالَ أَنْتَ مُضَارٌّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْأَنْصَارِيِّ اذْهَبْ فَاقْلَعْ نَخْلَهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al 'Ataki] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Washil] mantan budak Abu 'Uyainah, ia berkata; saya mendengar [Abu Ja'far Muhammad bin Ali] menceritakan dari [Samurah bin Jundub] bahwa ia dahulu memiliki pohon kurma kecil yang berada di kebun seorang laki-laki anshar.\" Samurah berkata, \"Laki-laki itu mempunyai keluarga.\" Muhammad berkata, \"Samurah pernah memasuki kebun kurmanya sehingga laki-laki Anshar tersebut merasa terganggu dan berat hati. Lalu ia meminta kepada Samurah untuk menjual pohon kurma tersebut, namun Samurah menolak. Lalu laki-laki Anshar itu meminta agar ia memindahnya, namun Samurah menolak. Maka ia pun datang menemui Nabi shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepadanya. Nabi shallallahu 'alaihi wasallam kemudian meminta Samurah agar menjual pohon kurma tersebut, namun ia menolak, lalu beliau memintanya agar memindahkannya namun Samurah tetap menolak. Beliau pun bersabda: \"Berikan kepadanya dan bagimu demikian dan demikian.\" -sesuatu yang menyenangkan-, namun ia menolak. Beliau lalu bersabda: \"Engkau adalah orang yang menimbulkan madlarat (kesusahan).\" Rasulullah shallallahu 'alaihi wasallam kemudian berkata kepada orang Anshar tersebut: \"Pergi dan cabutlah pohon kurmanya!\""},"3075":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا اللَّيْثِ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ أَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ حَدَّثَهُأَنَّ رَجُلًا خَاصَمَ الزُّبَيْرَ فِي شِرَاجِ الْحَرَّةِ الَّتِي يَسْقُونَ بِهَا فَقَالَ الْأَنْصَارِيُّ سَرِّحْ الْمَاءَ يَمُرُّ فَأَبَى عَلَيْهِ الزُّبَيْرُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلزُّبَيْرِ اسْقِ يَا زُبَيْرُ ثُمَّ أَرْسِلْ إِلَى جَارِكَ قَالَ فَغَضِبَ الْأَنْصَارِيُّ فَقَالَ يَا رَسُولَ اللَّهِ أَنْ كَانَ ابْنَ عَمَّتِكَ فَتَلَوَّنَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ اسْقِ ثُمَّ احْبِسْ الْمَاءَ حَتَّى يَرْجِعَ إِلَى الْجَدْرِفَقَالَ الزُّبَيْرُ فَوَاللَّهِ إِنِّي لَأَحْسَبُ هَذِهِ الْآيَةَ نَزَلَتْ فِي ذَلِكَ{ فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّى يُحَكِّمُوكَ }الْآيَةَ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Al Laits] dari [Az Zuhri] dari ['Urwah] bahwa [Abdullah bin Az Zubair] menceritakan kepadanya, bahwa ada seorang laki-laki bermusuhan dengan Az Zubair mengenai saluran-saluran air pada tanah keras yang berbatu hitam yang mereka gunakan untuk mengairi tanaman. Kemudian orang anshar tersebut berkata, \"Biarkanlah air lewat!\" Namun Az Zubair menolak. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepada Az Zubair: \"Siramilah tanamanmu wahai Az Zubair, kemudian alirkan kepada tetanggamu!\" Maka marahklah orang anshar tersebut, lalu ia berkata, \"Wahai Rasulullah, apakah karena ia itu anak bibimu!\" Maka rona muka Rasulullah shallallahu 'alaihi wasallam berubah, beliau bersabda: \"Siramlah tanamanmu, lalu tahanlah iar tersebut hingga ia kembali ke tempatnya semula.\" Az Zubair berkata, \"Demi Allah, sungguh aku mengira ayat ini turun mengenai hal tersebut; '(Maka demi Tuhanmu, mereka (pada hakekatnya) tidak beriman hingga mereka menjadikan kamu hakim…) ' (Qs. An Nisa: 65). "},"3076":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ يَعْنِي ابْنَ كَثِيرٍ عَنْ أَبِي مَالِكِ بْنِ ثَعْلَبَةَ عَنْ أَبِيهِ ثَعْلَبَةَ بْنِ أَبِي مَالِكٍ أَنَّهُ سَمِعَ كُبَرَاءَهُمْيَذْكُرُونَ أَنَّ رَجُلًا مِنْ قُرَيْشٍ كَانَ لَهُ سَهْمٌ فِي بَنِي قُرَيْظَةَ فَخَاصَمَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَهْزُورٍ يَعْنِي السَّيْلَ الَّذِي يَقْتَسِمُونَ مَاءَهُ فَقَضَى ب��يْنَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ الْمَاءَ إِلَى الْكَعْبَيْنِ لَا يَحْبِسُ الْأَعْلَى عَلَى الْأَسْفَلِ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala] telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Katsir] dari [Abu Malik bin Tsa'labah] dari [Tsa'labah bin Malik] bahwa ia mendengar [para pembesar] mereka menyebutkan bahwa seorang laki-laki Quraisy memiliki saham pada Bani Quraizhah, kemudian ia memperkarakan kepada Rasulullah shallallahu 'alaihi wasallam mengenai aliran yang mereka berbagi dengan airnya. Kemudian Rasulullah shallallahu 'alaihi wasallam memberi putusan untuk mereka, bahwa batas genangan air adalah sebatas mata kaki, orang yang lahannya di atas tidak boleh menahan dari yang di bawah.\""},"3077":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنِي أَبِي عَبْدُ الرَّحْمَنِ بْنُ الْحَارِثِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي السَّيْلِ الْمَهْزُورِ أَنْ يُمْسَكَ حَتَّى يَبْلُغَ الْكَعْبَيْنِ ثُمَّ يُرْسِلُ الْأَعْلَى عَلَى الْأَسْفَلِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] telah menceritakan kepadaku ayahku [Abdurrahman bin Al Harits] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam memberi putusan dalampembagian air, bahwa batas genangan air (pada tanaman) adalah setinggi mata kaki. Setelah itu orang yang lahannya di bagian atas memberikannya kepada orang yang lahannya di bawah.\""},"3078":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ أَنَّ مُحَمَّدَ بْنَ عُثْمَانَ حَدَّثَهُمْ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ أَبِي طُوَالَةَ وَعَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَاخْتَصَمَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلَانِ فِي حَرِيمِ نَخْلَةٍ فِي حَدِيثِ أَحَدِهِمَا فَأَمَرَ بِهَا فَذُرِعَتْ فَوُجِدَتْ سَبْعَةَ أَذْرُعٍ وَفِي حَدِيثِ الْآخَرِ فَوُجِدَتْ خَمْسَةَ أَذْرُعٍ فَقَضَى بِذَلِكَقَالَ عَبْدُ الْعَزِيزِ فَأَمَرَ بِجَرِيدَةٍ مِنْ جَرِيدِهَا فَذُرِعَتْ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] bahwa [Muhammad bin Utsman] menceritakan kepada mereka, ia berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Abu Thuwalah] dan ['Amru bin Yahya] dari [Ayahnya] dari [Abu Sa'id Al Khudri] ia berkata, \"Dua orang laki-laki mengadukan kepada Rasulullah shallallahu 'alaihi wasallam tentang batas kebun kurma mereka. Kemudian beliau memerintahkan agar mengukurnya, lalu batasan tersebut diukur dan didapati ukurannya adalah tujuh hasta. Dan dalam hadits yang lain, maka di dapati ukurannya adalah lima hasta, lalu beliau memutuskan dengan hal tersebut.\" Abdul Aziz berkata, \"Kemudian beliau memerintakan agar diambilkan salah satu dahan pohon kurma tersebut, kemudian batasan tersebut diukur.\""},"3079":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ سَمِعْتُ عَاصِمَ بْنَ رَجَاءِ بْنِ حَيْوَةَ يُحَدِّثُ عَنْ دَاوُدَ بْنِ جَمِيلٍ عَنْ كَثِيرِ بْنِ قَيْسٍ قَالَكُنْتُ جَالِسًا مَعَ أَبِي الدَّرْدَاءِ فِي مَسْجِدِ دِمَشْقَ فَجَاءَهُ رَجُلٌ فَقَالَ يَا أَبَا الدَّرْدَاءِ إِنِّي جِئْتُكَ مِنْ مَدِينَةِ الرَّسُولِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَدِيثٍ بَلَغَنِي أَنَّكَ تُحَدِّثُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا جِئْتُ لِحَاجَةٍ قَالَ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَلَكَ طَرِيقًا يَطْلُبُ فِيهِ عِلْمًا سَلَكَ اللَّهُ بِهِ طَرِيقًا مِنْ طُرُقِ الْجَنَّةِ وَإِنَّ الْمَلَائِكَةَ لَتَضَعُ أَجْنِحَتَهَا رِضًا لِطَالِبِ الْعِلْمِ وَإِنَّ الْعَالِمَ لَيَسْتَغْفِرُ لَهُ مَنْ فِي السَّمَوَاتِ وَمَنْ فِي الْأَرْضِ وَالْحِيتَانُ فِي جَوْفِ الْمَاءِ وَإِنَّ فَضْلَ الْعَالِمِ عَلَى الْعَابِدِ كَفَضْلِ الْقَمَرِ لَيْلَةَ الْبَدْرِ عَلَى سَائِرِ الْكَوَاكِبِ وَإِنَّ الْعُلَمَاءَ وَرَثَةُ الْأَنْبِيَاءِ وَإِنَّ الْأَنْبِيَاءَ لَمْ يُوَرِّثُوا دِينَارًا وَلَا دِرْهَمًا وَرَّثُوا الْعِلْمَ فَمَنْ أَخَذَهُ أَخَذَ بِحَظٍّ وَافِرٍحَدَّثَنَا مُحَمَّدُ بْنُ الْوَزِيرِ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ قَالَ لَقِيتُ شَبِيبَ بْنَ شَيْبَةَ فَحَدَّثَنِي بِهِ عَنْ عُثْمَانَ بْنِ أَبِي سَوْدَةَ عَنْ أَبِي الدَّرْدَاءِ يَعْنِي عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad] telah menceritakan kepada kami [Abdullah bin Daud] aku mendengar ['Ashim bin Raja bin Haiwah] menceritakan dari [Daud bin Jamil] dari [Katsir bin Qais] ia berkata, \"Aku pernah duduk bersama Abu Ad Darda di masjid Damaskus, lalu datanglah seorang laki-laki kepadanya dan berkata, \"Wahai Abu Ad Darda, sesungguhnya aku datang kepadamu dari kota Rasulullah shallallahu 'alaihi wasallam karena sebuah hadits yang sampai kepadaku bahwa engkau meriwayatannya dari Rasulullah shallallahu 'alaihi wasallam. Dan tidaklah aku datang kecuali untuk itu.\" Abu Ad Darda lalu berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meniti jalan untuk menuntut ilmu, maka Allah akan mempermudahnya jalan ke surga. Sungguh, para Malaikat merendahkan sayapnya sebagai keridlaan kepada penuntut ilmu. Orang yang berilmu akan dimintakan maaf oleh penduduk langit dan bumi hingga ikan yang ada di dasar laut. Kelebihan serang alim dibanding ahli ibadah seperti keutamaan rembulan pada malam purnama atas seluruh bintang. Para ulama adalah pewaris para nabi, dan para nabi tidak mewariskan dinar dan dirham, mereka hanyalah mewariskan ilmu. Barangsiapa mengambilnya maka ia telah mengambil bagian yang banyak.\" Telah menceritakan kepada kami [Muhammad bin Al Wazir Ad Dimasyqi] telah menceritakan kepada kami [Al Walid] ia berkata; aku berjumpa dengan [Syabib bin Syaibah] lalu ia menceritakannya kepadaku dari [Utsman bin Abu Saudah] dari [Abu Ad Darda] dari Nabi shallallahu 'alaihi wasallam dengan maknanya.\""},"3080":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زَائِدَةُ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ رَجُلٍ يَسْلُكُ طَرِيقًا يَطْلُبُ فِيهِ عِلْمًا إِلَّا سَهَّلَ اللَّهُ لَهُ بِهِ طَرِيقَ الْجَنَّةِ وَمَنْ أَبْطَأَ بِهِ عَمَلُهُ لَمْ يُسْرِعْ بِهِ نَسَبُهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zaidah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang laki-laki yang meniti jalan untuk mencari ilmu melainkan Allah akan mempermudah baginya jalan menuju Surga. Dan barangsiapa yang lambat amalannya maka nasabnya tidak akan memberinya manfaat.\""},"3081":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ ثَابِتٍ الْمَرْوَزِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي ابْنُ أَبِي نَمْلَةَ الْأَنْصَارِيُّ عَنْ أَبِيهِأَنَّهُ بَيْنَمَا هُوَ جَالِسٌ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ رَجُلٌ مِنْ الْيَهُودِ مُرَّ بِجَنَازَةٍ فَقَالَ يَا مُحَمَّدُ هَلْ تَتَكَلَّمُ هَذِهِ الْجَنَازَةُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُ أَعْلَمُ فَقَالَ الْيَهُودِيُّ إِنَّهَا تَتَكَلَّمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَدَّثَكُمْ أَهْلُ الْكِتَابِ فَلَا تُصَدِّقُوهُمْ وَلَا تُكَذِّبُوهُمْ وَقُولُوا آمَنَّا بِاللَّهِ وَرُسُلِهِ فَإِنْ كَانَ بَاطِلًا لَمْ تُصَدِّقُوهُ وَإِنْ كَانَ حَقًّا لَمْ تُكَذِّبُوهُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Tsabit Al Marwazi] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] telah mengabarkan kepadaku [Ibnu Abu Namlah Al Anshari] dari [Ayahnya] bahwa ketika ia sedang duduk di sisi Rasulullah shallallahu 'alaihi wasallam yang saat itu di sisi beliau ada seorang Yahudi, lewatnya jenazah di hadapan beliau. Lalu orang Yahudi itu berkata, \"Wahai Muhammad, apakah jenazah ini berbicara?\" Nabi shallallahu 'alaihi wasallam kemudian menjawab: \"Allah lebih mengetahui.\" Orang Yahudi itu pun berkata, \"Sesungguhnya jenazah tersebut berbicara.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang diceritakan oleh orang-orang ahli kitab kepada kalian maka janganlah kalian percayai atau kalian dustakan. Tetapi katakanlah, 'aku beriman kepada Allah dan para Rasul-Nya'. Jika mereka dusta maka kalian tidak mempercayainya dan jika benar maka kalian tidak mendustakannya.\""},"3082":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ خَارِجَةَ يَعْنِي ابْنَ زَيْدِ بْنِ ثَابِتٍ قَالَقَالَ زَيْدُ بْنُ ثَابِتٍ أَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَعَلَّمْتُ لَهُ كِتَابَ يَهُودَ وَقَالَ إِنِّي وَاللَّهِ مَا آمَنُ يَهُودَ عَلَى كِتَابِي فَتَعَلَّمْتُهُ فَلَمْ يَمُرَّ بِي إِلَّا نِصْفُ شَهْرٍ حَتَّى حَذَقْتُهُ فَكُنْتُ أَكْتُبُ لَهُ إِذَا كَتَبَ وَأَقْرَأُ لَهُ إِذَا كُتِبَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari [Ayahnya] dari [Kharijah bin Zaid bin Tsabit] ia berkata, [Zaid bin Tsabit] berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan aku untuk mempelajari tulisan orang-orang Yahudi. Lalu aku mempelajari penulisan orang-orang Yahudi untuk beliau.\" Zaid berkata, \"Demi Allah, sungguh aku tidak merasa aman kepada orang-orang Yahudi terhadap tulisanku. Lalu aku mempelajarinya, dan hanya berlalu setengah bulan aku telah menguasainya. Lalu aku menuliskan untuknya apabila Beliau (ingin) menulis dan aku membacakan untuknya jika beliau mendapat surat.\""},"3083":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ الْوَلِيدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي مُغِيثٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَكُنْتُ أَكْتُبُ كُلَّ شَيْءٍ أَسْمَعُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيدُ حِفْظَهُ فَنَهَتْنِي قُرَيْشٌ وَقَالُوا أَتَكْتُبُ كُلَّ شَيْءٍ تَسْمَعُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَشَرٌ يَتَكَلَّمُ فِي الْغَضَبِ وَالرِّضَا فَأَمْسَكْتُ عَنْ الْكِتَابِ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَوْمَأَ بِأُصْبُعِهِ إِلَى فِيهِ فَقَالَ اكْتُبْ فَوَالَّذِي نَفْسِي بِيَدِهِ مَا يَخْرُجُ مِنْهُ إِلَّا حَقٌّ","id":"Telah menceritakan kepada kami [Musaddad] dan [Abu Bakr bin Abu Syaibah] mereka berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah bin Al Akhnas] dari [Al Walid bin Abdullah bin Abu Mughits] dari [Yusuf bin Mahik] dari [Abdullah bin 'Amru] ia berkata, \"Aku menulis segala sesuatu yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, agar aku bisa menghafalnya. Kemudian orang-orang Quraisy melarangku dan mereka berkata, 'Apakah engkau akan menulis segala sesuatu yang engkau dengar, sementara Rasulullah shallallahu 'alaihi wasallam adalah seorang manusia yang berbicara dalam keadaan marah dan senang? ' Aku pun tidak menulis lagi, kemudian hal itu aku ceritakan kepada Rasulullah shallallahu 'alaihi wasallam. Beliau lalu berisyarat dengan meletakkan jarinya pada mulut, lalu bersabda: \"Tulislah, demi jiwaku yang ada di tangan-Nya, tidaklah keluar darinya (mulut) kecuali kebenaran.\""},"3084":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا أَبُو أَحْمَدَ حَدَّثَنَا كَثِيرُ بْنُ زَيْدٍ عَنْ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ بْنِ حَنْطَبٍ قَالَدَخَلَ زَيْدُ بْنُ ثَابِتٍ عَلَى مُعَاوِيَةَ فَسَأَلَهُ عَنْ حَدِيثٍ فَأَمَرَ إِنْسَانًا يَكْتُبُهُ فَقَالَ لَهُ زَيْدٌ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَنَا أَنْ لَا نَكْتُبَ شَيْئًا مِنْ حَدِيثِهِ فَمَحَاهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Katsir bin Zaid] dari [Al Muththalib bin Abdullah bin Hanthab] ia berkata, \" [Zaid bin Tsabit] datang menemui Mu'awiyah dan bertanya kepadanya tentang suatu hadits, dan ia memerintahkan seseorang agar menulisnya. Zaid lalu berkata kepadanya, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar tidak menulis apapun dari hadits beliau.\" Maka Mu'awiyah pun menghapusnya kembali.\""},"3085":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو شِهَابٍ عَنْ الْحَذَّاءِ عَنْ أَبِي الْمُتَوَكِّلِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَمَا كُنَّا نَكْتُبُ غَيْرَ التَّشَهُّدِ وَالْقُرْآنِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Syihab] dari [Al Hadzdza] dari [Abu Al Mutawakkil An Naji] dari [Abu Sa'id Al Khudri] ia berkata, \"Kami tidak pernah menulis selain tasyahud dan Al Qur'an.\""},"3086":{"ar":"حَدَّثَنَا مُؤَمَّلٌ قَالَ حَدَّثَنَا الْوَلِيدُ ح و حَدَّثَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ بْنِ مَزْيَدٍ قَالَ أَخْبَرَنِي أَبِي عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنَا أَبُو سَلَمَةَ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَلَمَّا فُتِحَتْ مَكَّةُ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْخُطْبَةَ خُطْبَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَامَ رَجُلٌ مِنْ أَهْلِ الْيَمَنِ يُقَالُ لَهُ أَبُو شَاهَ فَقَالَ يَا رَسُولَ اللَّهِ اكْتُبُوا لِي فَقَالَ اكْتُبُوا لِأَبِي شَاهَ","id":"Telah menceritakan kepada kami [Mu`ammal] ia berkata; telah menceritakan kepada kami [Al Walid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Al 'Abbas bin Al Walid bin Mazyad] ia berkata; telah mengabarkan kepadaku [Ayahku] dari [Al Auza'i] dari [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepada kami [Abu Salamah] -yaitu Ibnu Abdurrahman- ia berkata; telah menceritakan kepadaku [Abu Hurairah] ia berkata, \"Ketika Makkah ditaklukkan, Nabi shallallahu 'alaihi wasallam berdiri….. kemudian Abu Hurairah menyebutkan khutbah Nabi shallallahu 'alaihi wasallam, ia berkata, \"Kemudian seorang laki-laki dari penduduk Yaman yang bernama Abu Syah berdiri dab berkata, \"Wahai Rasulullah, tuliskan untukku! Lalu beliau bersabda: \"Tuliskan untuk Abu Syah!\""},"3087":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَهْلٍ الرَّمْلِيُّ قَالَ حَدَّثَنَا الْوَلِيدُ قَالَ قُلْتُ لِأَبِي عَمْرٍومَا يَكْتُبُوهُ قَالَ الْخُطْبَةَ الَّتِي سَمِعَهَا يَوْمَئِذٍ مِنْهُ","id":"Telah menceritakan kepada kami [Ali bin Sahl Ar Ramli] ia berkata; telah menceritakan kepada kami [Al Walid] ia berkata, \"Aku tanyakan kepada [Abu 'Amru], \"Apa yang mereka tulis?\" Ia menjawab, \"Khutbah yang ia dengar dari Rasulullah pada hari itu.\""},"3088":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ الْمَعْنَى عَنْ بَيَانِ بْنِ بِشْرٍ قَالَ مُسَدَّدٌ أَبُو بِشْرٍ عَنْ وَبَرَةُ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَ قُلْتُ لِلزُّبَيْرِمَا يَمْنَعُكَ أَنْ تُحَدِّثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا يُحَدِّثُ عَنْهُ أَصْحَابُهُ فَقَالَ أَمَا وَاللَّهِ لَقَدْ كَانَ لِي مِنْهُ وَجْهٌ وَمَنْزِلَةٌ وَلَكِنِّي سَمِعْتُهُ يَقُولُ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Khalid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid] secara makna, dari [Bayan bin Bisyr], [Musaddad Abu Bisyr] berkata dari [Wabarah bin Abdurrahman] dari [Amir bin Abdullah bin Az Zubair] dari [Ayahnya] ia berkata, \"Aku tanyakan kepada [Az Zubair], \"Apa yang menghalangimu untuk menceritakan dari Rasulullah shallallahu 'alaihi wasallam sebagaimana yang diceritakan para sahabatnya?\" kemudian ia menjawab, \"Sungguh aku memiliki posisi dan kedudukan di sisi Rasulullah shallallahu 'alaihi wasallam, akan tetapi aku mendengar beliau mengatakan: \"Barangsiapa berdusta kepadaku dengan sengaja maka hendaknya ia mempersiapkan tempatnya di Neraka.\""},"3089":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ يَحْيَى حَدَّثَنَا يَعْقُوبُ بْنُ إِسْحَاقَ الْمُقْرِئُ الْحَضْرَمِيُّ حَدَّثَنَا سُهَيْلُ بْنُ مِهْرَانَ أَخِي حَزْمٍ الْقُطَعِيُّ حَدَّثَنَا أَبُو عِمْرَانَ عَنْ جُنْدُبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ فِي كِتَابِ اللَّهِ عَزَّ وَجَلَّ بِرَأْيِهِ فَأَصَابَ فَقَدْ أَخْطَأَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Yahya] telah menceritakan kepadaku [Ya'qub bin Ishaq Al Muqri` Al Hadlrami] telah menceritakan kepada kami [Suhail bin Mihran] saudara Hazm Al Qutha'I, telah menceritakan kepada kami [Abu 'Imran] dari [Jundub] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berbicara tentang Kitabullah 'azza wajalla menggunakan pendapatnya, meskipun benar maka ia telah salah.\""},"3090":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مَرْزُوقٍ أَخْبَرَنَا شُعْبَةُ عَنْ أَبِي عَقِيلٍ هَاشِمِ بْنِ بِلَالٍ عَنْ سَابِقِ بْنِ نَاجِيَةَ عَنْ أَبِي سَلَّامٍ عَنْ رَجُلٍ خَدَمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا حَدَّثَ حَدِيثًا أَعَادَهُ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami ['Amru bin Marzuq] telah mengabarkan kepada kami [Syu'bah] dari [Abu 'Aqil Hasyim bin Bilal] dari [Sabiq bin Najiyah] dari [Abu Sallam] dari [Seorang laki-laki] yang melayani Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam apabila menceritakan suatu hadits maka beliau mengulanginya sebanyak tiga kali.\""},"3091":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مَنْصُورٍ الطُّوسِيُّ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ قَالَجَلَسَ أَبُو هُرَيْرَةَ إِلَى جَنْبِ حُجْرَةِ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا وَهِيَ تُصَلِّي فَجَعَلَ يَقُولُ اسْمَعِي يَا رَبَّةَ الْحُجْرَةِ مَرَّتَيْنِ فَلَمَّا قَضَتْ صَلَاتَهَا قَالَتْ أَلَا تَعْجَبُ إِلَى هَذَا وَحَدِيثِهِ إِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُحَدِّثُ الْحَدِيثَ لَوْ شَاءَ الْعَادُّ أَنْ يُحْصِيَهُ أَحْصَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Manshur Ath Thusi] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Urwah] ia berkata, \"Abu Hurairah duduk di samping kamar Aisyah radliallahu 'anha, sementara ia sedang melakukan shalat, Abu Hurairah lalu berkata, \"Dengarkan wahai pemilik kamar!\" Abu Hurairah mengucapkannya dua kali. Ketika [Aisyah] selesai shalat, ia pun berkata, \"Tidakkah engkau (Urwah) kagum terhadap orang ini (Abu Hurairah) dan pembicaraannya? Seandainya Rasulullah shallallahu 'alaihi wasallam menceritakan sebuah hadits jika ada orang yang menghitung ingin menghitung maka ia mampu untuk menghitungnya.\""},"3092":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ حَدَّثَهُ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْأَلَا يُعْجِبُكَ أَبُو هُرَيْرَةَ جَاءَ فَجَلَسَ إِلَى جَانِبِ حُجْرَتِي يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْمِعُنِي ذَلِكَ وَكُنْتُ أُسَبِّحُ فَقَامَ قَبْلَ أَنْ أَقْضِيَ سُبْحَتِي وَلَوْ أَدْرَكْتُهُ لَرَدَدْتُ عَلَيْهِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ يَسْرُدُ الْحَدِيثَ مِثْلَ سَرْدِكُمْ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud Al Mahri] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] bahwa ['Urwah bin Az Zubair] menceritakan kepadanya bahwa [Aisyah] isteri Nabi shallallahu 'alaihi wasallam berkata, \"Tidakkah engkau kagum kepada Abu Hurairah? Ia datang dan duduk di samping kamarku menceritakan dari Rasulullah shallallahu 'alaihi wasallam, ia memperdengarkannya kepadaku saat aku sedang melakukan shalat, lalu ia berdiri sebelum aku menyelesaikan shalatku, dan seandainya aku dapat mendapatinya niscaya aku akan menjawabnya, sesungguhnya Rasulullah shallallahu 'alaihi wasallam tidak tergesa-gesa seperti kalian tergesa-gesa.\""},"3093":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ حَدَّثَنَا عِيسَى عَنْ الْأَوْزَاعِيِّ عَنْ عَبْدِ اللَّهِ بْنِ سَعْدٍ عَنْ الصُّنَابِحِيِّ عَنْ مُعَاوِيَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْغُلُوطَاتِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] telah menceritakan kepada kami [Isa] dari [Al Auza'i] dari [Abdullah bin Sa'dan] dari [Ash Shunabihi] dari [Mu'awiyah] bahwa Nabi shallallahu 'alaihi wasallam telah melarang dari permasalahan-permasalahan yang sulit.\""},"3094":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَبْدِ الرَّحْمَنِ الْمُقْرِئُ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي أَيُّوبَ عَنْ بَكْرِ بْنِ عَمْرٍو عَنْ مُسْلِمِ بْنِ يَسَارٍ أَبِي عُثْمَانَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَفْتَى ح و حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ بَكْرِ بْنِ عَمْرٍو عَنْ عَمْرِو بْنِ أَبِي نُعَيْمَةَ عَنْ أَبِي عُثْمَانَ الطُّنْبُذِيِّ رَضِيعِ عَبْدِ الْمَلِكِ بْنِ مَرْوَانَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُفْتِيَ بِغَيْرِ عِلْمٍ كَانَ إِثْمُهُ عَلَى مَنْ أَفْتَاهُ زَادَ سُلَيْمَانُ الْمَهْرِيُّ فِي حَدِيثِهِ وَمَنْ أَشَارَ عَلَى أَخِيهِ بِأَمْرٍ يَعْلَمُ أَنَّ الرُّشْدَ فِي غَيْرِهِ فَقَدْ خَانَهُوَهَذَا لَفْظُ سُلَيْمَانَ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abu Abdurrahman Al Muqri`] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] dari [Bakr bin 'Amru] dari [Muslim bin Yasar Abu Utsman] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memberi fatwa…..\". (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Sulaiman bin Daud] telah mengabarkan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Yahya bin Ayyub] dari [Bakr bin 'Amru] dari ['Amru bin Abu Nu'aimah] dari [Abu Utsman Athunbudzi] orang yang disusui isteri Abdul Malik bin Marwan, ia berkata, \"Aku mendengar [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diberi fatwa tanpa dengan ilmu maka dosanya ditanggung orang yang memberi fatwa.\" Sulaiman Al Mahri menambahkan dalam hadits, \"Barangsiapa memberi isyarat kepada saudaranya dalam suatu perkara dan ia mengetahui bahwa yang benar ada pada orang lain, maka sungguh ia telah berkhianat kepadanya.\" Dan Ini adalah lafazh Sulaiman."},"3095":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَلِيُّ بْنُ الْحَكَمِ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سُئِلَ عَنْ عِلْمٍ فَكَتَمَهُ أَلْجَمَهُ اللَّهُ بِلِجَامٍ مِنْ نَارٍ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Ali bin Al Hakam] dari ['Atha] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ditanya mengenai suatu ilmu dan ia menyembunyikannya, maka ia akan dicambuk dengan cambuk dari api neraka pada hari kiamat.\""},"3096":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْمَعُونَ وَيُسْمَعُ مِنْكُمْ وَيُسْمَعُ مِمَّنْ سَمِعَ مِنْكُمْ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Utsman bin Abu Syaibah] mereka berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abdullah bin Abdullah] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian mendengarkan dan akan didengar dari kalian, dan akan didengar dari orang yang mendengar dari kalian.\""},"3097":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنِي عُمَرُ بْنُ سُلَيْمَانَ مِنْ وَلَدِ عُمَرَ بْنِ الْخَطَّابِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبَانَ عَنْ أَبِيهِ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ نَضَّرَ اللَّهُ امْرَأً سَمِعَ مِنَّا حَدِيثًا فَحَفِظَهُ حَتَّى يُبَلِّغَهُ فَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ وَرُبَّ حَامِلِ فِقْهٍ لَيْسَ بِفَقِيهٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] telah menceritakan kepadaku [Umar bin Sulaiman] dari putera Umar bin Al Khathab, dari [Abdurrahman bin Aban] dari [Ayahnya] dari [Zaid bin Tsabit] ia berkata, \"Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah memperindah orang yang mendengar hadits dariku lalu menghafal dan menyampaikannya kepada orang lain, berapa banyak orang menyampaikan ilmu kepada orang yang lebih berilmu, dan berapa banyak pembawa ilmu yang tidak berilmu.\""},"3098":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلٍ يَعْنِي ابْنَ سَعْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَاللَّهِ لَأَنْ يَهْدِيَ اللَّهُ بِهُدَاكَ رَجُلًا وَاحِدًا خَيْرٌ لَكَ مِنْ حُمْرِ النَّعَمِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [Ayahnya] dari [Sahl bin Sa'dan] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Demi Allah, sekiranya Allah memberi petunjuk kepada seorang laki-laki melalui perantaramu, maka itu lebih baik bagimu dari unta merah.\""},"3099":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِّثُوا عَنْ بَنِي إِسْرَائِيلَ وَلَا حَرَجَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ceritakanlah riwayat dari Bani Israil Israil, dan itu tidak mengapa.\""},"3100":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذٌ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي حَسَّانَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُنَا عَنْ بَنِي إِسْرَائِيلَ حَتَّى يُصْبِحَ مَا يَقُومُ إِلَّا إِلَى عُظْمِ صَلَاةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Mu'adz] telah menceritakan kepadaku [Ayahku] dari [Qatadah] dari [Abu Hassan] dari [Abdullah bin 'Amru] ia berkata, \"Nabi shallallahu 'alaihi wasallam pernah menceritakan kepada kami dari Bani Israil hingga pagi hari, dan beliau tidak berdiri kecuali untuk melakukan shalat fardlu.\""},"3101":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا فُلَيْحٌ عَنْ أَبِي طُوَالَةَ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَعْمَرٍ الْأَنْصَارِيِّ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَعَلَّمَ عِلْمًا مِمَّا يُبْتَغَى بِهِ وَجْهُ اللَّهِ عَزَّ وَجَلَّ لَا يَتَعَلَّمُهُ إِلَّا لِيُصِيبَ بِهِ عَرَضًا مِنْ الدُّنْيَا لَمْ يَجِدْ عَرْفَ الْجَنَّةِ يَوْمَ الْقِيَامَةِ يَعْنِي رِيحَهَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Suraij bin An Nu'man] telah menceritakan kepada kami [Fulaih] dari [Abu Thuwalah Abdullah bin Abdurrahman bin Ma'mar Al Anshari] dari [Sa'id bin Yasar] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mempelajari suatu ilmu yang seharusnya karena Allah Azza Wa Jalla, namun ia tidak mempelajarinya kecuali untuk mendapatkan sebagian dari dunia, maka ia tidak akan mendapatkan baunya Surga pada Hari Kiamat.\""},"3102":{"ar":"حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو مُسْهِرٍ حَدَّثَنِي عَبَّادُ بْنُ عَبَّادٍ الْخَوَّاصُ عَنْ يَحْيَى بْنِ أَبِي عَمْرٍو السَّيْبَانِيِّ عَنْ عَمْرِو بْنِ عَبْدِ اللَّهِ السَّيْبَانِيِّ عَنْ عَوْفِ بْنِ مَالِكٍ الْأَشْجَعِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَقُصُّ إِلَّا أَمِيرٌ أَوْ مَأْمُورٌ أَوْ مُخْتَالٌ","id":"Telah menceritakan kepada kami [Mahmud bin Khalid] telah menceritakan kepada kami [Abu Mushir] telah menceritakan kepadaku ['Abbad bin 'Abbad Al Khawwash] dari [Yahya bin Abu 'Amru As Saibani] dari ['Amru bin Abdullah As Saibani] dari ['Auf bin Malik Al Asyja'i] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada yang memberi nasihat kecuali seorang pemimpin, atau orang yang diperintah (oleh Amir), atau orang yang ingin dipuji.\""},"3103":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ الْمُعَلَّى بْنِ زِيَادٍ عَنْ الْعَلَاءِ بْنِ بَشِيرٍ الْمُزَنِيِّ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَجَلَسْتُ فِي عِصَابَةٍ مِنْ ضُعَفَاءِ الْمُهَاجِرِينَ وَإِنَّ بَعْضَهُمْ لَيَسْتَتِرُ بِبَعْضٍ مِنْ الْعُرْيِ وَقَارِئٌ يَقْرَأُ عَلَيْنَا إِذْ جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ عَلَيْنَا فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَكَتَ الْقَارِئُ فَسَلَّمَ ثُمَّ قَالَ مَا كُنْتُمْ تَصْنَعُونَ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّهُ كَانَ قَارِئٌ لَنَا يَقْرَأُ عَلَيْنَا فَكُنَّا نَسْتَمِعُ إِلَى كِتَابِ اللَّهِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَمْدُ لِلَّهِ الَّذِي جَعَلَ مِنْ أُمَّتِي مَنْ أُمِرْتُ أَنْ أَصْبِرَ نَفْسِي مَعَهُمْ قَالَ فَجَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسْطَنَا لِيَعْدِلَ بِنَفْسِهِ فِينَا ثُمَّ قَالَ بِيَدِهِ هَكَذَا فَتَحَلَّقُوا وَبَرَزَتْ وُجُوهُهُمْ لَهُ قَالَ فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَفَ مِنْهُمْ أَحَدًا غَيْرِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْشِرُوا يَا مَعْشَرَ صَعَالِيكِ الْمُهَاجِرِينَ بِالنُّورِ التَّامِّ يَوْمَ الْقِيَامَةِ تَدْخُلُونَ الْجَنَّةَ قَبْلَ أَغْنِيَاءِ النَّاسِ بِنِصْفِ يَوْمٍ وَذَاكَ خَمْسُ مِائَةِ سَنَةٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Al Mu'allim bin Ziyad] dari [Al 'Ala bin Basyir Al Muzni] dari [Abu Ash Shiddiq An Nahi] dari [Abu Sa'id Al Khudri] ia berkata, \"Aku duduk di antara beberapa orang lemah dari kalangan orang-orang muhajirin, dan sebagian mereka menutupi sebagian aurat sementara sebagian yang lain membacakan Al Qur'an kepada kami, tiba-tiba Rasulullah shallallahu 'alaihi wasallam datang dan berdiri di sisi kami. Tatkala Rasulullah shallallahu 'alaihi wasallam berdiri orang-orang yang membaca Al Qur'an diam. Lalu beliau mengucapkan salam dan bertanya: \"Apakah yang kalian lakukan?\" Kami menjawab, \"Wahai Rasulullah, dia adalah orang yang pandai membaca Al-Qur'an di antara kami, ia membacakan kepada kami dan yang mendengarnya.\" Abu Sa'id berkata, \"Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Segala puji bagi Allah Yang telah menjadikan di antara umatku, seseorang yang aku diperintahkan untuk bersabar bersama mereka.\" Abu Sa'id berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam duduk di tengah-tengah kami agar bisa bersama kami.\" Kemudian bersabda dengan isyarat tangannya seperti ini -mereka lalu melingkar dan wajah-wajah mereka nampak bagi beliau-.\" Abu Sa'id berkata, \"Aku tidak melihat Rasulullah shallallahu 'alaihi wasallam mengetahui seorangpun di antara mereka selain diriku. Kemudian beliau bersabda: \"Bergembiralah kalian wahai orang-orang fakir muhajirin dengan mendapatkan cahaya sempurna pada Hari Kiamat, kalian akan masuk Surga setengah hari sebelum orang-orang kaya, dan setengah hari itu adalah lima ratus ribu tahun.\""},"3104":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي عَبْدُ السَّلَامِ يَعْنِي ابْنَ مُطَهَّرٍ أَبُو ظَفَرٍ حَدَّثَنَا مُوسَى بْنُ خَلَفٍ الْعَمِّىُّ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ أَقْعُدَ مَعَ قَوْمٍ يَذْكُرُونَ اللَّهَ تَعَالَى مِنْ صَلَاةِ الْغَدَاةِ حَتَّى تَطْلُعَ الشَّمْسُ أَحَبُّ إِلَيَّ مِنْ أَنْ أَعْتِقَ أَرْبَعَةً مِنْ وَلَدِ إِسْمَعِيلَ وَلَأَنْ أَقْعُدَ مَعَ قَوْمٍ يَذْكُرُونَ اللَّهَ مِنْ صَلَاةِ الْعَصْرِ إِلَى أَنْ تَغْرُبَ الشَّمْسُ أَحَبُّ إِلَيَّ مَنْ أَنْ أَعْتِقَ أَرْبَعَةً","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepadaku [Abdussalam bin Muthahhar Abu Zhafar] telah menceritakan kepada kami [Musa bin Khalaf Al 'Ammi] dari [Qatadah] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, aku duduk bersama kaum yang berdzikir kepada Allah Ta'ala dari shalat Subuh hingga terbit matahari lebih aku sukai daripada aku membebaskan empat anak Isma'il. Dan sungguh aku duduk bersama suatu kaum yang berdzikir kepada Allah dari Shalat 'Ashar hingga matahari tenggelam adalah lebih aku sukai daripada aku membebaskan empat orang budak.\""},"3105":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ سُورَةَ النِّسَاءِ قَالَ قُلْتُ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي قَالَ فَقَرَأْتُ عَلَيْهِ حَتَّى إِذَا انْتَهَيْتُ إِلَى قَوْلِهِ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ }الْآيَةَ فَرَفَعْتُ رَأْسِي فَإِذَا عَيْنَاهُ تَهْمِلَانِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Ibrahim] dari ['Abidah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Bacakan kepadaku Surat An Nisa!\" Aku katakan, \"Apakah aku akan membacakan kepadamu sementara Al Qur'an turun kepadamu?\" Beliau bersabda: \"Aku senang untuk mendengarnya dari selainku.\" Abdullah berkata, \"Kemudian aku membacakan Al Qur'an kepadanya hingga sampai pada firman-Nya: '(Maka bagaimanakah (halnya orang kafir nanti), apabila Kami mendatangkan seseorang saksi (rasul) …) ' (Qs. An Nisa: 41) Kemudian aku angkat kepalaku dan ternyata kedua mata beliau telah berurai dengan air mata.\""},"3106":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو حَيَّانَ حَدَّثَنِي الشَّعْبِيُّ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَنَزَلَ تَحْرِيمُ الْخَمْرِ يَوْمَ نَزَلَ وَهِيَ مِنْ خَمْسَةِ أَشْيَاءَ مِنْ الْعِنَبِ وَالتَّمْرِ وَالْعَسَلِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالْخَمْرُ مَا خَامَرَ الْعَقْلَ وَثَلَاثٌ وَدِدْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يُفَارِقْنَا حَتَّى يَعْهَدَ إِلَيْنَا فِيهِنَّ عَهْدًا نَنْتَهِي إِلَيْهِ الْجَدُّ وَالْكَلَالَةُ وَأَبْوَابٌ مِنْ أَبْوَابِ الرِّبَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Abu Hayyan] telah menceritakan kepadaku [Asy Sya'bi] dari [Ibnu Umar] dari [Umar] ia berkata, \"Ketika pengharaman arak turun di hari pengharamannya, arak saat itu terbuat dari lima hal; anggur, kurma, madu, gandum, serta jewawut. Dan arak adalah sesuatu yang menutupi akal, dan ada tiga perkara yang aku inginkan Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan kami hingga menjelaskan kepada kami mengenai ketiga perkara tersebut hingga kami memahaminya; (warisan) seorang kakek, orang yang tidak memiliki anak dan orang tua, serta beberapa bab mengenai riba.\""},"3107":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ مُوسَى الْخُتَّلِيُّ أَخْبَرَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرٍو عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ عُمَرُ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي الْبَقَرَةِ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ }الْآيَةَ قَالَ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ قَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ الْآيَةُ الَّتِي فِي النِّسَاءِ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }فَكَانَ مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ الصَّلَاةُ يُنَادِي أَلَا لَا يَقْرَبَنَّ الصَّلَاةَ سَكْرَانُ فَدُعِيَ عُمَرُ فَقُرِئَتْ عَلَيْهِ فَقَالَ اللَّهُمَّ بَيِّنْ لَنَا فِي الْخَمْرِ بَيَانًا شِفَاءً فَنَزَلَتْ هَذِهِ الْآيَةُ{ فَهَلْ أَنْتُمْ مُنْتَهُونَ }قَالَ عُمَرُ انْتَهَيْنَا","id":"Telah menceritakan kepada kami ['Abbad bin Musa Al Khuttali] telah mengabarkan kepada kami [Isma'il bin Ja'far] dari [Israil] dari [Abu Ishaq] dari ['Amru] dari [Umar bin Al Khathab] ia berkata, \"Tatkala telah turun pengharaman arak Umar berkata, \"Ya Allah, jelaskan kepada kami mengenai arak dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat dalam Surat Al Baqarah (219): '(Mereka bertanya kepadamu tentang khamer dan judi…) '. 'Ammar berkata, \"Kemudian Umar dipanggil dan dibacakan kepadanya ayat tersebut, ia berkata lagi, \"Ya Allah, jelaskan kepada kami mengenai khamer dengan penjelasan yang memuaskan.\" Kemudian turunlah ayat yang terdapat pada Surat An Nisaa` (41): '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…..) ' Penyeru Rasulullah shallallahu 'alaihi wasallam apabila shalat telah ditegakkan maka ia berseru, 'ketahuilah bahwa tidak boleh orang yang mabuk mendekati shalat! ' Kemudian Umar dipanggil dan dibacakanlah ayat tersebut kepadanya, lalu ia berkata, \"Ya Allah jelaskanlah kepada kami mengenai khamer dengan penjelasan yang memuaskan!\" Maka turunlah ayat ini: '(….. apakah kalian akan berhenti?) ' (Qs. Al Maa`idah: 91) Umar berkata, \"Kami telah berhenti.\""},"3108":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ عَلَيْهِ السَّلَامأَنَّ رَجُلًا مِنْ الْأَنْصَارِ دَعَاهُ وَعَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ فَسَقَاهُمَا قَبْلَ أَنْ تُحَرَّمَ الْخَمْرُ فَأَمَّهُمْ عَلِيٌّ فِي الْمَغْرِبِ فَقَرَأَ قُلْ يَا أَيُّهَا الْكَافِرُونَ فَخَلَطَ فِيهَا فَنَزَلَتْ{ لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى حَتَّى تَعْلَمُوا مَا تَقُولُونَ }","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepada kami ['Atha bin As Saib] dari [Abu Abdurrahman As Sulami] dari [Ali bin Abu Thalib] bahwa seorang laki-laki Anshar memanggil dirinya dan Abdurrahman bin 'Auf, lalu ia memberi mereka minum khamer sebelum khamer diharamkan. Setelah itu Ali mengimami mereka dalam Shalat Maghrib. Ketika ia membaca Surat Al Ikhlash dan terbolak-balik dalam membacanya, maka turunlah ayat: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk, sehingga kamu mengerti apa yang kamu ucapkan…) ' (Qs. An Nisaa`: 41). "},"3109":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيِّ حَدَّثَنَا عَلِيُّ بْنُ حُسَيْنٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى }وَ{ يَسْأَلُونَكَ عَنْ الْخَمْرِ وَالْمَيْسِرِ قُلْ فِيهِمَا إِثْمٌ كَبِيرٌ وَمَنَافِعُ لِلنَّاسِ }نَسَخَتْهُمَا الَّتِي فِي الْمَائِدَةِ{ إِنَّمَا الْخَمْرُ وَالْمَيْسِرُ وَالْأَنْصَابُ }الْآيَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepada kami [Ali bin Husain] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia membaca: '(Hai orang-orang yang beriman, janganlah kamu shalat, sedang kamu dalam keadaan mabuk…) ' (Qs. An Nisaa`: 41). Dan ayat: '(Mereka bertanya kepadamu tentang khamer dan judi. Katakanlah: \"Pada keduanya terdapat dosa yang besar dan beberapa manfaat bagi manusia.....) ' (Qs. Al Baqarah: 219), ia berkata, \"Kedua ayat tersebut dihapus dan digantikan oleh ayat yang terdapat dalam Surat Al Maaidah: 91: '(Sesungguhnya (meminum) khamar, berjudi, (berkorban untuk) berhala…) '. "},"3110":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكُنْتُ سَاقِيَ الْقَوْمِ حَيْثُ حُرِّمَتْ الْخَمْرُ فِي مَنْزِلِ أَبِي طَلْحَةَ وَمَا شَرَابُنَا يَوْمَئِذٍ إِلَّا الْفَضِيخُ فَدَخَلَ عَلَيْنَا رَجُلٌ فَقَالَ إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ وَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا هَذَا مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] ia berkata, \"Aku pernah memberi orang-orang minum khamer di waktu khamer telah diharamkan di rumah Abu Thalhah. Ketika itu minuman kami terbuat uii Fadlikh (khamer dari kurma muda). Kemudian ada seorang laki-laki masuk menemui kami dan berkata, 'sesungguhnya khamer telah diharamkan, dan penyeru Rasulullah shallallahu 'alaihi wasallam telah mengumumkan', maka kami pun berkata, \"Ini adalah penyeru Rasulullah shallallahu 'alaihi wasallam.\""},"3111":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعُ بْنُ الْجَرَّاحِ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ عَنْ أَبِي عَلْقَمَةَ مَوْلَاهُمْ وَعَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ الْغَافِقِيِّ أَنَّهُمَا سَمِعَا ابْنَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ اللَّهُ الْخَمْرَ وَشَارِبَهَا وَسَاقِيَهَا وَبَائِعَهَا وَمُبْتَاعَهَا وَعَاصِرَهَا وَمُعْتَصِرَهَا وَحَامِلَهَا وَالْمَحْمُولَةَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Waki' bin Al Jarrah] dari [Abdul Aziz bin Umar] dari [Abu 'Alqamah] mantan budak mereka, dan [Abdurrahman bin Abdullah Al Ghafiqi] bahwa keduanya telah mendengar [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah melaknat khamer, peminumnya, yang menuangkannya, penjualnya, pembelinya, pemerasnya, orang yang diperaskannya, orang yang membawanya dan orang yang dibawakan kepadanya.\""},"3112":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ السُّدِّيِّ عَنْ أَبِي هُبَيْرَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ أَبَا طَلْحَةَ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَيْتَامٍ وَرِثُوا خَمْرًا قَالَ أَهْرِقْهَا قَالَ أَفَلَا أَجْعَلُهَا خَلًّا قَالَ لَا","id":"Telah menceritakan kepada kami [Zuhair bin Hazb] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [As Saddi] dari [Abu Hubairah] dari [Anas bin Malik] bahwa Abu Thalhah bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai anak-anak yatim yang mewarisi khamer. Beliau bersabda: \"Tumpahkanlah khamer tersebut!\" Abu Thalhah bertanya, \"Bolehkah aku jadikan cuka?\" Beliau menjawab: \"Tidak.\""},"3113":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ الشَّعْبِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مِنْ الْعِنَبِ خَمْرًا وَإِنَّ مِنْ التَّمْرِ خَمْرًا وَإِنَّ مِنْ الْعَسَلِ خَمْرًا وَإِنَّ مِنْ الْبُرِّ خَمْرًا وَإِنَّ مِنْ الشَّعِيرِ خَمْرًا","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Israil] dari [Ibrahim bin Muhajir] dari [Asy Sya'bi] dari [An Nu'man bin Basyir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya anggur bisa jadi khamer, kurma bisa jadi khamer, madu bisa jadi khamer, gandum bisa jadi khamer dan jewawut juga bisa jadi khamer.\""},"3114":{"ar":"حَدَّثَنَا مَالِكُ بْنُ عَبْدِ الْوَاحِدِ أَبُو غَسَّانَ حَدَّثَنَا مُعْتَمِرٌ قَالَ قَرَأْتُ عَلَى الْفُضَيْلِ بْنِ مَيْسَرَةَ عَنْ أَبِي حَرِيزٍ أَنَّ عَامِرًا حَدَّثَهُ أَنَّ النُّعْمَانَ بْنَ بَشِيرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الْخَمْرَ مِنْ الْعَصِيرِ وَالزَّبِيبِ وَالتَّمْرِ وَالْحِنْطَةِ وَالشَّعِيرِ وَالذُّرَةِ وَإِنِّي أَنْهَاكُمْ عَنْ كُلِّ مُسْكِرٍ","id":"Telah menceritakan kepada kami [Malik bin Abdul Wahid Abu Ghassan] telah menceritakan kepada kami [Mu'tamir] ia berkata; aku membacakan riwayat kepada [Al Fudlail bin Maisarah] dari [Abu Hariz] bahwa [Amir] menceritakan kepadanya, bahwa [An Nu'man bin Basyir] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya khamer terbuat dari perasan, anggur, kurma, biji gandum, jewawut, dan jagung. Dan aku melarang kalian dari segala sesuatu yang memabukkan.\""},"3115":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنِي يَحْيَى عَنْ أَبِي كَثِيرٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَمْرُ مِنْ هَاتَيْنِ الشَّجَرَتَيْنِ النَّخْلَةِ وَالْعِنَبَةِقَالَ أَبُو دَاوُد اسْمُ أَبِي كَثِيرٍ الْغُبَرِيِّ يَزِيدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ غُفَيْلَةَ السَّحْمِيِّ وَقَالَ بَعْضُهُمْ أُذَيْنَةُ وَالصَّوَابُ غُفَيْلَةُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Aban] telah menceritakan kepadaku [Yahya] dari [Abu Katsir] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khamer terbuat dari kedua pohon ini; pohon kurma dan anggur.\" Abu Daud berkata, \"Nama Abu Katsir adalah Al Ghubarah Yazid bin Abdurrahman bin Ghufailah As Sahmi. Sedang yang lain mengatakan Udzainah, dan yang benar adalah Ghufailah.\""},"3116":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَمُحَمَّدُ بْنُ عِيسَى فِي آخَرِينَ قَالُوا حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مُسْكِرٍ خَمْرٌ وَكُلُّ مُسْكِرٍ حَرَامٌ وَمَنْ مَاتَ وَهُوَ يَشْرَبُ الْخَمْرَ يُدْمِنُهَا لَمْ يَشْرَبْهَا فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud] dan [Muhammad bin Isa] di antara yang lain. Mereka berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap sesuatu yang memabukkan adalah khamer, dan setiap yang memabukkan adalah haram. Barangsiapa meninggal dalam keadaan minum khamer dan menyukainya maka ia tidak akan meminumnya pada Hari Kiamat.\""},"3117":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ النَّيْسَابُورِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُمَرَ الصَّنْعَانِيُّ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ أَبِي شَيْبَةَ يَقُولُ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ مُخَمِّرٍ خَمْرٌ وَكُلُّ مُسْكِرٍ حَرَامٌ وَمَنْ شَرِبَ مُسْكِرًا بُخِسَتْ صَلَاتُهُ أَرْبَعِينَ صَبَاحًا فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ فَإِنْ عَادَ الرَّابِعَةَ كَانَ حَقًّا عَلَى اللَّهِ أَنْ يَسْقِيَهُ مِنْ طِينَةِ الْخَبَالِ قِيلَ وَمَا طِينَةُ الْخَبَالِ يَا رَسُولَ اللَّهِ قَالَ صَدِيدُ أَهْلِ النَّارِ وَمَنْ سَقَاهُ صَغِيرًا لَا يَعْرِفُ حَلَالَهُ مِنْ حَرَامِهِ كَانَ حَقًّا عَلَى اللَّهِ أَنْ يَسْقِيَهُ مِنْ طِينَةِ الْخَبَالِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi' An Naisaburi] telah menceritakan kepada kami [Ibrahim bin Umar Ash Shan'ani] ia berkata; aku mendengar [An Nu'man bin Abu Syaibah] berkata dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Segala sesuatu yang memabukkan adalah khamer, dan segala sesuatu yang memabukkan adalah haram. Barangsiapa minum sesuatu yang memabukkan maka shalatnya selama empat puluh pagi tidak diterima, apabila ia bertaubat maka Allah akan memberinya taubat. Dan jika pada kali keempatnya ia kembali minum, maka menjadi hak atas Allah untuk memberinya minum dari thinah al khabal.\" Beliau ditanya, \"Wahai Rasulullah, apakah thinah al khabal itu?\" Beliau Menjawab: \"Nanah penghuni Neraka. Dan barangsiapa memberi minum khamer anak kecil, sementara anak kecil tidaklah mengetahui halal dan haramnya, maka Allah akan memberinya minum dari thinah al khabal.\""},"3118":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ جَعْفَرٍ عَنْ دَاوُدَ بْنِ بَكْرِ بْنِ أَبِي الْفُرَاتِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَسْكَرَ كَثِيرُهُ فَقَلِيلُهُ حَرَامٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Daud bin Bakr bin Abu Al Furat] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesuatu yang memabukkan, maka banyak dan sedikitnya adalah haram.\""},"3119":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْبِتْعِ فَقَالَ كُلُّ شَرَابٍ أَسْكَرَ فَهُوَ حَرَامٌقَالَ أَبُو دَاوُد قَرَأْتُ عَلَى يَزِيدَ بْنِ عَبْدِ رَبِّهِ الْجُرْجُسِيِّ حَدَّثَكُمْ مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ بِهَذَا الْحَدِيثِ بِإِسْنَادِهِ زَادَ وَالْبِتْعُ نَبِيذُ الْعَسَلِ كَانَ أَهْلُ الْيَمَنِ يَشْرَبُونَهُ قَالَ أَبُو دَاوُد سَمِعْت أَحْمَدَ بْنَ حَنْبَلٍ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ مَا كَانَ أَثْبَتَهُ مَا كَانَ فِيهِمْ مِثْلُهُ يَعْنِي فِي أَهْلِ حِمْصٍ يَعْنِي الْجُرْجُسِيَّ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dan [Aisyah] radliallahu 'anha, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam ditanya mengenai Al Bit' (minuman yang terbuat dari madu). Kemudian beliau menjawab: \"Segala minuman yang memabukkan adalah haram.\" Abu Daud berkata, \"Aku membaca riwayat di hadapan [Yazid bin Abdu Rabbih Al Jurjusi] [Muhammad bin Harb] telah menceritakan hadits ini kepada kalian dari [Az Zubaidi] dari [Az Zuhri] dengan sanadnya. Ia menambahkan, \"Al Bit' adalah minuman hasil perasan madu, dahulu penduduk Yaman biasa meminumnya.\" Abu Daud berkata, \"Aku mendengar Ahmad bin Hanbal berkata, \"Tidak ada tuhan yang berhak untuk disembah selain Allah, tidak ada yang lebih teguh daripadanya, tidak ada di antara mereka yang semisal dia, yaitu di antara penduduk Himsh. Dan yang ia maksudkan adalah Al Jurjusi.\""},"3120":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِىِّ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ الْيَزَنِيِّ عَنْ دَيْلَمٍ الْحِمْيَرِيِّ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضٍ بَارِدَةٍ نُعَالِجُ فِيهَا عَمَلًا شَدِيدًا وَإِنَّا نَتَّخِذُ شَرَابًا مِنْ هَذَا الْقَمْحِ نَتَقَوَّى بِهِ عَلَى أَعْمَالِنَا وَعَلَى بَرْدِ بِلَادِنَا قَالَ هَلْ يُسْكِرُ قُلْتُ نَعَمْ قَالَ فَاجْتَنِبُوهُ قَالَ قُلْتُ فَإِنَّ النَّاسَ غَيْرُ تَارِكِيهِ قَالَ فَإِنْ لَمْ يَتْرُكُوهُ فَقَاتِلُوهُمْ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] telah menceritakan kepada kami ['Abdah] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Murtsad bin Abdullah Al Yazini] dari [Dailam Al Himyari] ia berkata, \"Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, sesungguhnya kami berada di negeri yang dingin, di sana kami melakukan pekerjaan berat, dan kami membuat minuman dari gandum ini agar kami kuat untuk melakukan pekerjaan kami dan tahan terhadap dinginnya negeri kami?\" Beliau menjawab: \"Apakah hal itu memabukkan?\" Aku menjawab, \"Ya.\" Beliau bersabda: \"Jauhilah minuman tersebut!\" Aku katakan, \"Orang-orang tidak meninggalkannya.\" Beliau bersabda: \"Apabila mereka tidak meninggalkannya maka perangilah mereka.\""},"3121":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ شَرَابٍ مِنْ الْعَسَلِ فَقَالَ ذَاكَ الْبِتْعُ قُلْتُ وَيُنْتَبَذُ مِنْ الشَّعِيرِ وَالذُّرَةِ فَقَالَ ذَلِكَ الْمِزْرُ ثُمَّ قَالَ أَخْبِرْ قَوْمَكَ أَنَّ كُلَّ مُسْكِرٍ حَرَامٌ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Khalid] dari ['Ashim bin Kulaib] dari [Abu Burdah] dari [Abu Musa] ia berkata, \"Aku pernah bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai minuman yang terbuat dari madu. Kemudian beliau menjawab: \"Itu adalah arak.\" Aku katakan kepada beliau, \"Dia dibuat dari perasan jewawut dan jagung?\" Beliau bersabda: \"Itu adalah arak.\" Kemudian beliau bersabda: \"Beritahukan kepada kaummu bahwa segala sesuatu yang memabukkan adalah haram.\""},"3122":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ الْوَلِيدِ بْنِ عَبْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْخَمْرِ وَالْمَيْسِرِ وَالْكُوبَةِ وَالْغُبَيْرَاءِ وَقَالَ كُلُّ مُسْكِرٍ حَرَامٌقَالَ أَبُو دَاوُد قَالَ ابْنُ سَلَامٍ أَبُو عُبَيْدٍ الْغُبَيْرَاءُ السُّكْرُكَةُ تُعْمَلُ مِنْ الذُّرَةِ شَرَابٌ يَعْمَلُهُ الْحَبَشَةُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Al Walid bin 'Abdah] dari [Abdullah bin 'Amru] bahwa Nabi shallallahu 'alaihi wasallam melarang khamer, judi, gendang kecil, Al Ghubaira` (jenis minuman yang terbuat dari jagung). Dan beliau bersabda: \"Segala yang memabukkan adalah haram.\" Abu Daud berkata, \"Ibnu Salam Abu 'Ubaid berkata, \"Al Ghubaira` adalah sukrukah yang terbuat dari jagung, yaitu minuman yang dibuat oleh orang-orang Habasyah.\""},"3123":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو شِهَابٍ عَبْدُ رَبِّهِ بْنُ نَافِعٍ عَنْ الْحَسَنِ بْنِ عَمْرٍو الْفُقَيْمِيِّ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أُمِّ سَلَمَةَ قَالَتْنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ كُلِّ مُسْكِرٍ وَمُفَتِّرٍ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abu Syihab Abdu Rabbih bin Nafi'] dari [Al Hasan bin 'Amru Al Fuqaimi] dari [Al Hakam bin 'Utaibah] dari [Syahr bin Hausyab] dari [Ummu Salamah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah melarang dari segala sesuatu yang memabukkan dan melemahkan.\""},"3124":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَمُوسَى بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا مَهْدِيٌّ يَعْنِي ابْنَ مَيْمُونٍ حَدَّثَنَا أَبُو عُثْمَانَ قَالَ مُوسَى وَهُوَ عَمْرُو بْنُ سَلْمٍ الْأَنْصَارِيِّ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ مُسْكِرٍ حَرَامٌ وَمَا أَسْكَرَ مِنْهُ الْفَرْقُ فَمِلْءُ الْكَفِّ مِنْهُ حَرَامٌ","id":"Telah menceritakan kepada kami [Musaddad] dan [Musa bin Isma'il] mereka berkata; telah menceritakan kepada kami [Mahdi bin Maimun] telah menceritakan kepada kami [Abu Utsman] Musa -yaitu 'Amru bin Salm Al Anshari- berkata dari [Al Qasim] dari [Aisyah] radliallahu 'anha, ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam berkata: \"Segala sesuatu yang memabukkan adalah haram, sesuatu yang satu Faraq memabukkan, maka sepenuh telapak tangan darinya pun haram.\" "},"3125":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنْ حَاتِمِ بْنِ حُرَيْثٍ عَنْ مَالِكِ بْنِ أَبِي مَرْيَمَ قَالَ دَخَلَ عَلَيْنَا عَبْدُ الرَّحْمَنِ بْنُ غَنْمٍ فَتَذَاكَرْنَا الطِّلَاءَ فَقَالَ حَدَّثَنِي أَبُو مَالِكٍ الْأَشْعَرِيُّأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَشْرَبَنَّ نَاسٌ مِنْ أُمَّتِي الْخَمْرَ يُسَمُّونَهَا بِغَيْرِ اسْمِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Zaid bin Al Hubab] telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Hatim bin Huraits] dari [Malik bin Abu Maryam] ia berkata, \" [Abdurrahman bin Ghanm] masuk menemui kami, lalu kami menyebutkan Thila` (minuman yang dimasak hingga mengental). Ia kemudian berkata, \" [Abu Malik Al Asy'ari] menceritakan kepadaku bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh akan ada beberapa orang dari umatku yang minum khamer, mereka menamakannya dengan selain namanya.\""},"3126":{"ar":"قَالَ أَبُو دَاوُد حَدَّثَنَا شَيْخٌ مِنْ أَهْلِ وَاسِطٍ قَالَ حَدَّثَنَا أَبُو مَنْصُورٍ الْحَارِثُ بْنُ مَنْصُورٍ قَالَ سَمِعْتُ سُفْيَانَ الثَّوْرِيَّوَسُئِلَ عَنْ الدَّاذِيِّ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَشْرَبَنَّ نَاسٌ مِنْ أُمَّتِي الْخَمْرَ يُسَمُّونَهَا بِغَيْرِ اسْمِهَاقَالَ أَبُو دَاوُد و قَالَ سُفْيَانُ الثَّوْرِيُّ الدَّاذِيُّ شَرَابُ الْفَاسِقِينَ","id":"Abu Daud berkata; telah menceritakan kepada kami [seorang syaikh dari Wasith] ia berkata; telah menceritakan kepada kami [Abu Manshur Al Harits bin Manshur] ia berkata, aku mendengar [Sufyan Ats Tsauri] ia ditanya mengenai dadzi (biji yang diletakkan pada air perasan hingga mengeras dan memabukkan), kemudian ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh akan ada beberapa orang dari umatku yang minum khamer, mereka menamakannya dengan selain namanya.\" Abu Daud berkata, \"Sufyan Ats Tsauri berkata, \"Dadzi adalah minuman orang-orang fasik.\""},"3127":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا مَنْصُورُ بْنُ حَيَّانَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَ وَابْنِ عَبَّاسٍ قَالَانَشْهَدُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالنَّقِيرِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Manshur bin Hayyan] dari [Sa'id bin Jubair] dari [Ibnu Umar] dan [Ibnu Abbas] mereka berkata, \"Kami bersaksi bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang dari Ad dubba, Al hantam, Al muzaffat dan An naqir.\" "},"3128":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ الْمَعْنِيِّ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ يَعْلَى يَعْنِي ابْنَ حَكِيمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُحَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيذَ الْجَرِّ فَخَرَجْتُ فَزِعًا مِنْ قَوْلِهِ حَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيذَ الْجَرِّفَدَخَلْتُ عَلَى ابْنِ عَبَّاسٍ فَقُلْتُ أَمَا تَسْمَعُ مَا يَقُولُ ابْنُ عُمَرَ قَالَ وَمَا ذَاكَ قُلْتُ قَالَ حَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيذَ الْجَرِّ قَالَ صَدَقَ حَرَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيذَ الْجَرِّ قُلْتُ وَمَا الْجَرُّ قَالَ كُلُّ شَيْءٍ يُصْنَعُ مِنْ مَدَرٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dan [Muslim bin Ibrahim] secara makna, mereka berkata; telah menceritakan kepada kami [Jarir] dari [Ya'la bin Hakim] dari [Sa'id bin Jubair] ia berkata, \"Saya mendengar [Abdullah bin Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam telah mengharamkan perasan (arak) dalam bejana tembikar, kemudian aku keluar dalam keadaan kaget karena ucapannya, 'Rasulullah shallallahu 'alaihi wasallam telah mengharamkan perasan dalam bejana tembikar'. Maka aku pun menemui Ibnu Abbas dan aku katakan, \"Tidakkah engkau mendengar apa yang dikatakan Ibnu Umar?\" Ia menjawab, \"Apakah itu?\" Aku menjawab, \"Ia mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam telah mengharamkan perasan dalam bejana tembikar.\" [Ibnu Abbas] lantas berkata, \"Ibnu Umar benar. Rasulullah shallallahu 'alaihi wasallam telah mengharamkan perasan dalam bejana tembikar.\" Aku lalu bertanya, \"Al Jar itu apa?\" Ibnu Abbas menjawab, \"Sesuatu yang terbuat dari tanah.\""},"3129":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ عُبَيدٍ قَالَا حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ عَنْ أَبِي جَمْرَةَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُ وَقَالَ مُسَدَّدٌ عَنْ ابْنِ عَبَّاسٍ وَهَذَا حَدِيثُ سُلَيْمَانَ قَالَقَدِمَ وَفْدُ عَبْدِ الْقَيْسِ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّا هَذَا الْحَيَّ مِنْ رَبِيعَةَ قَدْ حَالَ بَيْنَنَا وَبَيْنَكَ كُفَّارُ مُضَرَ وَلَيْسَ نَخْلُصُ إِلَيْكَ إِلَّا فِي شَهْرٍ حَرَامٍ فَمُرْنَا بِشَيْءٍ نَأْخُذُ بِهِ وَنَدْعُو إِلَيْهِ مَنْ وَرَاءَنَا قَالَ آمُرُكُمْ بِأَرْبَعٍ وَأَنْهَاكُمْ عَنْ أَرْبَعٍ الْإِيمَانُ بِاللَّهِ وَشَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَعَقَدَ بِيَدِهِ وَاحِدَةً وَقَالَ مُسَدَّدٌ الْإِيمَانُ بِاللَّهِ ثُمَّ فَسَّرَهَا لَهُمْ شَهَادَةُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا رَسُولُ اللَّهِ وَإِقَامُ الصَّلَاةِ وَإِيتَاءُ الزَّكَاةِ وَأَنْ تُؤَدُّوا الْخُمُسَ مِمَّا غَنِمْتُمْ وَأَنْهَاكُمْ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالْمُزَفَّتِ وَالْمُقَيَّرِ وَقَالَ ابْنُ عُبَيْدٍ النَّقِيرُ مَكَانَ الْمُقَيَّرِ وَقَالَ مُسَدَّدٌ وَالنَّقِيرُ وَالْمُقَيَّرُ لَمْ يَذْكُرْ الْمُزَفَّتَقَالَ أَبُو دَاوُد أَبُو جَمْرَةَ نَصْرُ بْنُ عِمْرَانَ الضُّبَعِيُّ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] dan [Muhammad bin 'Ubaid] mereka berkata; telah menceritakan kepada kami [Hammad]. (Dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abbad bin 'Abbad] dari [Abu Jamrah] ia berkata; aku mendengar [Ibnu Abbas] berkata -Musaddad menyebutkan dari Ibnu Abbas; ini adalah hadits Sulaiman- Ibnu Abbas berkata, \"Delegasi Abdul Qais datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya kami orang-orang kampung Rabi'ah, antara kami dan anda terhalangi oleh orang-orang kafir Mudlar, dan kami tidak dapat dengan bebas pergi kepada anda kecuali pada Bulan Muharram. Maka perintahkanlah sesuatu kepada kami sehingga kami dapat lakukan dan sampaikan kepada orang-orang yang ada di belakang kami.\" Beliau bersabda: \"Aku perintahkan kalian untuk melakukan empat perkara dan aku larang kalian dari melakukan empat perkara. Yaitu beriman kepada Allah, bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah….\" dan beliau menghitung dengan satu tangan beliau. [Musaddad] menyebutkan, 'Beriman kepada Allah', kemudian beliau menafsirkannya kepada mereka, 'Yaitu bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah dan Muhammad adalah Rasulullah, mendirikan shalat, membayar zakat, dan menunaikan seperlima dari rampasan perang yang kalian dapatkan. Dan aku larang kalian dari Ad dubba`, Al hantam, Al muzzaffat dan Al muqayyar.\" Sedangkan Ibnu 'Ubaid menyebutkan, 'An Naqir sebagai ganti muqayyar. ' Dan Musaddad menyebutkan, 'An naqir dan Al muqayyar tanpa menyebutkan Al muzaffat.\" Abu Daud berkata, \"Abu Hamzah adalah Nashr bin Imran Adl Dluba'i.\" "},"3130":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ نُوحِ بْنِ قَيْسٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِوَفْدِ عَبْدِ الْقَيْسِ أَنْهَاكُمْ عَنْ النَّقِيرِ وَالْمُقَيَّرِ وَالْحَنْتَمِ وَالدُّبَّاءِ وَالْمُزَادَةِ الْمَجْبُوبَةِ وَلَكِنْ اشْرَبْ فِي سِقَائِكَ وَأَوْكِهْحَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ عَنْ عِكْرِمَةَ وَسَعِيدِ بْنِ الْمُسَيِّبِ عَنْ ابْنِ عَبَّاسٍ فِي قِصَّةِ وَفْدِ عَبْدِ الْقَيْسِ قَالُوا فِيمَ نَشْرَبُ يَا نَبِيَّ اللَّهِ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْكُمْ بِأَسْقِيَةِ الْأَدَمِ الَّتِي يُلَاثُ عَلَى أَفْوَاهِهَا","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Nuh bin Qais] telah menceritakan kepada kami [Abdullah bin 'Aun] dari [Muhammad bin Sirin] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada delegasi Abdul Qais: \"Aku melarang kalian dari An naqir, Al muqayyar, Al hantam, Ad dubba`dan Al Muzaffat. Akan tetapi minumlah pada tempat air minum kalian, dan ikatlah dengan tali!\" Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Qatadah] dari [Ikrimah] dan [Sa'id bin Al Musayyab] dari [Ibnu Abbas] mengenai kisah delegasi Abdul Qais. Mereka berkata, \"Pada apakah kami boleh minum wahai Nabi Allah? Nabi shallallahu 'alaihi wasallam bersabda: \"Hendaknya kalian minum dari tempat minum dari kulit yang ditutup dan diikat dengan tali pada bagian mulutnya.\" "},"3131":{"ar":"حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ عَنْ خَالِدٍ عَنْ عَوْفٍ عَنْ أَبِي الْقَمُوصِ زَيدِ بْنِ عَلِيٍّ حَدَّثَنِي رَجُلٌ كَانَ مِنْ الْوَفْدِ الَّذِينَ وَفَدُوا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَبْدِ الْقَيْسِ يَحْسَبُ عَوْفٌ أَنَّ اسْمَهُ قَيْسُ بْنُ النُّعْمَانِ فَقَالَلَا تَشْرَبُوا فِي نَقِيرٍ وَلَا مُزَفَّتٍ وَلَا دُبَّاءٍ وَلَا حَنْتَمٍ وَاشْرَبُوا فِي الْجِلْدِ الْمُوكَى عَلَيْهِ فَإِنْ اشْتَدَّ فَاكْسِرُوهُ بِالْمَاءِ فَإِنْ أَعْيَاكُمْ فَأَهْرِيقُوهُ","id":"Telah menceritakan kepada kami [Wahb bin Baqiyyah] dari [Khalid] dari ['Auf] dari [Abu Al Qamush Zaid bin Ali] telah menceritakan kepadaku [seorang laki-laki] yang termasuk di antara delegasi yang datang kepada Nabi shallallahu 'alaihi wasallam dari Abdul Qais. 'Auf mengira namanya adalah Qais bin An Nu'man. Kemudian beliau bersabda: \"Janganlah kalian minum dalam An naqir, Al muzaffat, Ad dubba dan hantam. Minumlah dalam kantung kulit yang terikat kepalanya, kemudian apabila telah mengeras maka stabilkan dengan air, dan apabila membuatmu tidak sadar maka tumpahkanlah!\" "},"3132":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ بَذِيمَةَ حَدَّثَنِي قَيْسُ بْنُ حَبْتَرٍ النَّهْشَلِيُّ عَنْ ابْنِ عَبَّاسٍأَنَّ وَفْدَ عَبْدِ الْقَيْسِ قَالُوا يَا رَسُولَ اللَّهِ فِيمَ نَشْرَبُ قَالَ لَا تَشْرَبُوا فِي الدُّبَّاءِ وَلَا فِي الْمُزَفَّتِ وَلَا فِي النَّقِيرِ وَانْتَبِذُوا فِي الْأَسْقِيَةِ قَالُوا يَا رَسُولَ اللَّهِ فَإِنْ اشْتَدَّ فِي الْأَسْقِيَةِ قَالَ فَصُبُّوا عَلَيْهِ الْمَاءَ قَالُوا يَا رَسُولَ اللَّهِ فَقَالَ لَهُمْ فِي الثَّالِثَةِ أَوْ الرَّابِعَةِ أَهْرِيقُوهُ ثُمَّ قَالَ إِنَّ اللَّهَ حَرَّمَ عَلَيَّ أَوْ حُرِّمَ الْخَمْرُ وَالْمَيْسِرُ وَالْكُوبَةُ قَالَ وَكُلُّ مُسْكِرٍ حَرَامٌقَالَ سُفْيَانُ فَسَأَلْتُ عَلِيَّ بْنَ بَذِيمَةَ عَنْ الْكُوبَةِ قَالَ الطَّبْلُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Ali bin Badzimah] telah menceritakan kepadaku [Qais bin Habtar An Nahsyali] dari [Ibnu Abbas] bahwa delegasi Abdul Qais berkata, \"Wahai Rasulullah, pada apakah kami boleh minum?\" Beliau menjawab: \"Janganlah kalian minum pada Ad dubba, Al muzaffat, An naqir, dan buatlah minuman perasan dalam tempat-tempat minum!\" Mereka bertanya lagi, \"Wahai Rasulullah, apabila telah mengeras dalam kantung-kantung minuman?\" Beliau menjawab: \"Tuangkan air padanya!\" Mereka bertanya lagi, \"Wahai Rasulullah! Kemudian beliau berkata kepada mereka pada kali ketiga atau keempat: \"Tumpahkan!\" Setelah itu beliau bersabda: \"Sesungguhnya Allah telah mengharamkan bagiku….\" Atau, \"Telah diharamkan bagiku khamer, judi dan kendang.\" Beliau bersabda: \"Dan segala sesuatu yang memabukkan adalah haram.\" [Sufyan] berkata, \"Aku bertanya Ali bin Badzimah bin Badzimah tentang Al Kubah?\" Ia lalu menjawab, \"Yaitu kendang.\""},"3133":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا إِسْمَعِيلُ بْنُ سُمَيْعٍ حَدَّثَنَا مَالِكُ بْنُ عُمَيْرٍ عَنْ عَلِيٍّ عَلَيْهِ السَّلَام قَالَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ وَالْجِعَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Wahid] telah menceritakan kepada kami [Isma'il bin Sumai'] telah menceritakan kepada kami [Malik bin 'Umair] dari [Ali] radliallahu 'anhu, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang kami dari menggunakan Ad dubba, Al hantam, An Naqir dan Al Ji'ah.\" "},"3134":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا مُعْرِّفُ بْنُ وَاصِلٍ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَيْتُكُمْ عَنْ ثَلَاثٍ وَأَنَا آمُرُكُمْ بِهِنَّ نَهَيْتُكُمْ عَنْ زِيَارَةِ الْقُبُورِ فَزُورُوهَا فَإِنَّ فِي زِيَارَتِهَا تَذْكِرَةً وَنَهَيْتُكُمْ عَنْ الْأَشْرِبَةِ أَنْ تَشْرَبُوا إِلَّا فِي ظُرُوفِ الْأَدَمِ فَاشْرَبُوا فِي كُلِّ وِعَاءٍ غَيْرَ أَنْ لَا تَشْرَبُوا مُسْكِرًا وَنَهَيْتُكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ أَنْ تَأْكُلُوهَا بَعْدَ ثَلَاثٍ فَكُلُوا وَاسْتَمْتِعُوا بِهَا فِي أَسْفَارِكُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Mu'arrif bin Washilah] dari [Muharib bin Ditsar] dari [Ibnu Buraidah] dari [Ayahnya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku larang kalian dari tiga hal dan aku perintahkan kalian tiga hal tersebut. Aku telah melarang kalian dari ziarah kubur, sekarang lakukanlah karena di dalamnya terdapat peringatan. Aku telah melarang kalian dari meminum beberapa minuman kecuali jika minuman tersebut berada dalam geriba kulit. Minumlah dari segala bejana, tetapi jangan kalian minum sesuatu yang memabukkan. Dan aku telah melarang kalian dari memakan daging kurban setelah tiga hari, sekarang makan dan nikmatilah dalam perjalanan kalian!\""},"3135":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ حَدَّثَنِي مَنْصُورٌ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَلَمَّا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْأَوْعِيَةِ قَالَ قَالَتْ الْأَنْصَارُ إِنَّهُ لَا بُدَّ لَنَا قَالَ فَلَا إِذَنْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] telah menceritakan kepadaku [Manshur] dari [Salim bin Abu Al Ja'd] dari [Jabir bin Abdullah] ia berkata, \"Tatkala Rasulullah shallallahu 'alaihi wasallam melarang dari beberapa tempat minum, maka orang-orang anshar berkata, \"Kami tidak bisa meninggalkan dari hal itu!\" Beliau bersabda: \"Jika demikian maka aku tidak melarangnya.\""},"3136":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرِ بْنِ زِيَادٍ حَدَّثَنَا شَرِيكٌ عَنْ زِيَادِ بْنِ فَيَّاضٍ عَنْ أَبِي عَيَّاضٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَوْعِيَةَ الدُّبَّاءَ وَالْحَنْتَمَ وَالْمُزَفَّتَ وَالنَّقِيرَ فَقَالَ أَعْرَابِيٌّ إِنَّهُ لَا ظُرُوفَ لَنَا فَقَالَ اشْرَبُوا مَا حَلَّحَدَّثَنَا الْحَسَنُ يَعْنِي ابْنَ عَلِيٍّ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا شَرِيكٌ بِإِسْنَادِهِ قَالَ اجْتَنِبُوا مَا أَسْكَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far bin Ziyad] telah menceritakan kepada kami [Syarik] dari [Ziyad bin Fayyadl] dari [Abu 'Ayyadl] dari [Abdullah bin 'Amru] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah menyebutkan beberapa tempat minum; Ad dubba, Al hantam, Al muzaffat dan An naqir. Kemudian orang-orang badui berkata, \"Kami tidak memiliki selain itu!\" Beliau pun bersabda: \"Minumlah apa yang halal!\" Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Syarik] dengan sanadnya, beliau bersabda: \"Jauhilah apa yang memabukkan!\" "},"3137":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى أَنْ يُنْتَبَذَ الزَّبِيبُ وَالتَّمْرُ جَمِيعًا وَنَهَى أَنْ يُنْتَبَذَ الْبُسْرُ وَالرُّطَبُ جَمِيعًا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari ['Atha bin Abu Rabbah] dari [Jabir bin Abdullah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau telah melarang anggur dan kurma dibuat perasaan bersama-sama, beliau juga melarang kurma mentah dan kurma segar dibuat perasan secara bersamaan.\""},"3138":{"ar":"حَدَّثَنَا أَبُو سَلَمَةَ مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنِي يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّهُ نَهَى عَنْ خَلِيطِ الزَّبِيبِ وَالتَّمْرِ وَعَنْ خَلِيطِ الْبُسْرِ وَالتَّمْرِ وَعَنْ خَلِيطِ الزَّهْوِ وَالرُّطَبِ وَقَالَ انْتَبِذُوا كُلَّ وَاحِدَةٍ عَلَى حِدَةٍقَالَ و حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي قَتَادَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abu Salamah Musa bin Isma'il] telah menceritakan kepada kami [Aban] telah menceritakan kepadaku [Yahya] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] bahwa ia telah melarang dari pencampuran anggur dan kurma, pencampuran zahw (kurma mentah) dan kurma segar.\" Beliau bersabda: \"Peraslah masing-masing secara tersendiri!\" Dan telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] dari [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini.\""},"3139":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ وَحَفْصُ بْنُ عُمَرَ النَّمَرِيُّ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى عَنْ رَجُلٍ قَالَ حَفْصٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَهَى عَنْ الْبَلَحِ وَالتَّمْرِ وَالزَّبِيبِ وَالتَّمْرِ","id":"Telah menceritakan kepadaku [Sulaiman bin Harb] dan [Hafsh bin Umar An Namari] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] dari [seorang laki-laki] Hafsh berkata -salah seorang sahabat Nabi shallallahu 'alaihi wasallam-, dari Nabi shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah melarang mencampur balah (buah kurma yang baru berwarna hijau) dan kurma, serta anggur dan kurma saat membuat perasan.\""},"3140":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ثَابِتِ بْنِ عُمَارَةَ حَدَّثَتْنِي رَيْطَةُ عَنْ كَبْشَةَ بِنْتِ أَبِي مَرْيَمَ قَالَتْ سَأَلْتُ أُمَّ سَلَمَةَمَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْهُ قَالَتْ كَانَ يَنْهَانَا أَنْ نَعْجُمَ النَّوَى طَبْخًا أَوْ نَخْلِطَ الزَّبِيبَ وَالتَّمْرَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Tsabit bin 'Umarah] telah menceritakan kepadaku [Raithah] dari [Kabsyah binti Abu Maryam] ia berkata, \"Aku pernah bertanya kepada [Ummu Salamah], \"Apa yang dilarang Rasulullah shallallahu 'alaihi wasallam? Ia menjawab, \"Beliau melarang kami untuk memasak biji kurma hingga matang, atau mencampurkan antara anggur dan kurma.\""},"3141":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوَدَ عَنْ مِسْعَرٍ عَنْ مُوسَى بْنِ عَبْدِ اللَّهِ عَنْ امْرَأَةٍ مِنْ بَنِي أَسَدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُنْبَذُ لَهُ زَبِيبٌ فَيُلْقِي فِيهِ تَمْرًا وَتَمْرٌ فَيُلْقِي فِيهِ الزَّبِيبَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdullah bin Daud] dari [Mis'ar] dari [Musa bin Abdullah] dari [seorang wanita Bani Asad] dari [Aisyah] radliallahu 'anha, bahwa Rasulullah shallallahu 'alaihi wasallam dibuatkan perasan anggur, beliau lalu memasukkan kurma ke dalam perasan anggur tersebut, dan memasukkan anggur dalam perasan kurma.\""},"3142":{"ar":"حَدَّثَنَا زِيَادُ بْنُ يَحْيَى الْحَسَّانِيُّ حَدَّثَنَا أَبُو بَحْرٍ حَدَّثَنَا عَتَّابُ بْنُ عَبْدِ الْعَزِيزِ الْحِمَّانِيُّ حَدَّثَتْنِي صَفِيَّةُ بِنْتُ عَطِيَّةَ قَالَتْدَخَلْتُ مَعَ نِسْوَةٍ مِنْ عَبْدِ الْقَيْسِ عَلَى عَائِشَةَ فَسَأَلْنَاهَا عَنْ التَّمْرِ وَالزَّبِيبِ فَقَالَتْ كُنْتُ آخُذُ قَبْضَةً مِنْ تَمْرٍ وَقَبْضَةً مِنْ زَبِيبٍ فَأُلْقِيهِ فِي إِنَاءٍ فَأَمْرُسُهُ ثُمَّ أَسْقِيهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ziyad bin Yahya Al Hassani] telah menceritakan kepada kami [Abu Bahr] telah menceritakan kepada kami ['Attab bin Abdul Aziz Al Himmani] telah menceritakan kepadaku [Shafiyyah binti 'Athiyyah] ia berkata, \"Aku bersama beberapa orang wanita dari Abdul Qais menemui Aisyah dan bertanya kepadanya mengenai kurma dan anggur. Lalu [Aisyah] menjawab, \"Aku pernah mengambil satu genggam kurma dan satu genggam anggur, lalu aku memasukkannya ke dalam bejana, aku lalu memerasnya untuk kemudian aku berikan kepada Nabi shallallahu 'alaihi wasallam.\""},"3143":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ جَابِرِ بْنِ زَيْدٍ وَعِكْرِمَةَأَنَّهُمَا كَانَا يَكْرَهَانِ الْبُسْرَ وَحْدَهُ وَيَأْخُذَانِ ذَلِكَ عَنْ ابْنِ عَبَّاسٍ وَقَالَ ابْنُ عَبَّاسٍ أَخْشَى أَنْ يَكُونَ الْمُزَّاءُ الَّذِي نُهِيَتْ عَنْهُ عَبْدُ القَيْسِفَقُلْتُ لِقَتَادَةَ مَا الْمُزَّاءُ قَالَ النَّبِيذُ فِي الْحَنْتَمِ وَالْمُزَفَّتِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Ayahku] dari [Qatadah] dari [Jabir bin Zaid] dan [Ikrimah] bahwa keduanya tidak menyukai busr (kurma yang masih hijau) semata. Mereka mengambil pendapat tersebut dari Ibnu Abbas. Dan [Ibnu Abbas] berkata, \"Aku khawatir hal tersebut adalah muzza` yang Abdul Qais telah dilarang darinya. Lalu aku tanyakan kepada Qatadah, \"Apakah muzza` itu?\" Ia menjawab, \"Perasan dalam Al hantam dan Al Muzaffat.\" "},"3144":{"ar":"حَدَّثَنَا عِيسَى بْنُ مُحَمَّدٍ حَدَّثَنَا ضَمُرَةُ عَنْ السَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الدَّيْلَمِيِّ عَنْ أَبِيهِ قَالَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْنَا يَا رَسُولَ اللَّهِ قَدْ عَلِمْتَ مَنْ نَحْنُ وَمِنْ أَيْنَ نَحْنُ فَإِلَى مَنْ نَحْنُ قَالَ إِلَى اللَّهِ وَإِلَى رَسُولِهِ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّ لَنَا أَعْنَابًا مَا نَصْنَعُ بِهَا قَالَ زَبِّبُوهَا قُلْنَا مَا نَصْنَعُ بِالزَّبِيبِ قَالَ انْبِذُوهُ عَلَى غَدَائِكُمْ وَاشْرَبُوهُ عَلَى عَشَائِكُمْ وَانْبِذُوهُ عَلَى عَشَائِكُمْ وَاشْرَبُوهُ عَلَى غَدَائِكُمْ وَانْبِذُوهُ فِي الشِّنَانِ وَلَا تَنْبِذُوهُ فِي الْقُلَلِ فَإِنَّهُ إِذَا تَأَخَّرَ عَنْ عَصْرِهِ صَارَ خَلًّا","id":"Telah menceritakan kepada kami [Isa bin Muhammad] telah menceritakan kepada kami [Dlamrah] dari [As Saibani] dari [Abdullah bin Ad Dailami] dari [Ayahnya] ia berkata, \"Kami datang kepada Rasulullah shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, kami telah mengetahui siapakah kami, dan dari mana kami berasal, lalu kepada siapakah kami akan kembali?\" Beliau menjawab: \"Kepada Allah dan kepada Rasul-Nya.\" Kami bertanya lagi, \"Wahai Rasulullah, sesungguhnya kami memiliki beberapa anggur, apa yang boleh kami lakukan terhadapnya?\" Beliau menjawab: \"Jadikanlah anggur tersebut menjadi kismis (anggur kering)!\" Kami bertanya lagi, \"Apa yang boleh kami lakukan terhadap kismis?\" Beliau menjawab: \"Buatlah perasan diwaktu pagi kalian dan minumlah diwaktu sore kalian. Buatlah perasan diwaktu sore kalian dan minumlah diwaktu pagi kalian. Buatlah perasan dalam geriba basah dan jangan kalian buat dalam gentong besar, sebab jika kalian terlambat memerasnya ia akan menjadi cuka.\""},"3145":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ الثَّقَفِيِّ عَنْ يُونُسَ بْنِ عُبَيدٍ عَنْ الْحَسَنِ عَنْ أُمِّهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ يُنْبَذُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سِقَاءٍ يُوكَأُ أَعْلَاهُ وَلَهُ عَزْلَاءُ يُنْبَذُ غُدْوَةً فَيَشْرَبُهُ عِشَاءً وَيُنْبَذُ عِشَاءً فَيَشْرَبُهُ غُدْوَةً","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepadaku [Abdul Wahhab bin Abdul Majid Ats Tsaqafi] dari [Yunus bin 'Ubaid] dari [Al Hasan] dari [Ibunya] dari [Aisyah] radliallahu 'anhuma, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam dibuatkan perasan nabidz dalam geriba air minum yang diikat bagian atasnya dan memiliki mulut (untuk keluar air). Diperas waktu pagi dan diminum waktu sore, diperas waktu sore dan diminum waktu pagi.\""},"3146":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ شَبِيبَ بْنَ عَبْدِ الْمَلِكِ يُحَدِّثُ عَنْ مُقَاتِلِ بْنِ حَيَّانَ قَالَ حَدَّثَتْنِي عَمَّتِي عَمْرَةُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا كَانَتْ تَنْبِذُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غُدْوَةً فَإِذَا كَانَ مِنْ الْعَشِيِّ فَتَعَشَّى شَرِبَ عَلَى عَشَائِهِ وَإِنْ فَضَلَ شَيْءٌ صَبَبْتُهُ أَوْ فَرَّغْتُهُ ثُمَّ تَنْبِذُ لَهُ بِاللَّيْلِ فَإِذَا أَصْبَحَ تَغَدَّى فَشَرِبَ عَلَى غَدَائِهِ قَالَتْ يُغْسَلُ السِّقَاءُ غُدْوَةً وَعَشِيَّةً فَقَالَ لَهَا أَبِي مَرَّتَيْنِ فِي يَوْمٍ قَالَتْ نَعَمْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Al Mu'tamir] ia berkata; aku mendengar [Syabib bin Abdul Malik] menceritakan dari [Muqatil bin Hayyan] ia berkata; telah menceritakan kepadaku bibiku ['Amrah] dari [Aisyah] radliallahu 'anhuma, bahwa ia pernah membuatkan perasan arak untuk Nabi shallallahu 'alaihi wasallam pada waktu makan pagi, kemudian saat makan malam beliau meminumnya. Jika ada yang sisa makan aku membuangnya, atau aku tuang. Kemudian Aisyah membuatkan perasan lagi untuk beliau diwaktu malam, saat maka pagi beliau meminumnya. Aisyah berkata, \"Tempat minum tersebut dicuci pada pagi dan sore hari. Kemudian ayahku berkata kepadanya, \"Apakah dua kali dalam sehari? Aisyah menjawab, \"Ya.\""},"3147":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي عُمَرَ يَحْيَى الْبَهْرَانِيِّ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ يُنْبَذُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الزَّبِيبُ فَيَشْرَبُهُ الْيَوْمَ وَالْغَدَ وَبَعْدَ الْغَدِ إِلَى مَسَاءِ الثَّالِثَةِ ثُمَّ يَأْمُرُ بِهِ فَيُسْقَى الْخَدَمُ أَوْ يُهَرَاقُقَالَ أَبُو دَاوُد مَعْنَى يُسْقَى الْخَدَمُ يُبَادَرُ بِه الْفَسَادَ قَالَ أَبُو دَاوُد أَبُو عُمَرَ يَحْيَى بْنُ عُبَيْدٍ الْبَهْرَانِيُّ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Umar Yahya Al Bahrani] dari [Ibnu Abbas] ia berkata, \"Nabi shallallahu 'alaihi wasallam pernah dibuatkan perasan anggur, beliau lalu meminumnya pada hari itu, kemudian keesokan harinya, kemudian keesokannya lagi, yaitu sore hari di hari ketiga. Kemudian beliau memerintahkan agar diberikan kepada pelayan atau dibuang.\" Abu Daud berkata, \"Makna diberikan kepada pelayan adalah mengejar rusaknya minuman tersebut.\" Abu Daud berkata, \"Abu Umar adalah Yahya bin 'Ubaid Al Bahrani.\""},"3148":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ حَنْبَلٍ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ أَنَّهُ سَمِعَ عُبَيْدَ بْنَ عُمَيْرٍ قَالَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُخْبِرُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمْكُثُ عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ فَيَشْرَبُ عِنْدَهَا عَسَلًا فَتَوَاصَيْتُ أَنَا وَحَفْصَةُ أَيَّتُنَا مَا دَخَلَ عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْتَقُلْ إِنِّي أَجِدُ مِنْكَ رِيحَ مَغَافِيرَ فَدَخَلَ عَلَى إِحْدَاهُنَّ فَقَالَتْ لَهُ ذَلِكَ فَقَالَ بَلْ شَرِبْتُ عَسَلًا عِنْدَ زَيْنَبَ بِنْتِ جَحْشٍ وَلَنْ أَعُودَ لَهُ فَنَزَلَتْ{ لِمَ تُحَرِّمُ مَا أَحَلَّ اللَّهُ لَكَ تَبْتَغِي إِلَى إِنْ تَتُوبَا إِلَى اللَّهِ }لِعَائِشَةَ وَحَفْصَةَ رَضِيَ اللَّهُ عَنْهُمَا{ وَإِذْ أَسَرَّ النَّبِيُّ إِلَى بَعْضِ أَزْوَاجِهِ حَدِيثًا }لِقَوْلِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلْ شَرِبْتُ عَسَلًاحَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ الْحَلْوَاءَ وَالْعَسَلَ فَذَكَرَ بَعْضَ هَذَا الْخَبَرِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَشْتَدُّ عَلَيْهِ أَنْ تُوجَدَ مِنْهُ الرِّيحُ وَفِي هَذَا الْحَدِيثِ قَالَتْ سَوْدَةُ بَلْ أَكَلْتَ مَغَافِيرَ قَالَ بَلْ شَرِبْتُ عَسَلًا سَقَتْنِي حَفْصَةُ فَقُلْتُ جَرَسَتْ نَحْلُهُ الْعُرْفُطَ نَبْتٌ مِنْ نَبْتِ النَّحْلِ قَالَ أَبُو دَاوُد الْمَغَافِيرُ مُقْلَةٌ وَهِيَ صَمْغَةٌ وَجَرَسَتْ رَعَتْ وَالْعُرْفُطُ نَبْتٌ مِنْ نَبْتِ النَّحْلِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad bin Hanbal] telah menceritakan kepada kami [Hajjaj bin Muhammad] ia berkata; [Ibnu Juraij] berkata dari ['Atha] bahwa ia mendengar ['Ubaid bin 'Umair] berkata; aku mendengar [Aisyah] radliallahu 'anhuma, isteri Nabi shallallahu 'alaihi wasallam, mengabarkan bahwa Nabi shallallahu 'alaihi wasallam tinggal di rumah Zainab binti Jahsy dan minum madu di sisinya. Kemudian aku dan Hafshah bersepakat bahwa barangsiapa di antara kami ditemui oleh Nabi shallallahu 'alaihi wasallam, maka hendaknya ia mengatakan 'Sesungguhnya saya mendapatkan bau Maghafir (sejenis tanaman) '. Lalu beliau menemui salah seorang dari mereka berdua, kemudian ia mengatakan hal tersebut kepada beliau. Maka beliau pun bersabda: \"Bahkan aku minum madu di rumah Zainab. Dan sekali-kali aku tidak akan mengulanginya lagi.\" Kemudian turunlah ayat: '(Kenapa engkau haramkan apa yang Allah halalkan kepadamu…) ' hingga firman-Nya: '(Jika kamu berdua bertaubat kepada Allah…) ' (Qs. At Tahriim: 1-4), untuk Aisyah dan Hafshah.\" '(Dan ingatlah ketika Nabi membicarakan secara rahasia kepada salah seorang isterinya (Hafsah) suatu peristiwa) ' (Qs. At Tahriim: 3), karena sebab sabda beliau: \"Bahkan aku minum madu.\" Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Ayahnya] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam senang manis-manisan dan madu.\" Lalu ia menyebutkan hadits ini. Dan Nabi shallallahu 'alaihi wasallam sangat tidak senang tercium darinya bau makanan tersebut. Dan dalam hadits ini Saudah berkata, \"Tuan makan maghafir!\" Beliau bersabda: \"Bahkan aku minum madu yang diberikan Hafshah.\" Lalu aku katakan, \"Lebahnya telah makan Urfuth (sejenis tanaman yang baunya tidak enak)!\" Abu Daud berkata, \"Maghafir adalah muqlah yaitu shamghah (sejenis tanaman), jarasat adalah menjaga sedangkan 'urfuth adalah tanaman di antara tanaman-tanaman lebah. "},"3149":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا صَدَقَةُ بْنُ خَالِدٍ حَدَّثَنَا زَيْدُ بْنُ وَاقِدٍ عَنْ خَالِدِ بْنِ عَبْدِ اللَّهِ بْنِ حُسَيْنٍ عَنْ أَبِي هُرَيْرَةَ قَالَعَلِمْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَصُومُ فَتَحَيَّنْتُ فِطْرَهُ بِنَبِيذٍ صَنَعْتُهُ فِي دُبَّاءٍ ثُمَّ أَتَيْتُهُ بِهِ فَإِذَا هُوَ يَنِشُّ فَقَالَ اضْرِبْ بِهَذَا الْحَائِطِ فَإِنَّ هَذَا شَرَابُ مَنْ لَا يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Shadaqah bin Khalid] telah menceritakan kepada kami [Zaid bin Waqid] dari [Khalid bin Abdullah bin Husain] dari [Abu Hurairah] ia berkata, \"Aku mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam berpuasa, maka aku menunggu waktu berbukanya beliau dengan menyiapkan perasan nabidz yang aku buat dalam Ad dubba (bejana yang terbuat dari labu kering), ternyata minuman tersebut telah mendidih. Beliau pun bersabda: \"Buanglah ke belakang dinding ini. Sebab ini adalah minuman orang yang tidak beriman kepada Allah dan Hari Akhir.\""},"3150":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَشْرَبَ الرَّجُلُ قَائِمًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang seorang laki-laki minum dalam keadaan berdiri.\""},"3151":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ مِسْعَرِ بْنِ كِدَامٍ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ عَنْ النَّزَّالِ بْنِ سَبُرَةَأَنَّ عَلِيًّا دَعَا بِمَاءٍ فَشَرِبَهُ وَهُوَ قَائِمٌ ثُمَّ قَالَ إِنَّ رِجَالًا يَكْرَهُ أَحَدُهُمْ أَنْ يَفْعَلَ هَذَا وَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ مِثْلَ مَا رَأَيْتُمُونِي أَفْعَلُهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Mis'ar bin Kidam] dari [Abdul Malik bin Maisarah] dari [An Nazzal bin Saburah] bahwa [Ali] minta diambilkan air minum, lalu ia meminumnya sambil berdiri, kemudian ia berkata, \"Banyak orang membenci untuk membenci untuk melakukan seperti ini, padahal aku pernah melihat Rasulullah shallallahu 'alaihi wasallam melakukan apa yang kalian lihat aku melakukannya (minum sambil berdiri).\""},"3152":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا قَتَادَةُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشُّرْبِ مِنْ فِي السِّقَاءِ وَعَنْ رُكُوبِ الْجَلَّالَةِ وَالْمُجَثَّمَةِقَالَ أَبُو دَاوُد الْجَلَّالَةُ الَّتِي تَأْكُلُ الْعَذْرَةَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang minum langsung melalui mulut geriba (bejana), menaiki hewan jallalah dan mujatstsamah (hewan yang diikat kemudian dilempari hingga mati).\" Abu Daud berkata, \"Jallalah adalah hewan yang makan kotoran.\""},"3153":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ أَنَّهُ سَمِعَ عُبَيْدَ اللَّهِ ابْنَ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ اخْتِنَاثِ الْأَسْقِيَةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] bahwa ia mendengar ['Ubaidullah bin Abdullah] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam melarang minum dari mulut bejana minuman.\""},"3154":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ عِيسَى بْنِ عَبْدِ اللَّهِ رَجُلٌ مِنْ الْأَنْصَارِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَا بِإِدَاوَةٍ يَوْمَ أُحُدٍ فَقَالَ اخْنِثْ فَمَ الْإِدَاوَةِ ثُمَّ شَرِبَ مِنْ فِيهَا","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami ['Ubaidullah bin Umar] dari [Isa bin Abdullah] seorang laki-laki anshar, dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah meminta bejana kecil pada saat perang Uhud, kemudian beliau bersabda: \"Potonglah mulut bejana kecil tersebut!\" kemudian beliau minum melalui mulutnya. "},"3155":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي قُرَّةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشُّرْبِ مِنْ ثُلْمَةِ الْقَدَحِ وَأَنْ يُنْفَخَ فِي الشَّرَابِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Qurrah bin Abdurrahman] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abu Sa'id Al Khudri] bahwa ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang minum dari mulut bejana dan bernafas di dalamnya.\""},"3156":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى قَالَكَانَ حُذَيْفَةُ بِالْمَدَائِنِ فَاسْتَسْقَى فَأَتَاهُ دِهْقَانٌ بِإِنَاءٍ مِنْ فِضَّةٍ فَرَمَاهُ بِهِ وَقَالَ إِنِّي لَمْ أَرْمِهِ بِهِ إِلَّا أَنِّي قَدْ نَهَيْتُهُ فَلَمْ يَنْتَهِ وَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْحَرِيرِ وَالدِّيبَاجِ وَعَنْ الشُّرْبِ فِي آنِيَةِ الذَّهَبِ وَالْفِضَّةِ وَقَالَ هِيَ لَهُمْ فِي الدُّنْيَا وَلَكُمْ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibnu Abu Laila] ia berkata, \"Saat [Hudzaifah] berada di Madain, ia pernah minta untuk diambnilkan minum, kemudian seorang pemimpin kaum datang membawa sebuah bejana yang terbuat dari perak, maka Hudzaifah pun melemparnya dengan bejana tersebut. kemudian ia berkata, \"Aku tidak melempar dia dengan bejana tersebut melainkan karena aku telah melarangnya namun ia tidak berhenti, dan sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang dari menggunakan kain sutera, dibaj (pakaian yang bersulam sutera), dan minum dari bejana emas serta perak. Beliau bersabda: \"Bejana tersebut untuk mereka di dunia dan untuk kalian di akhirat.\""},"3157":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنِي فُلَيْحٌ عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجُلٌ مِنْ أَصْحَابِهِ عَلَى رَجُلٍ مِنْ الْأَنْصَارِ وَهُوَ يُحَوِّلُ الْمَاءَ فِي حَائِطِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ عِنْدَكَ مَاءٌ بَاتَ هَذِهِ اللَّيْلَةَ فِي شَنٍّ وَإِلَّا كَرَعْنَا قَالَ بَلْ عِنْدِي مَاءٌ بَاتَ فِي شَنٍّ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepadaku [Fulaih] dari [Sa'id bin Al Harits] dari [Jabir bin Abdullah] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersama seorang sahabat beliau menemui seorang laki-laki anshar, sementara laki-laki tersebut sedang memindahkan air di kebunnya, Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Jika engkau memiliki air yang telah bermalam di dalam syann (geriba yang basah) pada malam ini maka berilah kami minum, jika tidak maka kami akan meminum dengan mulut kami.\" Ia berkata, \"Saya memiliki air yang telah bermalam dalam syann (sebuah geriba basah).\""},"3158":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الْمُخْتَارِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَاقِي الْقَوْمِ آخِرُهُمْ شُرْبًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Abu Al Mukhtar] dari [Abdullah bin Abu Aufa] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Orang yang memberi minum kepada suatu kaum hendaklah yang paling akhir minumnya.\""},"3159":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلَبَنٍ قَدْ شِيبَ بِمَاءٍ وَعَنْ يَمِينِهِ أَعْرَابِيٌّ وَعَنْ يَسَارِهِ أَبُو بَكْرٍ فَشَرِبَ ثُمَّ أَعْطَى الْأَعْرَابِيَّ وَقَالَ الْأَيْمَنَ فَالْأَيْمَنَ","id":"Telah menceritakan kepada kami [Al Qa'nabi Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam pernah diberi susu yang telah dicampur dengan air, sementara di samping kanan beliau ada seorang badui, dan di samping kiri beliau ada Abu Bakr. Beliau kemudian minum dan memberikan kepada orang badui tersebut seraya berkata: \"Dahulukan yang di samping kanan, dahulukan yang di samping kanan!\""},"3160":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ أَبِي عِصَامٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا شَرِبَ تَنَفَّسَ ثَلَاثًا وَقَالَ هُوَ أَهْنَأُ وَأَمْرَأُ وَأَبْرَأُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Abu 'Isham] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam apabila minum beliau bernafas tiga kali, dan beliau berkata: \"Hal itu lebih nyaman dan enak serta lebih selamat.\""},"3161":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَبْدِ الْكَرِيمِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُتَنَفَّسَ فِي الْإِنَاءِ أَوْ يُنْفَخَ فِيهِ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Abdul Karim] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang bernafas dalam bejana dan meniup di dalamnya.\""},"3162":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ خُمَيرٍ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ مَنْ بَنِي سُلَيْمٍ قَالَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَبِي فَنَزَلَ عَلَيْهِ فَقَدَّمَ إِلَيْهِ طَعَامًا فَذَكَرَ حَيْسًا أَتَاهُ بِهِ ثُمَّ أَتَاهُ بِشَرَابٍ فَشَرِبَ فَنَاوَلَ مَنْ عَلَى يَمِينِهِ وَأَكَلَ تَمْرًا فَجَعَلَ يُلْقِي النَّوَى عَلَى ظَهْرِ أُصْبُعَيْهِ السَّبَّابَةُ وَالْوُسْطَى فَلَمَّا قَامَ قَامَ أَبِي فَأَخَذَ بِلِجَامِ دَابَّتِهِ فَقَالَ ادْعُ اللَّهَ لِي فَقَالَ اللَّهُمَّ بَارِكْ لَهُمْ فِيمَا رَزَقْتَهُمْ وَاغْفِرْ لَهُمْ وَارْحَمْهُمْ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Khumair] dari [Abdullah bin Busr] dari Bani Sulaim, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah datang dan singgah di rumah ayahku, lalu ayahku menyuguhkan makanan kepada beliau. Lalu ia menyebutkan Hais (makanan yang terbuat dari campuran kurma, keju dan mentega) yang ia bawa kepada beliau, kemudian datang lagi dengan membawa minuman. Lalu beliau minum dan memberikannya kepada orang yang di samping kanannya, beliau makan kurma lalu membuang bijinya menggunakan punggung kedua jarinya, yaitu jari telunjuk dan jari tengah. Ketika beliau berdiri maka ayahku pun berdiri dan memegang tali kekang unta beliau seraya berkata, \"Berdoalah kepada Allah untukku.\" Kemudian beliau berdoa: \"Ya Allah, berkahilah apa yang Engkau berikan kepada mereka, ampuni dan rahmatilah mereka.\""},"3163":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ ح و حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ عُمَرَ بْنِ حَرْمَلَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكُنْتُ فِي بَيْتِ مَيْمُونَةَ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ خَالِدُ بْنُ الْوَلِيدِ فَجَاءُوا بِضَبَّيْنِ مَشْوِيَّيْنِ عَلَى ثُمَامَتَيْنِ فَتَبَزَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ خَالِدٌ إِخَالُكَ تَقْذُرُهُ يَا رَسُولَ اللَّهِ قَالَ أَجَلْ ثُمَّ أُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَبَنٍ فَشَرِبَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَكَلَ أَحَدُكُمْ طَعَامًا فَلْيَقُلْ اللَّهُمَّ بَارِكْ لَنَا فِيهِ وَأَطْعِمْنَا خَيْرًا مِنْهُ وَإِذَا سُقِيَ لَبَنًا فَلْيَقُلْ اللَّهُمَّ بَارِكْ لَنَا فِيهِ وَزِدْنَا مِنْهُ فَإِنَّهُ لَيْسَ شَيْءٌ يُجْزِئُ مِنْ الطَّعَامِ وَالشَّرَابِ إِلَّا اللَّبَنُقَالَ أَبُو دَاوُد هَذَا لَفْظُ مُسَدَّدٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] -yaitu Ibnu Salamah- dari [Ali bin Zaid] dari [Umar bin Harmalah] dari [Ibnu Abbas] ia berkata, \"Aku pernah berada di rumah Maimunah, kemudian Rasulullah shallallahu 'alaihi wasallam bersama Khalid bin Al Walid masuk. Para sahabat kemudian datang membawa dua ekor biawak bakar di atas dua dahan, Rasulullah shallallahu 'alaihi wasallam kemudian meludah (karena jijik). Khalid berkata, \"Wahai Rasulullah, apakah engkau jijik kepadanya?\" Beliau bersabda: \"Benar.\" Kemudian Rasulullah shallallahu 'alaihi wasallam diberi susu, lalu beliau meminumnya. Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian makan suatu makanan, maka hendaknya ia mengucapkan: 'ALLAAHUMMA BAARIK LANAA FIIHI WA ATH'IMNAA KHAIRAN MINHU (Ya Allah, berkahilah kami padanya dan berilah kami makan yang lebih baik darinya!) ', dan apabila ia diberi minum susu maka hendaknya ia mengucapkan: 'ALLAAHUMMA BAARIK LANAA FIIHI WA ZIDNAA MINHU (Ya Allah, berkahilah kami padanya dan tambahkanlah kami darinya!) '. Sesungguhnya tidak ada sesuatu yang mencukupkan dari makan dan minum kecuali susu.\" Abu Daud berkata, \"Ini adalah lafazh Musaddad.\""},"3164":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَغْلِقْ بَابَكَ وَاذْكُرْ اسْمَ اللَّهِ فَإِنَّ الشَّيْطَانَ لَا يَفْتَحُ بَابًا مُغْلَقًا وَأَطْفِ مِصْبَاحَكَ وَاذْكُرْ اسْمَ اللَّهِ وَخَمِّرْ إِنَاءَكَ وَلَوْ بِعُودٍ تَعْرِضُهُ عَلَيْهِ وَاذْكُرْ اسْمَ اللَّهِ وَأَوْكِ سِقَاءَكَ وَاذْكُرْ اسْمَ اللَّهِحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْخَبَرِ وَلَيْسَ بِتَمَامِهِ قَالَ فَإِنَّ الشَّيْطَانَ لَا يَفْتَحُ بَابًا غَلَقًا وَلَا يَحُلُّ وِكَاءً وَلَا يَكْشِفُ إِنَاءً وَإِنَّ الْفُوَيْسِقَةَ تُضْرِمُ عَلَى النَّاسِ بَيْتَهُمْ أَوْ بُيُوتَهُمْ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] telah mengabarkan kepadaku ['Atha] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tutuplah pintumu dan sebutlah nama Allah, sesungguhnya setan tidak akan membuka pintu yang tertutup. Matikan lampu kalian dan sebutlah nama Allah! Tutuplah bejanamu walaupun hanya dengan sebatang ranting yang merintang di atasnya, dan sebutlah nama Allah! Ikatlah tempat minum kalian, dan sebutlah nama Allah!\" Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] dari [Malik] dari [Abu Az Zubair] dari [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini dan tidak secara lengkap. Beliau bersabda: \"Sesungguhnya setan tidak membuka pintu yang tertutup, tidak akan melepas ikatan, serta tidak membuka bejana. Sesungguhnya tikus-tikus dapat membakar rumah manusia.\""},"3165":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَفُضَيْلُ بْنُ عَبْدُ الْوَهَّابِ السُّكَّرِيُّ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ كَثِيرِ بْنِ شِنْظِيرٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِرَفَعَهُ قَالَ وَاكْفِتُوا صِبْيَانَكُمْ عِنْدَ الْعِشَاءِ وَقَالَ مُسَدَّدٌ عِنْدَ الْمَسَاءِ فَإِنَّ لِلْجِنِّ انْتِشَارًا وَخَطْفَةً","id":"Telah menceritakan kepada kami [Musaddad] dan [Fudlail bin Abdul Wahhab As Sukkari] mereka berkata; telah menceritakan kepada kami [Hammad] dari [Katsir bin Syinzhir] dari ['Atha] dari [Jabir bin Abdullah] dan ia memarfu'kan hadits tersebut, ia berkata, \"Laranglah anak-anak kalian berkeliaran ketika waktu isya'.\" Musaddad menyebutkan, \"Ketika sore hari, karena setan berkeliaran dan merampas dengan cepat.\""},"3166":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ جَابِرٍ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَسْقَى فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَلَا نَسْقِيكَ نَبِيذًا قَالَ بَلَى قَالَ فَخَرَجَ الرَّجُلُ يَشْتَدُّ فَجَاءَ بِقَدَحٍ فِيهِ نَبِيذٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا خَمَّرْتَهُ وَلَوْ أَنْ تَعْرِضَ عَلَيْهِ عُودًاقَالَ أَبُو دَاوُد قَالَ الْأَصْمَعِيُّ تَعْرِضُهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Jabir] ia berkata, \"Saat kami bersama Nabi shallallahu 'alaihi wasallam, beliau minta diambilkan air minum. Lalu seorang laki-laki bertanya, \"Maukah jika tuan kami beri perasan nabidz (minuman hasil peraman)? Beliau menjawab: \"Ya.\" Jabir berkata, \"Kemudian orang tersebut keluar dengan cepat dan datang kembali membawa bejana berisi minuman hasil peraman. Nabi shallallahu 'alaihi wasallam lalu bertanya: \"Tidakkah engkau menutupnya walaupun hanya dengan merintangkan sebatang ranting di atasnya?\" Abu Daud berkata, \"Al Ashma'i menyebutkan, \"Merintangkan di atasnya.\""},"3167":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَعَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالُوا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسْتَعْذَبُ لَهُ الْمَاءُ مِنْ بُيُوتِ السُّقْيَاقَالَ قُتَيْبَةُ هِيَ عَيْنٌ بَيْنَهَا وَبَيْنَ الْمَدِينَةِ يَوْمَانِ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] dan [Abdullah bin Muhammad An Nufaili] dan [Qutaibah bin Sa'id] mereka berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Hisyam] dari [Ayahnya] dari [Aisyah] radliallahu 'anhuma, bahwa Nabi shallallahu 'alaihi wasallam diberi air tawar dari mata air Suqya.\" Qutaibah berkata, \"Yaitu mata air yang berjarak dua hari dari Madinah.\""},"3168":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دُعِيَ أَحَدُكُمْ إِلَى الْوَلِيمَةِ فَلْيَأْتِهَاحَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ زَادَ فَإِنْ كَانَ مُفْطِرًا فَلْيَطْعَمْ وَإِنْ كَانَ صَائِمًا فَلْيَدْعُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian diundang untuk menghadiri sebuah pesta, maka hendaknya ia mendatanginya!\" Telah menceritakan kepada kami [Makhlad bin Khalid] telah menceritakan kepada kami [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda dengan makna yang sama, ia menambahkan, \"Jika tidak berpuasa hendaklah ia makan, jika sedang berpuasa hendaklah ia (memberikan) doa.\""},"3169":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَعَا أَحَدُكُمْ أَخَاهُ فَلْيُجِبْ عُرْسًا كَانَ أَوْ نَحْوَهُحَدَّثَنَا ابْنُ الْمُصَفَّى حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا الزُّبَيْدِيُّ عَنْ نَافِعٍ بِإِسْنَادِ أَيُّوبَ وَمَعْنَاهُ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian mengundang saudaranya, hendaknya ia memenuhi undangannya baik berupa pesta atau yang semisalnya!\" Telah menceritakan kepada kami [Ibnu Al Mushaffa] telah menceritakan kepada kami [Baqiyyah] telah menceritakan kepada kami [Az Zubaidi] dari [Nafi'] dengan sanad dan makna hadits Ayyub.\""},"3170":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دُعِيَ فَلْيُجِبْ فَإِنْ شَاءَ طَعِمَ وَإِنْ شَاءَ تَرَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diundang hendaknya ia memenuhi undangan tersebut, jika mau ia boleh makan, dan jika mau ia boleh untuk tidak makan.\""},"3171":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا دُرُسْتُ بْنُ زِيَادٍ عَنْ أَبَانَ بْنِ طَارِقٍ عَنْ نَافِعٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ عُمَرَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ دُعِيَ فَلَمْ يُجِبْ فَقَدْ عَصَى اللَّهَ وَرَسُولَهُ وَمَنْ دَخَلَ عَلَى غَيْرِ دَعْوَةٍ دَخَلَ سَارِقًا وَخَرَجَ مُغِيرًاقَالَ أَبُو دَاوُد أَبَانُ بْنُ طَارِقٍ مَجْهُولٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Durst bin Ziyad] dari [Aban bin Thariq] dari [Nafi'] ia berkata, [Abdullah bin Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diundang dan ia tidak mendatangi undangan tersebut maka sungguh ia telah durhaka kepada Allah dan rasul-Nya. Barangsiapa yang masuk tanpa undangan maka ia masuk sebagai pencuri, dan keluar sebagai orang yang menyerang.\" Abu Daud berkata, \"Aban bin Thariq adalah orang yang tidak dikenal.\""},"3172":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ كَانَ يَقُولُشَرُّ الطَّعَامِ طَعَامُ الْوَلِيمَةِ يُدْعَى لَهَا الْأَغْنِيَاءُ وَيُتْرَكُ الْمَسَاكِينُ وَمَنْ لَمْ يَأْتِ الدَّعْوَةَ فَقَدْ عَصَى اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Al A'raj] dari [Abu Hurairah] bahwa ia pernah berkata, \"Seburuk-buruk makanan adalah makanan pesta, orang-orang kaya diundang untuk menghadirinya sementara orang-orang miskin ditinggalkan. Barangsiapa tidak mendatangi undangan maka ia telah durhaka kepada Allah dan Rasul-Nya.\""},"3173":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ قَالَذُكِرَ تَزْوِيجُ زَيْنَبَ بِنْتِ جَحْشٍ عِنْدَ أَنَسِ بْنِ مَالِكٍ فَقَالَ مَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلَمَ عَلَى أَحَدٍ مِنْ نِسَائِهِ مَا أَوْلَمَ عَلَيْهَا أَوْلَمَ بِشَاةٍ","id":"Telah menceritakan kepada kami [Musaddad] dan [Qutaibah bin Sa'id] mereka berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] ia berkata, \"Telah disebutkan pernikahan Zainab binti Jahsy di sisi [Anas bin Malik] maka Anas pun berkata, \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam merayakan pesta pernikahan dengan para isterinya, sebagaimana pesta pernikahan yang beliau rayakan bersama Zainab. Beliau merayakan hanya dengan satu kambing.\""},"3174":{"ar":"حَدَّثَنَا حَامِدُ بْنُ يَحْيَى حَدَّثَنَا سُفْيَانُ حَدَّثَنَا وَائِلُ بْنُ دَاوُدَ عَنْ ابْنِهِ بَكْرِ بْنِ وَائِلٍ عَنْ الزَّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلَمَ عَلَى صَفِيَّةَ بِسَوِيقٍ وَتَمْرٍ","id":"Telah menceritakan kepada kami [Hamid bin Yahya] dari [Sufyan] telah menceritakan kepada kami [Wail bin Daud] dari anaknya [Bakr bin Wail] dari [Az Zuhri] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam merayakan pernikahan Shafiyyah dengan memasak gandum dan kurma.\""},"3175":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ الثَّقَفِيِّ عَنْ رَجُلٍ أَعْوَرَ مِنْ ثَقِيفٍ كَانَ يُقَالُ لَهُ مَعْرُوفًا أَيْ يُثْنَى عَلَيْهِ خَيْرًا إِنْ لَمْ يَكُنْ اسْمُهُ زُهَيْرُ بْنُ عُثْمَانَ فَلَا أَدْرِي مَا اسْمُهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلِيمَةُ أَوَّلَ يَوْمٍ حَقٌّ وَالثَّانِيَ مَعْرُوفٌ وَالْيَوْمَ الثَّالِثَ سُمْعَةٌ وَرِيَاءٌقَالَ قَتَادَةُ وَحَدَّثَنِي رَجُلٌ أَنَّ سَعِيدَ بْنَ الْمُسَيِّبِ دُعِيَ أَوَّلَ يَوْمٍ فَأَجَابَ وَدُعِيَ الْيَوْمَ الثَّانِيَ فَأَجَابَ وَدُعِيَ الْيَوْمَ الثَّالِثَ فَلَمْ يُجِبْ وَقَالَ أَهْلُ سُمْعَةٍ وَرِيَاءٍ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ بِهَذِهِ الْقِصَّةِ قَالَ فَدُعِيَ الْيَوْمَ الثَّالِثَ فَلَمْ يُجِبْ وَحَصَبَ الرَّسُولَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Abdullah bin Utsman Ats Tsaqafi] dari -seorang laki-laki juling yang berasal dari Tsaqif yang dipanggil Ma'ruf, yaitu sebagai pujian yang baik kepadanya. Apabila namanya bukan- [Zuhair bin Utsman] maka aku tidak mengetahui siapa namanya. Nabi shallallahu 'alaihi wasallam bersabda: \"Pesta pada hari pertama adalah sesuatu yang hak, pada hari kedua adalah sesuatu yang baik, dan pada hari yang ketiga adalah suatu perbuatan sum'ah (ingin di dengar) dan riya` (ingin dilihat).\" [Qatadah] berkata, \"Telah menceritakan kepada kami seorang laki-laki bahwa [Sa'id bin Al Musayyab] pernah diundang pada hari pertama, kemudian ia memenuhi undangan tersebut, dan ia diundang pada hari kedua, kemudian ia memenuhi undangan tersebut, dan diundang pada hari ketiga, kemudian ia tidak memenuhi undangan tersebut seraya berkata, \"Ia adalah orang yang sum'ah dan riya`.\" Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Sa'id bin Al Musayyab] dengan hadits ini. Ia berkata, \"Ketika diundang pada hari ketiga ia tidak memenuhi undangan tersebut dan justru melempar sang utusan.\""},"3176":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرٍ قَالَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ نَحَرَ جَزُورًا أَوْ بَقَرَةً","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Muharib bin Ditsar] dari [Jabir] ia berkata, \"Tatkala Nabi shallallahu 'alaihi wasallam datang ke Madinah, beliau menyembelih unta dan sapi.\""},"3177":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْكَعْبِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ جَائِزَتُهُ يَوْمُهُ وَلَيْلَتُهُ الضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ وَمَا بَعْدَ ذَلِكَ فَهُوَ صَدَقَةٌ وَلَا يَحِلُّ لَهُ أَنْ يَثْوِيَ عِنْدَهُ حَتَّى يُحْرِجَهُقَالَ أَبُو دَاوُد قُرِئَ عَلَى الْحَارِثِ بْنِ مِسْكِينٍ وَأَنَا شَاهِدٌ أَخْبَرَكُمْ أَشْهَبُ قَالَ وَسُئِلَ مَالِكٌ عَنْ قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَائِزَتُهُ يَوْمٌ وَلَيْلَةٌ قَالَ يُكْرِمُهُ وَيُتْحِفُهُ وَيَحْفَظُهُ يَوْمًا وَلَيْلَةً وَثَلَاثَةَ أَيَّامٍ ضِيَافَةً","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Sa'id Al Maqburi] dari [Abu Syuraih Al Ka'bi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman kepada Allah dan Hari Akhir, hendaknya ia muliakan tamunya, wajibnya (memberi jamuan) adalah satu hari satu malam, dan penjamuan tamu adalah tiga hari, setelah itu adalah sedekah. Dan seorang tamu tidak boleh bermalam, sehingga ia diusir.\" Abu Daud berkata; telah dibacakan riwayat di hadapan Al Harits bin Miskin dan aku menyaksikannya. Telah mengabarkan kepada kalian Asyhab Ia berkata, \"Malik ditanya tentang sabda Nabi shallallahu 'alaihi wasallam 'wajibnya (memberi jamuan) adalah satu hari satu malam', Anas menjawab, \"Memuliakan, berbuat baik dan menjaganya selama satu hari satu malam. Dan bertamu itu selama tiga hari.\""},"3178":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ وَمُحَمَّدُ بْنُ مَحْبُوبٍ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ عَاصِمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ فَمَا سِوَى ذَلِكَ فَهُوَ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] dan [Muhammad bin Mahbub] mereka berkata; telah menceritakan kepada kami [Hammad] dari ['Ashim] dari [Abu Shalih] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Penjamuan tamu adalah tiga hari, dan selain itu adalah sebuah sedekah.\""},"3179":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَخَلَفُ بْنُ هِشَامٍ قَالَا حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ عَامِرٍ عَنْ أَبِي كَرِيمَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةُ الضَّيْفِ حَقٌّ عَلَى كُلِّ مُسْلِمٍ فَمَنْ أَصْبَحَ بِفِنَائِهِ فَهُوَ عَلَيْهِ دَيْنٌ إِنْ شَاءَ اقْتَضَى وَإِنْ شَاءَ تَرَكَ","id":"Telah menceritakan kepada kami [Musaddad] dan [Khalaf bin Hisyam] mereka berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari ['Amir] dari [Abu Karimah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Malam bertamu adalah kewajiban atas setiap Muslim 9untuk memuliakannya), maka barangsiapa diwaktu pagi ia (tamu) berada di halaman rumahnya, maka itu adalah hutang; jika mau ia boleh menjamu dan jika tidak maka ia boleh membiarkannya.\""},"3180":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنِي أَبُو الْجُودِيِّ عَنْ سَعِيدِ بْنِ أَبِي الْمُهَاجِرِ عَنْ الْمِقْدَامِ أَبِي كَرِيمَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ أَضَافَ قَوْمًا فَأَصْبَحَ الضَّيْفُ مَحْرُومًا فَإِنَّ نَصْرَهُ حَقٌّ عَلَى كُلِّ مُسْلِمٍ حَتَّى يَأْخُذَ بِقِرَى لَيْلَةٍ مِنْ زَرْعِهِ وَمَالِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah] telah menceritakan kepadaku [Abu Al Judi] dari [Sa'id bin Al Muhajir] dari [Al Miqdam Abu Karimah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Laki-laki manapun yang datang kepada suatu kaum sebagai tamu, kemudian tamu tersebut terhalang mendapatkan jamuan, maka atas setiap Muslim wajib menolongnya hingga ia mendapatkan jamuan pada malam hari dari tanaman serta harta orang yang kedatangan tamu.\""},"3181":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَنَّهُ قَالَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّكَ تَبْعَثُنَا فَنَنْزِلُ بِقَوْمٍ فَمَا يَقْرُونَنَا فَمَا تَرَى فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ نَزَلْتُمْ بِقَوْمٍ فَأَمَرُوا لَكُمْ بِمَا يَنْبَغِي لِلضَّيْفِ فَاقْبَلُوا فَإِنْ لَمْ يَفْعَلُوا فَخُذُوا مِنْهُمْ حَقَّ الضَّيْفِ الَّذِي يَنْبَغِي لَهُمْقَالَ أَبُو دَاوُد وَهَذِهِ حُجَّةٌ لِلرَّجُلِ يَأْخُذُ الشَّيْءَ إِذَا كَانَ لَهُ حَقًّا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] bahwa ia berkata, \"Kami bertanya, \"Wahai Rasulullah, ketika tuan mengirim kami, maka kami singgah di suatu kaum, namun mereka tidak mau menjamu kami, bagaimana pendapat anda?\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepada kami: \"Apabila kalian singgah di suatu kaum, lalu mereka memberikan apa yang layak bagi tamu maka terimalah, namun jika mereka tidak melakukannya maka ambillah apa yang berhak bagi seorang tamu dari mereka.\" Abu Daud berkata, \"Ini adalah dalil bagi seorang laki-laki untuk mengambil jika sesuatu itu adalah haknya.\""},"3182":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنِي عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ{ لَا تَأْكُلُوا أَمْوَالَكُمْ بَيْنَكُمْ بِالْبَاطِلِ إِلَّا أَنْ تَكُونَ تِجَارَةً عَنْ تَرَاضٍ مِنْكُمْ }فَكَانَ الرَّجُلُ يَحْرَجُ أَنْ يَأْكُلَ عِنْدَ أَحَدٍ مِنْ النَّاسِ بَعْدَ مَا نَزَلَتْ هَذِهِ الْآيَةُ فَنَسَخَ ذَلِكَ الْآيَةُ الَّتِي فِي النُّورِ قَالَ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَأْكُلُوا مِنْ بُيُوتِكُمْ إِلَى قَوْلِهِ أَشْتَاتًا كَانَ الرَّجُلُ الْغَنِيُّ يَدْعُو الرَّجُلَ مِنْ أَهْلِهِ إِلَى الطَّعَامِ قَالَ إِنِّي لَأَجَّنَّحُ أَنْ آكُلَ مِنْهُ وَالتَّجَنُّحُ الْحَرَجُ وَيَقُولُ الْمِسْكِينُ أَحَقُّ بِهِ مِنِّي فَأُحِلَّ فِي ذَلِكَ أَنْ يَأْكُلُوا مِمَّا ذُكِرَ اسْمُ اللَّهِ عَلَيْهِ وَأُحِلَّ طَعَامُ أَهْلِ الْكِتَابِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] telah menceritakan kepadaku [Ali bin Al Husain bin Waqid] dari [Ayahnya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Firman Allah: '(Janganlah kamu saling memakan harta sesamamu dengan jalan yang batil, kecuali dengan jalan perniagaan yang berlaku dengan suka sama-suka di antara kamu) ' (Qs. An Nisaa: 29), maka setelah ayat tersebut turun, seseorang merasa tidak enak untuk makan di rumah orang lain, kemudian hal tersebut dihapuskan oleh ayat yang ada dalam Surat An Nuur: '(dan tidak (pula) ada halangan bagi dirimu sendiri untuk makan (bersama-sama mereka) di rumah kamu sendiri atau di rumah bapak-bapakmu, di rumah ibu-ibumu, di rumah saudara- saudaramu yang laki-laki, di rumah saudaramu yang perempuan, di rumah saudara bapakmu yang laki-laki, di rumah saudara bapakmu yang perempuan, di rumah saudara ibumu yang laki-laki, di rumah saudara ibumu yang perempuan, di rumah yang kamu miliki kuncinya atau di rumah kawan-kawanmu. Tidak ada halangan bagi kamu makan bersama-sama mereka atau sendirian) '. Maka orang yang kaya mengundang seseorang dari keluarganya untuk makan. Ia berkata, \"Sungguh aku merasa ada ganjalan untuk makan darinya.\" Tajannuh adalah perasaan mengganjal dalam hati. Ia berkata; orang miskin lebih berhak daripada diriku. Kemudian dihalalkan dalam hal tersebut untuk maka apa yang disebutkan padanya nama Allah, dan telah dihalalkan makanan ahli kitab.\""},"3183":{"ar":"حَدَّثَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ حَدَّثَنَا أَبِي حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ الزُّبَيْرِ بْنِ الْخِرِّيتِ قَالَ سَمِعْتُ عِكْرِمَةَ يَقُولُ كَانَ ابْنُ عَبَّاسٍ يَقُولُإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ طَعَامِ الْمُتَبَارِيَيْنِ أَنْ يُؤْكَلَقَالَ أَبُو دَاوُد أَكْثَرُ مَنْ رَوَاهُ عَنْ جَرِيرٍ لَا يَذْكُرُ فِيهِ ابْنَ عَبَّاسٍ وَهَارُونُ النَّحْوِيُّ ذَكَرَ فِيهِ ابْنَ عَبَّاسٍ أَيْضًا وَحَمَّادُ بْنُ زَيْدٍ لَمْ يَذْكُرْ ابْنَ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Harun bin Zaid bin Abu Az Zarqa`] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Jarir bin Hazim] dari [Az Zubair bin Al Khirrit] ia berkata; aku mendengar [Ikrimah] berkata, \" [Ibnu Abbas] berkata, \"Sesungguhnya Nabi shallallahu 'alaihi wasallam melarang makan makanan dua orang yang saling membanggakan diri.\" Abu Daud berkata, \"Kebanyakkan orang yang meriwayatkan hadits tersebut dari Jarir tidak menyebutkan nama Ibnu Abbas, sementara [Harun An Nahwi] menyebutkan nama Ibnu Abbas juga. Demikian juga dengan [Hammad bin Zaid], ia tidak menyebutkan nama Ibnu Abbas.\""},"3184":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ أَخْبَرَنَا حَمَّادٌ عَنْ سَعِيدِ بْنِ جُمْهَانَ عَنْ سَفِينَةَ أَبِي عَبْدِ الرَّحْمَنِأَنَّ رَجُلًا أَضَافَ عَلِيَّ بْنَ أَبِي طَالِبٍ فَصَنَعَ لَهُ طَعَامًا فَقَالَتْ فَاطِمَةُ لَوْ دَعَوْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَ مَعَنَا فَدَعُوهُ فَجَاءَ فَوَضَعَ يَدَهُ عَلَى عِضَادَتَيْ الْبَابِ فَرَأَى الْقِرَامَ قَدْ ضُرِبَ بِهِ فِي نَاحِيَةِ الْبَيْتِ فَرَجَعَ فَقَالَتْ فَاطِمَةُ لِعَلِيٍّ الْحَقْهُ فَانْظُرْ مَا رَجَعَهُ فَتَبِعْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا رَدَّكَ فَقَالَ إِنَّهُ لَيْسَ لِي أَوْ لِنَبِيٍّ أَنْ يَدْخُلَ بَيْتًا مُزَوَّقًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah mengabarkan kepada kami [Hammad] dari [Sa'id bin Jumhan] dari [Safinah Abu Abdurrahman] bahwa seorang laki-laki datang kepada Ali bin Abu Thalib sebagai seorang tamu, kemudian Ali membuatkan makanan untuknya. Fatimah kemudian berkata, \"Seandainya kita mengundang Rasulullah shallallahu 'alaihi wasallam dan makan bersama kita, maka akan lebih baik.\" Kemudian mereka mengundang beliau, setelah itu beliau datang dan meletakkan tangannya di atas kedua sisi pintu. Ketika melihat tabir dari katun yang terpasang di salah satu sisi pintu, beliau pun kembali pulang. Fatimah lalu berkata kepada Ali, \"Kejarlah beliau dan lihat apa yang membuat beliau kembali pulang.\" Lalu aku mengikuti beliau dan aku katakan, \"Wahai Rasulullah, apakah yang membuat anda kembali pulang?\" Kemudian beliau menjawab: \"Sesungguhnya tidak boleh bagiku dan bagi seorang nabi untuk memasuki sebuah rumah yang diperhias.\""},"3185":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ عَبْدِ السَّلَامِ بْنِ حَرْبٍ عَنْ أَبِي خَالِدٍ الدَّالَانِيِّ عَنْ أَبِي الْعَلَاءِ الْأَوْدِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ الْحِمْيَرِيِّ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا اجْتَمَعَ الدَّاعِيَانِ فَأَجِبْ أَقْرَبَهُمَا بَابًا فَإِنَّ أَقْرَبَهُمَا بَابًا أَقْرَبَهُمَا جِوَارًا وَإِنْ سَبَقَ أَحَدُهُمَا فَأَجِبْ الَّذِي سَبَقَ","id":"Telah menceritakan kepada kami [Hannad bin As Sarri] dari [Abdussalam bin Harb] dari [Abu Khalid Ad Dalani] dari [Abu Al 'Ala Al Audi] dari [Humaid bin Abdurrahman Al Himyari] dari [seorang] sahabat Nabi shallallahu 'alaihi wasallam, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila terdapat dua orang yang mengundang dengan bersama-sama maka penuhilah undangan orang yang paling dekat pintunya, karena sesungguhnya orang yang paling dekat pintunya adalah orang yang paling dekat pertolongannya. Dan apabila ada yang lebih dahulu di antara keduanya, maka penuhilah undangan orang yang terlebih dahulu!\""},"3186":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُسَدَّدٌ الْمَعْنَى قَالَ أَحْمَدُ حَدَّثَنِي يَحْيَى الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وُضِعَ عَشَاءُ أَحَدِكُمْ وَأُقِيمَتْ الصَّلَاةُ فَلَا يَقُومُ حَتَّى يَفْرُغَزَادَ مُسَدَّدٌ وَكَانَ عَبْدُ اللَّهِ إِذَا وُضِعَ عَشَاؤُهُ أَوْ حَضَرَ عَشَاؤُهُ لَمْ يَقُمْ حَتَّى يَفْرُغَ وَإِنْ سَمِعَ الْإِقَامَةَ وَإِنْ سَمِعَ قِرَاءَةَ الْإِمَامِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Musaddad] secara makna, Ahmad berkata; telah menceritakan kepadaku [Yahya Al Qaththan] dari ['Ubaidullah] ia berkata; telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila makan malam salah seorang di antara kalian telah dihidangkan, atau telah siap makan malamnya, maka janganlah ia berdiri hingga selesai, walaupun ia mendengar iqamah dan mendengar bacaan imam.\""},"3187":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ بَزِيعٍ حَدَّثَنَا مُعَلَّى يَعْنِي ابْنَ مَنْصُورٍ عَنْ مُحَمَّدِ بْنِ مَيْمُونٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُؤَخَّرُ الصَّلَاةُ لِطَعَامٍ وَلَا لِغَيْرِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Bazi'] telah menceritakan kepada kami [Mua'lla bin Manshur] dari [Muhammad bin Maimun] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat tidak boleh ditunda karena makanan dan karena yang lainnya.\""},"3188":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ مُسْلِمٍ الطُّوسِيُّ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ حَدَّثَنَا الضَّحَّاكُ بْنُ عُثْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ قَالَكُنْتُ مَعَ أَبِي فِي زَمَانِ ابْنِ الزُّبَيْرِ إِلَى جَنْبِ عَبْدِ اللَّهِ بْنِ عُمَرَ فَقَالَ عَبَّادُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ إِنَّا سَمِعْنَا أَنَّهُ يُبْدَأُ بِالْعَشَاءِ قَبْلَ الصَّلَاةِ فَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ وَيْحَكَ مَا كَانَ عَشَاؤُهُمْ أَتُرَاهُ كَانَ مِثْلَ عَشَاءِ أَبِيكَ","id":"Telah menceritakan kepada kami [Ali bin Muslim Ath Thusi] telah menceritakan kepada kami [Abu Bakr Al Hanafi] telah menceritakan kepada kami [Adl Dlahhak bin Utsman] dari [Abdullah bin 'Ubaid bin 'Umair] ia berkata, \"Aku pernah bersama ayahku pada zaman kekhilafahan Ibnu Az Zubair menuju kepada [Abdullah bin Umar], kemudian 'Abbad bin Abdullah bin Az Zubair berkata, \"Sesungguhnya kami mendengar bahwa makan lebih didahulukan daripada shalat?\" Abdullah bin Umar menjawab, \"Celaka kami! Apa kamu kira makan malam mereka seperti makan malam ayah kamu? "},"3189":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَعِيلُ حَدَّثَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ الْخَلَاءِ فَقُدِّمَ إِلَيْهِ طَعَامٌ فَقَالُوا أَلَا نَأْتِيكَ بِوَضُوءٍ فَقَالَ إِنَّمَا أُمِرْتُ بِالْوُضُوءِ إِذَا قُمْتُ إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Ayyub] dari [Abdullah bin Abu Mulaikah] dari [Abdullah bin Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah keluar dari toilet, kemudian disuguhkan makanan kepada beliau. Para sahabat pun bertanya, \"Tidakkah kami bawakan kepada anda air wudlu?\" Beliau menjawab: \"Hanyasanya aku diperintah untuk berwudlu apabila hendak melakukan shalat.\""},"3190":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا قَيْسٌ عَنْ أَبِي هَاشِمٍ عَنْ زَاذَانَ عَنْ سَلْمَانَ قَالَقَرَأْتُ فِي التَّوْرَاةِ أَنَّ بَرَكَةَ الطَّعَامِ الْوُضُوءُ قَبْلَهُ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَرَكَةُ الطَّعَامِ الْوُضُوءُ قَبْلَهُ وَالْوُضُوءُ بَعْدَهُوَكَانَ سُفْيَانُ يَكْرَهُ الْوُضُوءَ قَبْلَ الطَّعَامِ قَالَ أَبُو دَاوُد وَهُوَ ضَعِيفٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Qais] dari [Abu Hasyim] dari [Zadzan] dari [Salman] ia berkata, \"Aku membaca dalam Taurat bahwa berkah makanan adalah dengan berwudlu sebelum makan. Lalu aku ceritakan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Berkah makanan adalah dengan berwudlu sebelum makan dan setelah makan.\" Sedangkan Sufyan tidak menyukai wudlu sebelum makan.\" Abu Daud berkata, \"Hadits tersebut adalah dla'if.\""},"3191":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا عَمِّي يَعْنِي سَعَيدَ بْنَ الْحَكَمِ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ أَخْبَرَنِي خَالِدُ بْنُ يَزِيدَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ قَالَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ شِعْبٍ مِنْ الْجَبَلِ وَقَدْ قَضَى حَاجَتَهُ وَبَيْنَ أَيْدِينَا تَمْرٌ عَلَى تُرْسٍ أَوْ حَجَفَةٍ فَدَعَوْنَاهُ فَأَكَلَ مَعَنَا وَمَا مَسَّ مَاءً","id":"Telah menceritakan kepada kami [Ahmad bin Abu Maryam] telah menceritakan kepada kami pamanku [Sa'id bin Al Hakam] telah menceritakan kepada kami [Al Laits bin Sa'd] telah mengabarkan kepadaku [Khalid bin Yazid] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah datang dari jalan sebuah gunung dalam keadaan telah menyelesaikan hajatnya, sementara di hadapan kami terdapat kurma di atas tameng, kemudian kami mengundang beliau, lalu beliau makan bersama kami dan tidak menyentuh air.\""},"3192":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ أبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَمَا عَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا قَطُّ إِنْ اشْتَهَاهُ أَكَلَهُ وَإِنْ كَرِهَهُ تَرَكَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Abu Hazim] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah mencela makanan sama sekali, apabila senang maka beliau memakannya dan apabila tidak menyukai maka beliau meninggalkannya.\""},"3193":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنِي وَحْشِيُّ بْنُ حَرْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ أَصْحَابَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا يَا رَسُولَ اللَّهِ إِنَّا نَأْكُلُ وَلَا نَشْبَعُ قَالَ فَلَعَلَّكُمْ تَفْتَرِقُونَ قَالُوا نَعَمْ قَالَ فَاجْتَمِعُوا عَلَى طَعَامِكُمْ وَاذْكُرُوا اسْمَ اللَّهِ عَلَيْهِ يُبَارَكْ لَكُمْ فِيهِقَالَ أَبُو دَاوُد إِذَا كُنْتَ فِي وَلِيمَةٍ فَوُضِعَ الْعَشَاءُ فَلَا تَأْكُلْ حَتَّى يَأْذَنَ لَكَ صَاحِبُ الدَّارِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] telah menceritakan kepada kami [Al Walid bin Muslim] ia berkata; telah menceritakan kepadaku [Wahsyi bin Harb] dari [Ayahnya] dari [Kakeknya] bahwa para sahabat Nabi shallallahu 'alaihi wasallam berkata, \"Wahai Rasulullah, sesungguhnya kami makan dan tidak merasa kenyang?\" Beliau bersabda: \"Kemungkinan kalian makan sendiri-sendiri.\" Mereka menjawab, \"Ya.\" Beliau bersabda: \"Hendaklah kalian makan secara bersama-sama, dan sebutlah nama Allah, maka kalian akan diberi berkah padanya.\" Abu Daud berkata, \"Apabila engkau berada pada sebuah pesta kemudian dihidangkan makan malam, maka janganlah engkau memakannya hingga pemilik rumah mengizinkanmu.\""},"3194":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا دَخَلَ الرَّجُلُ بَيْتَهُ فَذَكَرَ اللَّهَ عِنْدَ دُخُولِهِ وَعِنْدَ طَعَامِهِ قَالَ الشَّيْطَانُ لَا مَبِيتَ لَكُمْ وَلَا عَشَاءَ وَإِذَا دَخَلَ فَلَمْ يُذْكَرْ اللَّهَ عِنْدَ دُخُولِهِ قَالَ الشَّيْطَانُ أَدْرَكْتُمْ الْمَبِيتَ فَإِذَا لَمْ يَذْكُرْ اللَّهَ عِنْدَ طَعَامِهِ قَالَ أَدْرَكْتُمْ الْمَبِيتَ وَالْعَشَاءَ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf] telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Abu Az Zubair] dari [Jabir bin Abdullah] ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila seseorang memasuki rumahnya dan menyebutkan nama Allah ketika masuk dan ketika makan, maka setan berkata, 'Tidak ada tempat bermalam bagi kalian dan tidak ada makan malam'. Dan apabila ia masuk rumah dan tidak menyebutkan nama Allah ketika masuk maka setan berkata, 'Kalian mendapatkan tempat bermalam'. Kemudian apabila ia tidak menyebutkan nama Allah ketika makan maka setan berkata, 'Kalian mendapatkan tempat bermalam dan makan malam'.\""},"3195":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ خَيْثَمَةَ عَنْ أَبِي حُذَيْفَةَ عَنْ حُذَيْفَةَ قَالَكُنَّا إِذَا حَضَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا لَمْ يَضَعْ أَحَدُنَا يَدَهُ حَتَّى يَبْدَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنَّا حَضَرْنَا مَعَهُ طَعَامًا فَجَاءَ أَعْرَابِيٌّ كَأَنَّمَا يُدْفَعُ فَذَهَبَ لِيَضَعَ يَدَهُ فِي الطَّعَامِ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ ثُمَّ جَاءَتْ جَارِيَةٌ كَأَنَّمَا تُدْفَعُ فَذَهَبَتْ لِتَضَعَ يَدَهَا فِي الطَّعَامِ فَأَخَذَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهَا وَقَالَ إِنَّ الشَّيْطَانَ لَيَسْتَحِلُّ الطَّعَامَ الَّذِي لَمْ يُذْكَرْ اسْمُ اللَّهِ عَلَيْهِ وَإِنَّهُ جَاءَ بِهَذَا الْأَعْرَابِيِّ يَسْتَحِلُّ بِهِ فَأَخَذْتُ بِيَدِهِ وَجَاءَ بِهَذِهِ الْجَارِيَةِ يَسْتَحِلُّ بِهَا فَأَخَذْتُ بِيَدِهَا فَوَالَّذِي نَفْسِي بِيَدِهِ إِنَّ يَدَهُ لَفِي يَدِي مَعَ أَيْدِيهِمَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Khaitsamah] dari [Abu Hudzaifah] dari [Hudzaifah] ia berkata, \"Jika kami bersama Rasulullah shallallahu 'alaihi wasallam menghadiri jamuan makanan, maka tidak ada seorangpun di antara kami yang meletakkan tangannya hingga Rasulullah shallallahu 'alaihi wasallam memulai. Dan kami pernah bersama beliau menghadiri jamuan makan, lalu seorang Arab badui datang yang seolah-oleh ia terdorong, lalu ia meletakkan tangannya pada makanan, namun Rasulullah shallallahu 'alaihi wasallam memegang tangannya. Kemudian seorang budak wanita datang sepertinya ia terdorong hendak meletakkan tangannya pada makanan, namun beliau memegang tangannya dan berkata: \"Sungguh, setan menghalalkan makanan yang tidak disebutkan nama Allah padanya. Setan datang bersama orang badui ini, dengannya setan ingin menghalalkan makanan tersebut, maka aku pegang tangannya. Dan setan tersebut juga datang bersama budak wanita ini, dengannya ia ingin menghalalkan makanan tersebut, maka aku pegang tangannya. Demi Dzat yang jiwaku ada di tangan-Nya, sesungguhnya tangan setan tersebut ada di tanganku bersama tangan mereka berdua.\""},"3196":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ هِشَامٍ يَعْنِي ابْنَ أَبِي عَبْدِ اللَّهِ الدَّسْتُوَائِيَّ عَنْ بُدَيْلٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدٍ عَنْ امْرَأَةٍ مِنْهُمْ يُقَالُ لَهَا أُمُّ كُلْثُومٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ فَلْيَذْكُرْ اسْمَ اللَّهِ تَعَالَى فَإِنْ نَسِيَ أَنْ يَذْكُرَ اسْمَ اللَّهِ تَعَالَى فِي أَوَّلِهِ فَلْيَقُلْ بِسْمِ اللَّهِ أَوَّلَهُ وَآخِرَهُ","id":"Telah menceritakan kepada kami [Muammal bin Hisyam] telah menceritakan kepada kami [Isma'il] dari [Hisyam bin Abu Abdullah Ad Dastuwai] dari [Budail] dari [Abdullah bin 'Ubaid] dari seorang wanita di antara mereka yang dipanggil [Ummu Kultsum] dari [Aisyah] radliallahu 'anhuma, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang di antara kalian makan, maka hendaknya ia menyebutkan nama Allah Ta'ala. Jika ia lupa untuk menyebut nama Allah Ta'ala di awal, hendaklah ia mengucapkan: BISMILLAAHI AWWALAHU WA AAKHIRAHU (dengan nama Allah pada awal dan akhirnya) '.\""},"3197":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ الْفَضْلِ الْحَرَّانِيُّ حَدَّثَنَا عِيسَى يَعْنِي ابْنَ يُونُسَ حَدَّثَنَا جَابِرُ بْنُ صُبْحٍ حَدَّثَنَا الْمُثَنَّى بْنُ عَبْدِ الرَّحْمَنِ الْخُزَاعِيُّ عَنْ عَمِّهِ أُمَيَّةَ بْنِ مَخْشِيٍّ وَكَانَ مَنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا وَرَجُلٌ يَأْكُلُ فَلَمْ يُسَمِّ حَتَّى لَمْ يَبْقَ مِنْ طَعَامِهِ إِلَّا لُقْمَةٌ فَلَمَّا رَفَعَهَا إِلَى فِيهِ قَالَ بِسْمِ اللَّهِ أَوَّلَهُ وَآخِرَهُ فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ مَا زَالَ الشَّيْطَانُ يَأْكُلُ مَعَهُ فَلَمَّا ذَكَرَ اسْمَ اللَّهِ عَزَّ وَجَلَّ اسْتَقَاءَ مَا فِي بَطْنِهِقَالَ أَبُو دَاوُد جَابِرُ بْنُ صُبْحٍ جَدُّ سُلَيْمَانَ بْنَ حَرْبٍ مِنْ قِبَلِ أُمِّهِ","id":"Telah menceritakan kepada kami [Muammal bin Al Fadll Al Harrani] telah menceritakan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Jabir bin Shubh] telah menceritakan kepada kami [Al Mutsanna bin Abdurrahman Al Khuza'i] dari pamannya [Umayyah bin Makhsyi] seorang sahabat Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah duduk, sementara ada seorang laki-laki makan dan tidak menyebutkan nama Allah hingga makanannya hanya tersisa satu suap, kemudian tatkala ia mengangkatnya ke mulut ia mengucapkan; BISMILLAAHI AWWALAHU WA AAKHIRAHU (Dengan nama Allah, pada awal dan akhirnya), maka Nabi shallallahu 'alaihi wasallam tertawa kemudian berkata: \"Setan terus makan bersamanya, kemudian tatkala ia menyebutkan nama Allah Azza wa Jalla, maka setan memuntahkan apa yang ada di perutnya.\" Abu Daud berkata, \"Jabir bin Shubh adalah kakek Sulaiman bin Harb dari pihak ibunya.\""},"3198":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ قَالَ سَمِعْتُ أَبَا جُحَيْفَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا آكُلُ مُتَّكِئًا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Ali bin Al Aqmar] ia berkata; aku mendengar [Abu Juhaifah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak makan dengan bersandar.\""},"3199":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ شُعَيْبِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِيهِ قَالَمَا رُئِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ مُتَّكِئًا قَطُّ وَلَا يَطَأُ عَقِبَهُ رَجُلَانِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Tsabit Al Bunani] dari [Syu'aib bin Abdullah bin 'Amru] dari [Ayahnya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah terlihat makan dalam keadaan bersandar sama sekali, dan tidak ada dua orangpun yang berjalan di belakang beliau.\""},"3200":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا وَكِيعٌ عَنْ مُصْعَبِ بْنِ سُلَيْمٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَجَعْتُ إِلَيْهِ فَوَجَدْتُه�� يَأْكُلُ تَمْرًا وَهُوَ مُقْعٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] telah mengabarkan kepada kami [Waki'] dari [Mush'ab bin Sulaim] ia berkata; aku mendengar [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam mengutusku, ketika kembali aku melihat beliau makan kurma dengan duduk (di atas bokong dengan menegakkan kedua betisnya).\""},"3201":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ طَعَامًا فَلَا يَأْكُلْ مِنْ أَعْلَى الصَّحْفَةِ وَلَكِنْ لِيَأْكُلْ مِنْ أَسْفَلِهَا فَإِنَّ الْبَرَكَةَ تَنْزِلُ مِنْ أَعْلَاهَا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari ['Atha bin As Saib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila salah seorang di antara kalian makan makanan maka janganlah ia makan dari atas piring, tetapi hendaknya ia makan dari bawahnya, sesungguhnya berkah turun dari atasnya.\" "},"3202":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ الْحِمْصِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عِرْقٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُسْرٍ قَالَكَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَصْعَةٌ يُقَالُ لَهَا الْغَرَّاءُ يَحْمِلُهَا أَرْبَعَةُ رِجَالٍ فَلَمَّا أَضْحَوْا وَسَجَدُوا الضُّحَى أُتِيَ بِتِلْكَ الْقَصْعَةِ يَعْنِي وَقَدْ ثُرِدَ فِيهَا فَالْتَفُّوا عَلَيْهَا فَلَمَّا كَثَرُوا جَثَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعْرَابِيٌّ مَا هَذِهِ الْجِلْسَةُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ جَعَلَنِي عَبْدًا كَرِيمًا وَلَمْ يَجْعَلْنِي جَبَّارًا عَنِيدًا ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا مِنْ حَوَالَيْهَا وَدَعُوا ذِرْوَتَهَا يُبَارَكْ فِيهَا","id":"Telah menceritakan kepada kami ['Amru bin Utsman Al Himshi] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Muhammad bin Abdurrahman bin 'Irq] telah menceritakan kepada kami [Abdullah bin Busr] ia berkata, \"Nabi shallallahu 'alaihi wasallam memiliki nampan yang disebut Gharra`, dan hanya bisa diangkat oleh empat orang laki-laki. Di pagi hari saat mereka telah melaksanakan shalat dluha, nampan tersebut dihadirkan dan telah penuh dengan bubur. Orang-orang pun mengerumuninya, ketika jumlah mereka telah banyak, Rasulullah shallallahu 'alaihi wasallam duduk di atas lututnya. Seorang Arab badui lalu berkata, \"Duduk apakah ini?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Sesungguhnya Allah telah menjadikan aku seorang hamba yang mulia, bukan seorang yang otoriter dan pembangkang.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda lagi: \"Makanlah dari sekitarnya dan biarkan bagian atasnya maka akan diberkahi padanya.\""},"3203":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا كَثِيرُ بْنُ هِشَامٍ عَنْ جَعْفَرِ بْنِ بُرْقَانَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مَطْعَمَيْنِ عَنْ الْجُلُوسِ عَلَى مَائِدَةٍ يُشْرَبُ عَلَيْهَا الْخَمْرُ وَأَنْ يَأْكُلَ الرَّجُلُ وَهُوَ مُنْبَطِحٌ عَلَى بَطْنِهِقَالَ أَبُو دَاوُد هَذَا الْحَدِيثُ لَمْ يَسْمَعْهُ جَعْفَرٌ مِنْ الزُّهْرِيِّ وَهُوَ مُنْكَرٌ حَدَّثَنَا هَارُونُ بْنُ زَيْدِ بْنِ أَبِي الزَّرْقَاءِ حَدَّثَنَا أَبِي حَدَّثَنَا جَعْفَرٌ أَنَّهُ بَلَغَهُ عَنْ الزُّهْرِيِّ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Katsir bin Hisyam] dari [Ja'far bin Burqan] dari [Zuhri] dari [Salim] dari [Ayahnya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah melarang dari dua tempat makan; duduk menghadap hidangan yang padanya diminum khamer dan serta seseorang makan dalam keadaan tengkurap.\" Abu Daud berkata, \"Hadits ini adalah hadits yang tidak didengar oleh Ja'far dari Az Zuhri, dan hadits tersebut adalah hadits mungkar.\" Telah menceritakan kepada kami [Harun bin Zaid bin Abu Az Zarqa`] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Ja'far] bahwa hadits ini telah sampai kepadanya dari [Az Zuhri].\""},"3204":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ جَدِّهِ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ فَلْيَأْكُلْ بِيَمِينِهِ وَإِذَا شَرِبَ فَلْيَشْرَبْ بِيَمِينِهِ فَإِنَّ الشَّيْطَانَ يَأْكُلُ بِشِمَالِهِ وَيَشْرَبُ بِشِمَالِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] telah mengabarkan kepadaku [Abu Bakr bin 'Ubaidullah bin Abdullah bin Umar] dari kakeknya [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian makan, maka hendaknya ia makan dengan menggunakan tangan kanannya, dan apabila minum maka hendaknya ia minum dengan tangan kanannya, karena sesungguhnya setan makan dan minum menggunakan tangan kirinya.\""},"3205":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ لُوَيْنٌ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ أَبِي وَجْزَةَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْنُ بُنَيَّ فَسَمِّ اللَّهَ وَكُلْ بِيَمِينِكَ وَكُلْ مِمَّا يَلِيكَ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Luwain] dari [Sulaiman bin Bilal] dari [Abu Wajzah] dari [Umar bin Abu Salamah] ia berkata, \"Nabi shallallahu 'alaihi wasallam berkata: \"Wahai anakku mendekatlah, sebutlah nama Allah, makanlah dengan tangan kananmu, serta makanlah dari yang dekat.\""},"3206":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو مَعْشَرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقْطَعُوا اللَّحْمَ بِالسِّكِّينِ فَإِنَّهُ مِنْ صَنِيعِ الْأَعَاجِمِ وَانْهَسُوهُ فَإِنَّهُ أَهْنَأُ وَأَمْرَأُقَالَ أَبُو دَاوُد وَلَيْسَ هُوَ بِالْقَوِيِّ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abu Ma'syar] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anhuma, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian memotong daging menggunakan pisau, sesungguhnya hal tersebut termasuk perbuatan orang-orang 'Ajam (selain Arab), gigitlah daging tersebut karena sesungguhnya hal tersebut lebih nyaman dan nikmat.\" Abu Dawud berkata, \"Hadits ini tidak kuat.\""},"3207":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ أَبِي سُلَيْمَانَ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ قَالَكُنْتُ آكُلُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَآخُذُ اللَّحْمَ بِيَدِي مِنْ الْعَظْمِ فَقَالَ أَدْنِ الْعَظْمَ مِنْ فِيكَ فَإِنَّهُ أَهْنَأُ وَأَمْرَأُقَالَ أَبُو دَاوُد عُثْمَانُ لَمْ يَسْمَعْ مِنْ صَفْوَانَ وَهُوَ مُرْسَلٌ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibnu 'Ulaiyyah] dari [Abdurrahman bin Ishaq] dari [Abdurrahman bin Mu'awiyah] dari [Utsman bin Abu Sulaiman] dari [Shafwan bin Umayyah] ia berkata, \"Aku pernah makan bersama Nabi shallallahu 'alaihi wasallam, lalu aku mengambil daging dari tulang menggunakan tanganku. Maka beliau pun bersabda: \"Dekatkanlah tulang dari mulutmu, sesungguhnya hal tersebut lebih nyaman dan nikmat.\" Abu Daud berkata, \"Utsman tidak mendengar dari Shafwan, dan hadits tersebut adalah hadits mursal.\""},"3208":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو دَاوُدَ عَنْ زُهَيْرٍ عَنْ أَبِي إِسْحَقَ عَنْ سَعْدِ بْنِ عِيَاضٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكَانَ أَحَبُّ الْعُرَاقِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُرَاقَ الشَّاةِحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ بِهَذَا الْإِسْنَادِ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْجِبُهُ الذِّرَاعُ قَالَ وَسُمَّ فِي الذِّرَاعِ وَكَانَ يَرَى أَنَّ الْيَهُودَ هُمْ سَمُّوهُ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Abu Daud] dari [Zuhair] dari [Abu Ishaq] dari [Sa'd bin 'Iyadl] dari [Abdullah bin Mas'ud] ia berkata, \"Kuah yang paling disukai Rasulullah shallallahu 'alaihi wasallam adalah kuah daging kambing.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Daud] dengan sanad ini. Ia berkata, \"Nabi shallallahu 'alaihi wasallam menyukai paha kambing.\" Ia berkata, \"Pernah paha kambing diberi racun, dan beliau melihat bahwa yang orang-orang Yahudi yang telah meracuninya.\""},"3209":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُإِنَّ خَيَّاطًا دَعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَهُ قَالَ أَنَسٌ فَذَهَبْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ذَلِكَ الطَّعَامِ فَقُرِّبَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُبْزًا مِنْ شَعِيرٍ وَمَرَقًا فِيهِ دُبَّاءٌ وَقَدِيدٌ قَالَ أَنَسٌ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَتَبَّعُ الدُّبَّاءَ مِنْ حَوَالَيْ الصَّحْفَةِ فَلَمْ أَزَلْ أُحِبُّ الدُّبَّاءَ بَعْدَ يَوْمَئِذٍ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] bahwa ia mendengar [Anas bin Malik] berkata, \"Seorang penjahit mengundang Rasulullah shallallahu 'alaihi wasallam untuk menghadiri makanan yang telah ia buat.\" Anas berkata, \"Lalu aku pergi bersama Rasulullah shallallahu 'alaihi wasallam menghadiri makanan tersebut, kemudian makanan tersebut didekatkan kepada Rasulullah shallallahu 'alaihi wasallam yang berupa roti yang terbuat dari gandum serta kuah yang padanya terdapat labu dan dendeng.\" Anas berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam mencari-cari labu yang ada di nampan tersebut, maka semenjak itu aku suka makan labu.\""},"3210":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَسَّانَ السَّمْتِيُّ حَدَّثَنَا الْمُبَارَكُ بْنُ سَعِيدٍ عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ رَجُلٍ مَنْ أَهْلِ الْبَصْرَةِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ أَحَبَّ الطَّعَامِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الثَّرِيدُ مِنْ الْخُبْزِ وَالثَّرِيدُ مِنْ الْحَيْسِقَالَ أَبُو دَاوُد وَهُوَ ضَعِيفٌ","id":"Telah menceritakan kepada kami [Muhammad bin Hassan As Samti] telah menceritakan kepada kami [Al Mubarak bin Sa'id] dari [Umar bin Sa'id] dari [seorang laki-laki penduduk Bashrah] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Makanan yang paling disukai Rasulullah shallallahu 'alaihi wasallam adalah bubur yang terbuat dari roti, serta bubur dari hais (yaitu campuran antara kurma, keju dan mentega).\" Abu Daud berkata, \"Ini adalah hadits lemah.\""},"3211":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ حَدَّثَنِي قَبِيصَةُ بْنُ هُلْبٍ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلَهُ رَجُلٌ فَقَالَ إِنَّ مِنْ الطَّعَامِ طَعَامًا أَتَحَرَّجُ مِنْهُ فَقَالَ لَا يَتَخَلَّجَنَّ فِي صَدْرِكَ شَيْءٌ ضَارَعْتَ فِيهِ النَّصْرَانِيَّةَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Simak bin Harb] telah menceritakan kepadaku [Qabishah bin Hulb] dari [Ayahnya] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam ditanya seorang laki-laki, \"Di antara makanan ada makanan yang aku merasa ragu untuk memakannya.\" Beliau bersabda: \"Janganlah ada keraguan ada dalam hatimu (akan kehalalannya) sehingga engkau menyerupai orang-orang Nashrani.\""},"3212":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ الْجَلَّالَةِ وَأَلْبَانِهَا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami ['Abdah] dari [Muhammad bin Ishaq] dari [Ibnu Abu Najih] dari [Mujahid] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang makan hewan Jallalah dan meminum susunya.\" "},"3213":{"ar":"حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنِي أَبُو عَامِرٍ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لَبَنِ الْجَلَّالَةِ","id":"Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepadaku [Abu 'Amir] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam melarang dari meminum susu hewan Jallalah.\" "},"3214":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي سُرَيْجٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ جَهْمٍ حَدَّثَنَا عُمْرُو بْنُ أَبِي قَيْسٍ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَلَّالَةِ فِي الْإِبِلِ أَنْ يُرْكَبَ عَلَيْهَا أَوْ يُشْرَبَ مِنْ أَلْبَانِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Abu Suraij] telah mengabarkan kepadaku [Abdullah bin Jahm] telah menceritakan kepada kami ['Amru bin Abu Qais] dari [Ayyub As Sakhtiyani] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang menaiki dan minum susu unta yang makan kotoran.\""},"3215":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ لُحُومِ الْحُمُرِ وَأَذِنَ لَنَا فِي لُحُومِ الْخَيْلِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari ['Amru bin Dinar] dari [Muhammad bin Ali] dari [Jabir bin Abdullah] ia berkata, \"Pada saat perang Khaibar Rasulullah shallallahu 'alaihi wasallam melarang kami untuk makan daging keledai dan mengizinkan kami makan daging kuda.\""},"3216":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَذَبَحْنَا يَوْمَ خَيْبَرَ الْخَيْلَ وَالْبِغَالَ وَالْحَمِيرَ فَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْبِغَال�� وَالْحَمِيرِ وَلَمْ يَنْهَنَا عَنْ الْخَيْلِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata, \"Pada saat perang Khaibar kami menyembelih kuda, bighal dan keledai, lalu Rasulullah shallallahu 'alaihi wasallam melarang kami untuk menyembelih bighal dan keledai, dan tidak melarang kami dari menyembelih kuda.\""},"3217":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ شَبِيبٍ وَحَيْوَةُ بْنُ شُرَيْحٍ الْحِمْصِيُّ قَالَ حَيْوَةُ حَدَّثَنَا بَقِيَّةُ عَنْ ثَوْرِ بْنِ يَزِيدَ عَنْ صَالِحِ بْنِ يَحْيَى بْنِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ خَالِدِ بْنِ الْوَلِيدِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ لُحُومِ الْخَيْلِ وَالْبِغَالِ وَالْحَمِيرِ زَادَ حَيْوَةُ وَكُلِّ ذِي نَابٍ مِنْ السِّبَاعِقَالَ أَبُو دَاوُد وَهُوَ قَوْلُ مَالِكٍ قَالَ أَبُو دَاوُد لَا بَأْسَ بِلُحُومِ الْخَيْلِ وَلَيْسَ الْعَمَلُ عَلَيْهِ قَالَ أَبُو دَاوُد وَهَذَا مَنْسُوخٌ قَدْ أَكَلَ لُحُومَ الْخَيْلِ جَمَاعَةٌ مَنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ ابْنُ الزُّبَيْرِ وَفَضَالَةُ بْنُ عُبَيْدٍ وَأَنَسُ بْنُ مَالِكٍ وَأَسْمَاءُ بِنْتُ أَبِي بَكْرٍ وسُوَيْدُ بْنُ غَفَلَةَ وَعَلْقَمَةُ وَكَانَتْ قُرَيْشٌ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَذْبَحُهَا","id":"Telah menceritakan kepada kami [Sa'id bin Syabib] dan [Haiwah bin Syuraih Al Himshi] [Haiwah] berkata; telah menceritakan kepadaku [Baqiyyah] dari [Tsaur bin Yazid] dari [Shalih bin Yahya bin Al Miqdam bin Ma'dikarib] dari [Ayahnya] dari [Kakeknya] dari [Khalid bin Al Walid] bahwa Rasulullah shallallahu 'alaihi wasallam melarang kami makan daging kuda, bighal, dan keledai.\" Haiwah menambahkan, \"Dan setiap binatang buas yang bertaring.\" Abu Daud berkata, \"Ini adalah pendapat Malik.\" Abu Daud berkata, \"Tidak mengapa memakan daging kuda, dan hal tersebut bukan menjadi dasar beramal.\" Abu Daud berkata, \"Hadits ini telah dihapuskan, sebab sejumlah sahabat Nabi shallallahu 'alaihi wasallam telah memakan daging kuda. Di antara mereka adalah Ibnu Az Zubair, Fadlalah bin 'Ubaid, Anas bin Malik, Asma` binti Abu Bakar, Suwaid bin Ghafalah, dan 'Alqamah. Dan orang-orang Quraisy pada zaman Rasulullah shallallahu 'alaihi wasallam juga menyembelihnya.\""},"3218":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ هِشَامِ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ غُلَامًا حَزَوَّرًا فَصِدْتُ أَرْنَبًا فَشَوَيْتُهَا فَبَعَثَ مَعِي أَبُو طَلْحَةَ بِعَجُزِهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ بِهَا فَقَبِلَهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Hisyam bin Zaid] dari [Anas bin Malik] ia berkata, \"Aku adalah seorang anak yang kuat, lalu aku berburu kelinci dan membakarnya. Kemudian Abu Thalhah menyuruhku untuk mengirimkan bagian pantat kelinci kepada Nabi shallallahu 'alaihi wasallam, lalu aku membawanya kepada beliau dan beliau menerimanya.\""},"3219":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ قَالَ سَمِعْتُ أَبِي خَالِدَ بْنَ الْحُوَيْرِثِ يَقُولُإِنَّ عَبْدَ اللَّهِ بْنَ عَمْرٍو كَانَ بِالصِّفَاحِ قَالَ مُحَمَّدٌ مَكَانٌ بِمَكَّةَ وَإِنَّ رَجُلًا جَاءَ بِأَرْنَبٍ قَدْ صَادَهَا فَقَالَ يَا عَبْدَ اللَّهِ بْنَ عَمْرٍو مَا تَقُولُ قَالَ قَدْ جِيءَ بِهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا جَالِسٌ فَلَمْ يَأْكُلْهَا وَلَمْ يَنْهَ عَنْ أَكْلِهَا وَزَعَمَ أَنَّهَا تَحِيضُ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Muhammad bin Khalid] ia berkata; aku mendengar bapakku [Khalid bin Al Huwairits] berkata, \" [Abdullah bin 'Amru] pernah berada di Ash Shifah -Muhammad berkata; tempat di Makkah-, lalu seorang laki-laki datang membawa kelinci yang ia buru. Laki-laki itu lalu berkata, \"Wahai Abdullah bin 'Amru, apa pendapatmu? Abdullah bin Amru menjawab, \"Pernah seekor kelinci (bakar) dibawa ke hadapan Rasulullah shallallahu 'alaihi wasallam, beliau tidak memakannya dan tidak melarang untuk memakannya, sementara saat itu aku berada di sisi beliau. Dan beliau menyakini bahwa kelinci tersebut mengeluarkan darah.\""},"3220":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ خَالَتَهُ أَهْدَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمْنًا وَأَضُبًّا وَأَقِطًا فَأَكَلَ مِنْ السَّمْنِ وَمِنْ الْأَقِطِ وَتَرَكَ الْأَضُبَّ تَقَذُّرًا وَأُكِلَ عَلَى مَائِدَتِهِ وَلَوْ كَانَ حَرَامًا مَا أُكِلَ عَلَى مَائِدَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] telah menceritakan kepada kami [Syu'bah] dan [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa bibinya telah memberi hadiah mentega, biawak dan keju kepada Rasulullah shallallahu 'alaihi wasallam. Lalu beliau memakan sebagian dari mentega dan keju, serta meninggalkan biawak karena merasa jijik. Dan biawak tersebut dimakan di atas meja makan beliau, seandainya biawak itu haram, maka biawak tersebut tidak akan dimakan di atas meja makan Rasulullah shallallahu 'alaihi wasallam.\""},"3221":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ خَالِدِ بْنِ الْوَلِيدِأَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتَ مَيْمُونَةَ فَأُتِيَ بِضَبٍّ مَحْنُوذٍ فَأَهْوَى إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ فَقَالَ بَعْضُ النِّسْوَةِ اللَّاتِي فِي بَيْتِ مَيْمُونَةَ أَخْبِرُوا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَا يُرِيدُ أَنْ يَأْكُلَ مِنْهُ فَقَالُوا هُوَ ضَبٌّ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ قَالَ فَقُلْتُ أَحَرَامٌ هُوَ يَا رَسُولَ اللَّهِ قَالَ لَا وَلَكِنَّهُ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Abu Umamah bin Sahl bin Hunaif] dari [Abdullah bin Abbas] dari [Khalid bin Al Walid] bahwa ia bersama Rasulullah shallallahu 'alaihi wasallam pernah memasuki rumah Maimunah, kemudian didatangkan seekor biawak bakar. Rasulullah shallallahu 'alaihi wasallam berkeinginan untuk mengambilnya, lalu sebagian isteri yang berada di rumah Maimunah berkata, \"Beritahukanlah kepada Nabi shallallahu 'alaihi wasallam apa yang hendak beliau makan!\" Kemudian mereka berkata, \"Itu daging biawak.\" Maka Rasulullah shallallahu 'alaihi wasallam pun mengangkat tangannya.\" Khalid berkata, \"Lalu aku katakan, \"Wahai Rasulullah, apakah daging itu haram?\" Beliau menjawab: \"Tidak, akan tetapi biawak tersebut tidak ada di negeri kaumku, maka aku dapati diriku tidak menyukainya.\" Khalid berkata, \"Lalu aku mengambil dan memakannya, sementara Rasulullah shallallahu 'alaihi wasallam melihat.\""},"3222":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدٌ عَنْ حُصَيْنٍ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ ثَابِتٍ بْنِ وَدِيعَةَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَيْشٍ فَأَصَبْنَا ضِبَابًا قَالَ فَشَوَيْتُ مِنْهَا ضَبًّا فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعْتُهُ بَيْنَ يَدَيْهِ قَالَ فَأَخَذَ عُودًا فَعَدَّ بِهِ أَصَابِعَهُ ثُمَّ قَالَ إِنَّ أُمَّةً مِنْ بَنِي إِسْرَائِيلَ مُسِخَتْ دَوَابَّ فِي الْأَرْضِ وَإِنِّي لَا أَدْرِي أَيُّ الدَّوَابِّ هِيَ قَالَ فَلَمْ يَأْكُلْ وَلَمْ يَنْهَ","id":"Telah menceritakan kepada kami ['Amru bin 'Aun] telah mengabarkan kepada kami [Khalid] dari [Hushain] dari [Zaid bin Wahb] dari [Tsabit bin Wadi'ah] ia berkata, \"Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam berada di antara pasukan, lalu kami mendapatkan beberapa ekor biawak.\" Tsabit berkata, \"Lalu aku membakar satu ekor darinya. Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan meletakkannya di hadapan beliau.\" Tsabit bin Wadi'ah melanjutkan, \"Beliau lantas mengambil sebatang ranting dan beliau gunakan untuk menghitung jari-jarinya (biawak). Setelah itu beliau bersabda: \"Sekelompok umat dari kalangan Bani Israil telah diubah menjadi hewan melata di bumi, dan aku tidak tahu hewan apakah itu?\" Tsabit berkata, \"Maka beliau tidak makan dan tidak melarang.\""},"3223":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَوْفٍ الطَّائِيُّ أَنَّ الْحَكَمَ بْنَ نَافِعٍ حَدَّثَهُمْ حَدَّثَنَا ابْنُ عَيَّاشٍ عَنْ ضَمْضَمِ بْنِ زُرْعَةَ عَنْ شُرَيْحِ بْنِ عُبَيْدٍ عَنْ أَبِي رَاشِدٍ الْحُبْرَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ شِبْلٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ لَحْمِ الضَّبِّ","id":"Telah menceritakan kepada kami [Muhammad bin 'Auf Ath Thai] bahwa [Al Hakam bin Nafi'] telah menceritakan kepada mereka, ia berkata; telah menceritakan kepada kami [Ibnu 'Ayyasy] dari [Dlamdlam bin Zur'ah] dari [Syuraih bin 'Ubaid] dari [Abu Rasyid Al Hubrani] dari [Abdurrahman bin Syibl] bahwa Rasulullah shallallahu 'alaihi wasallam melarang makan daging biawak.\""},"3224":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ سَهْلٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عَبْدِ الرَّحْمَنِ ابْنِ مَهْدِيٍّ حَدَّثَنِي بُرَيْهُ بْنُ عُمَرَ بْنِ سَفِينَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَأَكَلْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَحْمَ حُبَارَى","id":"Telah menceritakan kepada kami [Al Fadll bin Sahl] telah menceritakan kepada kami [Ibrahim bin Abdurrahman bin Mahdi] telah menceritakan kepadaku [Buraih bin Umar bin Safinah] dari [Ayahnya] dari [Kakeknya] ia berkata, \"Aku bersama Rasulullah shallallahu 'alaihi wasallam pernah makan daging hubara (burung yang panjang lehernya menyerupai angsa).\""},"3225":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا غَالِبُ بْنُ حَجْرَةَ حَدَّثَنِي مِلْقَامُ بْنُ التَّلِبِّ عَنْ أَبِيهِ قَالَصَحِبْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ أَسْمَعْ لِحَشَرَةِ الْأَرْضِ تَحْرِيمًا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ghalib bin Hajrah] telah menceritakan kepadaku [Milqam bin At Talib] dari [Ayahnya] ia berkata, \"Aku telah menemani Nabi shallallahu 'alaihi wasallam dan tidak mendengar adanya pengharaman serangga bumi.\""},"3226":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ الْكَلْبِيُّ أَبُو ثَوْرٍ حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عِيسَى بْنِ نُمَيْلَةَ عَنْ أَبِيهِ قَالَكُنْتُ عِنْدَ ابْنِ عُمَرَ فَسُئِلَ عَنْ أَكْلِ الْقُنْفُذِ فَتَلَا{ قُلْ لَا أَجِدُ فِيمَا أُوحِيَ إِلَيَّ مُحَرَّمًا }الْآيَةَقَالَ قَالَ شَيْخٌ عِنْدَهُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ ذُكِرَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ خَبِيثَةٌ مِنْ الْخَبَائِثِ فَقَالَ ابْنُ عُمَرَ إِنْ كَانَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا فَهُوَ كَمَا قَالَ مَا لَمْ نَدْرِ","id":"Telah menceritakan kepada kami [Ibrahim bin Khalid Al Kalbi Abu Tsaur] telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Isa bin Numailah] dari [Ayahnya] ia berkata, \"Aku pernah berada di sisi Ibnu Umar kemudian ia ditanya tentang hukum makan daging landak, kemudian ia membaca firman Allah: '(Katakanlah: \"Aku tidak mendapatkan dalam wahyu yang diwahyukan kepadaku, sesuatu yang diharamkan….) ' (Qs. Al An'aam: 145). Numailah berkata, \" [Seorang laki-laki tua] yang ada di sisinya berkata, \"Aku pernah mendengar [Abu Hurairah] berkata, \"Telah disebutkan landak di hadapan Nabi shallallahu 'alaihi wasallam, kemudian beliau bersabda: \"Landak adalah sesuatu yang buruk.\" Kemudian Ibnu Umar berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam mengatakan demikian, maka hukumnya adalah sebagaimana yang beliau ucapkan.\""},"3227":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ صَبِيحٍ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ شَرِيكٍ الْمَكِّيَّ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي الشَّعْثَاءِ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ أَهْلُ الْجَاهِلِيَّةِ يَأْكُلُونَ أَشْيَاءَ وَيَتْرُكُونَ أَشْيَاءَ تَقَذُّرًا فَبَعَثَ اللَّهُ تَعَالَى نَبِيَّهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنْزَلَ كِتَابَهُ وَأَحَلَّ حَلَالَهُ وَحَرَّمَ حَرَامَهُ فَمَا أَحَلَّ فَهُوَ حَلَالٌ وَمَا حَرَّمَ فَهُوَ حَرَامٌ وَمَا سَكَتَ عَنْهُ فَهُوَ عَفْوٌ وَتَلَا{ قُلْ لَا أَجِدُ فِيمَا أُوحِيَ إِلَيَّ مُحَرَّمًا }إِلَى آخِرِ الْآيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Daud bin Shabih] telah menceritakan kepada kami [Al Fadll bin Dukain] telah menceritakan kepada kami [Muhammad bin Syarik Al Makki] dari ['Amru bin Dinar] dari [Abu Asy Sya'tsa`] dari [Ibnu Abbas] ia berkata, \"Dahulu orang-orang jahiliyah biasa makan beberapa macam makanan dan meninggalkan beberapa makanan karena jijik. Kemudian Allah Ta'ala mengutus Nabi-Nya shallallahu 'alaihi wasallam dan menurunkan Kitab-Nya, serta menghalalkan yang halal dan mengharamkan yang haram. Maka apa yang Allah halalkan adalah halal, apa yang Allah haramkan adalah haram, dan apa yang Allah diamkan maka hukumnya dimaafkan.\" Kemudian Ibnu Abbas membaca ayat: '(Katakanlah: \"Aku tidak mendapatkan dalam wahyu yang diwahyukan kepadaku, sesuatu yang diharamkan…) ' (Qs. Al An'aam: 145) hingga akhir ayat.\""},"3228":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخُزَاعِيُّ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمَّارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الضَّبُعِ فَقَالَ هُوَ صَيْدٌ وَيُجْعَلُ فِيهِ كَبْشٌ إِذَا صَادَهُ الْمُحْرِمُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Al Khuza'i] telah menceritakan kepada kami [Jarir bin Hazim] dari [Abdullah bin 'Ubaid] dari [Abdurrahman bin Abu 'Ammar] dari [Jabir bin Abdullah] ia berkata, \"Aku pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai biawak, beliau lalu menjawab: \"Biawak adalah hewan buruan, dan dijadikan padanya denda satu ekor domba apabila orang yang berihram memburunya.\""},"3229":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السَّبُعِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari [Abu Idris Al Khaulani] dari [Abu Tsa'labah Al Khusyani] bahwa Rasulullah shallallahu 'alaihi wasallam melarang makan semua binatang buas yang bertaring.\""},"3230":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السَّبُعِ وَعَنْ كُلِّ ذِي مِخْلَبٍ مِنْ الطَّيْرِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Maimun bin Mihran] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah melarang mengkonsumsi semua binatang buas yang bertaring dan semua burung yang memiliki cakar.\""},"3231":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى الْحِمْصِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ مَرْوَانَ بْنِ رُؤْبَةَ التَّغْلِبِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَوْفٍ عَنْ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَلَا لَا يَحِلُّ ذُو نَابٍ مِنْ السِّبَاعِ وَلَا الْحِمَارُ الْأَهْلِيُّ وَلَا اللُّقَطَةُ مِنْ مَالِ مُعَاهَدٍ إِلَّا أَنْ يَسْتَغْنِيَ عَنْهَا وَأَيُّمَا رَجُلٍ ضَافَ قَوْمًا فَلَمْ يَقْرُوهُ فَإِنَّ لَهُ أَنْ يُعْقِبَهُمْ بِمِثْلِ قِرَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mushaffa Al Himshi] telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Marwan bin Ru`bah At Taghlibi] dari [Abdurrahman bin Abu 'Auf] dari [Al Miqdam bin Ma'dikarib] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Ketahuilah, tidak halal hewan buas yang memiliki taring, keledai jinak, barang temuan dari harta orang kafir Mu'ahad (yang menjalin perjanjian dengan negara Islam) kecuali ia tidak membutuhkannya. Dan siapapun laki-laki yang bertamu kepada suatu kaum dan mereka tidak menjamunya, maka baginya untuk menuntut ganti yang seperti jamuan untuknya.\""},"3232":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ ابْنِ أَبِي عَدِيٍّ عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ عَلِيِّ بْنِ الْحَكَمِ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ وَعَنْ كُلِّ ذِي مِخْلَبٍ مِنْ الطَّيْرِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] dari [Ibnu Abu Adi] dari [Ibnu Abu 'Arubah] dari [Ali bin Al Hakam] dari [Maimun bin Mihran] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Saat perang Khaibar Rasulullah shallallahu 'alaihi wasallam melarang makan daging binatang buas yang memiliki taring dan segala burung yang memiliki cakar.\""},"3233":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنِي أَبُو سَلَمَةَ سُلَيْمَانُ بْنُ سُلَيْمٍ عَنْ صَالِحِ بْنِ يَحْيَى بْنِ الْمِقْدَامِ عَنْ جَدِّهِ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ عَنْ خَالِدِ بْنِ الْوَلِيدِ قَالَغَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْبَرَ فَأَتَتْ الْيَهُودُ فَشَكَوْا أَنَّ النَّاسَ قَدْ أَسْرَعُوا إِلَى حَظَائِرِهِمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا لَا تَحِلُّ أَمْوَالُ الْمُعَاهَدِينَ إِلَّا بِحَقِّهَا وَحَرَامٌ عَلَيْكُمْ حُمُرُ الْأَهْلِيَّةِ وَخَيْلُهَا وَبِغَالُهَا وَكُلُّ ذِي نَابٍ مِنْ السِّبَاعِ وَكُلُّ ذِي مِخْلَبٍ مِنْ الطَّيْرِ","id":"Telah menceritakan kepada kami ['Amru bin Utsman] telah menceritakan kepada kami [Muhammad bin Harb] telah menceritakan kepadaku [Abu Salamah Sulaiman bin Sulaim] dari [Shalih bin Yahya bin Al Miqdam] dari kakeknya [Al Miqdam bin Ma'dikarib] dari [Khalid bin Al Walid] ia berkata, \"Aku pernah mengikuti perang Khaibar bersama Rasulullah shallallahu 'alaihi wasallam, kemudian orang-orang Yahudi datang dan mengeluhkan bahwa kaum Muslimin cepat-cepat menyerbu kandang mereka. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, tidak halal harta orang-orang kafir Mu'ahad (yang memiliki perjanjian damai dengan orang-orang muslim) kecuali dengan haknya, dan haram atas kalian keledai jinak, kuda jinak, dan bighal jinak serta segala binatang buas yang memiliki taring dan segala burung yang memiliki cakar.\""},"3234":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَمُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ عُمَرَ بْنِ زَيْدٍ الصَّنْعَانِيِّ أَنَّهُ سَمِعَ أَبَا الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الْهِرِّ قَالَ ابْنُ عَبْدِ الْمَلِكِ عَنْ أَكْلِ الْهِرِّ وَأَكْلِ ثَمَنِهَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Muhammad bin Abdul Malik] mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] dari [Umar bin Zaid Ash Shan'ani] bahwa ia mendengar [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam telah melarang menjual kucing.\" Ibnu Abdul Malik menyebutkan, \"Memakan daging kucing dan memakan hasil penjualannya.\""},"3235":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَسَنٍ الْمِصِّيصِيُّ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَخْبَرَنِي رَجُلٌ عَنْ جَابِرِ بَنِ عَبْدِ اللَّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ أَنْ نَأْكُلَ لُحُومَ الْحُمُرِ وَأَمَرَنَا أَنْ نَأْكُلَ لُحُومَ الْخَيْلِقَالَ عَمْرٌو فَأَخْبَرْتُ هَذَا الْخَبَرَ أَبَا الشَّعْثَاءِ فَقَالَ قَدْ كَانَ الْحَكَمُ الْغِفَارِيُّ فِينَا يَقُولُ هَذَا وَأَبَى ذَلِكَ الْبَحْرُ يُرِيدُ ابْنَ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Hasan Al Mishshi] telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] telah mengabarkan kepadaku ['Amru bin Dinar] telah mengabarkan kepadaku [seorang laki-laki] dari [Jabir bin Abdullah] ia berkata, \"Saat perang Khaibar Rasulullah shallallahu 'alaihi wasallam melarang dari memakan daging keledai, dan memerintahkan kami agar makan daging kuda.\" 'Amru berkata, \"Aku lalu memberitahukan hadits ini kepada Abu Asy Sya'tsa`, maka ia pun berkata, \"Dahulu Al Hakam Al Ghifari berada di antara kami, ia membolehkannya, namun hal itu ditolak oleh Ibnu Abbas.\""},"3236":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي زِيَادٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ عُبَيْدٍ أَبِي الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ عَنْ غَالِبِ بْنِ أَبْجَرَ قَالَأَصَابَتْنَا سَنَةٌ فَلَمْ يَكُنْ فِي مَالِي شَيْءٌ أُطْعِمُ أَهْلِي إِلَّا شَيْءٌ مِنْ حُمُرٍ وَقَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ لُحُومَ الْحُمُرِ الْأَهْلِيَّةِ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَصَابَتْنَا السَّنَةُ وَلَمْ يَكُنْ فِي مَالِي مَا أُطْعِمُ أَهْلِي إِلَّا سِمَانُ الْحُمُرِ وَإِنَّكَ حَرَّمْتَ لُحُومَ الْحُمُرِ الْأَهْلِيَّةِ فَقَالَ أَطْعِمْ أَهْلَكَ مِنْ سَمِينِ حُمُرِكَ فَإِنَّمَا حَرَّمْتُهَا مِنْ أَجْلِ جَوَّالِ الْقَرْيَةِ يَعْنِي الْجَلَّالَةَقَالَ أَبُو دَاوُد عَبْدُ الرَّحْمَنِ هَذَا هُوَ ابْنُ مَعْقِلٍ قَالَ أَبُو دَاوُد رَوَى شُعْبَةُ هَذَا الْحَدِيثَ عَنْ عُبَيْدٍ أَبِي الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَعْقِلٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بِشْرٍ عَنْ نَاسٍ مِنْ مُزَيْنَةَ أَنَّ سَيِّدَ مُزَيْنَةَ أَبْجَرَ أَوِ ابْنَ أَبْجَرَ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ مِسْعَرٍ عَنْ عُبَيْدٍ عَنْ ابْنِ مَعْقِلٍ عَنْ رَجُلَيْنِ مِنْ مُزَيْنَةَ أَحَدُهُمَا عَنْ الْآخَرِ أَحَدُهُمَا عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ عُوَيْمٍ وَالْآخَرُ غَالِبُ بْنُ الْأَبْجَرِ قَالَ مِسْعَرٌ أَرَى غَالِبًا الَّذِي أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Abdullah bin Abu Ziyad] telah menceritakan kepada kami ['Ubaidullah] dari [Israil] dari [Manshur] dari ['Ubaid Abu Al Hasan] dari [Abdurrahman] dari [Ghalib bin Abhar] ia berkata, \"Kami tertimpa kekeringan, dan di antara hartaku tidak ada sesuatu yang dapat aku gunakan untuk memberi makan keluargaku, kecuali lemak keledai. Sementara Rasulullah shallallahu 'alaihi wasallam telah mengharamkan daging keledai jinak. Lalu aku datang kepada Nabi shallallahu 'alaihi wasallam dan aku katakan, \"Wahai Rasulullah, kami telah tertimpa musim kering, dan tidak ada di antara hartaku sesuatu yang dapat aku gunakan untuk memberi makan keluargaku kecuali lemak keledai, sementara anda telah mengharamkan daging keledai jinak. Kemudian beliau berkata: \"Berilah makan keluargamu dari lemak keledaimu, hanysanya aku haramkan itu karena hewan-hewan yang suka berkeliling kampung (hewan yang suka makan kotoran).\" Abu Daud berkata, \"Abdurrahman ini adalah Ibnu Ma'qil.\" Abu Daud berkata, \" [Syu'bah] meriwayatkan hadits ini dari ['Ubaid Abu Al Hasan] dari [Abdurrahman bin Ma'qil] dari [Abdurrahman bin Bisyr] dari [beberapa orang] yang berasal dari Muzainah, bahwa pemimpin Muzainah [Abjar atau anak Abjar] telah bertanya kepada Nabi shallallahu 'alaihi wasallam….\" Telah menceritakan kepada kami [Muhammad bin Sulaiman] telah menceritakan kepada kami [Abu Nu'aim] dari [Mis'ar] dari ['Ubaid] dari [Abu Ma'qil] dari [dua orang laki-laki] yang berasal dari Muzainah, salah seorang dari mereka (meriwayatkan) dari yang lainnya. Salah seorang mereka adalah [Abdullah bin 'Amru bin 'Uwaim] sedangkan yang lainnya adalah [Ghalib bin Al Abjar] Mis'ar berkata, \"Menurutku Ghalib lah yang datang kepada Nabi shallallahu 'alaihi wasallam, dengan hadits seperti ini.\""},"3237":{"ar":"حَدَّثَنَا سَهْلُ بْنُ بَكَّارٍ حَدَّثَنَا وُهَيْبٌ عَنْ ابْنِ طَاوُسٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ وَعَنْ الْجَلَّالَةِ عَنْ رُكُوبِهَا وَأَكْلِ لَحْمِهَا","id":"Telah menceritakan kepada kami [Sahl bin Bakkar] telah menceritakan kepada kami [Wuhaib] dari [Ibnu Thawus] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] ia berkata, \"Saat perang Khaibar Rasulullah shallallahu 'alaihi wasallam melarang makan daging keledai jinak, menaiki hewan jallalah dan meminum susunya.\" "},"3238":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي يَعْفُورٍ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَىوَسَأَلْتُهُ عَنْ الْجَرَادِ فَقَالَ غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّ أَوْ سَبْعَ غَزَوَاتٍ فَكُنَّا نَأْكُلُهُ مَعَهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namari] telah menceritakan kepada kami [Syu'bah] dari [Abu Ya'fur] ia berkata; aku mendengar [Ibnu Abu Aufa] dan aku tanyakan kepadanya mengenai belalang, kemudian ia menjawab, \"Aku pernah berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak enam atau tujuh kali peperangan, dan kami pernah memakannya bersama beliau.\""},"3239":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْفَرَجِ الْبَغْدَادِيُّ حَدَّثَنَا ابْنُ الزِّبْرِقَانِ حَدَّثَنَا سُلَيْمَانُ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ سَلْمَانَ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَرَادِ فَقَالَ أَكْثَرُ جُنُودِ اللَّهِ لَا آكُلُهُ وَلَا أُحَرِّمُهُقَالَ أَبُو دَاوُد رَوَاهُ الْمُعْتَمِرُ عَنْ أَبِيهِ عَنْ أَبِي عُثْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَذْكُرْ سَلْمَانَ حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ وَعَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى بْنِ عُمَارَةَ عَنْ أَبِي الْعَوَّامِ الْجَزَّارِ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ سَلْمَانَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ فَقَالَ مِثْلَهُ فَقَالَ أَكْثَرُ جُنْدِ اللَّهِ قَالَ عَلِيٌّ اسْمُهُ فَائِدٌ يَعْنِي أَبَا الْعَوَّامِ قَالَ أَبُو دَاوُد رَوَاهُ حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الْعَوَّامِ عَنْ أَبِي عُثْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَذْكُرْ سَلْمَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Faraj Al Baghdadi] telah menceritakan kepada kami [Ibnu Az Zibriqan] telah menceritakan kepada kami [Sulaiman At Tamimi] dari [Abu Utsman An Nahdi] dari [Salman] ia berkata, \"Nabi shallallahu 'alaihi wasallam ditanya mengenai belalang, kemudian beliau bersabda: \"Mereka adalah tentara Allah terbanyak. Aku tidak memakannya dan tidak mengharamkannya.\" Abu Daud berkata, \"Hadits tersebut diriwayatkan oleh [Al Mu'tamir] dari [Ayahnya] dari [Abu Utsman] dari Nabi shallallahu 'alaihi wasallam, namun ia tidak menyebutkan Salman.\" Telah menceritakan kepada kami [Nashr bin Ali] serta [Ali bin Abdullah] mereka berkata; telah menceritakan kepada kami [Zakaria bin Yahya bin 'Umarah] dari [Abu Al 'Awwam Al Hazzar] dari [Abu Utsman An Nahdi] dari [Salman] bahwa Rasulullah shallallahu 'alaihi wasallam ditanya, kemudian beliau mengatakan seperti itu. Beliau bersabda: \"Mereka adalah pasukan Allah yang terbanyak.\" Ali berkata, \"Namanya adalah Faid Abu Al 'Awwam.\" Abu Daud berkata, \"Hadits tersebut diriwayatkan oleh [Hammad bin Salamah] dari [Abu Al 'Awwam] dari [Abu Utsman] dari Nabi shallallahu 'alaihi wasallam, namuan Ia tidak menyebutkan Salman.\""},"3240":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدَةَ حَدَّثَنَا يَحْيَى بْنُ سُلَيْمٍ الطَّائِفِيُّ حَدَّثَنَا إِسْمَعِيلَ بْنُ أُمَيَّةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَلْقَى الْبَحْرُ أَوْ جَزَرَ عَنْهُ فَكُلُوهُ وَمَا مَاتَ فِيهِ وَطَفَا فَلَا تَأْكُلُوهُقَالَ أَبُو دَاوُد رَوَى هَذَا الْحَدِيثَ سُفْيَانُ الثَّوْرِيُّ وَأَيُّوبُ وَحَمَّادٌ عَنْ أَبِي الزُّبَيْرِ أَوْقَفُوهُ عَلَى جَابِرٍ وَقَدْ أُسْنِدَ هَذَا الْحَدِيثُ أَيْضًا مِنْ وَجْهٍ ضَعِيفٍ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin 'Abdah] telah menceritakan kepada kami [Yahya bin Sulaim Ath Thaifi] telah menceritakan kepada kami [Isma'il bin Umayyah] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang didamparkan oleh laut atau yang tersingkap darinya maka makanlah, dan apa yang mati padanya dalam keadaan mengapung maka janganlah engkau makan.\" Abu Daud berkata, \"Hadits tersebut diriwayatkan oleh [Sufyan Ats Tsauri] dan [Ayyub] serta [Hammad] dari [Abu Az Zubair] mereka menyandarkannya kepada Jabir. Dan hadits ini juga di sandarkan dengan sanad yang lemah, dari jalur Ibnu Abu Dzi`b dari Abu Az Zubair dari Jabir dari Nabi shallallahu 'alaihi wasallam.\""},"3241":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ رَجُلًا نَزَلَ الْحَرَّةَ وَمَعَهُ أَهْلُهُ وَوَلَدُهُ فَقَالَ رَجُلٌ إِنَّ نَاقَةً لِي ضَلَّتْ فَإِنْ وَجَدْتَهَا فَأَمْسِكْهَا فَوَجَدَهَا فَلَمْ يَجِدْ صَاحِبَهَا فَمَرِضَتْ فَقَالَتْ امْرَأَتُهُ انْحَرْهَا فَأَبَى فَنَفَقَتْ فَقَالَتْ اسْلُخْهَا حَتَّى نُقَدِّدَ شَحْمَهَا وَلَحْمَهَا وَنَأْكُلَهُ فَقَالَ حَتَّى أَسْأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَاهُ فَسَأَلَهُ فَقَالَ هَلْ عِنْدَكَ غِنًى يُغْنِيكَ قَالَ لَا قَالَ فَكُلُوهَا قَالَ فَجَاءَ صَاحِبُهَا فَأَخْبَرَهُ الْخَبَرَ فَقَالَ هَلَّا كُنْتَ نَحَرْتَهَا قَالَ اسْتَحْيَيْتُ مِنْكَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Simak bin Harb] dari [Jabir bin Samurah] bahwa seorang laki-laki singgah di Harrah bersama dengan anak dan isterinya. Kemudian seorang laki-laki berkata, \"Sesungguhnya untaku telah hilang, apabila engkau mendapatkannya maka tangkaplah!\" Laki-laki itu kemudian mendapatkannya dan tidak mendapati pemiliknya, lalu unta tersebut sakit. Lantas isterinya berkata, \"Sembelihlah unta tersebut!\" Namun suaminya menolak, hingga unta itu pun mati. Isterinya kemudian berkata, \"Kulitilah unta tersebut hingga kita jadikan lemak dan dagingnya menjadi dendeng hingga kita bisa memakannya.\" Suaminya berkata, \"Tidak, hingga aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam.\" Lalu ia datang kepada beliau dan beliau bertanya: \"Apakah engkau memiliki sesuatu yang memberikan kecukupan bagimu?\" Ia berkata, \"Tidak.\" Beliau lalu bersabda: \"Makanlah!\" Jabir bin Samurah berkata, \"Kemudian pemiliknya datang hingga ia pun mengabarkan perihal unta tersebut. Sang pemilik unta lalu berkata, \"Kenapa tidak kamu sembelih?\" laki-laki itu menjawab, \"Aku malu darimu.\""},"3242":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا عُقْبَةُ بْنُ وَهْبِ بْنِ عُقْبَةَ الْعَامِرِيُّ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ الْفُجَيْعِ الْعَامِرِيِّأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا يَحِلُّ لَنَا مِنْ الْمَيْتَةِ قَالَ مَا طَعَامُكُمْ قُلْنَا نَغْتَبِقُ وَنَصْطَبِحُقَالَ أَبُو نُعَيْمٍ فَسَّرَهُ لِي عُقْبَةُ قَدَحٌ غُدْوَةً وَقَدَحٌ عَشِيَّةً قَالَ ذَاكَ وَأَبِي الْجُوعُ فَأَحَلَّ لَهُمْ الْمَيْتَةَ عَلَى هَذِهِ الْحَالِ قَالَ أَبُو دَاوُد الْغَبُوقُ مِنْ آخِرِ النَّهَارِ وَالصَّبُوحُ مِنْ أَوَّلِ النَّهَارِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Al Fadll bin Dukain] telah menceritakan kepada kami ['Uqbah bin Wahb bin 'Uqbah Al 'Amiri] ia berkata; aku mendengar [Ayahku] menceritakan dari [Al Fujai' Al 'Amiri] bahwa ia telah datang kepada Rasulullah shallallahu 'alaihi wasallam dan bertanya, \"Bangkai apakah yang halal bagi kami?\" Beliau menjawab: \"Apakah makanan kalian?\" Kami menjawab, \"Kami minum susu pada satu gelas pada sore hari dan minum satu gelas pada pagi hari.\" Abu Nu'aim berkata, \"Uqbah mentafsirkannya untukku, 'Yaitu satu gelas pada pagi hari dan satu gelas pada sore hari'. Beliau bersabda: \"Ukuran itu tidak cukup dan masih ada rasa lapar.\" Kemudian beliau menghalalkan bangkai bagi mereka dalam keadaan ini.\" Abu Daud berkata, \"Ghabuq adalah dari akhir siang sedangkan shabuh dari awal siang.\""},"3243":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ أَخْبَرَنَا الْفَضْلُ بْنُ مُوسَى عَنْ حُسَيْنِ بْنِ وَاقِدٍ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدِدْتُ أَنَّ عِنْدِي خُبْزَةً بَيْضَاءَ مِنْ بُرَّةٍ سَمْرَاءَ مُلَبَّقَةً بِسَمْنٍ وَلَبَنٍ فَقَامَ رَجُلٌ مِنْ الْقَوْمِ فَاتَّخَذَهُ فَجَاءَ بِهِ فَقَالَ فِي أَيِّ شَيْءٍ كَانَ هَذَا قَالَ فِي عُكَّةِ ضَبٍّ قَالَ ارْفَعْهُقَالَ أَبُو دَاوُد هَذَا حَدِيثٌ مُنْكَرٌ قَالَ أَبُو دَاوُد وَأَيُّوبُ لَيْسَ هُوَ السَّخْتِيَانِيُّ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Aziz bin Abu Rizmah] telah mengabarkan kepada kami [Al Fadll bin Musa] dari [Husain bin Waqid] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berharap memiliki roti putih yang terbuat dari gandum yang dicampur dengan mentega dan susu.\" Kemudian seorang laki-laki dari salah seorang mereka berdiri dan lalu membuatnya uantuk kemudian membawanya kepada beliau. Beliau kemudian bertanya: \"Di tempat apakah mentega ini sebelumnya?\" Laki-laki itu menjawab, \"Berada dalam bejana yang terbuat dari kulit biawak.\" Beliau bersabda: \"Angkatlah makanan tersebut!\" Abu Daud berkata, \"Hadits ini adalah hadits mungkar.\" Abu Daud berkata, \"Ayyub bukanlah As Sakhtinyani.\""},"3244":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى الْبَلْخِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ مَنْصُورٍ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عُمَرَ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجُبْنَةٍ فِي تَبُوكَ فَدَعَا بِسِكِّينٍ فَسَمَّى وَقَطَعَ","id":"Telah menceritakan kepada kami [Yahya bin Musa Al Balkhi] telah menceritakan kepada kami [Ibrahim bin 'Uyainah] dari ['Amru bin Manshur] dari [Asy Sya'bi] dari [Ibnu Umar] ia berkata, \"Nabi shallallahu 'alaihi wasallam diberi keju di Tabuk, kemudian beliau meminta pisau lalu menyebutkan nama Allah dan memotongnya.\""},"3245":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاوِيَةُ بْنُ هِشَامٍ حَدَّثَنَا سُفْيَانُ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ الْإِدَامُ الْخَلُّ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Mu'awiyah bin Hisyam] telah menceritakan kepada kami [Sufyan] dari [Muharib bin Ditsar] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik lauk adalah cuka.\""},"3246":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا الْمُثَنَّى بْنُ سَعِيدٍ عَنْ طَلْحَةَ بْنِ نَافِعٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ الْإِدَامُ الْخَلُّ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] dan [Muslim bin Ibrahim] mereka berkata; telah menceritakan kepada kami [Al Mutsanna bin Sa'id] dari [Thalhah bin Nafi'] dari [Jabir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sebaik-baik lauk adalah cuka.\""},"3247":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَكَلَ ثُومًا أَوْ بَصَلًا فَلْيَعْتَزِلْنَا أَوْ لِيَعْتَزِلْ مَسْجِدَنَا وَلْيَقْعُدْ فِي بَيْتِهِ وَإِنَّهُ أُتِيَ بِبَدْرٍ فِيهِ خَضِرَاتٌ مِنْ الْبُقُولِ فَوَجَدَ لَهَا رِيحًا فَسَأَلَ فَأُخْبِرَ بِمَا فِيهَا مِنْ الْبُقُولِ فَقَالَ قَرِّبُوهَا إِلَى بَعْضِ أَصْحَابِهِ كَانَ مَعَهُ فَلَمَّا رَآهُ كَرِهَ أَكْلَهَا قَالَ كُلْ فَإِنِّي أُنَاجِي مَنْ لَا تُنَاجِيقَالَ أَحْمَدُ بْنُ صَالِحٍ بِبَدْرٍ فَسَّرَهُ ابْنُ وَهْبٍ طَبَقٌ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah menceritakan kepadaku ['Atha bin Abu Rabah] bahwa [Jabir bin Abdullah] berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa makan bawang putih dan bawang merah, maka hendaknya ia menjauhi masjid kami dan duduk di rumahnya.\" Beliau pernah diberi nampan berisi sayur-sayuran hijau. Kemudian beliau mencium bau sesuatu, ketika beliau menanyakan perihal bau tersebut, maka beliau pun diberitahu tentang bau tersebut. Kemudian beliau bersabda: \"Dekatkan!\" yaitu kepada sebagian sahabat yang bersamanya! Kemudian ketika beliau melihat mereka enggan makan, beliau pun bersabda: \"Makanlah, sesungguhnya aku bermunajat kepada Dzat yang engkau tidak bermunajat kepada-Nya.\" Ahmad bin Shalih berkata, \"Badr ditafsirkan Ibnu Wahb dengan nampan.\""},"3248":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو أَنَّ بَكْرَ بْنَ سَوَادَةَ حَدَّثَهُ أَنَّ أَبَا النَّجِيبِ مَوْلَى عَبْدِ اللَّهِ بْنِ سَعْدٍ حَدَّثَهُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ حَدَّثَهُأَنَّهُ ذُكِرَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الثُّومُ وَالْبَصَلُ وَقِيلَ يَا رَسُولَ اللَّهِ وَأَشَدُّ ذَلِكَ كُلُّهُ الثُّومُ أَفَتُحَرِّمُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوهُ وَمَنْ أَكَلَهُ مِنْكُمْ فَلَا يَقْرَبْ هَذَا الْمَسْجِدَ حَتَّى يَذْهَبَ رِيحُهُ مِنْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku ['Amru] bahwa [Bakr bin Sawadah] telah menceritakan kepadanya, bahwa [Abu An Najib] mantan budak Abdullah bin Sa'd menceritakan kepadanya, bahwa [Abu Sa'id Al Khudri] menceritakan kepadanya, bahwa disebutkan bawang putih dan bawang merah di hadapan Rasulullah shallallahu 'alaihi wasallam. Dikatakan, \"Wahai Rasulullah, di antara yang ada, yang paling keras baunya adalah bawang putih. Apakah anda mengharamkannya?\" Nabi shallallahu 'alaihi wasallam bersabda: \"Makanlah, siapa di antara kalian yang telah memakannya, maka janganlah ia mendekati masjid kami hingga baunya hilang.\""},"3249":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الشَّيْبَانِيِّ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ حُذَيْفَةَأَظُنُّهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَفَلَ تُجَاهَ الْقِبْلَةِ جَاءَ يَوْمَ الْقِيَامَةِ تَفْلُهُ بَيْنَ عَيْنَيْهِ وَمَنْ أَكَلَ مِنْ هَذِهِ الْبَقْلَةِ الْخَبِيثَةِ فَلَا يَقْرَبَنَّ مَسْجِدَنَا ثَلَاثًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Asy Syaibani] dari [Adi bin Tsabit] dari [Zirr bin Khubaisy] dari [Hudzaifah] aku mengira dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa meludah ke arah kiblat, maka pada hari kiamat ia akan datang sementara ludahnya ada di antara kedua matanya. Dan barangsiapa makan sebagian dari sayur yang berbau busuk ini, maka janganlah ia mendekati masjid kami!\" Beliau mengatakannya sebanyak tiga kali.\""},"3250":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ فَلَا يَقْرَبَنَّ الْمَسَاجِدَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa makan sebagian dari pohon ini, maka janganlah ia mendekati masjid-masjid!\""},"3251":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا أبُو هِلَالٍ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ عَنْ أَبِي بُرْدَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَأَكَلْتُ ثُومًا فَأَتَيْتُ مُصَلَّى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ سُبِقْتُ بِرَكْعَةٍ فَلَمَّا دَخَلْتُ الْمَسْجِدَ وَجَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رِيحَ الثُّومِ فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاتَهُ قَالَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ فَلَا يَقْرَبَنَّا حَتَّى يَذْهَبَ رِيحُهَا أَوْ رِيحُهُ فَلَمَّا قُضِيَتْ الصَّلَاةُ جِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ لَتُعْطِيَنِّي يَدَكَ قَالَ فَأَدْخَلْتُ يَدَهُ فِي كُمِّ قَمِيصِي إِلَى صَدْرِي فَإِذَا أَنَا مَعْصُوبُ الصَّدْرِ قَالَ إِنَّ لَكَ عُذْرًا","id":"Telah menceritakan kepada kami [Syaiban bin Farrukh] telah menceritakan kepada kami [Abu Hilal] telah menceritakan kepada kami [Humaid bin Hilal] dari [Abu Burdah] dari [Al Mughirah bin Syu'bah] ia berkata, \"Aku pernah makan bawang putih kemudian mendatangi mushalla Nabi shallallahu 'alaihi wasallam, dan aku telah ketinggalan satu rakaat. Saat aku masuk masjid Nabi shallallahu 'alaihi wasallam mencium bau bawang putih, selesai shalat Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Barangsiapa makan sebagian dari pohon ini maka janganlah ia mendekati kami, hingga hilang baunya.\" Selesai shalat aku datang menemui Rasulullah shallallahu 'alaihi wasallam dan aku katakan, \"Wahai Rasulullah, demi Allah! Berikanlah tanganmu kepadaku.\" Aku lalu memasukkan tangan beliau ke dalam lubang pergelangan bajuku hingga menyentuh dadaku. Sementara aku telah mengikat perut bagian dada dengan kain (karena lapar), maka beliau pun bersabda: \"Sesungguhnya engkau memiliki udzur.\""},"3252":{"ar":"حَدَّثَنَا عَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ حَدَّثَنَا أَبُو عَامِرٍ عَبْدُ الْمَلِكِ بْنُ عَمْرٍو حَدَّثَنَا خَالِدُ بْنُ مَيْسَرَةَ يَعْنِي الْعَطَّارَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ هَاتَيْنِ الشَّجَرَتَيْنِ وَقَالَ مَنْ أَكَلَهُمَا فَلَا يَقْرَبَنَّ مَسْجِدَنَا وَقَالَ إِنْ كُنْتُمْ لَا بُدَّ آكِلِيهِمَا فَأَمِيتُوهُمَا طَبْخًاقَالَ يَعْنِي الْبَصَلَ وَالثُّومَ","id":"Telah menceritakan kepada kami [Abbas bin Abdul 'Azhim] telah menceritakan kepada kami [Abu 'Amir Abdul Malik bin 'Amru] telah menceritakan kepada kami [Khalid bin Maisarah Al 'Aththar] dari [Mu'awiyah bin Qurrah] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam telah melarang dari dua pohon ini, beliau bersabda: \"Barangsiapa memakan keduanya maka janganlah ia mendekati masjid kami!\" Dan beliau bersabda: \"Apabila kalian harus memakannya maka hilangkan bau keduanya dengan dimasak!\" Qurrah berkata, \"Yaitu bawang merah dan bawang putih.\""},"3253":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا الْجَرَّاحُ أَبُو وَكِيعٍ عَنْ أَبِي إِسْحَقَ عَنْ شَرِيكٍ عَنْ عَلِيٍّ عَلَيْهِ السَّلَام قَالَنُهِيَ عَنْ أَكْلِ الثُّومِ إِلَّا مَطْبُوخًاقَالَ أَبُو دَاوُد شَرِيكُ بْنُ حَنْبَلٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Al Jarrah Abu Waki'] dari [Abu Ishaq] dari [Syarik] dari [Ali] radliallahu 'anhu, ia berkata, \"Telah dilarang makan bawang putih kecuali dalam keadaan dimasak.\" Abu Daud berkata, \"Syarik bin Hanbal.\""},"3254":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا ح و حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدٍ عَنْ أَبِي زِيَادٍ خِيَارِ بْنِ سَلَمَةَأَنَّهُ سَأَلَ عَائِشَةَ عَنْ الْبَصَلِ فَقَالَتْ إِنَّ آخِرَ طَعَامٍ أَكَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامٌ فِيهِ بَصَلٌ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Haiwah bin Syuraih] telah menceritakan kepada kami [Baqiyyah] dari [Bahir] dari [Khalid] dari [Abu Ziyad Khiyar bin Salamah] bahwa ia pernah bertanya kepada [Aisyah] mengenai bawang merah, lalu ia menjawab, \"Sesungguhnya makanan terakhir yang dimakan Rasulullah shallallahu 'alaihi wasallam adalah makanan yang padanya terdapat bawang merah.\""},"3255":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ أَبِي يَحْيَى عَنْ يَزِيدَ الْأَعْوَرِ عَنْ يُوسُفَ بْنِ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ كِسْرَةً مِنْ خُبْزِ شَعِيرٍ فَوَضَعَ عَلَيْهَا تَمْرَةً وَقَالَ هَذِهِ إِدَامُ هَذِهِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Umar bin Hafsh] telah menceritakan kepada kami [Ayahku] dari [Muhammad bin Abu Yahya] dari [Yazid Al A'war] dari [Yusuf bin Abdullah bin Salam] ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam mengambil pecahan roti yang terbuat dari gandum lalu meletakkan kurma di atasnya, dan beliau bersabda: 'Kurma ini adalah lauk untuk roti ini.\""},"3256":{"ar":"حَدَّثَنَا الْوَلِيدُ بْنُ عُتْبَةَ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنِي هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْتٌ لَا تَمْرَ فِيهِ جِيَاعٌ أَهْلُهُ","id":"Telah menceritakan kepada kami [Al Walid bin 'Utbah] telah menceritakan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepadaku [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Rumah yang tidak ada kurma padanya maka penghuninya adalah orang-orang yang lapar.\""},"3257":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرِو بْنِ جَبَلَةَ حَدَّثَنَا سَلْمُ بْنُ قُتَيْبَةَ أَبُو قُتَيْبَةَ عَنْ هَمَّامٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَمْرٍ عَتِيقٍ فَجَعَلَ يُفَتِّشُهُ يُخْرِجُ السُّوسَ مِنْهُحَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا هَمَّامٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُؤْتَى بِالتَّمْرِ فِيهِ دُودٌ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Amru bin Jabalah] telah menceritakan kepada kami [Salm bin Qutaibah Abu Qutaibah] dari [Hammam] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] ia berkata, \"Nabi shallallahu 'alaihi wasallam diberi kurma 'Atiq, lalu beliau memeriksanya untuk mengeluarkan kutu darinya.\" Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Hammam] dari [Ishaq bin Abdullah bin Abu Thalhah] bahwa Nabi shallallahu 'alaihi wasallam pernah diberi kurma yang padanya terdapat ulat... lalu Abdullah bin Abu Thalhah menyebutkan makna hadits tersebut.\""},"3258":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِي إِسْحَقَ عَنْ جَبَلَةَ بْنِ سُحَيْمٍ عَنْ ابْنِ عُمَرَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْإِقْرَانِ إِلَّا أَنْ تَسْتَأْذِنَ أَصْحَابَكَ","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la] telah menceritakan kepada kami [Ibnu Fudlail] dari [Abu Ishaq] dari [Jabalah bin Suhaim] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah melarang dari iqran (makan kurma dua, dua) kecuali engkau meminta izin para sahabatmu (yang makan bersama).\""},"3259":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْكُلُ الْقِثَّاءَ بِالرُّطَبِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namari] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ayahnya] dari [Abdullah bin Ja'far] bahwa Nabi shallallahu 'alaihi wasallam pernah makan mentimun dengan ruthab (kurma segar).\""},"3260":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ نُصَيْرٍ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الْبِطِّيخَ بِالرُّطَبِ فَيَقُولُ نَكْسِرُ حَرَّ هَذَا بِبَرْدِ هَذَا وَبَرْدَ هَذَا بِحَرِّ هَذَا","id":"Telah menceritakan kepada kami [Sa'id bin Nushair] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah makan labu dengan kurma segar. Kemudian beliau bersabda: \"Kita menghilangkan panas ini dengan dinginnya ini, dan dingin ini dengan panas ini.\""},"3261":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْوَزِيرِ حَدَّثَنَا الْوَلِيدُ بْنُ مَزْيَدَ قَالَ سَمِعْتُ ابْنَ جَابِرٍ قَال�� حَدَّثَنِي سُلَيْمُ بْنُ عَامِرٍ عَنْ ابْنَيْ بُسْرٍ السُّلَمِيَّيْنِ قَالَادَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدَّمْنَا زُبْدًا وَتَمْرًا وَكَانَ يُحِبُّ الزُّبْدَ وَالتَّمْرَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Wazir] telah menceritakan kepada kami [Al Walid bin Mazyad] ia berkata; aku mendengar [Ibnu Jabir] berkata; telah menceritakan kepadaku [Sulaim bin 'Amir] dari [dua anak] [Busr As Sulami] mereka berkata, \"Rasulullah shallallahu 'alaihi wasallam menemui kami, lalu kami menghidangkan keju dan kurma, dan beliau menyukai keduanya.\""},"3262":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى وَإِسْمَعِيلُ عَنْ بُرْدِ بْنِ سِنَانٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَكُنَّا نَغْزُو مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنُصِيبُ مِنْ آنِيَةِ الْمُشْرِكِينَ وَأَسْقِيَتِهِمْ فَنَسْتَمْتِعُ بِهَا فَلَا يَعِيبُ ذَلِكَ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] dan [Isma'il] dari [Burd bin Sinan] dari ['Atha] dari [Jabir] ia berkata, \"Dahulu kami pernah berperang bersama Rasulullah shallallahu 'alaihi wasallam, lalu kami mendapatkan bejana orang-orang musyrik dan tempat minum mereka. Lalu kami menggunakannya dan beliau tidak mencela mereka.\""},"3263":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَاصِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ بْنِ زَبْرٍ عَنْ أَبِي عُبَيْدِ اللَّهِ مُسْلِمِ بْنِ مِشْكَمٍ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّأَنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّا نُجَاوِرُ أَهْلَ الْكِتَابِ وَهُمْ يَطْبُخُونَ فِي قُدُورِهِمْ الْخِنْزِيرَ وَيَشْرَبُونَ فِي آنِيَتِهِمْ الْخَمْرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ وَجَدْتُمْ غَيْرَهَا فَكُلُوا فِيهَا وَاشْرَبُوا وَإِنْ لَمْ تَجِدُوا غَيْرَهَا فَارْحَضُوهَا بِالْمَاءِ وَكُلُوا وَاشْرَبُوا","id":"Telah menceritakan kepada kami [Nashr bin 'Ashim] telah menceritakan kepada kami [Muhammad bin Syu'aib] telah mengabarkan kepada kami [Abdullah bin Al 'Ala bin Zabr] dari [Abu 'Ubaidullah Muslim bin Misykam] dari [Abu Tsa'labah Al Khusyani] bahwa ia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Sesungguhnya kami bertetangga dengan orang ahli kitab sementara mereka merebus babi di dalam kuali mereka dan minum khamr dalam bejana mereka?\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kalian mendapatkan selainnya maka makan dan minumlah padanya, dan apabila kalian tidak mendapatkan selainnya maka cucilah menggunakan air dan makan serta minumlah!\""},"3264":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَبَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَّرَ عَلَيْنَا أَبَا عُبَيْدَةَ بْنَ الْجَرَّاحِ نَتَلَقَّى عِيرًا لِقُرَيْ��ٍ وَزَوَّدَنَا جِرَابًا مِنْ تَمْرٍ لَمْ نَجِدْ لَهُ غَيْرَهُ فَكَانَ أَبُو عُبَيْدَةَ يُعْطِينَا تَمْرَةً تَمْرَةً كُنَّا نَمُصُّهَا كَمَا يَمُصُّ الصَّبِيُّ ثُمَّ نَشْرَبُ عَلَيْهَا مِنْ الْمَاءِ فَتَكْفِينَا يَوْمَنَا إِلَى اللَّيْلِ وَكُنَّا نَضْرِبُ بِعِصِيِّنَا الْخَبَطَ ثُمَّ نَبُلُّهُ بِالْمَاءِ فَنَأْكُلُهُ وَانْطَلَقْنَا عَلَى سَاحِلِ الْبَحْرِ فَرُفِعَ لَنَا كَهَيْئَةِ الْكَثِيبِ الضَّخْمِ فَأَتَيْنَاهُ فَإِذَا هُوَ دَابَّةٌ تُدْعَى الْعَنْبَرَ فَقَالَ أَبُو عُبَيْدَةَ مَيْتَةٌ وَلَا تَحِلُّ لَنَا ثُمَّ قَالَ لَا بَلْ نَحْنُ رُسُلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي سَبِيلِ اللَّهِ وَقَدْ اضْطُرِرْتُمْ إِلَيْهِ فَكُلُوا فَأَقَمْنَا عَلَيْهِ شَهْرًا وَنَحْنُ ثَلَاثُ مِائَةٍ حَتَّى سَمِنَّا فَلَمَّا قَدِمْنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرْنَا ذَلِكَ لَهُ فَقَالَ هُوَ رِزْقٌ أَخْرَجَهُ اللَّهُ لَكُمْ فَهَلْ مَعَكُمْ مِنْ لَحْمِهِ شَيْءٌ فَتُطْعِمُونَا مِنْهُ فَأَرْسَلْنَا مِنْهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكَلَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutus kami dan menjadikan Abu 'Ubaidah bin Al Jarrah sebagai pemimpin untuk menghadang rombongan pedagang Quraisy, beliau membekali kami dengan sekantung kurma yang kami tidak mengetahui beliau mempuyai kurma selain itu. Abu Ubaidah lalu membagikan kepada kami setiap satu butir untuk satu orang, dan kami hanya mengulum kurma tersebut sebagaimana seorang bayi mengulum. Kemudian kami minum air yang ada padanya, maka kurma tersebut cukup bagi kami pada hari itu hingga malam hari. Dan kami menggugurkan daun menggunakan tongkat kami, lalu kami membasahinya menggunakan air dan memakannya. Kami pergi ke tepi laut, kemudian kami mendapati sesuatu yang bentuknya seperti gundukan pasir yang besar. Kemudian kami mendatanginya, ternyata benda tersebut adalah hewan yang disebut paus. Abu 'Ubaidah berkata, \"Itu adalah bangkai, tidak halal bagi kita!\" Kemudian ia berkata, \"Tidak, melainkan kita adalah para utusan Rasulullah shallallahu 'alaihi wasallam, dan berada di jalan Allah. Kalian dalam keadaan terdesak untuk memakannya, maka makanlah!\" Kami kemudian memakannya selama satu bulan sedangkan jumlah kami adalah tiga ratus orang, hingga kami menjadi gemuk. Kemudian tatkala kami sampai kepada Rasulullah shallallahu 'alaihi wasallam, maka hal tersebut kami ceritakan kepada beliau. Beliau lalu bersabda: \"Itu adalah rizki yang telah Allah keluarkan untuk kalian. Apakah kalian membawa sebagian dagingnya, hingga kalian berikan kepada kami?\" Kemudian kami mengirimkan sebagiannya kepada Rasulullah shallallahu 'alaihi wasallam, dan beliau pun menerimanya.\""},"3265":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَأَنَّ فَأْرَةً وَقَعَتْ فِي سَمْنٍ فَأُخْبِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلْقُوا مَا حَوْلَهَا وَكُلُوا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dari ['Ubaidillah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah] bahwa ada seekor tikus yang jatuh ke dalam mentega, lalu aku beritahukan kepada Nabi shallallahu 'alaihi wasallam. Kemudian beliau bersabda: \"Buanglah sekitarnya dan makanlah!\""},"3266":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَالْحَسَنُ بْنُ عَلِيٍّ وَاللَّفْظُ لِلْحَسَنِ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَقَعَتْ الْفَأْرَةُ فِي السَّمْنِ فَإِنْ كَانَ جَامِدًا فَأَلْقُوهَا وَمَا حَوْلَهَا وَإِنْ كَانَ مَائِعًا فَلَا تَقْرَبُوهُقَالَ الْحَسَنُ قَالَ عَبْدُ الرَّزَّاقِ وَرُبَّمَا حَدَّثَ بِهِ مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ بُوذَوَيْهِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيِّبِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] dan [Al Hasan bin Ali] lafazh hadits ini adalah lafazh Al Hasan, mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika ada tikus jatuh ke dalam mentega, jika mentega tersebut beku maka buanglah tikus tersebut dan yang ada di sekitarnya, namun jika mentega tersebut cair maka jangan engkau dekati (ambil).\" [Al Hasan] berkata, \" [Abdurrazzaq] berkata, \"Terkadang [Ma'mar] meriwayatkan hadits tersebut dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah] dari Nabi shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Abdurrahman bin Budzawaih] dari [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah] dari Nabi shallallahu 'alaihi wasallam dengan hadits seperti hadits Az Zuhri, dari Ibnu Al Musayyab.\""},"3267":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وَقَعَ الذُّبَابُ فِي إِنَاءِ أَحَدِكُمْ فَامْقُلُوهُ فَإِنَّ فِي أَحَدِ جَنَاحَيْهِ دَاءً وَفِي الْآخَرِ شِفَاءً وَإِنَّهُ يَتَّقِي بِجَنَاحِهِ الَّذِي فِيهِ الدَّاءُ فَلْيَغْمِسْهُ كُلُّهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] dari [Ibnu 'Ajlan] dari [Sa'id Al Maqburi] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika ada lalat jatuh ke dalam bejana salah seorang dari kalian maka celupkanlah lalat tersebut, karena sesungguhnya di dalam salah satu sayapnya terdapat penyakit dan pada sayap yang lain terdapat obat. Sesungguhnya lalat tersebut melindungi diri dengan sayap yang padanya terdapat penyakit, maka celupkanlah semuannya!\""},"3268":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَكَلَ طَعَامًا لَعِقَ أَصَابِعَهُ الثَّلَاثَ وَقَالَ إِذَا سَقَطَتْ لُقْمَةُ أَحَدِكُمْ فَلْيُمِطْ عَنْهَا الْأَذَى وَلْيَأْكُلْهَا وَلَا يَدَعْهَا لِلشَّيْطَانِ وَأَمَرَنَا أَنْ نَسْلُتَ الصَّحْفَةَ وَقَالَ إِنَّ أَحَدَكُمْ لَا يَدْرِي فِي أَيِّ طَعَامِهِ يُبَارَكُ لَهُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam jika makan makanan, beliau menjilat jari-jarinya sebanyak tiga kali, beliau bersabda: \"Jika suapan salah seorang dari kalian jatuh, maka hendaknya ia membersihkannya dari kotoran dan memakannya, dan janganlah ia membiarkannya untuk setan!\" Dan beliau memerintahkan kami agar mengusap piring. Beliau bersabda: \"Sesungguhnya tidak seorangpun di antara kalian mengetahui dibagian makanan makanakah ia diberi berkah.\""},"3269":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ مُوسَى بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَنَعَ لِأَحَدِكُمْ خَادِمُهُ طَعَامًا ثُمَّ جَاءَهُ بِهِ وَقَدْ وَلِيَ حَرَّهُ وَدُخَانَهُ فَلْيُقْعِدْهُ مَعَهُ لِيَأْكُلَ فَإِنْ كَانَ الطَّعَامُ مَشْفُوهًا فَلْيَضَعْ فِي يَدِهِ مِنْهُ أَكْلَةً أَوْ أَكْلَتَيْنِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] telah menceritakan kepada kami [Daud bin Qais] dari [Musa bin Yasar] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila pembantu salah seorang di antara kalian membuatkan makanan untuknya kemudian ia datang membawa makanan tersebut kepadanya, sementara pembantu tersebut telah merasakan panas dan terkena asapnya maka hendaknya ia memintanya agar duduk untuk makan bersamanya. Apabila makakan tersebut sedikit maka hendaknya ia meletakkan di tangannya satu atau dua suap.\""},"3270":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَكَلَ أَحَدُكُمْ فَلَا يَمْسَحَنَّ يَدَهُ بِالْمِنْدِيلِ حَتَّى يَلْعَقَهَا أَوْ يُلْعِقَهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] dari ['Atha] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorangii kalian makan, maka janganlah ia usap tangannya menggunakan sapu tangan hingga ia menjilatnya atau menjilatkannya!\""},"3271":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعْدٍ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْكُلُ بِثَلَاثِ أَصَابِعَ وَلَا يَمْسَحُ يَدَهُ حَتَّى يَلْعَقَهَا","id":"Telah menceritakan kepada kami [An Nufaili] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam bin 'Urwah] dari [Abdurrahman bin Sa'dan] dari [Ibnu Ka'b bin Malik] dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam makan menggunakan tiga jari, dan tidak mengusap tangannya hingga beliau menjilatnya.\""},"3272":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ثَوْرٍ عَنْ خَالِدِ بَنِ مَعْدَانَ عَنْ أَبِي أُمَامَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رُفِعَتْ الْمَائِدَةُ قَالَ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ غَيْرَ مَكْفِيٍّ وَلَا مُوَدَّعٍ وَلَا مُسْتَغْنًى عَنْهُ رَبُّنَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Tsaur] dari [Khalid bin Ma'dan] dari [Abu Umamah] ia berkata, \"Jika selesai makan Rasulullah shallallahu 'alaihi wasallam membaca doa: 'ALHAMDULILLAAHI HAMDAN KATSIIRAN THAYYIBAN MUBAARAKAN FIIHI GHAIRA MAKFIYYIN WA LAA MUWADDA'IN WA LAA MUSTAGHNAN 'ANHU RABBUNAA (Segala puji bagi Allah, dengan pujian yang banyak, baik dan mendapatkan berkah padanya tidak cukup hanya itu, dan tidak terputus, serta senantiasa butuh kepadanya, wahai Tuhan kami) '.\""},"3273":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي هَاشِمٍ الْوَاسِطِيِّ عَنْ إِسْمَعِيلَ بْنِ رَبَاحٍ عَنْ أَبِيهِ أَوْ غَيْرِهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا فَرَغَ مِنْ طَعَامِهِ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَطْعَمَنَا وَسَقَانَا وَجَعَلَنَا مُسْلِمِينَ","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Hasyim Al Wasithi] dari [Isma'il bin Rabah] dari [Ayahnya atau selainnya] dari [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam jika selesai makan beliau mengucapkan: 'Al HAMDULILLAAHILLADZII ATH'AMANAA WA SAQAANAA WA JA'ALANAA MUSLIMIIN (Segala puji bagi Allah Yang telah memberi makan serta minum kami dan menjadikan kami orang-orang muslim) '.\""},"3274":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ أَبِي عَقِيلٍ الْقُرَشِيِّ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَكَلَ أَوْ شَرِبَ قَالَ الْحَمْدُ لِل��َهِ الَّذِي أَطْعَمَ وَسَقَى وَسَوَّغَهُ وَجَعَلَ لَهُ مَخْرَجًا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Sa'id bin Abu Ayyub] dari [Abu 'Aqil Al Qurasyi] dari [Abu Abdurrahman Al Hubuli] dari [Abu Ayyub Al Anshari] ia berkata, \"Jika Rasulullah shallallahu 'alaihi wasallam selesai dari makan atau minum, beliau mengucapkan: 'Al HAMDULILLAAHILLADZII ATH'AMA WA SAQAA WA SAWWAGHAHU WA JA'ALA LAHU MAKHRAJAN (Segala puji bagi Allah Yang telah memberi makan dan minum, memudahkan saat menelan dan menjadikan baginya tempat keluar) '.\""},"3275":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سُهَيْلُ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ وَفِي يَدِهِ غَمَرٌ وَلَمْ يَغْسِلْهُ فَأَصَابَهُ شَيْءٌ فَلَا يَلُومَنَّ إِلَّا نَفْسَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tidur dan di tangannya terdapat lemak daging yang belum ia bersihkan kemudian mengenai sesuatu, maka janganlah ia mencela kecuali kepada dirinya sendiri!\""},"3276":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ يَزِيدَ أَبِي خَالِدٍ الدَّالَانِيِّ عَنْ رَجُلٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَصَنَعَ أَبُو الْهَيْثَمِ بْنُ التَّيْهَانِ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا فَدَعَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ فَلَمَّا فَرَغُوا قَالَ أَثِيبُوا أَخَاكُمْ قَالُوا يَا رَسُولَ اللَّهِ وَمَا إِثَابَتُهُ قَالَ إِنَّ الرَّجُلَ إِذَا دُخِلَ بَيْتُهُ فَأُكِلَ طَعَامُهُ وَشُرِبَ شَرَابُهُ فَدَعَوْا لَهُ فَذَلِكَ إِثَابَتُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Sufyan] dari [Yazid Abu Khalid Abu Daud Dalani] dari [seorang laki-laki] dari [Jabir bin Abdullah] ia berkata, \"Abu Al Haitsam bin At Taihan membuatkan makanan untuk Nabi shallallahu 'alaihi wasallam, kemudian ia mengundang Nabi shallallahu 'alaihi wasallam dan para sahabatnya. Ketika telah selesai beliau bersabda: \"Balaslah saudaramu!\" Para sahabat bertanya, \"Wahai Rasulullah, bagaimana membalasnya?\" Beliau menjawab: \"Sesungguhnya seseorang apabila dimasuki rumahnya kemudian dimakan makanannya serta diminum minumannya lalu mereka mendoakan untuknya, maka itulah balasan kepadanya.\""},"3277":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ إِلَى سَعْدِ بْنِ عُبَادَةَ فَجَاءَ بِخُبْزٍ وَزَيْتٍ فَأَكَلَ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْطَرَ عِنْدَكُمْ الصَّائِمُونَ وَأَكَلَ طَعَامَكُمْ الْأَبْرَارُ وَصَلَّتْ عَلَيْكُمْ الْمَلَائِكَةُ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Tsabit] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam datang kepada Sa'd bin 'Ubadah, lalu Sa'd menyuguhkan roti dan minyak samin. Nabi shallallahu 'alaihi wasallam kemudian memakannya, setelah itu beliau bersabda: \"Telah berbuka di rumahmu orang-orang yang berpuasa, dan telah makan makananmu orang-orang yang baik, dan bershalawat kepadamu para Malaikat.\""},"3278":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابَهُ كَأَنَّمَا عَلَى رُءُوسِهِمْ الطَّيْرُ فَسَلَّمْتُ ثُمَّ قَعَدْتُ فَجَاءَ الْأَعْرَابُ مِنْ هَا هُنَا وَهَا هُنَا فَقَالُوا يَا رَسُولَ اللَّهِ أَنَتَدَاوَى فَقَالَ تَدَاوَوْا فَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَمْ يَضَعْ دَاءً إِلَّا وَضَعَ لَهُ دَوَاءً غَيْرَ دَاءٍ وَاحِدٍ الْهَرَمُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namari] telah menceritakan kepada kami [Syu'bah] dari [Ziyad bin 'Ilaqah] dari [Usamah bin Syarik] ia berkata, \"Aku pernah mendatangi Nabi shallallahu 'alaihi wasallam dan para sahabatnya, dan seolah-olah di atas kepala mereka terdapat burung. Aku kemudian mengucapkan salam dan duduk, lalu ada seorang Arab badui datang dari arah ini dan ini, mereka lalu berkata, \"Wahai Rasulullah, apakah boleh kami berobat?\" Beliau menjawab: \"Berobatlah, sesungguhnya Allah 'azza wajalla tidak menciptakan penyakit melainkan menciptakan juga obatnya, kecuali satu penyakit, yaitu pikun.\""},"3279":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو دَاوُدَ وَأَبُو عَامِرٍ وَهَذَا لَفْظُ أَبِي عَامِرٍ عَنْ فُلَيْحِ بْنِ سُلَيْمَانَ عَنْ أَيُّوبَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ صَعْصَعَةَ الْأَنْصَارِيِّ عَنْ يَعْقُوبَ بْنِ أَبِي يَعْقُوبَ عَنْ أُمِّ الْمُنْذِرِ بِنْتِ قَيْسٍ الْأَنْصَارِيَّةِ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَهُ عَلِيٌّ عَلَيْهِ السَّلَام وَعَلِيٌّ نَاقِهٌ وَلَنَا دَوَالِي مُعَلَّقَةٌ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ مِنْهَا وَقَامَ عَلِيٌّ لِيَأْكُلَ فَطَفِقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِعَلِيٍّ مَهْ إِنَّكَ نَاقِهٌ حَتَّى كَفَّ عَلِيٌّ عَلَيْهِ السَّلَام قَالَتْ وَصَنَعْتُ شَعِيرًا وَسِلْقًا فَجِئْتُ بِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَلِيُّ أَصِبْ مِنْ هَذَا فَهُوَ أَنْفَعُ لَكَقَالَ أَبُو دَاوُد قَالَ هَارُونُ الْعَدَوِيَّةَ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Abu Daud] dan [Abu 'Amir] hadits ini adalah lafazh Abu 'Amir, dari [Fulaih bin Sulaiman] dari [Ayyub bin Abdurrahman bin Sha'sha'ah Al Anshari] dari [Ya'qub bin Abu Ya'qub] dari [Ummu Al Mundzir binti Qais Al Anshariyyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemuiku bersama Ali radliallahu 'anhu, sementara Ali yang sedang sakit. Saat itu kami memiliki buah kurma yang tergantung, Rasulullah shallallahu 'alaihi wasallam lalu berdiri dan makan sebagian darinya. Ketika Ali berdiri untuk makan, Rasulullah shallallahu 'alaihi wasallam berkata kepada Ali: \"Tahanlah, sesungguhnya engkau baru saja sembuh dari sakit!\" Hingga Ali menahan diri.\" Ummu Al Mundzir berkata, \"Aku lalu masak gandum dan rebusan sayur. Setelah itu aku membawanya dan Rasulullah shallallahu 'alaihi wasallam pun berkata: \"Wahai Ali, makanlah dari makanan ini, makanan tersebut lebih bermanfaat bagimu.\" Abu Daud berkata, \"Harun berkata, \"Ia adalah Ummu Al Mundzir Al Anshariyyah Al 'Adawiyyah.\""},"3280":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرِةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ كَانَ فِي شَيْءٍ مِمَّا تَدَاوَيْتُمْ بِهِ خَيْرٌ فَالْحِجَامَةُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila ada sesuatu yang lebih baik untuk kalian gunakan berobat, maka sesuatu tersebut adalah bekam.\""},"3281":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْوَزِيرِ الدِّمَشْقِيُّ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ حَسَّانَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الْمَوَالِي حَدَّثَنَا فَائِدٌ مَوْلَى عُبَيْدِ اللَّهِ بْنِ عَلِيِّ بْنِ أَبِي رَافِعٍ عَنْ مَوْلَاهُ عُبَيْدِ اللَّهِ بْنِ عَلِيِّ بْنِ ��َبِي رَافِعٍ عَنْ جَدَّتِهِ سَلْمَى خَادِمِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْمَا كَانَ أَحَدٌ يَشْتَكِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعًا فِي رَأْسِهِ إِلَّا قَالَ احْتَجِمْ وَلَا وَجَعًا فِي رِجْلَيْهِ إِلَّا قَالَ اخْضِبْهُمَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Wazir Ad Dimasyqi] telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Abdurrahman bin Abu Al Mawali] telah menceritakan kepada kami [Faid] mantan budak 'Ubaidullah bin Ali bin Abu Rafi', dari [Ubaidullah bin Abu Rafi'] dari neneknya [Salma] pelayan Rasulullah shallallahu 'alaihi wasallam, Ia berkata, \"Tidak ada seorangpun yang mengeluhkan penyakit kepada Rasulullah shallallahu 'alaihi wasallam pada kepalanya melainkan beliau berkata: \"Berbekamlah!\" Dan tidaklah ia mengeluhkan sakit pada kedua kakinya melainkan beliau berkata: \"Warnailah dengan pacar!\""},"3282":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ وَكَثِيرُ بْنُ عُبَيْدٍ قَالَا حَدَّثَنَا الْوَلِيدُ عَنْ ابْنِ ثَوْبَانَ عَنْ أَبِيهِ عَنْ أَبِي كَبْشَةَ الْأَنْمَارِيِّقَالَ كَثِيرٌ إِنَّهُ حَدَّثَهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَحْتَجِمُ عَلَى هَامَتِهِ وَبَيْنَ كَتِفَيْهِ وَهُوَ يَقُولُ مَنْ أَهْرَاقَ مِنْ هَذِهِ الدِّمَاءِ فَلَا يَضُرُّهُ أَنْ لَا يَتَدَاوَى بِشَيْءٍ لِشَيْءٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] dan [Katsir bin 'Ubaid] mereka berkata; telah menceritakan kepada kami [Al Walid] dari [Ibnu Tsauban] dari [Abu Kabsyah Al Anmari] [Katsir] berkata, \"Sesungguhnya ia telah meriwayatkannya bahwa Nabi shallallahu 'alaihi wasallam berbekam pada kepalanya, dan di antara kedua pundanya. Beliau bersabda: \"Barangsiapa mengalirkan sebagian dari darah ini, maka ia tidak akan terkena bahaya sekiranya tidak berobat dengan sesuatu, untuk suatu penyakit tertentu.\""},"3283":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ ثَلَاثًا فِي الْأَخْدَعَيْنِ وَالْكَاهِلِقَالَ مُعَمَّرٌ احْتَجَمْتُ فَذَهَبَ عَقْلِي حَتَّى كُنْتُ أُلَقَّنُ فَاتِحَةَ الْكِتَابِ فِي صَلَاتِي وَكَانَ احْتَجَمَ عَلَى هَامَتِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam pernah berbekam pada tiga tempat; pada kedua urat leher dan kahil (bagian punggung antara dua pundak).\" Mu'ammar berkata, \"Ketika aku berbekam, akalku kemudian hilang hingga aku dibacakan Surat Al Fatihah dalam shalatku.\" Mu'ammar berbekam pada kepalanya. "},"3284":{"ar":"حَدَّثَنَا أَبُو تَوْبَةَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْجُمَحِيُّ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ احْتَجَمَ لِسَبْعَ عَشْرَةَ وَتِسْعَ عَشْرَةَ وَإِحْدَى وَعِشْرِينَ كَانَ شِفَاءً مِنْ كُلِّ دَاءٍ","id":"Telah menceritakan kepada kami [Abu Taubah Ar Rabi' bin Nafi'] telah menceritakan kepada kami [Sa'id bin Abdurrahman Al Jumahi] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berbekam pada tanggal tujuh belas, sembilan belas dan dua puluh satu, maka bekam tersebut menjadi obat dari segala penyakit.\""},"3285":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ أَخْبَرَنِي أَبُو بَكْرَةَ بَكَّارُ بْنُ عَبْدِ الْعَزِيزِ أَخْبَرَتْنِي عَمَّتِي كَبْشَةُ بِنْتُ أَبِي بَكْرَةَ وَقَالَ غَيْرُ مُوسَى كَيِّسَةُ بِنْتُ أَبِي بَكْرَةَأَنَّ أَبَاهَا كَانَ يَنْهَى أَهْلَهُ عَنْ الْحِجَامَةِ يَوْمَ الثُّلَاثَاءِ وَيَزْعُمُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ يَوْمَ الثُّلَاثَاءِ يَوْمُ الدَّمِ وَفِيهِ سَاعَةٌ لَا يَرْقَأُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah mengabarkan kepadaku [Abu Bakrah Bakkar bin Abdul Aziz] telah mengabarkan kepadaku bibiku [Kabsyah binti Abu Bakrah] -dan selain Musa berkata; Ia adalah Kayyisah binti Abu Bakrah-, bahwa [Ayahnya] melarang keluarganya untuk melakukan bekam pada hari Selasa, dan ia mengaku berasal dari Rasulullah shallallahu 'alaihi wasallam bahwa hari Selasa adalah hari yang tubuh banyak mengandung darah, dan tidak terputus (aliran darah dalam pembuluh sangat kuat).\""},"3286":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ عَلَى وِرْكِهِ مِنْ وَثْءٍ كَانَ بِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam berbekam pada sisi pantatnya karena penyakit cacar yang beliau derita.\""},"3287":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَبَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أُبَيٍّ طَبِيبًا فَقَطَعَ مِنْهُ عِرْقًا","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata, \"Nabi shallallahu 'alaihi wasallam mengutus seorang dokter kepada Ubai, kemudian dokter tersebut memotong uratnya.\""},"3288":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمُّادٌ عَنْ ثَابِتٍ عَنْ مُطَرِّفٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْكَيِّ فَاكْتَوَيْنَا فَمَا أَفْلَحْنَ وَلَا أَنْجَحْنَقَالَ أَبُو دَاوُد وَكَانَ يَسْمَعُ تَسْلِيمَ الْمَلَائِكَةِ فَلَمَّا اكْتَوَى انْقَطَعَ عَنْهُ فَلَمَّا تَرَكَ رَجَعَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Mutharrif] dari [Imran bin Hushain] ia berkata, \"Nabi shallallahu 'alaihi wasallam melarang dari kay (pengobatan dengan sengatan besi panas), kemudian kami melakukan kay, maka kay itu tidak beruntung dan tidak berhasil.\" Abu Daud berkata, \"Rasulullah shallallahu 'alaihi wasallam mendengar salam para Malaikat, ketika beliau melakukan kay suara itu hilang, dan ketika beliau meninggalkan pengobatan kay, beliau dapat mendengar suara Malaikat kembali.\""},"3289":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَوَى سَعْدَ بْنَ مُعَاذٍ مِنْ رَمِيَّتِهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Abu Az Zubair] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam pernah melakukan pengobatan kay untuk Sa'd bin Mu'adz karena luka panah yang ia derita.\""},"3290":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَقَ حَدَّثَنَا وُهَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَعَطَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepadaku [Ahmad bin Ishaq] telah menceritakan kepada kami [Wuhaib] dari [Abdullah bin Thawus] dari [Ayahnya] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam memakai obat yang dimasukkan ke hidung.\""},"3291":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا عَقِيلُ بْنُ مَعْقِلٍ قَالَ سَمِعْتُ وَهْبَ بْنَ مُنَبِّهٍ يُحَدِّثُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النُّشْرَةِ فَقَالَ هُوَ مِنْ عَمَلِ الشَّيْطَانِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami ['Aqil bin Ma'qil] ia berkata; aku pernah mendengar [Wahb bin Munabbih] menceritakan dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah ditanya mengenai nusyrah (jampi), kemudian beliau menjawab: \"Itu adalah perbuatan setan.\""},"3292":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ بْنِ مَيْسَرَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يِزِيدَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنَا شُرَحْبِيلُ بْنُ يَزِيدَ الْمُعَافِرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ رَافِعٍ التَّنُوخِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا أُبَالِي مَا أَتَيْتُ إِنْ أَنَا شَرِبْتُ تِرْيَاقًا أَوْ تَعَلَّقْتُ تَمِيمَةً أَوْ قُلْتُ الشِّعْرَ مِنْ قِبَلِ نَفْسِيقَالَ أَبُو دَاوُد هَذَا كَانَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاصَّةً وَقَدْ رَخَّصَ فِيهِ قَوْمٌ يَعْنِي التِّرْيَاقَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Umar bin Maisarah] telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] telah menceritakan kepada kami [Syurahbil bin Yazid Al Mu'afiri] dari [Abdurrahman bin Rafi' At Tanukhi] ia berkata; aku pernah mendengar [Abdullah bin 'Amru] berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika aku minum tiryaq (penawar racun), aku tidak peduli dengan yang aku lakukan; menggantungkan jimat atau mengucapkan kata-kata syair dari diriku.\" Abu Daud berkata, \"Ini khusus untuk Nabi shallallahu 'alaihi wasallam, namun sebagian orang memberikan keringanan dalam hal itu, yakni saat minum obat penghilang racun.\""},"3293":{"ar":"قَالَ لَنَا حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ مُجَاهِدٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الدَّوَاءِ الْخَبِيثِ","id":"Ia telah berkata kepada kami; telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Mujahid] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang mengunakan obat yang telah diharamkan.\""},"3294":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثيِرٍ أَخْبَرَنَا سُفْيَانُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ خَالِدٍ عَنْ سَعِيدِ بْنِ الْمُسَيِّبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَأَنَّ طَبِيبًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ضِفْدَعٍ يَجْعَلُهَا فِي دَوَاءٍ فَنَهَاهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَتْلِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Ibnu Abu Dzi`b] dari [Sa'id bin Khalid] dari [Sa'id bin Al Musayyab] dari [Abdurrahman bin Utsman] bahwa seorang dokter pernah bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai katak yang ia jadikan sebagai campuran obat. Kemudian Nabi shallallahu 'alaihi wasallam melarang dari membunuhnya.\""},"3295":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَسَا سُمًّا فَسُمُّهُ فِي يَدِهِ يَتَحَسَّاهُ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meneguk racun, maka di neraka Jahannam ia akan meneguk racun yang ada di tangannya tersebut, ia kekal di dalamnya selama-lamanya.\""},"3296":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ ذَكَرَ طَارِقُ بْنُ سُوَيْدٍ أَوْ سُوَيْدُ بْنُ طَارِقٍسَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَمْرِ فَنَهَاهُ ثُمَّ سَأَلَهُ فَنَهَاهُ فَقَالَ لَهُ يَا نَبِيَّ اللَّهِ إِنَّهَا دَوَاءٌ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَلَكِنَّهَا دَاءٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Simak] dari ['Alqamah bin Wail] dari [Ayahnya] [Thariq bin Suwaid] atau Suwaid bin Thariq menyebutkan, \"Ia bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai khamer, kemudian beliau melarangnya. Lalu ia bertanya lagi kepada beliau, kemudian beliau melarangnya. Lalu ia berkata lagi kepada beliau, \"Wahai Nabi Allah, sesungguhnya khamer adalah obat!\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak! Tetapi dia adalah penyakit.\""},"3297":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَادَةَ الْوَاسِطِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ ثَعْلَبَةَ بْنِ مُسْلِمٍ عَنْ أَبِي عِمْرَانَ الْأَنْصَارِيِّ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ أَنْزَلَ الدَّاءَ وَالدَّوَاءَ وَجَعَلَ لِكُلِّ دَاءٍ دَوَاءً فَتَدَاوَوْا وَلَا تَدَاوَوْا بِحَرَامٍ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubadah Al Wasithi] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Isma'il bin 'Ayyasy] dari [Tsa'labah bin Muslim] dari [Abu Imran Al Anshari] dari [Ummu Ad Darda] dari [Abu Ad Darda] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah menurunkan penyakit dan obat, dan menjadikan bagi setiap penyakit terdapat obatnya, maka berobatlah dan jangan berobat dengan sesuatu yang haram!\""},"3298":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِسْمَعِيلَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ سَعْدٍ قَالَمَرِضْتُ مَرَضًا أَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي فَوَضَعَ يَدَهُ بَيْنَ ثَدْيَيَّ حَتَّى وَجَدْتُ بَرْدَهَا عَلَى فُؤَادِي فَقَالَ إِنَّكَ رَجُلٌ مَفْئُودٌ ائْتِ الْحَارِثَ بْنَ كَلَدَةَ أَخَا ثَقِيفٍ فَإِنَّهُ رَجُلٌ يَتَطَبَّبُ فَلْيَأْخُذْ سَبْعَ تَمَرَاتٍ مِنْ عَجْوَةِ الْمَدِينَةِ فَلْيَجَأْهُنَّ بِنَوَاهُنَّ ثُمَّ لِيَلُدَّكَ بِهِنَّ","id":"Telah menceritakan kepada kami [Ishaq bin Isma'il] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari [Sa'd] ia berkata, \"Aku pernah mengalami sakit, Rasulullah shallallahu 'alaihi wasallam lalu datang menjengukku, beliau kemudian meletakkan tangannya di antara kedua dadaku hingga aku merasakan dinginnya tangan beliau pada dadaku. Kemudian beliau bersabda: \"Sesungguhnya engkau adalah seorang laki-laki yang terkena penyakit pada hatinya, datanglah kepada Al Harits bin Kaladah saudara Tsaqif, ia orang yang bisa kedokteran. Hendaknya ia mengambil tujuh buah kurma 'ajwah Madinah, hendaknya ia tumbuk bersamaan dengan bijinya, kemudian meminumkannya kepadamu!\""},"3299":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا هَاشِمُ بْنُ هَاشِمٍ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَصَبَّحَ سَبْعَ تَمَرَاتٍ عَجْوَةٍ لَمْ يَضُرَّهُ ذَلِكَ الْيَوْمَ سَمٌّ وَلَا سِحْرٌ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami [Hasyim bin Hasyim] dari ['Amir bin Sa'd bin Abu Waqqash] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa pada pagi hari makan tujuh butir kurma 'ajwah, maka pada hari itu ia tidak akan terkena racun dan sihir.\""},"3300":{"ar":"حَدَّثَنَا مُسَدَّدُ وَحَامِدُ بْنُ يَحْيَى قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أُمِّ قَيْسٍ بِنْتِ مِحْصَنٍ قَالَتْدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِابْنٍ لِي قَدْ أَعْلَقْتُ عَلَيْهِ مِنْ الْعُذْرَةِ فَقَالَ عَلَامَ تَدْغَرْنَ أَوْلَادَكُنَّ بِهَذَا الْعِلَاقِ عَلَيْكُنَّ بِهَذَا الْعُودِ الْهِنْدِيِّ فَإِنَّ فِيهِ سَبْعَةَ أَشْفِيَةٍ مِنْهَا ذَاتُ الْجَنْبِ يُسْعَطُ مِنْ الْعُذْرَةِ وَيُلَدُّ مِنْ ذَاتِ الْجَنْبِقَالَ أَبُو دَاوُد يَعْنِي بِالْعُودِ الْقُسْطَ","id":"Telah menceritakan kepada kami [Musaddad] dan [Hamid bin Yahya] mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ummu Qais binti Mihshan] ia berkata, \"Aku pernah menemui Rasulullah shallallahu 'alaihi wasallam membawa anakku yang telah aku obati dari penyakit radang kelenjar leher (amandel). Kemudian beliau berkata: \"Atas dasar apakah kalian menekan dan mengangkat tenggorokan anak kalian dengan mengangkat dagu mereka? Hendaknya kalian menggunakan gaharu India, karena sesungguhnya padanya terdapat tujuh macam obat, diantaranya adalah obat penyakit tulang rusuk, digunakan sebagai obat radang amandel yang dimasukkan dari hidung, serta obat penyakit rusuk yang dimasukkan lewat mulut.\" Abu Daud berkata, \"Yang dimaksud dengan 'ud adalah gaharu.\""},"3301":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَسُوا مِنْ ثِيَابِكُمْ الْبَيَاضَ فَإِنَّهَا مِنْ خَيْرِ ثِيَابِكُمْ وَكَفِّنُوا فِيهَا مَوْتَاكُمْ وَإِنَّ خَيْرَ أَكْحَالِكُمُ الْإِثْمِدُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعْرَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pakailah pakaian yang putih, sebab ia adalah sebaik-baik pakaian kalian, dan kafanilah jenazah kalian dengannya. Sesungguhnya sebaik-baik celak kalian adalah itsmid (sejenis tumbuhan), itsmid dapat mempertajam pandangan dan menumbuhkan rambut.\""},"3302":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهِ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعَيْنُ حَقٌّ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Abdurrazzaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] ia berkata; Ini adalah hadits yang telah diceritakan [Abu Hurairah] kepada kami dari Rasulullah, \"Beliau bersabda: \"Penyakit Ain (pengaruh mata orang yang dengki) itu benar adanya.\""},"3303":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ يُؤْمَرُ الْعَائِنُ فَيَتَوَضَّأُ ثُمَّ يَغْتَسِلُ مِنْهُ الْمَعِينُ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] radliallahu 'anha, ia berkata, \"Orang yang menimbulkan penyakit Ain diperintahkan untuk berwudlu, kemudian orang yang menderita penyakit Ain diperintahkan untuk mandi dengan air sisa wudlunya.\""},"3304":{"ar":"حَدَّثَنَا الرَّبِيعُ بْنُ نَافِعٍ أَبُو تَوْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ مُهَاجِرٍ عَنْ أَبِيهِ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ بْنِ السَّكَنِ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَقْتُلُوا أَوْلَادَكُمْ سِرًّا فَإِنَّ الْغَيْلَ يُدْرِكُ الْفَارِسَ فَيُدَعْثِرُهُ عَنْ فَرَسِهِ","id":"Telah menceritakan kepada kami [Ar Rabi' bin Nafi' Abu Taubah] telah menceritakan kepada kami [Muhammad bin Muhajir] dari [Ayahnya] dari [Asma` binti Yazid bin As Sakan] ia berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian membunuh anak-anak kalian secara rahasia, sesungguhnya pengaruh menggauli isteri pada waktu menyusui akan menimpa penunggang kuda sehingga menyebabkannya lemah dan terjatuh dari kudanya.\""},"3305":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ جُدَامَةَ الْأَسَدِيَّةِأَنَّهَا سَمِعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَقَدْ هَمَمْتُ أَنْ أَنْهَى عَنْ الْغِيلَةِ حَتَّى ذَكَرْتُ أَنَّ الرُّومَ وَفَارِسَ يَفْعَلُونَ ذَلِكَ فَلَا يَضُرُّ أَوْلَادَهُمْقَالَ مَالِكٌ الْغِيلَةُ أَنْ يَمَسَّ الرَّجُلُ امْرَأَتَهُ وَهِيَ تُرْضِعُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Muhammad bin Abdurrahman bin Naufal] telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, dari [Judamah Al Asadiyyah] bahwa ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku telah berniat untuk melarang dari menggauli isteri pada waktu menyusui, hingga aku ingat bahwa orang-orang Romawi dan Persia melakukan hal tersebut dan tidak membahayakan anak-anak mereka.\" Malik berkata, \"Ghailah adalah seorang laki-laki menggauli isterinya ketika dalam keadaan menyusui.\""},"3306":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ يَحْيَى بْنِ الْجَزَّارِ عَنْ ابْنِ أَخِي زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ عَنْ زَيْنَبَ امْرَأَةِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الرُّقَى وَالتَّمَائِمَ وَالتِّوَلَةَ شِرْكٌ قَالَتْ قُلْتُ لِمَ تَقُولُ هَذَا وَاللَّهِ لَقَدْ كَانَتْ عَيْنِي تَقْذِفُ وَكُنْتُ أَخْتَلِفُ إِلَى فُلَانٍ الْيَهُودِيِّ يَرْقِينِي فَإِذَا رَقَانِي سَكَنَتْ فَقَالَ عَبْدُ اللَّهِ إِنَّمَا ذَاكَ عَمَلُ الشَّيْطَانِ كَانَ يَنْخُسُهَا بِيَدِهِ فَإِذَا رَقَاهَا كَفَّ عَنْهَا إِنَّمَا كَانَ يَكْفِيكِ أَنْ تَقُولِي كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَذْهِبْ الْبَأْسَ رَبَّ النَّاسِ اشْفِ أَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ شِفَاءً لَا يُغَادِرُ سَقَمًا","id":"Telah menceritakan kepada kami [Muhammad bin Al 'Ala] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari ['Amru bin Murrah] dari [Yahya bin Al Jazzar] dari [anak saudara Zainab] isteri Abdullah, dari [Zainab] dari [Abdullah] ia berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya jampi-jampi, jimat dan tiwalah (menjadikan seorang wanita mencintai suaminya) adalah bentuk kesyirikan.\" Zainab berkata, \"Aku katakan, 'Kenapa engkau mengucapkan hal ini? Demi Allah! Sungguh, mataku telah mengeluarkan air mata dan kotoran. Dan aku bolak-balik datang kepada Fulan seorang Yahudi yang menjampiku, apabila ia menjampiku maka mataku menjadi tenang?\" Kemudian Abdullah menjawab, 'Sesungguhnya hal tersebut adalah perbuatan setan. Setan telah menusuk matanya menggunakan tangannya, kemudian apabila orang yahudi tersebut menjampinya maka setan menahan tusukannya. Sebenarnya cukup bagimu mengucapkan sebagaimana yang diucapkan Rasulullah shallallahu 'alaihi wasallam: 'ADZHIBIL BA`SA RABBAN NAASA ISYFI ANTA ASY SYAAFII LAA SYIFAA A ILLAA SYIFAA`UKA SYIFAA`AN LAA YUGHAADIRU SAQAMAN (Wahai Tuhan manusia, hilangkanlah penyakit, sesungguhnya Engkau Pemberi kesembuhan, tidak ada kesembuhan kecuali kesembuhan dari-Mu, kesembuhan yang tidak meninggalkan efek penyakit) '.\""},"3307":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دَاوُدَ عَنْ مَالِكِ بْنِ مِغْوَلٍ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ عِمْرَانَ بْنَ حُصَيْنٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا رُقْيَةَ إِلَّا مِنْ عَيْنٍ أَوْ حُمَةٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdullah bin Daud] dari [Malik bin Mighwal] dari [Hushain] dari [Asy Sya'bi] dari [Imran bin Hushain] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada jampi kecuali karena 'ain (pengaruh mata orang yang dengki), atau dari racun.\""},"3308":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وابْنُ السَّرْحِ قَالَ أَحْمَدُ حَدَّثَنَا ابْنُ وَهْبٍ و قَالَ ابْنُ السَّرْحِ أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنَا دَاوُدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَمْروِ بْنِ يَحْيَى عَنْ يُوسُفَ بْنِ مُحَمَّدٍ وَقَالَ ابْنُ صَالِحٍ مُحَمَّدُ بْنُ يُوسُفَ بْنِ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ دَخَلَ عَلَى ثَابِتِ بْنِ قَيْسٍ قَالَ أَحْمَدُ وَهُوَ مَرِيضٌ فَقَالَ اكْشِفْ الْبَأْسَ رَبَّ النَّاسِ عَنْ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ ثُمَّ أَخَذَ تُرَابًا مِنْ بَطْحَانَ فَجَعَلَهُ فِي قَدَحٍ ثُمَّ نَفَثَ عَلَيْهِ بِمَاءٍ وَصَبَّهُ عَلَيْهِقَالَ أَبُو دَاوُد قَالَ ابْنُ السَّرْحِ يُوسُفُ بْنُ مُحَمَّدٍ وَهُوَ الصَّوَابُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] dan [Ibnu As Sarh] [Ahmad] berkata; telah menceritakan kepada kami [Ibnu Wahb] dan [Ibnu As Sarh] berkata; telah mengabarkan kepada kami [Ibnu Wahb] telah menceritakan kepada kami [Daud bin Abdurrahman] dari ['Amru bin Yahya] dari [Yusuf bin Muhammad] -Ibnu Shalih Muhammad bin Yusuf bin Tsabit bin Qais bin Syammas berkata- dari [Ayahnya] dari [Kakeknya] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau pernah menemui Tsabit bin Qais -Ahmad berkata; saat ia sedang sakit-, lalu beliau mengucapkan: 'IKSYIFIL BA`SA RABBAN NAASI (Hilangkan penyakit wahai Tuhan manusia!) '. Dari Tsabit bin Qais bin Syammas, \"Kemudian beliau mengambil tanah dari Bathhan dan memasukkannya ke dalam sebuah gelas, beliau kemudian menyemburkan air ke dalamnya, lalu menuangkannya kepadanya.\" Abu Daud berkata; Ibnu As As Sarh berkata, \"Yang benar adalah Yusuf bin Muhammad.\""},"3309":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي مُعَاوِيَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ عَوْفِ بْنِ مَالِكٍ قَالَكُنَّا نَرْقِي فِي الْجَاهِلِيَّةِ فَقُلْنَا يَا رَسُولَ اللَّهِ كَيْفَ تَرَى فِي ذَلِكَ فَقَالَ اعْرِضُوا عَلَيَّ رُقَاكُمْ لَا بَأْسَ بِالرُّقَى مَا لَمْ تَكُنْ شِرْكًا","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Mu'awiyah] dari [Abdurrahman bin Jubair] dari [Ayahnya] dari ['Auf bin Malik] ia berkata, \"Pada masa jahiliyah aku pernah melakukan penjampian, lalu aku berkata, \"Wahai Rasulullah, bagaimana pendapat anda mengenai hal tersebut?\" Beliau menjawab: \"Perlihatkan jampi kalian kepadaku! Tidak mengapa dengan jampi selama bukan perbuatan syirik.\""},"3310":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مَهْدِيٍّ الْمِصِّيصِيُّ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ أَبِي بَكْرِ بْنِ سُلَيْمَانَ بْنِ أَبِي حَثْمَةَ عَنْ الشِّفَاءِ بِنْتِ عَبْدِ اللَّهِ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عِنْدَ حَفْصَةَ فَقَالَ لِي أَلَا تُعَلِّمِينَ هَذِهِ رُقْيَةَ النَّمْلَةِ كَمَا عَلَّمْتِيهَا الْكِتَابَةَ","id":"Telah menceritakan kepada kami [Ibrahim bin Mahdi Al Mishshi] telah menceritakan kepada kami [Ali bin Mushir] dan [Abdul Aziz bin Umar bin Abdul Aziz] dari [Shalih bin Kaisan] dari [Abu Bakr bin Sulaiman bin Abu Hatsmah] dari [Asy Syifa` binti Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah menemuiku, sementara aku sedang berada di rumah Hafshah. Lalu beliau berkata kepadaku: \"Tidakkah engkau ajari dia jampi namlah sebagaimana engkau mengajarinya menulis?\" "},"3311":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ حَدَّثَتْنِي جَدَّتِي قَالَتْ سَمِعْتُ سَهْلَ بْنَ حُنَيفٍ يَقُولُمَرَرْنَا بِسَيْلٍ فَدَخَلْتُ فَاغْتَسَلْتُ فِيهِ فَخَرَجْتُ مَحْمُومًا فَنُمِيَ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرُوا أَبَا ثَابِتٍ يَتَعَوَّذُ قَالَتْ فَقُلْتُ يَا سَيِّدِي وَالرُّقَى صَالِحَةٌ فَقَالَ لَا رُقْيَةَ إِلَّا فِي نَفْسٍ أَوْ حُمَةٍ أَوْ لَدْغَةٍقَالَ أَبُو دَاوُد الْحُمَةُ مِنْ الْحَيَّاتِ وَمَا يَلْسَعُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Utsman bin Hakim] telah menceritakan kepadaku [Nenekku] ia berkata; Aku pernah mendengar [Sahl bin Hunaif] berkata, \"Kami pernah melewati sebuah air yang mengalir (banjir), kemudian aku mencebur dan mandi di dalamnya, setelah itu aku keluar dan dalam keadaan terserang demam. Hal itu lalu sampai kepada Rasulullah shallallahu 'alaihi wasallam hingga beliau pun bersabda: \"Perintahkan Abu Tsabit agar membaca ta'awwudz!\" Nenekku berkata, \"Lalu aku katakan, \"Wahai tuanku, apakah jampi diperbolehkan?\" Beliau bersabda: \"Tidak ada jampi kecuali karena pengaruh perbuatan dengki, atau racun, atau sengatan hewan.\" Abu Daud berkata, \"(Yaitu) racun ular dan apa yang menyengat.\""},"3312":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ حَدَّثَنَا شَرِيكٌ ح و حَدَّثَنَا الْعَبَّاسُ الْعَنْبَرِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شَرِيكٌ عَنْ الْعَبَّاسِ بْنِ ذَرِيحٍ عَنْ الشَّعْبِيِّ قَالَ الْعَبَّاسُ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا رُقْيَةَ إِلَّا مِنْ عَيْنٍ أَوْ حُمَةٍ أَوْ دَمٍ يَرْقَأُ لَمْ يَذْكُرْ الْعَبَّاسُ الْعَيْنَ وَهَذَا لَفْظُ سُلَيْمَانَ بْنِ دَاوُدَ","id":"Telah menceritakan kepada kami [Sulaiman bin Daud] telah menceritakan kepada kami [Syarik]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Al 'Abbas Al 'Anbari] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Syarik] dari [Al 'Abbas bin Dzarih] dari [Asy Sya'bi] [Al 'Abbas] menyebutkan dari [Anas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada jampi kecuali karena 'ain (pengaruh mata orang yang dengki), atau racun, atau darah yang terhenti.\" Al 'Abbas tidak menyebutkan 'ain, dan ini adalah lafazh Sulaiman bin Daud.\""},"3313":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ قَالَ قَالَ أَنَسٌ يَعْنِي لِثَابِتٍأَلَا أَرْقِيكَ بِرُقْيَةِ رَسُولِ اللَّهِ قَالَ بَلَى قَالَ فَقَالَ اللَّهُمَّ رَبَّ النَّاسِ مُذْهِبَ الْبَأْسِ اشْفِ أَنْتَ الشَّافِي لَا شَافِيَ إِلَّا أَنْتَ اشْفِهِ شِفَاءً لَا يُغَادِرُ سَقَمًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz bin Shuhaib] ia berkata, \" [Anas] berkata kepada Tsabit, \"Maukah aku jampi engkau dengan jampi yang dilakukan Rasulullah shallallahu 'alaihi wasallam?\" Tsabit menjawab, \"Ya.\" Anas lalu mengucapkan, \"ALLAAHUMMA RABBAN NAASI, MUDZHIBIL BA`SI ISYFI ANTA ASY SYAAFII LAA SYAAFIYA ILLAA ANTA ISYFIHI SYIFAA AN LAA YUGHAADIRU SAQAMAN (Ya Allah, Tuhan manusia, Penghilang penyakit, sembuhkanlah. Engkau adalah Pemberi kesembuhan, tidak ada yang dapat menyembuhkan kecuali Engkau. Sembuhkanlah dia dengan kesembuhan yang tidak meninggalkan efek sakit) '.\""},"3314":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ أَنَّ عَمْرَو بْنَ عَبْدِ اللَّهِ بْنِ كَعْبٍ السُّلَمِيَّ أَخْبَرَهُ أَنَّ نَافِعَ بْنَ جُبَيرٍ أَخْبَرَهُ عَنْ عُثْمَانَ بْنِ أَبِي الْعَاصِأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عُثْمَانُ وَبِي وَجَعٌ قَدْ كَادَ يُهْلِكُنِي قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْسَحْهُ بِيَمِينِكَ سَبْعَ مَرَّاتٍ وَقُلْ أَعُوذُ بِعِزَّةِ اللَّهِ وَقُدْرَتِهِ مِنْ شَرِّ مَا أَجِدُقَالَ فَفَعَلْتُ ذَلِكَ فَأَذْهَبَ اللَّهُ عَزَّ وَجَلَّ مَا كَانَ بِي فَلَمْ أَزَلْ آمُرُ بِهِ أَهْلِي وَغَيْرَهُمْ","id":"Telah menceritakan kepada kami [Abdullah Al Qa'nabi] dari [Malik] dari [Yazid bin Khushaifah] bahwa ['Amru bin Abdullah bin Ka'b As Sulami] telah mengabarkan kepadanya, bahwa [Nafi' bin Jubair] mengabarkan kepadanya dari [Utsman bin Abu Al 'Ash] bahwa ia telah datang kepada Nabi shallallahu 'alaihi wasallam -Utsman berkata; sementara aku sedang sakit yang hampir membinasakanku- Utsman berkata, \"Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Usaplah menggunakan tangan kananmu sebanyak tujuh kali, lalu ucapkanlah: A'UUDZU BI'IZZATILLAAHI WA QUDRATIHI MIN SYARRI MAA AJIDU (aku berlindung kepada kemuliaan Allah dan kemampuan-Nya dari keburukan yang aku temui) '.\" Utsman berkata, \"Lalu aku melakukan hal tersebut, maka Allah 'azza wajalla menghilangkan apa yang ada padaku, dan aku selalu memerintahkan keluargaku dan yang lainnya untuk mengucapkannya.\""},"3315":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ الرَّمْلِيُّ حَدَّثَنَا اللَّيْثُ عَنْ زِيَادَةَ بِنِ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ فَضَالَةَ بْنِ عُبَيْدٍ عَنْ أَبِي الدَّرْدَاءِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اشْتَكَى مِنْكُمْ شَيْئًا أَوْ اشْتَكَاهُ أَخٌ لَهُ فَلْيَقُلْ رَبَّنَا اللَّهُ الَّذِي فِي السَّمَاءِ تَقَدَّسَ اسْمُكَ أَمْرُكَ فِي السَّمَاءِ وَالْأَرْضِ كَمَا رَحْمَتُكَ فِي السَّمَاءِ فَاجْعَلْ رَحْمَتَكَ فِي الْأَرْضِ اغْفِرْ لَنَا حُوبَنَا وَخَطَايَانَا أَنْتَ رَبُّ الطَّيِّبِينَ أَنْزِلْ رَحْمَةً مِنْ رَحْمَتِكَ وَشِفَاءً مِنْ شِفَائِكَ عَلَى هَذَا الْوَجَعِ فَيَبْرَأَ","id":"Telah menceritakan kepada kami [Yazid bin Khalid bin Mauhib Ar Ramli] telah menceritakan kepada kami [Al Laits] dari [Ziyadah bin Muhammad] dari [Muhammad bin Ka'b Al Qurazhi] dari [Fadlalah bin 'Ubaid] dari [Abu Darda] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian mengeluhkan sesuatu atau saudaranya mengeluhkannya, maka hendaknya ia mengucapkan: RABBANALLAAHULLADZII FIS SAMAA`I TAQADDASA ISMUKA AMRUKA FIS SAMAA`I WAL ARDLI KAMAA RAHMATUKA FIS SAMAA`I, FAJ'AL RAHMATAKA FIL ARDLI, IGHFIR LANAA HUUBANAA WA KHATHAAYAANAA, ANTA RABBUTH THAYYIBIINA, ANZIL RAHMATAN MIN RAHMATIKA WA SYIFAA`AN MIN SYIFAA`IKA 'ALAA HAADZAL WAJA'I (Tuhanku adalah Allah yang berada di langit, Maha Suci nama-Mu, urusan-Mu berada di langit dan bumi. Sebagaimana rahmat-Mu berada di langit, maka jadikanlah rahmat-Mu berada di bumi! Ampunilah dosa dan kesalahan kami! Engkau Tuhan orang-orang yang baik, turunkan rahmat di antara rahmat-Mu, serta kesembuhan di antara kesembuhan-Mu kepada penyakit ini) ' maka ia akan sembuh.\""},"3316":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُعَلِّمُهُمْ مِنْ الْفَزَعِ كَلِمَاتٍ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ غَضَبِهِ وَشَرِّ عِبَ��دِهِ وَمِنْ هَمَزَاتِ الشَّيَاطِينِ وَأَنْ يَحْضُرُونِوَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ يُعَلِّمُهُنَّ مَنْ عَقَلَ مِنْ بَنِيهِ وَمَنْ لَمْ يَعْقِلْ كَتَبَهُ فَأَعْلَقَهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Muhammad bin Ishaq] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengajari mereka beberapa kalimat karena adanya rasa takut, yaitu: A'UUDZU BIKALIMAATILLAAHIT TAAMMATI MIN GHADLABIHI WA SYARRI 'IBAADIHI WA MIN HAMAZAATISY SYAYAATHIINI WA AN YAHDLURUUNA (Aku berlindung kepada kalimat-kalimat Allah yang sempurna dari kemurkaan-Nya serta kejahatan para hamba-Nya, dan dari bisikan setan serta kedatangan mereka kepadaku) '. Abdullah bin Umar mengajarkan kalimat-kalimat tersebut kepada orang yang telah berakal di antara anak-anaknya serta orang yang belum berakal. Ia menulisnya dan menggantungkannya kepadanya.\""},"3317":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ أَبِي سُرَيْجٍ الرَّازِيُّ أَخْبَرَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ قَالَرَأَيْتُ أَثَرَ ضَرْبَةٍ فِي سَاقِ سَلَمَةَ فَقُلْتُ مَا هَذِهِ قَالَ أَصَابَتْنِي يَوْمَ خَيْبَرَ فَقَالَ النَّاسُ أُصِيبَ سَلَمَةُ فَأُتِيَ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَفَثَ فِيَّ ثَلَاثَ نَفَثَاتٍ فَمَا اشْتَكَيْتُهَا حَتَّى السَّاعَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Abu Suraih Ar Razi] telah mengabarkan kepada kami [Makki bin Ibrahim] telah menceritakan kepada kami [Yazid bin 'Ubaid] ia berkata, \"Aku melihat pengaruh pukulan pada betis [Salamah], lalu aku katakan, 'Apakah ini? ' Ia menjawab, 'Aku mendapatkan luka ini saat perang Khaibar. ' Kemudian orang-orang berkata, 'Salamah telah terkena musibah'. Kemudian aku dibawa ke hadapkan Rasulullah shallallahu 'alaihi wasallam. Lalu beliau meludah padaku sebanyak tiga kali, kemudian aku tidak mengeluhkannya hingga saat ini.\""},"3318":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ رَبِّهِ يَعْنِي ابْنَ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِلْإِنْسَانِ إِذَا اشْتَكَى يَقُولُ بِرِيقِهِ ثُمَّ قَالَ بِهِ فِي التُّرَابِ تُرْبَةُ أَرْضِنَا بِرِيقَةِ بَعْضِنَا يُشْفَى سَقِيمُنَا بِإِذْنِ رَبِّنَا","id":"Telah menceritakan kepada kami [Zuhair bin Kharb] dan [Utsman bin Abu Syaibah] mereka berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Abdu Rabbih bin Sa'id] dari ['Amrah] dari [Aisyah] ia berkata, \"Jika ada orang yang mengeluhkan sakit, Nabi shallallahu 'alaihi wasallam meludah ke tanah lalu berdoa: 'TURBATU ARDHINAA BIRIIQATI BA'DHINAA YUSYFAA SAQIIMUNAA BI IDZNI RABBINAA (Ini adalah debu tanah kami, dengan ludah sebagian kami maka tersembuhkan orang sakit kami dengan izin Tuhan kami) '.\""},"3319":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ زَكَرِيَّا قَالَ حَدَّثَنِي عَامِرٌ عَنْ خَارِجَةَ بْنِ الصَّلْتِ التَّمِيمِيِّ عَنْ عَمِّهِأَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمَ ثُمَّ أَقْبَلَ رَاجِعًا مِنْ عِنْدِهِ فَمَرَّ عَلَى قَوْمٍ عِنْدَهُمْ رَجُلٌ مَجْنُونٌ مُوثَقٌ بِالْحَدِيدِ فَقَالَ أَهْلُهُ إِنَّا حُدِّثْنَا أَنَّ صَاحِبَكُمْ هَذَا قَدْ جَاءَ بِخَيْرٍ فَهَلْ عِنْدَكَ شَيْءٌ تُدَاوِيهِ فَرَقَيْتُهُ بِفَاتِحَةِ الْكِتَابِ فَبَرَأَ فَأَعْطَوْنِي مِائَةَ شَاةٍ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ هَلْ إِلَّا هَذَا وَقَالَ مُسَدَّدٌ فِي مَوْضِعٍ آخَرَ هَلْ قُلْتَ غَيْرَ هَذَا قُلْتُ لَا قَالَ خُذْهَا فَلَعَمْرِي لَمَنْ أَكَلَ بِرُقْيَةِ بَاطِلٍ لَقَدْ أَكَلْتَ بِرُقْيَةِ حَقٍّحَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا ابْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ خَارِجَةَ بْنِ الصَّلْتِ عَنْ عَمِّهِ أَنَّهُ مَرَّ قَالَ فَرَقَاهُ بِفَاتِحَةِ الْكِتَابِ ثَلَاثَةَ أَيَّامٍ غُدْوَةً وَعَشِيَّةً كُلَّمَا خَتَمَهَا جَمَعَ بُزَاقَهُ ثُمَّ تَفَلَ فَكَأَنَّمَا أُنْشِطَ مِنْ عِقَالٍ فَأَعْطَوْهُ شَيْئًا فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ذَكَرَ مَعْنَى حَدِيثِ مُسَدَّدٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Zakaria] ia berkata; telah menceritakan kepadaku ['Amir] dari [Kharijah bin Ash Shalt At Tamimi] dari [Pamannya] bahwa ia datang kepada Rasulullah shallallahu 'alaihi wasallam lalu masuk Islam, kemudian kembali dari sisinya dan melewati sebuah kaum yang pada mereka terdapat orang gila yang diikat dengan sebuah besi. Keluarganya lalu berkata, \"Telah sampai kabar kepada kami bahwa sahabat kalian ini datang dengan membawa kebaikan, apakah kalian memiliki sesuatu yang dapat engkau gunakan untuk mengobati? ' Lalu aku menjampinya menggunakan Surat Al Fatihah sehingga orang itu pun sembuh. Kemudian mereka memberiku seratus ekor kambing. Setelah itu aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengabarkan hal tersebut, beliau lantas bertanya: \"Apakah engkau hanya mengucapkan ini?\" Musaddad pada tempat yang lain menyebutkan, 'Apakah engkau mengucapkan selain hal ini? ' Maka aku jawab, \"Tidak.\" Beliau lalu bersabda: \"Demi Dzat yang memanjangkan umurku, ambillah! Sungguh, orang makan dengan jampi batil sedangkan engkau makan dengan jampi yang benar.\" Telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [Ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Basysyar] telah menceritakan kepada kami [Ibnu Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] dari [Asy Sya'bi] dari [Kharijah bin Ash Shalt] dari [Pamannya] bahwa ia lewat, Kharijah berkata, \"Kemudian ia menjampi orang tersebut menggunakan Surat Al Fatihah selama tiga hari pagi dan sore, setiap kali ia menyelesaikannya maka ia mengumpulkan ludahnya kemudian meludah. Maka orang tersebut seolah-olah telah terbebas dari ikatan, kemudian mereka memberinya sesuatu. Lalu ia datang kepada Nabi shallallahu 'alaihi wasallam… lalu ia menyebutkan makna hadits Musaddad.\""},"3320":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ حَدَّثَنِي الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ طَارِقٍ يَعْنِي ابْنَ مَخَاشِنٍ عَنْ أَبِي هُرَيْرَةَ قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَدِيغٍ لَدَغَتْهُ عَقْرَبٌ قَالَ فَقَالَ لَوْ قَالَ أَعُوذُ بِكَلِمَاتِ اللَّهِ التَّامَّةِ مِنْ شَرِّ مَا خَلَقَ لَمْ يُلْدَغْ أَوْ لَمْ يَضُرَّهُ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] telah menceritakan kepada kami [Baqiyyah] telah menceritakan kepadaku [Az Zubaidi] dari [Az Zuhri] dari [Thariq bin Makhasyin] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki yang terkena sengatan kalajengking datang menemui Nabi shallallahu 'alaihi wasallam.\" Abu Hurairah berkata, \"Kemudian beliau bersabda: \"Seandainya ia mengucapkan A'UUDZU BIKALIMAATILLAAHIT TAAMMAATI MIN SYARRI MAA KHALAQ (Aku berlindung kepada kalimat-kalimat Allah yang sempurna dari keburukan makhluk yang Allah ciptakan) ', maka ia tidak akan tersengat, atau kalajengking tersebut tidak akan membahayakannya.\""},"3321":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ أَبِي الْمُتَوَكِّلِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَهْطًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلَقُوا فِي سَفْرَةٍ سَافَرُوهَا فَنَزَلُوا بِحَيٍّ مِنْ أَحْيَاءِ الْعَرَبِ فَقَالَ بَعْضُهُمْ إِنَّ سَيِّدَنَا لُدِغَ فَهَلْ عِنْدَ أَحَدٍ مِنْكُمْ شَيْءٌ يَنْفَعُ صَاحِبَنَا فَقَالَ رَجُلٌ مِنْ الْقَوْمِ نَعَمْ وَاللَّهِ إِنِّي لَأَرْقِي وَلَكِنْ اسْتَضَفْنَاكُمْ فَأَبَيْتُمْ أَنْ تُضَيِّفُونَا مَا أَنَا بِرَاقٍ حَتَّى تَجْعَلُوا لِي جُعْلًا فَجَعَلُوا لَهُ قَطِيعًا مِنْ الشَّاءِ فَأَتَاهُ فَقَرَأَ عَلَيْهِ أُمَّ الْكِتَابِ وَيَتْفُلُ حَتَّى بَرَأَ كَأَنَّمَا أُنْشِطَ مِنْ عِقَالٍ قَالَ فَأَوْفَاهُمْ جُعْلَهُمْ الَّذِي صَالَحُوهُمْ عَلَيْهِ فَقَالُوا اقْتَسِمُوا فَقَالَ الَّذِي رَقَى لَا تَفْعَلُوا حَتَّى نَأْتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَسْتَأْمِرَهُ فَغَدَوْا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرُوا لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ أَيْنَ عَلِمْتُمْ أَنَّهَا رُقْيَةٌ أَحْسَنْتُمْ اقْتَسِمُوا وَاضْرِبُوا لِي مَعَكُمْ بِسَهْمٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Abu Al Mutawakkil] dari [Abu Sa'id Al Khudri] bahwa beberapa sahabat Nabi shallallahu 'alaihi wasallam pergi dalam suatu perjalanan yang mereka lakukan. Kemudian mereka singgah di sebuah kampung Arab, sebagian penduduk kampung tersebut lalu berkata, \"Sesungguhnya pemimpin kami tersengat, apakah salah seorang di antara kalian memiliki sesuatu yang bermanfaat bagi sahabat kami tersebut?\" Kemudian salah seorang dari para sahabat tersebut menjawab, \"Ya. Demi Allah, sesungguhnya aku akan menjampi, akan tetapi kami telah meminta kalian agar menjamu kami namun kalian menolak untuk menjadikan kami sebagai tamu. Aku tidak akan menjampi hingga kalian memberikan hadiah kepadaku.\" Penduduk kampung tersebut kemudian memberikan hadiah sekumpulan kambing kepadanya, lalu sahabat tersebut datang kepada orang yang tersengat dan membacakan Surat Al Fatihah kepadanya, lalu meniupkan hingga orang tersebut sembuh seolah-olah telah terbebas dari ikatan.\" Abu Sa'id Al Khudri berkata, \"Kemudian mereka memenuhi janjinya untuk memberikan hadiah kepada para sahabat sebagaimana yang mereka janjikan. Kemudian para sahabat berkata, \"Bagilah kambing-kambing tersebut!\" Lalu sahabat yang telah membacakan jampi mengatakan, \"Kalian jangan melakukannya hingga kita datang kepada Rasulullah shallallahu 'alaihi wasallam dan minta pertimbangannya.\" Lalu mereka pergi menemui Rasulullah shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepada beliau. Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Dari mana kalian mengetahui bahwa Al Fatihah adalah jampi? Kalian telah berbuat baik, bagilah dan berilah aku bagian bersama kalian.\""},"3322":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا اشْتَكَى يَقْرَأُ فِي نَفْسِهِ بِالْمُعَوِّذَاتِ وَيَنْفُثُ فَلَمَّا اشْتَدَّ وَجَعُهُ كُنْتُ أَقْرَأُ عَلَيْهِ وَأَمْسَحُ عَلَيْهِ بِيَدِهِ رَجَاءَ بَرَكَتِهَا","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam apabila sakit maka beliau membacakan surat-surat mu'awwidzat (minta perlindungan) dan meniupkannya. Ketika sakit beliau semakin keras, maka aku yang membacakan kepada beliau dan aku usapkan kepadanya dengan tangan beliau, dengan harapan mendapatkan berkahnya.\""},"3323":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا نُوحُ بْنُ يَزِيدَ بْنِ سَيَّارٍ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَرَادَتْ أُمِّي أَنْ تُسَمِّنَنِي لِدُخُولِي عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ أَقْبَلْ عَلَيْهَا بِشَيْءٍ مِمَّا تُرِيدُ حَتَّى أَطْعَمَتْنِي الْقِثَّاءَ بِالرُّطَبِ فَسَمِنْتُ عَلَيْهِ كَأَحْسَنِ السَّمْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] telah menceritakan kepada kami [Nuh bin Yazid bin Sayyar] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Muhammad bin Ishaq] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata, \"Ibuku ingin aku terlihat gemuk (segar) saat aku bertemu Rasulullah shallallahu 'alaihi wasallam, namun aku tidak menerima apapun yang diinginkannya hingga ia memberiku makan mentimun dengan ruthab (kurma segar). Kemudian aku menjadi tampak gemuk (segar) dengan bentuk yang edial.\""},"3324":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ حَمَّادِ ��ْنِ سَلَمَةَ عَنْ حَكِيمٍ الْأَثْرَمِ عَنْ أَبِي تَمِيمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَتَى كَاهِنًا قَالَ مُوسَى فِي حَدِيثِهِ فَصَدَّقَهُ بِمَا يَقُولُ ثُمَّ اتَّفَقَا أَوْ أَتَى امْرَأَةً قَالَ مُسَدَّدٌ امْرَأَتَهُ حَائِضًا أَوْ أَتَى امْرَأَةً قَالَ مُسَدَّدٌ امْرَأَتَهُ فِي دُبُرِهَا فَقَدْ بَرِئَ مِمَّا أُنْزِلَ عَلَى مُحَمَّدٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad]. (dalam jalur lain disebutkan) Telah diriwayatkan [Musaddad] telah menceritakan kepada kami [Yahya] dari [Hammad bin Salamah] dari [Hakim Al Atsram] dari [Abu Tamimah] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendatangi seorang dukun -Musa menyebutkan dalam haditsnya- kemudian membenarkan apa yang ia katakan -kemudian keduanya sepakat pada lafadz-, atau mendatangi seorang wanita -Musaddad menyebutkan-, isterinya saat haid, atau mendatangi wanita -Musaddad menyebutkan; mendatangi istrinya lewat dubur-, maka ia telah berlepas diri dari apa yang telah diturunkan kepada Muhammad.\""},"3325":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُسَدَّدٌ الْمَعْنَى قَالَا حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ الْوَلِيدِ بْنِ عَبْدِ اللَّهِ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَبَسَ عِلْمًا مِنْ النُّجُومِ اقْتَبَسَ شُعْبَةً مِنْ السِّحْرِ زَادَ مَا زَادَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Musaddad] secara makna, mereka berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah bin Al Akhnas] dari [Al Walid bin Abdullah] dari [Yusuf bin Mahik] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mempelajari ilmu nujum, maka ia telah mempelajari bagian dari sihir.\" Beliau menambah celaannya dengan apa yang beliau tambahkan. "},"3326":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ بِالْحُدَيْبِيَةِ فِي إِثْرِ سَمَاءٍ كَانَتْ مِنْ اللَّيْلِ فَلَمَّا انْصَرَفَ أَقْبَلَ عَلَى النَّاسِ فَقَالَ هَلْ تَدْرُونَ مَاذَا قَالَ رَبُّكُمْ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ قَالَ أَصْبَحَ مِنْ عِبَادِي مُؤْمِنٌ بِي وَكَافِرٌ فَأَمَّا مَنْ قَالَ مُطِرْنَا بِفَضْلِ اللَّهِ وَبِرَحْمَتِهِ فَذَلِكَ مُؤْمِنٌ بِي كَافِرٌ بِالْكَوْكَبِ وَأَمَّا مَنْ قَالَ مُطِرْنَا بِنَوْءِ كَذَا وَكَذَا فَذَلِكَ كَافِرٌ بِي مُؤْمِنٌ بِالْكَوْكَبِ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dan [Shalih bin Kaisan] dari ['Ubaidullah bin Abdullah] dari [Zaid bin Khalid Al Juhani] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah melakukan Shalat Subuh mengimami kami di Hudaibiyah pada bekas hujan yang terjadi pada malam hari. Selesai shalat beliau menghadap ke arah orang-orang dan berkata: \"Apakah kalian mengetahui apa yang dikatakan Tuhan kalian?\" Mereka menjawab, \"Allah dan Rasul-Nya lebih mengetahuinya.\" Beliau bersabda: \"Allah berfirman: 'Pada pagi ini di antara para hamba-ku ada yang beriman kepada-ku dan ada yang kafir. Adapun orang yang mengatakan, 'Hujan turun hujan kepada kami dengan karena Allah dan rahmat-Nya', maka orang tersebut adalah orang yang beriman kepada-ku dan kafir kepada bintang. Adapun orang yang mengatakan, 'Hujan turun kepada kami berkat bintang ini dan ini', maka orang tersebut adalah orang yang kafir kepada-ku dan beriman kepada kepada bintang'.\""},"3327":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى حَدَّثَنَا عَوُفٌ حَدَّثَنَا حَيَّانُ قَالَ غَيْر مُسَدَّدٍ حَيَانُ بْنُ الْعَلَاءِ حَدَّثَنَا قَطَنُ بْنُ قَبِيصَةَ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْعِيَافَةُ وَالطِّيَرَةُ وَالطَّرْقُ مِنْ الْجِبْتِ الطَّرْقُ الزَّجْرُ وَالْعِيَافَةُ الْخَطُّ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami ['Auf] telah menceritakan kepada kami [Hayyan] -selain Musaddad menyebut; Hayyan bin Al 'Ala- Telah menceritakan kepada kami [Qathan bin Qabishah] dari [Ayahnya] ia berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"'Iyafah, thiyarah dan tharq adalah termasuk jibt. Tharq adalah hardikan dan Iyafah adalah garis.\" "},"3328":{"ar":"حَدَّثَنَا ابْنُ بَشَّارٍ قَالَ قَالَ مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ عَوْفٌالْعِيَافَةُ زَجْرُ الطَّيْرِ وَالطَّرْقُ الْخَطُّ يُخَطُّ فِي الْأَرْضِ","id":"Telah menceritakan kepada kami [Ibnu Basysysar] ia berkata; telah berkata [Muhammad bin Ja'far] ['Auf] berkata, \"'Iyafah adalah menghardik burung, sedangkan tharq adalah garis yang dibuat di tanah.\""},"3329":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ الْحَجَّاجِ الصَّوَّافِ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السُّلَمِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ وَمِنَّا رِجَالٌ يَخُطُّونَ قَالَ كَانَ نَبِيٌّ مِنْ الْأَنْبِيَاءِ يَخُطُّ فَمَنْ وَافَقَ خَطَّهُ فَذَاكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Al Hajjaj Ash Shawwaf] telah menceritakan kepadaku [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] dari ['Atha bin Yasar] dari [Mu'awiyah bin Al Hakam As Sulami] ia berkata, \"Aku katakan, \"Wahai Rasulullah, di antara kami ada orang-orang yang menggambar garis?\" Beliau bersabda: \"Di antara para Nabi ada yang membuat garis, maka barangsiapa yang garisnya sama dengan garis nabi tersebut maka hal itu adalah diperbolehkan.\" "},"3330":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَيْسَى بْنِ عَاصِمٍ عَنْ زِرِ بْنِ حُبَيْشٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الطِّيَرَةُ شِرْكٌ الطِّيَرَةُ شِرْكٌ ثَلَاثًا وَمَا مِنَّا إِلَّا وَلَكِنَّ اللَّهَ يُذْهِبُهُ بِالتَّوَكُّلِ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepadaku [Sufyan] dari [Salamah bin Kuhail] dari [Isa bin 'Ashim] dari [Zir bin Hubaisy] dari [Abdullah bin Mas'ud] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Thiyarah adalah syirik, thiyarah adalah syirik -tiga kali-. Tidaklah di antara kita kecuali beranggapan seperti itu, akan tetapi Allah menghilangkannya dengan tawakal.\""},"3331":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُتَوَكِّلِ الْعَسْقَلَانِيُّ وَالْحَسَنُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَدْوَى وَلَا طِيَرَةَ وَلَا صَفَرَ وَلَا هَامَّةَ فَقَالَ أَعْرَابِيٌّ مَا بَالُ الْإِبِلِ تَكُونُ فِي الرَّمْلِ كَأَنَّهَا الظِّبَاءُ فَيُخَالِطُهَا الْبَعِيرُ الْأَجْرَبُ فَيُجْرِبُهَا قَالَ فَمَنْ أَعْدَى الْأَوَّلَقَالَ مَعْمَرٌ قَالَ الزُّهْرِيُّ فَحَدَّثَنِي رَجُلٌ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُورِدَنَّ مُمْرِضٌ عَلَى مُصِحٍّ قَالَ فَرَاجَعَهُ الرَّجُلُ فَقَالَ أَلَيْسَ قَدْ حَدَّثَنَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى وَلَا صَفَرَ وَ��َا هَامَةَ قَالَ لَمْ أُحَدِّثْكُمُوهُ قَالَ الزُّهْرِيُّ قَالَ أَبُو سَلَمَةَ قَدْ حَدَّثَ بِهِ وَمَا سَمِعْتُ أَبَا هُرَيْرَةَ نَسِيَ حَدِيثًا قَطُّ غَيْرَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutawakkil Al 'Asqalani] dan [Al Hasan bin Ali] mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'adwa, thiyarah, shafar, dan tidak ada hammah.\" Seorang Arab badui lalu berkata, \"Kenapa seekor unta yang ada gurun pasir seperti kijang, kemudian bercampur dengan unta yang terkena penyakit kurap lalu ia tertular penyakit kurap?\" Beliau menjawab: \"(Jika begitu) siapakah yang menularkannya kepada yang pertama?\" Ma'mar berkata; Az Zuhri berkata; telah menceritakan kepadaku seorang laki-laki dari Abu Hurairah bahwa ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah orang yang memiliki unta yang sakit mendatangkannya kepada orang yang memiliki unta yang sehat!\" Kemudian orang tersebut kembali kepadanya dan berkata, \"Bukankah ia telah menceritakan kepada kita bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'Adwa, thiyarah, shafar dan tidak ada hammah.\" Abu Hurairah berkata, \"Aku belum pernah menceritakannya kepada kalian.\" [Az Zuhri] berkata; [Abu Salamah] berkata, \"Abu Hurairah telah menceritakannya dan aku tidak pernah mendengar ia lupa kepada suatu hadits pun selian hadits tersebut.\" "},"3332":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ بْنِ الْبَرْقِيِّ أَنَّ سَعِيدَ بْنَ الْحَكَمِ حَدَّثَهُمْ قَالَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنِي ابْنُ عَجْلَانَ حَدَّثَنِي الْقَعْقَاعُ بْنُ حَكِيمٍ وَعُبَيْدُ اللَّهِ بْنُ مِقْسَمٍ وَزَيدُ بْنُ أَسْلَمَ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا غُولَقَالَ أَبُو دَاوُد قُرِئَ عَلَى الْحَارِثِ بْنِ مِسْكِيْنٍ وَأَنَا شَاهِدٌ أَخْبَرَكُمْ أَشْهَبُ قَالَ سُئِلَ مَالِكٌ عَنْ قَوْلِهِ لَا صَفَرَ قَالَ إِنَّ أَهْلَ الْجَاهِلِيَّةِ كَانُوا يُحِلُّونَ صَفَرَ يُحِلُّونَهُ عَامًا وَيُحَرِّمُونَهُ عَامًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَفَرَ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا بَقِيَّةُ قَالَ قُلْتُ لِمُحَمَّدٍ يَعْنِي ابْنَ رَاشِدٍ قَوْلُهُ هَامَ قَالَ كَانَتْ الْجَاهِلِيَّةُ تَقُولُ لَيْسَ أَحَدٌ يَمُوتُ فَيُدْفَنُ إِلَّا خَرَجَ مِنْ قَبْرِهِ هَامَةٌ قُلْتُ فَقَوْلُهُ صَفَرَ قَالَ سَمِعْتُ أَنَّ أَهْلَ الْجَاهِلِيَّةِ يَسْتَشْئِمُونَ بِصَفَرٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَفَرَ قَالَ مُحَمَّدٌ وَقَدْ سَمِعْنَا مَنْ يَقُولُ هُوَ وَجَعٌ يَأْخُذُ فِي الْبَطْنِ فَكَانُوا يَقُولُونَ هُوَ يُعْدِي فَقَالَ لَا صَفَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim bin Al Barqi] bahwa [Sa'id bin Al Hakam] telah menceritakan kepada mereka, ia berkata; telah mengabarkan kepada kami [Yahya bin Ayyub] telah menceritakan kepadaku [Ibnu 'Ajlan] telah menceritakan kepadaku [Al Qa'qa' bin Hakim] dan ['Ubaidullah bin Miqsam] dan [Zaid bin Aslam] dari [Abu Shalih] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada ghul (yang dapat menyesatkan seseorngpun).\" Abu Daud berkata; telah dibacakan di hadapan [Al Harits bin Miskin] -sementara aku menyaksikan- telah mengabarkan kepada kalian [Asyhab] ia berkata; [Malik] pernah ditanya mengenai sabda beliau 'Tidak ada shafar', maka ia menjawab, \"Sesungguhnya orang-orang jahiliyah dahulu menghalalkan bulan Shafar satu tahun dan mengharamkannya satu tahun. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: 'Tidak ada shafar'. Telah menceritakan kepada kami [Muhammad bin Al Mushaffa] telah menceritakan kepada kami [Baqiyyah] ia berkata, \"Aku tanyakan kepada [Muhammad bin Rasyid], \"Bagaimana dengan kata 'haam'? Ia menjawab, \"Orang-orang jahiliyah dulu mengatakan, 'Tidaklah orang yang meninggal kemudian dikubur melainkan keluar serangga berbisa dari kuburnya'. Aku tanyakan lagi, \"Bagaimana dengan kata, 'Shafar'? Ia menjawab, \"Aku pernah mendengar bahwa orang-orang jahiliyah menisbatkan kesialan kepada bulan Shafar.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada shafar.\" Muhammad berkata, \"Aku mendengar orang yang mengatakan, 'Itu adalah suatu penyakit yang bertempat di dalam perut. Dahulu mereka mengatakan, 'Penyakit tersebut menular'. Maka beliau bersabda: \"Tidak ada shafar.\""},"3333":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّه�� عَلَيْهِ وَسَلَّمَ قَالَ لَا عَدْوَى وَلَا طِيَرَةَ وَيُعْجِبُنِي الْفَأْلُ الصَّالِحُ وَالْفَأْلُ الصَّالِحُ الْكَلِمَةُ الْحَسَنَةُ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada 'Adwa dan tidak ada thiyarah, aku tertarik dengan Al fa'l (optimisme) yang baik, dan optimisme yang baik adalah perkataan yang baik.\""},"3334":{"ar":"حَدَّثَنَا يَحْيَى بْنُ خَلَفٍ حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ قَالَيَقُولُ النَّاسُ الصَّفَرُ وَجَعٌ يَأْخُذُ فِي الْبَطْنِ قُلْتُ فَمَا الْهَامَةُ قَالَ يَقُولُ النَّاسُ الْهَامَةُ الَّتِي تَصْرُخُ هَامَةُ النَّاسِ وَلَيْسَتْ بِهَامَةِ الْإِنْسَانِ إِنَّمَا هِيَ دَابَّةٌ","id":"Telah menceritakan kepada kami [Yahya bin Khalaf] telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Ibnu Juraij] dari ['Atha] orang-orang berkata, \"Shafar adalah sebuah penyakit yang ada dalam perut.\" Kemudian aku tanyakan, 'Apakah hamah itu? ' 'Atha melanjutkan, \"Orang-orang menjawab, 'Burung hantu yang berteriak itu sebenarnya arwah orang-orang. ' Padahal itu bukan nyawa manuisa, sesungguhnya hammah adalah binatang melata.\""},"3335":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ وَأبُو بَكْرِ بْنُ شَيْبَةَ الْمَعْنَى قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عُرْوَةَ بْنِ عَامِرٍ قَالَ أَحْمَدُ الْقُرَشِيُّ قَالَذُكِرَتْ الطِّيَرَةُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحْسَنُهَا الْفَأْلُ وَلَا تَرُدُّ مُسْلِمًا فَإِذَا رَأَى أَحَدُكُمْ مَا يَكْرَهُ فَلْيَقُلْ اللَّهُمَّ لَا يَأْتِي بِالْحَسَنَاتِ إِلَّا أَنْتَ وَلَا يَدْفَعُ السَّيِّئَاتِ إِلَّا أَنْتَ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِكَ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] dan [Abu Bakr bin Syaibah] secara makna, mereka berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Habib bin Abu Tsabit] dari ['Urwah bin 'Amir], Ahmad Al Qurasyi berkata, \"Telah disebutkan thiyarah di sisi Nabi shallallahu 'alaihi wasallam, kemudian beliau bersabda: \"Yang terbaik adalah sikap optimisme, dan thiyarah tidak boleh menahan kehendak seorang muslim. Apabila salah seorang di antara kalian melihat apa yang ia tidak sukai, maka hendaknya ia mengucapkan: ALLAAHUMMA LAA YA`TII BILHASANAATI ILLAA ANTA WA LAA YADFA'USSAYYIAATI ILLAA ANTA, WA LAA HAULA WA LAA QUWWATA ILLAA BIKA (Ya Allah, tidak ada yang mendatangkan kebaikan kecuali Engkau, dan tidak ada yang dapat menolak keburukan kecuali Engkau, dan tidak ada daya serta kekuatan kecuali karena-Mu) '.\""},"3336":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَتَطَيَّرُ مِنْ شَيْءٍ وَكَانَ إِذَا بَعَثَ عَامِلًا سَأَلَ عَنْ اسْمِهِ فَإِذَا أَعْجَبَهُ اسْمُهُ فَرِحَ بِهِ وَرُئِيَ بِشْرُ ذَلِكَ فِي وَجْهِهِ وَإِنْ كَرِهَ اسْمَهُ رُئِيَ كَرَاهِيَةُ ذَلِكَ فِي وَجْهِهِ وَإِذَا دَخَلَ قَرْيَةً سَأَلَ عَنْ اسْمِهَا فَإِنْ أَعْجَبَهُ اسْمُهَا فَرِحَ وَرُئِيَ بِشْرُ ذَلِكَ فِي وَجْهِهِ وَإِنْ كَرِهَ اسْمَهَا رُئِيَ كَرَاهِيَةُ ذَلِكَ فِي وَجْهِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Abdullah bin Buraidah] dari [Ayahnya], bahwa Nabi shallallahu 'alaihi wasallam tidak melakukan tathuyyur dari sesuatupun, beliau apabila telah mengutus seorang pekerja maka beliau bertanya mengenai namanya, apabila tertarik dengan namanya maka beliau senang dan terlihat kesenangan kepada hal tersebut pada wajah beliau. Dan apabila tidak menyukai namanya maka terlihat ketidak senangan kepada hal tersebut pada wajah beliau. Apabila beliau memasuki sebuah kampung maka beliau bertanya mengenai namanya, apabila tertarik dengan namanya maka beliau senang dan terlihat kesenangan kepada hal tersebut pada wajah beliau. Dan apabila beliau tidak menyukai nama tersebut maka terlihat ketidak senangan kepada hal tersebut pada wajah beliau.\" "},"3337":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حَمْزَةَ وَسَالِمٍ ابْنَيْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشُّؤْمُ فِي الدَّارِ وَالْمَرْأَةِ وَالْفَرَسِقَالَ أَبُو دَاوُد قُرِئَ عَلَى الْحَارِثِ بْنِ مِسْكِينٍ وَأَنَا شَاهِدٌ أَخْبَرَكَ ابْنُ الْقَاسِمِ قَالَ سُئِلَ مَالِكٌ عَنْ الشُّؤْمِ فِي الْفَرَسِ وَالدَّارِ قَالَ كَمْ مِنْ دَارٍ سَكَنَهَا نَاسٌ فَهَلَكُوا ثُمَّ سَكَنَهَا آخَرُونَ فَهَلَكُوا فَهَذَا تَفْسِيرُهُ فِيمَا نَرَى وَاللَّهُ أَعْلَمُ قَالَ أَبُو دَاوُد قَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ حَصِيرٌ فِي الْبَيْتِ خَيْرٌ مِنْ امْرَأَةٍ لَا تَلِدُ","id":"Telah menceritakan kepada kami [Al Qa'nabi] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Hamzah] dan [Salim] keduanya adalah anak Abdullah bin Umar, dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kesialan ada pada rumah, wanita dan kuda.\" Abu Daud berkata; telah dibacakan sebuah riwayat kepada Al Harits bin Miskin -sementara aku menyaksikan-, telah mengabarkan kepadaku Ibnu Al Qasim ia berkata, \"Malik ditanya mengenai kesialan pada kuda dan rumah. Ia lalu menjawab, \"Betapa banyak rumah yang ditempati orang-orang kemudian mereka binasa, kemudian ditempati orang-orang yang lain, lalu mereka binasa. Ini adalah penafsirannya yang kami lihat. Wallahu 'alam.\" Abu Daud berkata; Umar radliallahu 'anhu berkata, \"Tikar yang ada di rumah lebih baik daripada seorang wanita yang tidak dapat melahirkan.\""},"3338":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ وَعَبَّاسُ الْعَنْبَرِيُّ قَالَا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ يَحْيَى بْنُ عَبْدِ اللَّهِ بْنِ بَحِيرٍ قَالَ أَخْبَرَنِي مَنْ سَمِعَ فَرْوَةَ بْنَ مُسَيْكٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرْضٌ عِنْدَنَا يُقَالُ لَهَا أَرْضُ أَبْيَنَ هِيَ أَرْضُ رِيفِنَا وَمِيرَتِنَا وَإِنَّهَا وَبِئَةٌ أَوْ قَالَ وَبَاؤُهَا شَدِيدٌ فَقَالَ النَّبِيُّ دَعْهَا عَنْكَ فَإِنَّ مِنْ الْقَرَفِ التَّلَفَ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid] serta [Abbas Al 'Anbari] mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Yahya bin Abdullah bin Bahir] ia berkata; telah mengabarkan kepadaku [orang yang telah] mendengar [Farwah bin Musaik] berkata; aku katakan; wahai Rasulullah, lahan kami yang bernama tanah Abyan adalah tanah yang memiliki tanaman serta subur, tanah ladang kami, sesungguhnya tanah tersebut berwabah... -atau dia mengatakan; wabahnya keras- kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Tinggalkan tanah tersebut, sesungguhnya bersinggungan dengan penyakit adalah kebinasaan.\""},"3339":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُفَضَّلُ بْنُ فَضَالَةَ عَنْ حَبِيبِ بْنِ الشَّهِيدِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ بِيَدِ مَجْذُومٍ فَوَضَعَهَا مَعَهُ فِي الْقَصْعَةِ وَقَالَ كُلْ ثِقَةً بِاللَّهِ وَتَوَكُّلًا عَلَيْهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Mufadldlal bin Fadlalah] dari [Habib bin Asy Syahid] dari [Muhammad bin Al Munkadir] dari [Jabir], bahwa Rasulullah shallallahu 'alaihi wasallam menggandeng tangan orang yang menderita penyakit kusta, kemudian beliau meletakkan tangan orang tersebut di atas nampan seraya bersabda: \"Makanlah dengan percaya kepada Allah dan bertawakal kepada-Nya.\""},"3340":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو بَدْرٍ حَدَّثَنِي أَبُو عُتْبَةَ إِسْمَعِيلُ بْنُ عَيَّاشٍ حَدَّثَنِي سُلَيْمَانُ بْنُ سُلَيْمٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُكَاتَبُ عَبْدٌ مَا بَقِيَ عَلَيْهِ مِنْ مُكَاتَبَتِهِ دِرْهَمٌ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Abu Badr] telah menceritakan kepadaku [Abu 'Utbah Isma'il bin 'Ayyasy] telah menceritakan kepadaku [Sulaiman bin Sulaim] dari ['Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang mukatab tetap sebagai seorang budak selama ia belum menyelesaikan tanggungan pembebasannya meskipun satu dirham.\" "},"3341":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَبَّاسٌ الْجُرَيْرِيُّ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا عَبْدٍ كَاتَبَ عَلَى مِائَةِ أُوقِيَّةٍ فَأَدَّاهَا إِلَّا عَشْرَةَ أَوَاقٍ فَهُوَ عَبْدٌ وَأَيُّمَا عَبْدٍ كَاتَبَ عَلَى مِائَةِ دِينَارٍ فَأَدَّاهَا إِلَّا عَشْرَةَ دَنَانِيرَ فَهُوَ عَبْدٌقَالَ أَبُو دَاوُد لَيْسَ هُوَ عَبَّاسٌ الْجُرَيْرِيُّ قَالُوا هُوَ وَهْمٌ وَلَكِنَّهُ هُوَ شَيْخٌ آخَرُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepadaku [Abdushshamad] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami ['Abbas Al Jurairi] dari ['Amru bin Syu'aib] dari [Ayahnya] dari [Kakeknya], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Budak manasaja yang mengadakan perjanjian pembebasan dirinya seharga seratus uqiyah, kemudian ia telah menyelesaikan semua membayarnya kecuali sepuluh uqiyah, maka ia tetap sebagai budak. Dan budak manasaja yang mengadakan perjanjian pembebasan dirinya dengan harga seratus dinar, kemudian ia telah menyelesaikan semua pembayarannya kecuali sepuluh dinar, maka ia tetap sebagai budak.\" Abu Daud berkata, \"Ia bukanlah Abbas Al Jurairi, yang mereka katakan hanyalah peraduka, yang benar bahwa ia adalah syaikh yang lain.\" "},"3342":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ نَبْهَانَ مُكَاتَبِ أُمِّ سَلَمَةَ قَالَ سَمِعْتُ أُمَّ سَلَمَةَ تَقُولُقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ لِإِحْدَاكُنَّ مُكَاتَبٌ فَكَانَ عِنْدَهُ مَا يُؤَدِّي فَلْتَحْتَجِبْ مِنْهُ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Nabhan] seorang budak yang ingin membebaskan dirinya milik Ummu Salamah, ia berkata, \"Aku pernah mendengar [Ummu Salamah] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah berkata kepada kami: \"Apabila salah seorang di antara kalian memiliki budak mukatab dan budak tersebut memiliki sesuatu yang dapat ia bayarkan, maka hendaknya ia memasang hijab darinya.\" "},"3343":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُأَنَّ بَرِيرَةَ جَاءَتْ عَائِشَةَ تَسْتَعِينُهَا فِي كِتَابَتِهَا وَلَمْ تَكُنْ قَضَتْ مِنْ كِتَابَتِهَا شَيْئًا فَقَالَتْ لَهَا عَائِشَةُ ارْجِعِي إِلَى أَهْلِكِ فَإِنْ أَحَبُّوا أَنْ أَقْضِيَ عَنْكِ كِتَابَتَكِ وَيَكُونَ وَلَاؤُكِ لِي فَعَلْتُ فَذَكَرَتْ ذَلِكَ بَرِيرَةُ لِأَهْلِهَا فَأَبَوْا وَقَالُوا إِنْ شَاءَتْ أَنْ تَحْتَسِبَ عَلَيْكِ فَلْتَفْعَلْ وَيَكُونُ لَنَا وَلَاؤُكِ فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعِي فَأَعْتِقِي فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَالُ أُنَاسٍ يَشْتَرِطُونَ شُرُوطًا لَيْسَتْ فِي كِتَابِ اللَّهِ مَنْ اشْتَرَطَ شَرْطًا لَيْسَ فِي كِتَابِ اللَّهِ فَلَيْسَ لَهُ وَإِنْ شَرَطَهُ مِائَةَ مَرَّةٍ شَرْطُ اللَّهِ أَحَقُّ وَأَوْثَقُحَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ جَاءَتْ بَرِيرَةُ لِتَسْتَعِينَ فِي كِتَابَتِهَا فَقَالَتْ إِنِّي كَاتَبْتُ أَهْلِي عَلَى تِسْعِ أَوَاقٍ فِي كُلِّ عَامٍ أُوقِيَّةٌ فَأَعِينِينِي فَقَالَتْ إِنْ أَحَبَّ أَهْلُكِ أَنْ أَعُدَّهَا عَدَّةً وَاحِدَةً وَأَعْتِقَكِ وَيَكُونَ وَلَاؤُكِ لِي فَعَلْتُ فَذَهَبَتْ إِلَى أَهْلِهَا وَسَاقَ الْحَدِيثَ نَحْوَ الزُّهْرِيِّ زَادَ فِي كَلَامِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آخِرِهِ مَا بَالُ رِجَالٍ يَقُولُ أَحَدُهُمْ أَعْتِقْ يَا فُلَانُ وَالْوَلَاءُ لِي إِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dan [Qutaibah bin Sa'id] mereka berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] bahwa [Aisyah] radliallahu 'anhuma mengabarkan kepadanya, bahwa Barirah telah datang kepada Aisyah meminta bantuan kepadanya dalam hal perjanjian pembebasan dirinya, sementara ia tidak mampu melunasi sedikitpun dari perjanjain pembebasannya. Kemudian Aisyah berkata kepadanya, \"Kembalilah kepada tuanmu, jika mereka mau aku melunasi pembayaranmu dan perwaliannya untukku, maka aku akan melakukannya.\" Kemudian Barirah menyebutkan hal tersebut kepada tuannya. Namun mereka menolak dan berkata, \"Apabila Aisyah berkehendak untuk mendapatkan pahala dengan membebaskanmu maka silahkan ia melakukan, dan perwalianmu untuk kami.\" Aisyah kemudian menceritakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam pun berkata kepadanya: \"Beli dan bebaskanlah dia, sesungguhnya perwalian adalah untuk orang yang telah membebaskan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berdiri dan bersabda: \"Mengapa orang-orang membuat syarat yang tidak ada dalam kitab Allah! Barangsiapa memberikan syarat yang tidak ada dalam kitab Allah, maka tidak ada hak baginya walaupun ia memberikan syarat sebanyak seratus kali. Syarat Allah lebih berhak dan lebih kuat.\" Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anhuma, ia berkata, \"Barirah telah datang minta bantuan mengenai perjanjian pembebasannya, ia berkata, \"Sesungguhnya aku mengadakan perjanjian pembebasan diriku dengan tuanku seharga sembilan uqiyah, yaitu satu uqiyah untuk setiap tahunnya. Maka bantulah aku!\" Kemudian Aisyah berkata, \"Jika tuanmu ingin aku melunasi pembayaran tersebut, lalu aku bebaskan kamu dan perlianmu juga tetap untukku maka aku akan lakukan.\" Barirah kemudian pergi menemui tuannya…lalu 'Urwah menyebutkan hadits tersebut seperti hadits Az Zuhri. Ia menambahkan pada akhir sabda Nabi shallallahu 'alaihi wasallam: \"Kenapa di antara orang-orang ada seorang laki-laki berkata, 'Bebaskan wahai Fulan, dan perwaliannya milikku' sesungguhnya perwalian adalah milik orang yang membebaskan.\""},"3344":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ يَحْيَى أَبُو الْأَصْبَغِ الْحَرَّانِيُّ حَدَّثَنِي مُحَمَّدٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ ابْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْوَقَعَتْ جُوَيْرِيَةُ بِنْتُ الْحَارِثِ بْنِ الْمُصْطَلِقِ فِي سَهْمِ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ أَوْ ابْنِ عَمٍّ لَهُ فَكَاتَبَتْ عَلَى نَفْسِهَا وَكَانَتْ امْرَأَةً مَلَّاحَةً تَأْخُذُهَا الْعَيْنُ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا فَجَاءَتْ تَسْأَلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كِتَابَتِهَا فَلَمَّا قَامَتْ عَلَى الْبَابِ فَرَأَيْتُهَا كَرِهْتُ مَكَانَهَا وَعَرَفْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَيَرَى مِنْهَا مِثْلَ الَّذِي رَأَيْتُ فَقَالَتْ يَا رَسُولَ اللَّهِ أَنَا جُوَيْرِيَةُ بِنْتُ الْحَارِثِ وَإِنَّمَا كَانَ مِنْ أَمْرِي مَا لَا يَخْفَى عَلَيْكَ وَإِنِّي وَقَعْتُ فِي سَهْمِ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ وَإِنِّي كَاتَبْتُ عَلَى نَفْسِي فَجِئْتُكَ أَسْأَلُكَ فِي كِتَابَتِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهَلْ لَكِ إِلَى مَا هُوَ خَيْرٌ مِنْهُ قَالَتْ وَمَا هُوَ يَا رَسُولَ اللَّهِ قَالَ أُؤَدِّي عَنْكِ كِتَابَتَكِ وَأَتَزَوَّجُكِ قَالَتْ قَدْ فَعَلْتُ قَالَتْ فَتَسَامَعَ تَعْنِي النَّاسَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ تَزَوَّجَ جُوَيْرِيَةَ فَأَرْسَلُوا مَا فِي أَيْدِيهِمْ مِنْ السَّبْيِ فَأَعْتَقُوهُمْ وَقَالُوا أَصْهَارُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا رَأَيْنَا امْرَأَةً كَانَتْ أَعْظَمَ بَرَكَةً عَلَى قَوْمِهَا مِنْهَا أُعْتِقَ فِي سَبَبِهَا مِائَةُ أَهْلِ بَيْتٍ مِنْ بَنِي الْمُصْطَلِقِقَالَ أَبُو دَاوُد هَذَا حُجَّةٌ فِي أَنَّ الْوَلِيَّ هُوَ يُزَوِّجُ نَفْسَهُ","id":"Telah menceritakan kepada kami [Abdul Aziz bin Yahya Abu Al Ashbagh Al Harrani] telah menceritakan kepadaku [Muhammad bin Salamah] dari [Ibnu Ishaq] dari [Muhammad bin Ja'far bin Az Zubair] dari ['Urwah bin Az Zubair] dari [Aisyah] radliallahu 'anhuma, ia berkata, \"Juwairiyah binti Al Harits bin Al Mushthaliq menjadi milik Tsabit bin Qais bin Syammas saat pembagian ghanimah, atau pada anak pamannya. Kemudian Juwairiyah mengadakan perjanjian pembebasan dirinya. Ia adalah wanita menawan yang selalu menarik perhatian orang yang memandangnya. Aisyah radliallahu 'anha berkata, \"Kemudian ia datang memohon bantuan kepada Rasulullah shallallahu 'alaihi wasallam dalam hal perjanjian pembebasannya. Ketika ia berdiri di depan pintu dan aku melihatnya, maka aku tidak menyukai posisinya dan aku mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam akan melihat dirinya seperti yang aku lihat. Kemudian Juwairiyah berkata, \"Wahai Rasulullah, aku adalah Juwairiyah binti Al Harits, permasalahanku sudah tuan ketahui. Sungguh, aku telah menjadi milik Tsabit bin Qais bin Syammas dalam pembagian, dan aku telah mengadakan perjanjian pembebasan diriku. Maka aku datang kepadamu memohon pertolongan dalam perjanjian pembebasanku.\" Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Apakah engkau mau mengambil sesuatu yang lebih baik dari hal itu?\" Juwairiyah bertanya, \"Hal apakah itu wahai Rasulullah?\" Beliau bersabda: \"Aku bayarkan perjanjian pembebasanmu dan aku akan menikahimu!\" Jiwairiyah menjawab, \"Aku telah melakukannya (siap).\" Aisyah berkata, \"Kemudian orang-orang mendengar bahwa Rasulullah shallallahu 'alaihi wasallam telah menikahi Juwairiyah, mereka pun melepaskan tawanan yang ada di tangan mereka dan membebaskan mereka. kemudian mereka berkata, \"Para tawanan itu adalah kerabat (besan) Rasulullah shallallahu 'alaihi wasallam. Kami tidak melihat seorang wanita yang lebih besar berkahnya bagi kaumnya dari pada dirinya, sebab karenanya seratus keluarga Bani Mushthaliq dibebaskan.\" Abu Daud berkata, \"Hadits ini adalah hujjah bahwa seorang wali boleh menikahkan dirinya.\""},"3345":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ سَعِيدِ بْنِ جُمْهَانَ عَنْ سَفِينَةَ قَالَكُنْتُ مَمْلُوكًا لِأُمِّ سَلَمَةَ فَقَالَتْ أُعْتِقُكَ وَأَشْتَرِطُ عَلَيْكَ أَنْ تَخْدُمَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا عِشْتَ فَقُلْتُ وَإِنْ لَمْ تَشْتَرِطِي عَلَيَّ مَا فَارَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا عِشْتُ فَأَعْتَقَتْنِي وَاشْتَرَطَتْ عَلَيَّ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad] telah menceritakan kepada kami [Abdul Warits] dari [Sa'id bin Jumhan] dari [Safinah] ia berkata, \"Aku dahulu adalah seorang budak milik [Ummu Salamah], lalu ia berkata, 'Aku akan membebaskanmu dan aku meminta syarat kepadamu agar melayani Rasulullah shallallahu 'alaihi wasallam selama engkau hidup'. Lalu aku katakan, 'Walaupun engkau tidak mensyaratkan kepadaku, aku tidak akan meninggalkan Rasulullah shallallahu 'alaihi wasallam selama aku hidup. ' Lalu Ummu Salamah membebaskanku dan memberikan syarat kepadaku.\""},"3346":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ الْمَعْنَى أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ قَالَ أَبُو الْوَلِيدِ عَنْ أَبِيهِأَنَّ رَجُلًا أَعْتَقَ شِقْصًا لَهُ مِنْ غُلَامٍ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَيْسَ لِلَّهِ شَرِيكٌ زَادَ ابْنُ كَثِيرٍ فِي حَدِيثِهِ فَأَجَازَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِتْقَهُ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammam]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Katsir] secara makna, telah mengabarkan kepada kami [Hammam] dari [Qatadah] dari [Abu Al Malih], Abu Al Walid berkata dari [Ayahnya], bahwa seorang laki-laki telah memerdekakan bagiannya dari seorang budak. Kemudian hal tersebut diceritakan kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Allah tidak memiliki sekutu.\" Ibnu Katsir menambahkan dalam haditsnya, \"Kemudian Nabi shallallahu 'alaihi wasallam memperbolehkan untuk membebaskannya.\""},"3347":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنِي هَمَّامٌ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا أَعْتَقَ شِقْصًا لَهُ مِنْ غُلَامٍ فَأَجَازَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِتْقَهُ وَغَرَّمَهُ بَقِيَّةَ ثَمَنِهِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ عَلِيِّ بْنِ سُوَيْدٍ حَدَّثَنَا رَوْحٌ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ بِإِسْنَادِهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ مَمْلُوكًا بَيْنَهُ وَبَيْنَ آخَرَ فَعَلَيْهِ خَلَاصُهُ وَهَذَا لَفْظُ ابْنِ سُوَيْدٍ حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي ح و حَدَّثَنَا أَحْمَدُ بْنُ عَلِيِّ بْنِ سُوَيْدٍ حَدَّثَنَا رَوْحٌ حَدَّثَنَا هِشَامُ بْنُ أَبِي عَبْدِ اللَّهِ عَنْ قَتَادَةَ بِإِسْنَادِهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ نَصِيبًا لَهُ فِي مَمْلُوكٍ عَتَقَ مِنْ مَالِهِ إِنْ كَانَ لَهُ مَالٌ وَلَمْ يَذْكُرْ ابْنُ الْمُثَنَّى النَّضْرَ بْنَ أَنَسٍ وَهَذَا لَفْظُ ابْنِ سُوَيْدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepadaku [Hammam] dari [Qatadah] dari [An Nadlr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah], bahwa seorang laki-laki telah membebaskan baginnya dari seorang budak. Kemudian Nabi shallallahu 'alaihi wasallam memperbolehkan untuk membebaskannya dan beliau menanggungkan kepadanya sisa harga budak tersebut.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Ali bin Suwaid] telah menceritakan kepada kami [Rauh] mereka berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dengan sanadnya, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membebaskan seorang budak antara dirinya dan orang lain, maka hendaklah ia menanggung sisa pembayaran.\" Lafazh ini adalah lafazh Ibnu Suwaid.\" Telah menceritakan kepada kami [Ibnu Al Mutsanna] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Ayahku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin Ali bin Suwaid] telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Hisyam bin Abu Abdullah] dari [Qatadah] dengan sanadnya, bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membebaskan bagiannya dalam diri seorang budak, hendaklah ia bebaskan sisanya jika memiliki uang.\" Namun Ibnu Al Mutsanna belum menyebutkan nama An Nadlr bin Anas, dan ini adalah lafadz Ibnu Suwaid.\""},"3348":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ يَعْنِي الْعَطَّارَ حَدَّثَنَا قَتَادَةُ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ شَقِيصًا فِي مَمْلُوكِهِ فَعَلَيْهِ أَنْ يُعْتِقَهُ كُلَّهُ إِنْ كَانَ لَهُ مَالٌ وَإِلَّا اسْتُسْعِيَ الْعَبْدُ غَيْرَ مَشْقُوقٍ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban Al 'Aththar] telah menceritakan kepada kami [Qatadah] dari [An Nadlr bin Anas] dari [Basyir bin Nuhaik] dari [Abu Hurairah] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membebaskan bagian kepemilikannya pada diri seorang budak, maka hendaklah ia membebaskan seluruhnya jika ia memiliki harta, jika tidak maka hendaklah budak tersebut diminta untuk berusaha (membebaskan diri) dengan tanpa diperberat.\""},"3349":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ أَخْبَرَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ ح و حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ وَهَذَا لَفْظُهُ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ شِقْصًا لَهُ أَوْ شَقِيصًا لَهُ فِي مَمْلُوكٍ فَخَلَاصُهُ عَلَيْهِ فِي مَالِهِ إِنْ كَانَ لَهُ مَالٌ فَإِنْ لَمْ يَكُنْ لَهُ مَالٌ قُوِّمَ الْعَبْدُ قِيمَةَ عَدْلٍ ثُمَّ اسْتُسْعِيَ لِصَاحِبِهِ فِي قِيمَتِهِ غَيْرَ مَشْقُوقٍ عَلَيْهِ قَالَ أَبُو دَاوُد فِي حَدِيثِهِمَا جَمِيعًا فَاسْتُسْعِيَ غَيْرَ مَشْقُوقٍ عَلَيْهِ وَهَذَا لَفْظُ عَلِيٍّحَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى وَابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ أَبُو دَاوُد وَرَوَاهُ رَوْحُ بْنُ عُبَادَةَ عَنْ سَعِيدٍ بْنِ أَبِي عَرُوبَةَ لَمْ يَذْكُرْ السِّعَايَةَ وَرَوَاهُ جَرِيرُ بْنُ حَازِمٍ وَمُوسَى بْنُ خَلَفٍ جَمِيعًا عَنْ قَتَادَةَ بِإِسْنَادِ يَزِيدَ بْنِ زُرَيْعٍ وَمَعْنَاهُ وَذَكَرَا فِيهِ السِّعَايَةَ","id":"Telah menceritakan kepada kami [Nashr bin Ali] telah mengabarkan kepada kami [Yazid bin Zurai']. Telah menceritakan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Muhammad bin Bisyr] dan ini adalah lafadznya, dari [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [An Nadlr bin Anas] dari [Basyir bin Nuhaik] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa memerdekakan bagiannya dalam diri seorang budak, maka ia berkewajiban membayar sisa harganya dengan harta miliknya jika ia memiliki. Namun jika tidak memiliki harta, maka budak tersebut dinilai dengan nilai pertengahan, kemudian ia diminta (untuk membebaskan diri dengan tebusan) dengan tidak memperberatnya.\" Abu Daud menyebutkan dalam kedua haditsnya, 'kemudian diminta untuk membebaskan dirinya dengan tidak memperberatnya. ' Dan ini adalah lafadz Ali.\" Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya], dan [Ibnu Abu Adi] dari [Sa'id] dengan sanad dan maknanya.\" Abu Daud berkata, \" [Rauh bin 'Ubadah] juga meriwayatkannya dari [Sa'id bin Abu 'Arubah], namun ia tidak menyebutkan lafadz 'berusaha'. [Jarir bin Hazim] dan [Musa bin Khalaf] keduanya juga meriwayatkannya dari [Qatadah] dengan sanad Yazid bin Zurai', seperti makna hadits tersebut, namun dalam hadits tersebut mereka menyebutkan lafadz 'berusaha'.\""},"3350":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ شِرْكًا لَهُ فِي مَمْلُوكٍ أُقِيمَ عَلَيْهِ قِيمَةُ الْعَدْلِ فَأَعْطَى شُرَكَاءَهُ حِصَصَهُمْ وَأُعْتِقَ عَلَيْهِ الْعَبْدُ وَإِلَّا فَقَدْ عَتَقَ مِنْهُ مَا عَتَقَحَدَّثَنَا مُؤَمَّلٌ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَاهُ قَالَ وَكَانَ نَافِعٌ رُبَّمَا قَالَ فَقَدْ عَتَقَ مِنْهُ مَا عَتَقَ وَرُبَّمَا لَمْ يَقُلْهُ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْعَتَكِيُّ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ قَالَ أَيُّوبُ فَلَا أَدْرِي هُوَ فِي الْحَدِيثِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ شَيْءٌ قَالَهُ نَافِعٌ وَإِلَّا عَتَقَ مِنْهُ مَا عَتَقَ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membebaskan bagiannya dalam diri seorang budak, maka budak tersebut dinilai dengan nilai pertengahan. Lalu ia memberikan bagian para sekutunya kepada mereka, dan budak tersebut dibebaskan, jika tidak maka ia telah membebaskan darinya bagian yang telah ia bebaskan.\" Telah menceritakan kepada kami [Muammal] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan maknanya. Ia berkata, \"Nafi' dimungkinkan mengatakan, 'Sungguh ia telah membebaskan darinya bagian yang telah ia bebaskan', dan mungkin juga ia tidak mengatakannya.\" Telah menceritakan kepada kami [Sulaiman bin Daud Al 'Ataki] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini. Ayyub berkata, \"Aku tidak tahu, lafadz tersebut ada dalam hadits Nabi shallallahu 'alaihi wasallam, atau sesuatu yang ia dikatakan oleh Nafi', yaitu ucapan, 'jika tidak maka ia telah membebaskan darinya bagian yang telah ia bebaskan'.\""},"3351":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى الرَّازِيُّ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ شِرْكًا مِنْ مَمْلُوكٍ لَهُ فَعَلَيْهِ عِتْقُهُ كُلِّهِ إِنْ كَانَ لَهُ مَا يَبْلُغُ ثَمَنَهُ وَإِنْ لَمْ يَكُنْ لَهُ مَالٌ عَتَقَ نَصِيبَهُحَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنِي يَحْيَى بْنُ سَعِيدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى إِبْرَاهِيمَ بْنِ مُوسَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى مَالِكٍ وَلَمْ يَذْكُرْ وَإِلَّا فَقَدْ عَتَقَ مِنْهُ مَا عَتَقَ ا��ْتَهَى حَدِيثُهُ إِلَى وَأُعْتِقَ عَلَيْهِ الْعَبْدُ عَلَى مَعْنَاهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa Ar Razi] telah mengabarkan kepada kami [Isa bin Yunus] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membebaskan baginya dari budaknya maka ia berkewajiban membebaskan seluruhnya apabila ia memiliki harta yang mencapai nilai harga budak tersebut. Jika tidak memiliki harta, maka ia telah membebaskan bagiannya.\" Telah menceritakan kepada kami [Makhlad bin Khalid] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepadaku [Yahya bin Sa'id] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan makna hadits Ibnu bin Musa.\" Telah menceritakan kepada kami [Abdullah bin Muhammad bin Asma`] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan makna hadits Malik, namun ia tidak menyebutkan kata, 'jika tidak (mempunyai uang), maka ia telah membebaskan darinya apa yang telah menjadi bagiannya. ' Dan haditsnya berakhir pada lafadz 'dan budak tersebut telah dibebaskan', seperti makna hadits tersebut.\""},"3352":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَعْتَقَ شِرْكًا لَهُ فِي عَبْدٍ عَتَقَ مِنْهُ مَا بَقِيَ فِي مَالِهِ إِذَا كَانَ لَهُ مَا يَبْلُغُ ثَمَنَ الْعَبْدِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membebaskan bagiannya dalam diri seorang budak, maka ia berkewajiban membebaskan bagian yang tersisa jika uangnya mencukupi nilai harga budak tersebut.\""},"3353":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَالِمٍ عَنْ أَبِيهِيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الْعَبْدُ بَيْنَ اثْنَيْنِ فَأَعْتَقَ أَحَدُهُمَا نَصِيبَهُ فَإِنْ كَانَ مُوسِرًا يُقَوَّمُ عَلَيْهِ قِيمَةً لَا وَكْسَ وَلَا شَطَطَ ثُمَّ يُعْتَقُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [Salim] dari [Ayahnya] dan sampai kepada Nabi shallallahu 'alaihi wasallam, \"Jika seorang budak milik dua orang, kemudian salah seorang dari mereka membebaskan bagian yang menjadi miliknya, jika ia masih memiliki kelebihan harta maka budak tersebut hendaklah dihargai (tidak dilebihkan atau dikurangi), kemudian dibebaskan.\""},"3354":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ خَالِدٍ عَنْ أَبِي بِشْرٍ الْعَنْبَرِيِّ عَنْ ابْنِ التَّلِبِّ عَنْ أَبِيهِأَنَّ رَجُلًا أَعْتَقَ نَصِيبًا لَهُ مِنْ مَمْلُوكٍ فَلَمْ يُضَمِّنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَحْمَدُ إِنَّمَا هُوَ بِالتَّاءِ يَعْنِي التَّلِبَّ وَكَانَ شُعْبَةُ أَلْثَغُ لَمْ يُبَيِّنْ التَّاءَ مِنْ الثَّاءِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Khalid] dari [Abu Bisyr Al 'Anbari] dari [Ibnu At Talib] dari [Ayahnya], bahwa seorang laki-laki telah membebaskan bagiannya dari diri seorang budak, dan Nabi shallallahu 'alaihi wasallam tidak membebaninya dengan tanggungan.\" Ahmad berkata, \"Hanyasanya itu dengan huruf ta', yaitu At Talib. Sedangkan Syu'bah tidak mampu mengucapkan sebagian huruf, ia tidak dapat membedakan dengan jelas antara ta` dan tsa`.\""},"3355":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ وَمُوسَى بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مُوسَى فِي مَوْضِعٍ آخَرَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ فِيمَا يَحْسِبُ حَمَّادٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ مَلَكَ ذَا رَحِمٍ مَحْرَمٍ فَهُوَ حُرٌّقَالَ أَبُو دَاوُد رَوَى مُحَمَّدُ بْنُ بَكْرٍ الْبُرْسَانِيُّ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ قَتَادَةَ وَعَاصِمٍ عَنْ الْحَسَنِ عَنْ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ الْحَدِيثِ قَالَ أَبُو دَاوُد وَلَمْ يُحَدِّثْ ذَلِكَ الْحَدِيثَ إِلَّا حَمَّادُ بْنُ سَلَمَةَ وَقَدْ شَكَّ فِيهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] dan [Musa bin Isma'il] mereka berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam, dan Musa berkata pada tempat yang lain, dari Samurah bin Jundub menurut perhitungan Hammad, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memiliki hubungan kekerabatan, maka ia adalah orang yang merdeka.\" Abu Daud berkata; [Muhammad bin Bakr Al Bursani] meriwayatkannya dari [Hammad bin Salamah] dari [Qatadah] dan ['Ashim] dari [Al Hasan] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam seperti hadits tersebut.\" Abu Daud berkata, \"Tidak ada yang menceritakan hadits tersebut kecuali Hammad bin Salamah, dan ia telah ragu dalam hal tersebut.\""},"3356":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ سَعِيدٍ عَنْ قَتَادَةَ أَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَمَنْ مَلَكَ ذَا رَحِمٍ مَحْرَمٍ فَهُوَ حُرٌّ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Abdul Wahhab] dari [Sa'id] dari [Qatadah] bahwa [Umar bin Al Khathab] radliallahu 'anhu berkata, \"Barangsiapa memiliki hubungan kekerabatan maka ia adalah orang yang merdeka.\""},"3357":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ قَالَمَنْ مَلَكَ ذَا رَحِمٍ مَحْرَمٍ فَهُوَ حُرٌّحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ جَابِرِ بْنِ زَيْدٍ وَالْحَسَنِ مِثْلَهُ قَالَ أَبُو دَاوُد سَعِيدٌ أَحْفَظُ مِنْ حَمَّادٍ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman] telah menceritakan kepada kami [Abdul Wahhab] dari [Sa'id] dari [Qatadah] dari [Al Hasan] ia berkata, \"Barangsiapa memiliki hubungan kekerabatan, maka ia adalah orang yang merdeka.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Sa'id] dari [Qatadah] dari [Jabir bin Zaid] dan [Al Hasan] seperti itu.\" Abu Daud berkata, \"Sa'id lebih hafal daripada Hammad.\""},"3358":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ خَطَّابِ بْنِ صَالِحٍ مَوْلَى الْأَنْصَارِيِّ عَنْ أُمِّهِ عَنْ سَلَامَةَ بِنْتِ مَعْقِلٍ امْرَأَةٍ مِنْ خَارِجَةِ قَيْسِ عَيْلَانَ قَالَتْقَدِمَ بِي عَمِّي فِي الْجَاهِلِيَّةِ فَبَاعَنِي مِنْ الْحُبَابِ بْنِ عَمْرٍو أَخِي أَبِي الْيُسْرِ بْنِ عَمْرٍو فَوَلَدْتُ لَهُ عَبْدَ الرَّحْمَنِ بْنَ الْحُبَابِ ثُمَّ هَلَكَ فَقَالَتْ امْرَأَتُهُ الْآنَ وَاللَّهِ تُبَاعِينَ فِي دَيْنِهِ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي امْرَأَةٌ مِنْ خَارِجَةِ قَيْسِ عَيْلَانَ قَدِمَ بِي عَمِّي الْمَدِينَةَ فِي الْجَاهِلِيَّةِ فَبَاعَنِي مِنْ الْحُبَابِ بْنِ عَمْرٍو أَخِي أَبِي الْيُسْرِ بْنِ عَمْرٍو فَوَلَدْتُ لَهُ عَبْدَ الرَّحْمَنِ بْنَ الْحُبَابِ فَقَالَتْ امْرَأَتُهُ الْآنَ وَاللَّهِ تُبَاعِينَ فِي دَيْنِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ وَلِيُّ الْحُبَابِ قِيلَ أَخُوهُ أَبُو الْيُسْرِ بْنُ عَمْرٍو فَبَعَثَ إِلَيْهِ فَقَالَ أَعْتِقُوهَا فَإِذَا سَمِعْتُمْ بِرَقِيقٍ قَدِمَ عَلَيَّ فَأْتُونِي أُعَوِّضْكُمْ مِنْهَا قَالَتْ فَأَعْتَقُونِي وَقَدِمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَقِيقٌ فَعَوَّضَهُمْ مِنِّي غُلَامًا","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Muhammad bin Salamah] dari [Muhammad bin Ishaq] dari [Khaththab bin Shalih] mantan budak Al Anshari, dari [Ibunya] dari [Salamah binti Ma'qil] seorang wanita dari Kabilah Kharijah Qais 'Ailan, ia berkata, \"Pamanku datang membawaku pada masa jahiliyah, kemudian ia menjualku kepada Al Hubab bin 'Amru, saudara Abu Al Yusr bin 'Amru. Setelah itu aku melahirkan seorang anak untuknya bernama Abdurrahman bin Al Hubab, ketika ia meninggal isterinya berkata, \"Demi Allah, sekarang engkau akan dijual untuk melunasi hutangnya.\" Lalu aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan aku katakan, \"Wahai Rasulullah, sesungguhnya saya adalah seorang wanita yang berasal dari Kharijah Qais 'Ailan. Pamanku datang ke Madinah membawaku pada masa jahiliyah, kemudian ia menjualku kepada Al Hubab bin 'Amru, saudara Abu Al Yusr bin 'Amru. Lalu aku melahirkan anaknya yang bernama Abdurrahman bin Al Hubab, kemudian isterinya berkata, 'Demi Allah, sekarang engkau akan dijual untuk melunasi hutangnya'? Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Siapakah wali Al Hubab?\" Kemudian dijawab, \"Saudaranya, yaitu Abu Al Yusr bin 'Amru.\" Beliau lalu mengirim utusan kepadanya dan berkata: \"Bebaskan wanita itu! Dan jika kalian mendengar ada budak yang datang untuk diberkan kepadaku (dari rampasan perang), maka bawalah ia kemari hingga aku memberikannya kepada kalian sebagai gantinya.\" Salamah berkata, \"Kemudian mereka membebaskanku, ketidak datang seorangh budak untuk Rasulullah shallallahu 'alaihi wasallam, maka beliau menganti (pembebasanku) dengan seorang budak.\""},"3359":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ قَيْسٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبِعْنَا أُمَّهَاتِ الْأَوْلَادِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ فَلَمَّا كَانَ عُمَرُ نَهَانَا فَانْتَهَيْنَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Qais] dari ['Atha] dari [Jabir bin Abdullah] ia berkata, \"Kami pernah membeli beberapa ummul walad pada zaman Rasulullah shallallahu 'alaihi wasallam serta pada zaman Abu Bakr. Ketika Umar menjabat sebagai Khalifah, ia melarang kami, maka kami pun tidak melakukannya lagi.\" "},"3360":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا هُشَيْمٌ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ وَإِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَجُلًا أَعْتَقَ غُلَامًا لَهُ عَنْ دُبُرٍ مِنْهُ وَلَمْ يَكُنْ لَهُ مَالٌ غَيْرُهُ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبِيعَ بِسَبْعِ مِائَةِ أَوْ بِتِسْعِ مِائَةِحَدَّثَنَا جَعْفَرُ بْنُ مُسَافِرٍ حَدَّثَنَا بِشْرُ بْنُ بَكْرٍ أَخْبَرَنَا الْأَوْزَاعِيُّ حَدَّثَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ بِهَذَا زَادَ وَقَالَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْتَ أَحَقُّ بِثَمَنِهِ وَاللَّهُ أَغْنَى عَنْهُ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Husyaim] dari [Abdul Malik bin Abu Sulaiman] dari ['Atha] dan [Isma'il bin Abu Khalid] dari [Salamah bin Kuhail] dari ['Atha] dari [Jabir bin Abdullah], bahwa seorang laki-laki berjanji kepada budaknya, bahwa dirinya akan merdeka setelah ia (tuan) meninggal, padahal ia tidak memiliki seorang pun selain budak tersebut. Lalu Nabi shallallahu 'alaihi wasallam memerintahkan agar menjualnya, lalu budak tersebut dijual dengan harga tujuh ratus atau sembilan ratus.\" Telah menceritakan kepada kami [Ja'far bin Musafir] telah menceritakan kepada kami [Bisyr bin Bakr] telah mengabarkan kepada kami [Al Auza'i] telah menceritakan kepadaku ['Atha bin Abu Rabah] telah menceritakan kepadaku [Jabir bin Abdullah] dengan hadits ini, ia menambahkan, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Engkau lebih berhak terhadap harganya dan Allah tidak butuh kepadanya.\""},"3361":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي الزُّبَيْر�� عَنْ جَابِرٍأَنَّ رَجُلًا مِنْ الْأَنْصَارِ يُقَالُ لَهُ أَبُو مَذْكُورٍ أَعْتَقَ غُلَامًا لَهُ يُقَالُ لَهُ يَعْقُوبُ عَنْ دُبُرٍ وَلَمْ يَكُنْ لَهُ مَالٌ غَيْرُهُ فَدَعَا بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ يَشْتَرِيهِ فَاشْتَرَاهُ نُعَيْمُ بْنُ عَبْدِ اللَّهِ بْنِ النَّحَّامِ بِثَمَانِ مِائَةِ دِرْهَمٍ فَدَفَعَهَا إِلَيْهِ ثُمَّ قَالَ إِذَا كَانَ أَحَدُكُمْ فَقِيرًا فَلْيَبْدَأْ بِنَفْسِهِ فَإِنْ كَانَ فِيهَا فَضْلٌ فَعَلَى عِيَالِهِ فَإِنْ كَانَ فِيهَا فَضْلٌ فَعَلَى ذِي قَرَابَتِهِ أَوْ قَالَ عَلَى ذِي رَحِمِهِ فَإِنْ كَانَ فَضْلًا فَهَاهُنَا وَهَاهُنَا","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Ayyub] dari [Abu Az Zubair] dari [Jabir], bahwa seorang laki-laki anshar yang bernama Abu Madzkur telah membebaskan seorang budaknya yang bernama Ya'qub (dengan syarat ia telah meninggal), dan ia tidak memiliki harta selain budak tersebut. Kemudian Rasulullah shallallahu 'alaihi wasallam meminta untuk membawanya dan bersabda: \"Siapakah yang mau membelinya?\" Kemudian Nu'aim bin Abdullah bin An Nahham membelinya dengan harga delapan ratus dirham. Beliau lalu menyerahkan uang tersebut kepadanya seraya bersabda: \"Jika salah seorang di antara kalian fakir, maka hendaknya ia memulai (sedekah) kepada dirinya sendiri, jika ada kelebihan maka ia berikan kepada keluarganya, jika ada kelebihan maka ia berikan kepada orang yang memiliki hubungan kekerabatan, kemudian jika masih ada kelebihan maka ia bisa memberikannya kepada siapa saja.\""},"3362":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا أَعْتَقَ سِتَّةَ أَعْبُدٍ عِنْدَ مَوْتِهِ وَلَمْ يَكُنْ لَهُ مَالٌ غَيْرُهُمْ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ قَوْلًا شَدِيدًا ثُمَّ دَعَاهُمْ فَجَزَّأَهُمْ ثَلَاثَةَ أَجْزَاءٍ فَأَقْرَعَ بَيْنَهُمْ فَأَعْتَقَ اثْنَيْنِ وَأَرَقَّ أَرْبَعَةًحَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ الْمُخْتَارِ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ بِإِسْنَادِهِ وَمَعْنَاهُ وَلَمْ يَقُلْ فَقَالَ لَهُ قَوْلًا شَدِيدًا حَدَّثَنَا وَهْبُ بْنُ بَقِيَّةَ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ هُوَ الطَّحَّانُ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي زَيْدٍ أَنَّ رَجُلًا مِنْ الْأَنْصَارِ بِمَعْنَاهُ وَقَالَ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ شَهِدْتُهُ قَبْلَ أَنْ يُدْفَنَ لَمْ يُدْفَنْ فِي مَقَابِرِ الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran bin Hushain], bahwa seorang laki-laki telah membebaskan enam orang budak dengan syarat ia telah meninggal, sedangkan ia tidak memiliki harta selain mereka. Kemudian hal tersebut sampai kepada Nabi shallallahu 'alaihi wasallam, hingga beliau pun marah. Kemudian beliau mengundang mereka dan membagi mereka menjadi tiga kelompok, beliau lalu mengundi mereka, kemudian membebaskan dua orang dan menyisakan empat orang (sebagai budak).\" Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Abdul Aziz bin Al Mukhtar] telah menceritakan kepada kami [Khalid] dari [Abu Qilabah] dengan sanad dan maknanya, namun ia tidak menyebutkan, 'kemudian beliau marah. ' Telah menceritakan kepada kami [Wahb bin Baqiyyah] telah menceritakan kepada kami [Khalid bin Abdullah Ath Thahhan] dari [Khalid] dari [Abu Qilabah] dari [Abu Zaid] bahwa seorang laki-laki anshar, seperti makna hadits tersebut. Nabi shallallahu 'alaihi wasallam lalu bersabda: \"Seandainya aku menyaksikannya sebelum ia dikubur, maka ia tidak dikubur di pekuburan orang-orang Muslim.\""},"3363":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ عَتِيقٍ وَأَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَجُلًا أَعْتَقَ سِتَّةَ أَعْبُدٍ عِنْدَ مَوْتِهِ وَلَمْ يَكُنْ لَهُ مَالٌ غَيْرُهُمْ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْرَعَ بَيْنَهُمْ فَأَعْتَقَ اثْنَيْنِ وَأَرَقَّ أَرْبَعَةً","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin 'Atiq] dan [Ayyub] dari [Muhammad bin Sirin] dari [Imran bin Hushain], bahwa seorang laki-laki telah memerdekakan enam budak dengan syarat sepeninggalnya, sementara ia tidak memiliki harta selain mereka. Kemudian hal tersebut sampai kepada Nabi shallallahu 'alaihi wasallam. Beliau pun mengundi di antara mereka dan memerdekakan dua orang dan menyisakan empat orang sebagai budak.\""},"3364":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي ابْنُ لَهِيعَةَ وَاللَّيْثُ بْنُ سَعْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ عَبْدًا وَلَهُ مَالٌ فَمَالُ الْعَبْدِ لَهُ إِلَّا أَنْ يَشْتَرِطَهُ السَّيِّدُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Ibnu Lahi'ah] dan [Al Laits bin Sa'd] dari ['Ubaidullah bin Abu Ja'far] dari [Bukair bin Al Asyajj] dari [Nafi'] dari [Abdullah bin Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memerdekakan budak miliknya yang mempunyai harta, maka harta tersebut adalah milik si budak, kecuali jika sang tuan mempersyaratkannya.\""},"3365":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا جَرِيرٌ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَدُ الزِّنَا شَرُّ الثَّلَاثَةِو قَالَ أَبُو هُرَيْرَةَ لَأَنْ أُمَتِّعَ بِسَوْطٍ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ أَحَبُّ إِلَيَّ مِنْ أَنْ أَعْتِقَ وَلَدَ زِنْيَةٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Jarir] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak hasil zina adalah orang buruk ketiga.\" Abu Hurairah berkata, \"Sungguh aku bersedekah dengan sebuah cemeti di jalan Allah 'azza wajalla adalah lebih aku sukai daripada membebaskan anak zina.\""},"3366":{"ar":"حَدَّثَنَا عِيسَى بْنُ مُحَمَّدٍ الرَّمْلِيُّ حَدَّثَنَا ضَمْرَةُ عَنْ إِبْرَاهِيمَ بْنِ أَبِي عَبْلَةَ عَنْ الْغَرِيفِ بْنِ الدَّيْلَمِيِّ قَالَأَتَيْنَا وَاثِلَةَ بْنَ الْأَسْقَعِ فَقُلْنَا لَهُ حَدِّثْنَا حَدِيثًا لَيْسَ فِيهِ زِيَادَةٌ وَلَا نُقْصَانٌ فَغَضِبَ وَقَالَ إِنَّ أَحَدَكُمْ لَيَقْرَأُ وَمُصْحَفُهُ مُعَلَّقٌ فِي بَيْتِهِ فَيَزِيدُ وَيَنْقُصُ قُلْنَا إِنَّمَا أَرَدْنَا حَدِيثًا سَمِعْتَهُ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَاحِبٍ لَنَا أَوْجَبَ يَعْنِي النَّارَ بِالْقَتْلِ فَقَالَ أَعْتِقُوا عَنْهُ يُعْتِقْ اللَّهُ بِكُلِّ عُضْوٍ مِنْهُ عُضْوًا مِنْهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Isa bin Muhammad Ar Ramli] telah menceritakan kepada kami [Dlamrah] dari [Ibrahim bin Abu 'Abalah] dari [Al Gharif bin Ad Dailami] ia berkata, \"Kami datang menemui [Watsilah bin Al Asqa'] dan berkata kepadanya, \"Ceritakanlah kepada kami sebuah hadits yang tidak ada penambahan dan pengurangan padanya.\" Kemudian Watsilah marah dan berkata, \"Sungguh, salah seorang di antara kalian ada yang membaca sementara mushhafnya tergantung di rumahnya, sehingga ia pun menambah dan mengurang.\" Kami katakan, \"Sebenarnya kami hanya ingin mendengar hadits yang kamu dengar dari Nabi shallallahu 'alaihi wasallam.\" Watsilah lalu berkata, \"Kami pernah datang kepada Rasulullah shallallahu 'alaihi wasallam menanyakan perihal sahabat kami yang telah divonis neraka karena sebab membunuh. Beliau kemudian bersabda: \"Bebaskan budak untuknya, maka Allah akan membebaskan dengan setiap anggota badan budak tersebut satu anggotan badannya dari Neraka.\""},"3367":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمَرِيِّ عَنْ أَبِي نَجِيحٍ السُّلَمِيِّ قَالَحَاصَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَصْرِ الطَّائِفِ قَالَ مُعَاذٌ سَمِعْتُ أَبِي يَقُولُ بِقَصْرِ الطَّائِفِ بِحِصْنِ الطَّائِفِ كُلَّ ذَلِكَ فَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ بَلَغَ بِسَهْمٍ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَلَهُ دَرَجَةٌ وَسَاقَ الْحَدِيثَ وَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا رَجُلٍ مُسْلِمٍ أَعْتَقَ رَجُلًا مُسْلِمًا فَإِنَّ اللَّهَ عَزَّ وَجَلَّ جَاعِلٌ وِقَاءَ كُلِّ عَظْمٍ مِنْ عِظَامِهِ عَظْمًا مِنْ عِظَامِ مُحَرَّرِهِ مِنْ النَّارِ وَأَيُّمَا امْرَأَةٍ أَعْتَقَتْ امْرَأَةً مُسْلِمَةً فَإِنَّ اللَّهَ جَاعِلٌ وِقَاءَ كُلِّ عَظْمٍ مِنْ عِظَامِهَا عَظْمًا مِنْ عِظَامِ مُحَرَّرِهَا مِنْ النَّارِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Ayahku] dari [Qatadah] dari [Salim bin Abu Al Ja'd] dari [Ma'dan bin Abu Thalhah Al Ya'muri] dari [Abu Najih As Sulami] ia berkata, \"Kami pernah mengepung istana Thaif bersama Rasulullah shallallahu 'alaihi wasallam, Mu'adz lalu berkata, \"Aku mendengar ayahku mengatakan di istana Thaif atau benteng Thaif, setiap itu ia mengatakan, 'Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memanahkan satu anak panah kepada orang kafir di jalan Allah 'azza wajalla maka baginya satu derajat…lalu ia meneruskan hadits tersebut. Dan aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Muslim mansaja yang membebaskan seorang Muslim, maka Allah 'azza wajalla menjadikan perlindungan setiap tulangnya dari api neraka dengan setiap tulang orang yang ia bebaskan. Dan wanita manasaja yang membebaskan seorang wanita muslimah, maka pada hari kiamat Allah menjadikan perlindungan setiap tulangnya dari api neraka dengan setiap tulang orang yang ia bebaskan.\""},"3368":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا صَفْوَانُ بْنُ عَمْرٍو حَدَّثَنِي سُلَيْمُ بْنُ عَامِرٍ عَنْ شُرَحْبِيلَ بْنِ السَّمْطِ أَنَّهُ قَالَ لِعَمْرِو بْنِ عَبَسَةَحَدِّثْنَا حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَعْتَقَ رَقَبَةً مُؤْمِنَةً كَانَتْ فِدَاءَهُ مِنْ النَّارِحَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ شُرَحْبِيلَ بْنِ السَّمْطِ أَنَّهُ قَالَ لِكَعْبِ بْنِ مُرَّةَ أَوْ مُرَّةَ بْنِ كَعْبٍ حَدِّثْنَا حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَى مُعَاذٍ إِلَى قَوْلِهِ وَأَيُّمَا امْرِئٍ أَعْتَقَ مُسْلِمًا وَأَيُّمَا امْرَأَةٍ أَعْتَقَتْ امْرَأَةً مُسْلِمَةً زَادَ وَأَيُّمَا رَجُلٍ أَعْتَقَ امْرَأَتَيْنِ مُسْلِمَتَيْنِ إِلَّا كَانَتَا فِكَاكَهُ مِنْ النَّارِ يُجْزِئُ مَكَانَ كُلِّ عَظْمَيْنِ مِنْهُمَا عَظْمٌ مِنْ عِظَامِهِ قَالَ أَبُو دَاوُد سَالِمٌ لَمْ يَسْمَعْ مِنْ شُرَحْبِيلَ مَاتَ شُرَحْبِيلُ بِصِفِّينَ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah] telah menceritakan kepada kami [Baqiyyah] telah menceritakan kepada kami [Shafwan bin 'Amru] telah menceritakan kepadaku [Sulaim bin Amir] dari [Syurahbil bin As Samth] bahwa ia berkata kepada ['Amru bin 'Abasah], \"Ceritakan kepada kami sebuah hadits yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam! Amru lalu berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membebaskan seorang budak mukmin, maka ia akan menjadi penebusnya dari Neraka.\" Telah menceritakan kepada kami [Hafshah bin Umar] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Salim bin Abu Al Ja'd] dari [Syurahbil bin As Samth] bahwa ia berkata kepada [Ka'b bin Murrah atau Murrah bin Ka'b], \"Ceritakanlah kepada kami sebuah hadits yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam!\" Kemudian ia menyebutkan makna hadits Mu'adz hingga perkataannya, \"Siapapun orang yang membebaskan seorang laki-laki dan siapapun wanita yang membebaskan seorang wanita muslimah….\" Ka'b bin Murrah menambahkan, \"Siapapun laki-laki yang membebaskan dua orang wanita muslimah melainkan keduanya akan menjadi penebusnya dari Neraka, satu tulang dari tulang-tulangnya terwakili oleh setiap dua tulang dari keduanya.\" Abu Daud berkata, \"Salim tidak mendengar dari Syurahbil, sebab Syurahbil meninggal di perang Shiffin.\""},"3369":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي حَبِيبَةَ الطَّائِيِّ عَنْ أَبِي الدَّرْدَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الَّذِي يَعْتِقُ عِنْدَ الْمَوْتِ كَمَثَلِ الَّذِي يُهْدِي إِذَا شَبِعَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Habibah Ath Tha`i] dari [Abu Ad Darda] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Permisalan orang yang membebaskan budak ketika hendak meninggal seperti orang yang memberi hadiah apabila ia telah kenyang.\""},"3370":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ النُّفَيْلِيُّ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ ح و حَدَّثَنَا نَصْرُ بْنُ عَاصِمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ وَاتَّخِذُوا مِنْ مَقَامِ إِبْرَاهِيمَ مُصَلًّى }","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad An Nufaili] telah menceritakan kepada kami [Hatim bin Isma'il]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Nashr bin 'Ashim] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ja'far bin Muhammad] dari [Ayahnya] dan [Jabir] radliallahu 'anhu, bahwa Nabi shallallahu 'alaihi wasallam membaca ayat: '(Dan jadikanlah sebahagian maqam Ibrahim tempat shalat) ' (Qs. Al Baqarah: 125). "},"3371":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ حَدَّثَنَا خُصَيْفٌ حَدَّثَنَا مِقْسَمٌ مَوْلَى ابْنِ عَبَّاسٍ قَالَ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَانَزَلَتْ هَذِهِ الْآيَةُ{ وَمَا كَانَ لِنَبِيٍّ أَنْ يَغُلَّ }فِي قَطِيفَةٍ حَمْرَاءَ فُقِدَتْ يَوْمَ بَدْرٍ فَقَالَ بَعْضُ النَّاسِ لَعَلَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَهَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَمَا كَانَ لِنَبِيٍّ أَنْ يَغُلَّ }إِلَى آخِرِ الْآيَةِقَالَ أَبُو دَاوُد يَغُلَّ مَفْتُوحَةُ الْيَاءِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Wahid bin Ziyad] telah menceritakan kepada kami [Khushaif] telah menceritakan kepada kami [Miqsam] mantan budak Ibnu Abbas, ia berkata, [Ibnu Abbas] radliallahu 'anhu berkata, \"Turunnya ayat ini: '(Tidak mungkin seorang nabi berkhianat dalam urusan harta rampasan perang) ' (Qs. Ali Imran: 161), berkenaan dengan hilangnya kasur merah di badar. Sebagian orang mengatakan, \"Kemungkinan Rasulullah shallallahu 'alaihi wasallam mengambilnya, maka Allah 'azza wajalla menurunkan ayat: '(Tidak mungkin seorang nabi berkhianat dalam urusan harta rampasan perang) ' (Qs. Ali Imran: 161), hingga akhir ayat.\" Abu Daud berkata, \"Yaghulla, dengan memberi harakat fathah pada huruf ya'.\""},"3372":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَبِي قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْبَخَلِ وَالْهَرَمِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Mu'tamir] ia berkata; aku mendengar [Ayahku] berkata; aku pernah mendengar [Anas bin Malik] berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"ALLAAHUMMA INNII A'UUDZU BIKA MINAL BUKHLI WAL HARAMI (Ya Allah, aku berlindung kepada-Mu dari sifat kikir dan pikun) '.\""},"3373":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَحِقَ الْمُسْلِمُونَ رَجُلًا فِي غُنَيْمَةٍ لَهُ فَقَالَ السَّلَامُ عَلَيْكُمْ فَقَتَلُوهُ وَأَخَذُوا تِلْكَ الْغُنَيْمَةَ فَنَزَلَتْ{ وَلَا تَقُولُوا لِمَنْ أَلْقَى إِلَيْكُمْ السَّلَامَ لَسْتَ مُؤْمِنًا تَبْتَغُونَ عَرَضَ الْحَيَاةِ الدُّنْيَا }تِلْكَ الْغُنَيْمَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru bin Dinar] dari ['Atha] dari [Ibnu Abbas] ia berkata, \"Orang-orang muslim bertemu dengan seorang laki-laki yang membawa kambingnya, kemudian ia mengucapkan, 'Assalaamu 'alaikum! ' Lalu mereka membunuhnya dan mengambil kambing tersebut. Maka turunlah ayat: '(Dan janganlah kamu mengatakan kepada orang yang mengucapkan 'salam' kepadamu: 'Kamu bukan seorang mukmin' (lalu kamu membunuhnya), dengan maksud mencari harta benda kehidupan di dunia) ' (Qs. An Nisaa: 94), yaitu kambing tersebut.\""},"3374":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ الْأَنْبَارِيُّ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ أَبِي الزِّنَادِ وَهُوَ أَشْبَعُ عَنْ أَبِيهِ عَنْ خَارِجَةَ بْنِ زَيْدِ بْنِ ثَابِتٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ{ غَيْرُ أُولِي الضَّرَرِ }وَلَمْ يَقُلْ سَعِيدٌ كَانَ يَقْرَأُ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Ibnu Abu Az Zinad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad bin Sulaiman Al Anbari] telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Abu Az Zinad Asyba'] dari [Ayahnya] dari [Kharijah bin Zaid bin Tsabit] dari [Ayahnya], bahwa Nabi shallallahu 'alaihi wasallam membaca ayat: (yang tidak mempunyai 'uzur…) ' (Qs. An Nisaa; 95). Sa'id tidak menyebutkan kata, 'membaca'.\""},"3375":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا يُونُسُ بْنُ يَزِيدَ عَنْ أَبِي عَلِيِّ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَرَأَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَالْعَيْنُ بِالْعَيْنِ }","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Muhammad bin Al 'Ala] mereka berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] telah menceritakan kepada kami [Yunus bin Yazid] dari [Abu Ali bin Yazid] dari [Az Zuhri] dari [Anas bin Malik] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membaca ayat: '(... dan mata dengan mata) ' (Qs. Al Maidah: 45). "},"3376":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا فُضَيْلُ بْنُ مَرْزُوقٍ عَنْ عَطِيَّةَ بْنِ سَعْدٍ الْعَوْفِيِّ قَالَقَرَأْتُ عَلَى عَبْدِ اللَّهِ بْنِ عُمَرَ{ اللَّهُ الَّذِي خَلَقَكُمْ مِنْ ضَعْفٍ }فَقَالَ{ مِنْ ضُعْفٍ }قَرَأْتُهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا قَرَأْتَهَا عَلَيَّ فَأَخَذَ عَلَيَّ كَمَا أَخَذْتُ عَلَيْكَ","id":"Telah menceritakan kepada kami [An Nufaili] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Fudlail bin Marzuq] dari ['Athiyyah bin Sa'dan Al 'Aufi] ia berkata, \"Aku pernah membacakan kepada [Abdullah bin Umar] ayat: 'ALLAHULLADZII KHALAQAKUM MIN DLA'FIN… (Allah, Dialah yang menciptakan kamu dari keadaan lemah...) (Qs. Ar Ruum: 54) ', kemudian ia berkata, 'MIN DLU'FIN…(dari kelemahan) -dengan dlammah-', aku pernah membacakan ayat tersebut kepada Rasulullah shallallahu 'alaihi wasallam sebagaimana engkau telah membacakannya kepadaku, kemudian beliau mengoreksiku sebagaimana aku telah mengoreksimu.\""},"3377":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى الْقُطَعِيُّ حَدَّثَنَا عُبَيْدٌ يَعْنِي ابْنَ عَقِيلٍ عَنْ هَارُونَ عَنْ عَبْدِ اللَّهِ بْنِ جَابِرٍ عَنْ عَطِيَّةَ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ضُعْفٍ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya Al Qutha'i] telah menceritakan kepada kami ['Ubaid bin 'Aqil] dari [Harun] dari [Abdullah bin Jabir] dari ['Athiyyah] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam, beliau membaca: 'MIN DLU'FIN (dari kelemahan) (Qs. Ar Ruum: 54). -dengan harakat dlammah-. "},"3378":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الْمُغِيرَةُ بْنُ سَلَمَةَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ الْأَجْلَحِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ أُبَيٍّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ بِفَضْلِ اللَّهِ وَبِرَحْمَتِهِ فَبِذَلِكَ فَلْتَفْرَحُوا هُوَ خَيْرٌ مِمَّا تَجْمَعُونَ }","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah] telah menceritakan kepada kami [Al Mughirah bin Salamah] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Al Ajlah] telah menceritakan kepadaku [Abdullah bin Abdurrahman bin Abza] dari [ayahnya] dari [Ubai] bahwa Nabi shallallahu 'alaihi wasallam pernah membaca ayat: BIFADHLILLAAHI WA RAHMATIHI, FABIDZAALIKA FAL TAFRAHUU, HUWA KHAIRUN MIMMAA TAJMA'UUN (Katakanlah: \"Dengan karunia Allah dan rahmat-Nya, hendaklah dengan itu kalian bergembira. Karunia Allah dan rahmat-Nya itu adalah lebih baik dari apa yang kalian kumpulkan.\"); "},"3379":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَأَنَّهَا سَمِعَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ{ إِنَّهُ عَمِلَ غَيْرَ صَالِحٍ }","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Tsabit] dari [Syahr bin Hausyab] dari [Asma` binti Yazid], bahwa ia pernah mendengar Nabi shallallahu 'alaihi wasallam membaca: 'INNAHUU 'AMILA GHAIRA SHAALIH (Sesungguhnya ia telah melakukan perbuatan yang tidak baik) '. (Qs. Huud: 46). "},"3380":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ أَبِي عُذْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ دُخُولِ الْحَمَّامَاتِ ثُمَّ رَخَّصَ لِلرِّجَالِ أَنْ يَدْخُلُوهَا فِي الْمَيَازِرِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammad] dari [Abdullah bin Syaddad] dari [Abu 'Udzrah] dari [Aisyah] radliallahu 'anhuma, bahwa Rasulullah shallallahu 'alaihi wasallam melarang memasuki tempat-tempat pemandian umum. Dan beliau memberi keringanan bagi kaum laki-laki dengan syarat mengenakan kain sarung.\""},"3381":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ قُدَامَةَ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ جَمِيعًا عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ قَالَ ابْنُ الْمُثَنَّى عَنْ أَبِي الْمَلِيحِ قَالَدَخَلَ نِسْوَةٌ مِنْ أَهْلِ الشَّامِ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقَالَتْ مِمَّنْ أَنْتُنَّ قُلْنَ مِنْ أَهْلِ الشَّامِ قَالَتْ لَعَلَّكُنَّ مِنْ الْكُورَةِ الَّتِي تَدْخُلُ نِسَاؤُهَا الْحَمَّامَاتِ قُلْنَ نَعَمْ قَالَتْ أَمَا إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ امْرَأَةٍ تَخْلَعُ ثِيَابَهَا فِي غَيْرِ بَيْتِهَا إِلَّا هَتَكَتْ مَا بَيْنَهَا وَبَيْنَ اللَّهِ تَعَالَى قَالَ أَبُو دَاوُد هَذَا حَدِيثُ جَرِيرٍ وَهُوَ أَتَمُّ وَلَمْ يَذْكُرْ جَرِيرٌ أَبَا الْمَلِيحِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Qudamah] telah menceritakan kepada kami [Jarir]. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] semuanya berasal dari [Manshur] dari [Salim bin Abu Al Ja'dan], [Ibnu Al Mutsanna] menyebutkan dari [Abu Al Malih] ia berkata, \"Beberapa wanita Syam menemui [Aisyah] radliallahu 'anhuma, Aisyah kemudian bertanya, \"Dari manakah kalian?\" Mereka menjawab, \"Dari penduduk Syam.\" Aisyah berkata, \"Kemungkinan kalian berasal dari Al Kurah yang para wanitanya biasa memasuki pemandian umum?\" Mereka menjawab, Ya. Aisyah lalu berkata, \"Ketahuilah, aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang wanita yang melepas pakaiannya di luar rumah kecuali ia telah melepaskan tabir antara dirinya dengan Allah Ta'ala.\" Abu Daud berkata, \"Ini adalah hadits Jarir, dan hadits ini lebih sempurna. Namun ia tidak menyebutkan nama Abu Al Malih. Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda\""},"3382":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زِيَادِ بْنِ أَنْعُمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ رَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا سَتُفْتَحُ لَكُمْ أَرْضُ الْعَجَمِ وَسَتَجِدُونَ فِيهَا بُيُوتًا يُقَالُ لَهَا الْحَمَّامَاتُ فَلَا يَدْخُلَنَّهَا الرِّجَالُ إِلَّا بِالْأُزُرِ وَامْنَعُوهَا النِّسَاءَ إِلَّا مَرِيضَةً أَوْ نُفَسَاءَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abdurrahman bin Ziyad bin An'am] dari [Abdurrahman bin Rafi'] dari [Abdullah bin 'Amru], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya akan ditaklukkan untuk kalian negeri orang-orang 'ajam (non Arab), dan di dalamnya akan kalian dapati beberapa bangunan yang disebut pemandian. Maka orang laki-laki tidak boleh memasukinya kecuali dengan memakai sarung, dan laranglah para wanita untuk memasukinya kecuali wanita yang sakit atau para wanita yang nifas.\""},"3383":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ نُفَيْلٍ حَدَّثَنَا زُهَيْرٌ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ الْعَرْزَمِيِّ عَنْ عَطَاءٍ عَنْ يَعْلَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَغْتَسِلُ بِالْبَرَازِ بِلَا إِزَارٍ فَصَعَدَ الْمِنْبَرَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ حَيِيٌّ سِتِّيرٌ يُحِبُّ الْحَيَاءَ وَالسَّتْرَ فَإِذَا اغْتَسَلَ أَحَدُكُمْ فَلْيَسْتَتِرْحَدَّثَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ قَالَ أَبُو دَاوُد الْأَوَّلُ أَتَمُّ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Nufail] telah menceritakan kepada kami [Zuhair] dari [Abdul Malik bin Abu Sulaiman Al 'Arzami] dari ['Atha] dari [Ya'la], bahwa Rasulullah shallallahu 'alaihi wasallam melihat seorang laki-laki mandi di tanah lapang tanpa memakai sarung. Kemudian beliau naik mimbar, lalu memuji Allah dan bersabda: \"Sesungguhnya Allah 'azza wajalla Maha Pemalu dan Tertutup, Dia menyukai sifat malu dan tertutup. Apabila salah seorang di antara kalian mandi, maka hendaknya ia menutupi dirinya.\" Telah menceritakan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Al Aswad bin 'Amir] telah menceritakan kepada kami [Abu Bakr bin 'Ayyasy] dari [Abdul Malik bin Abu Sulaiman] dari ['Atha] dari [Shafwan bin Ya'la] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini.\" Abu Daud berkata, \"Hadits yang pertama lebih sempurna.\""},"3384":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ عَنْ زُرْعَةَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ جَرْهَدٍ عَنْ أَبِيهِ قَالَكَانَ جَرْهَدٌ هَذَا مِنْ أَصْحَابِ الصُّفَّةِ قَالَ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَنَا وَفَخِذِي مُنْكَشِفَةٌ فَقَالَ أَمَا عَلِمْتَ أَنَّ الْفَخِذَ عَوْرَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu An Nadlr] dari [Zur'ah bin Abdurrahman bin Jarhad] dari [Ayahnya] ia berkata, \" [Jarhad] adalah termasuk para penghuni Shuffah. Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam duduk di antara kami, sementara pahaku terbuka. Beliau lalu bersabda: \"Sesungguhnya paha adalah aurat.\""},"3385":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ سَهْلٍ الرَّمْلِيُّ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أُخْبِرْتُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ عَاصِمِ بْنِ ضَمْرَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَكْشِفْ فَخِذَكَ وَلَا تَنْظُرْ إِلَى فَخِذِ حَيٍّ وَلَا مَيِّتٍقَالَ أَبُو دَاوُد هَذَا الْحَدِيثُ فِيهِ نَكَارَةٌ","id":"Telah menceritakan kepada kami [Ali bin Sahl Ar Ramli] telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] ia berkata; aku mendapat kabar dari [Habib bin Abu Tsabit] dari ['Ashim bin Dlamrah] dari [Ali] radliallahu 'anhu, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah engkau buka pahamu, dan jangan engkau melihat kepada paha orang yang hidup maupun yang mati!\" Abu Daud berkata, \"Dalam hadits ini terdapat sesuatu yang diingkari.\""},"3386":{"ar":"حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ عَنْ عُثْمَانَ بْنِ حَكِيمٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلٍ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَحَمَلْتُ حَجَرًا ثَقِيلًا فَبَيْنَا أَمْشِي فَسَقَطَ عَنِّي ثَوْبِي فَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُذْ عَلَيْكَ ثَوْبَكَ وَلَا تَمْشُوا عُرَاةً","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Yahya bin Sa'id Al Umawi] dari [Utsman bin Hakim] dari [Abu Umamah bin Sahl] dari [Al Miswar bin Makhramah] ia berkata, \"Saat berjalan membawa batu berat, pakaianku terjatuh. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Ambillah pakaianmu dan jangan berjalan dalam keadaan telanjang!\""},"3387":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا أَبِي ح و حَدَّثَنَا ابْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى نَحْوَهُ عَنْ بَهْزِ بْنِ حَكِيمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ عَوْرَاتُنَا مَا نَأْتِي مِنْهَا وَمَا نَذَرُ قَالَ احْفَظْ عَوْرَتَكَ إِلَّا مِنْ زَوْجَتِكَ أَوْ مَا مَلَكَتْ يَمِينُكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِذَا كَانَ الْقَوْمُ بَعْضُهُمْ فِي بَعْضٍ قَالَ إِنْ اسْتَطَعْتَ أَنْ لَا يَرَيَنَّهَا أَحَدٌ فَلَا يَرَيَنَّهَا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِذَا كَانَ أَحَدُنَا خَالِيًا قَالَ اللَّهُ أَحَقُّ أَنْ يُسْتَحْيَا مِنْهُ مِنْ النَّاسِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] berkata, telah menceritakan kepada kami [Bapakku]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ibnu Basysyar] berkata, telah menceritakan kepada kami [Yahya] sebagaimana dalam riwayatnya, dari [Bahz bin Hakim] dari [Bapaknya] dari [Kakeknya] ia berkata, \"Aku bertanya, \"Wahai Rasulullah, tentang aurat kami, siapakah yang boleh kami perlihatkan dan siapa yang tidak boleh?\" beliau menjawab: \"Jagalah auratmu kecuali kepada isteri atau budak yang kamu miliki.\" Ia berkata, \"Aku bertanya, \"Wahai Rasulullah, bagaimana dengan suatu kaum saling bercampur dalam satu tempat (yang mereka saling melihat aurat antara satu dengan yang lain)?\" beliau menjawab: \"Jika kamu mampu, maka jangan sampai ada seorang pun yang melihatnya.\" Ia berkata, \"Aku bertanya, \"Wahai Rasulullah, bagaimana jika salah seorang dari kami sedang sendiri?\" beliau menjawab: \"Allah lebih berhak untuk kamu malu darinya dari pada manusia.\""},"3388":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْظُرُ الرَّجُلُ إِلَى عُرْيَةِ الرَّجُلِ وَلَا الْمَرْأَةُ إِلَى عُرْيَةِ الْمَرْأَةِ وَلَا يُفْضِي الرَّجُلُ إِلَى الرَّجُلِ فِي ثَوْبٍ وَاحِدٍ وَلَا تُفْضِي الْمَرْأَةُ إِلَى الْمَرْأَةِ فِي ثَوْبٍ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Ibrahim] berkata, telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Adh Dhahhak bin Utsman] dari [Zaid bin Aslam] dari ['Abdurrahman bin Abu Sa'id Al Khudri] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang laki-laki tidak boleh untuk melihat aurat laki-laki lain, dan seorang wanita tidak boleh melihat aurat wanita yang lain. Seorang laki-laki tidak boleh tidur dengan laki-laki lain dalam satu selimut, dan seorang wanita tidak boleh tidur dengan wanita lain dalam satu selimut.\""},"3389":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا ابْنُ عُلَيَّةَ عَنْ الْجُرَيْرِيِّ ح و حَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ رَجُلٍ مِنْ الطُّفَاوَةِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُفْضِيَنَّ رَجُلٌ إِلَى رَجُلٍ وَلَا امْرَأَةٌ إِلَى امْرَأَةٍ إِلَّا وَلَدًا أَوْ وَالِدًا قَالَ وَذَكَرَ الثَّالِثَةَ فَنَسِيتُهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah mengabarkan kepada kami [Ibnu Ulayyah] dari [Al Jurairi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muammal bin Hisyam] ia berkata; telah menceritakan kepada kami [Isma'il] dari [Al Jurairi] dari [Abu Nadhrah] dari [seorang laki-laki] -dari Ath Thufawah- dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang laki-laki tidak boleh tidur dengan laki-laki lain dalam satu selimut, dan seorang wanita tidak boleh tidur dengan wanita lain dalam satu selimut, kecuali anak atau orang tua (yakni orang tua yang menidurkan anaknya).\" (perawi berkata) berkata, \"Beliau menyebutkan yang ketiga, namun aku lupa.\""},"3390":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَجَدَّ ثَوْبًا سَمَّاهُ بِاسْمِهِ إِمَّا قَمِيصًا أَوْ عِمَامَةً ثُمَّ يَقُولُ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ كَسَوْتَنِيهِ أَسْأَلُكَ مِنْ خَيْرِهِ وَخَيْرِ مَا صُنِعَ لَهُ وَأَعُوذُ بِكَ مِنْ شَرِّهِ وَشَرِّ مَا صُنِعَ لَهُقَالَ أَبُو نَضْرَةَ فَكَانَ أَصْحَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَبِسَ أَحَدُهُمْ ثَوْبًا جَدِيدًا قِيلَ لَهُ تُبْلَى وَيُخْلِفُ اللَّهُ تَعَالَى حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ الْجُرَيْرِيِّ بِإِسْنَادِهِ نَحْوَهُ حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا مُحَمَّدُ بْنُ دِينَارٍ عَنْ الْجُرَيْرِيِّ بِإِسْنَادِهِ وَمَعْنَاهُ قَالَ أَبُو دَاوُد عَبْدُ الْوَهَّابِ الثَّقَفِيُّ لَمْ يَذْكُرْ فِيهِ أَبَا سَعِيدٍ وَحَمَّادُ ابْنُ سَلَمَةَ قَالَ عَنْ الْجُرَيْرِيِّ عَنْ أَبِي الْعَلَاءِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو دَاوُد حَمَّادُ بْنُ سَلَمَةَ وَالثَّقَفِيُّ سَمَاعُهُمَا وَاحِدٌ","id":"Telah menceritakan kepada kami [Amru bin Aun] berkata, telah mengabarkan kepada kami [Ibnul Mubarak] dari [Al Jurairi] dari [Abu Nadhrah] dari [Abu Sa'id Al Khudri] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam jika mencoba baju baru beliau memulai dengan menyebutkan namanya (baju tersebut), baik itu kemeja atau imamah (semacam surban yang diikatkan pada kepala). Kemudian beliau membaca doa: 'ALLAHUMMA LAKAL HAMDU ANTA KASAUTANI AS`ALUKA MIN KHAIRIHI WA KHAIRI MAA SHUNI'A LAHU WA A'UUDZU BIKA MIN SYARRIHI WA SYARRI MAA SHUNI'A LAHU (Ya Allah, hanya milik-Mu segala puji, Engkaulah yang memberikan pakaian ini kepadaku. Aku memohon kepada-Mu untuk memperoleh kebaikannya dan kebaikan yang terbuat karenanya (untuk beribadah dan ketaatan kepada Allah). Aku berlindung kepada-Mu dari kejahatannya dan kejahatan yang terbuat karenanya (untuk bermaksiat kepada Allah). ' Abu Nadhrah berkata; \"Dan biasanya para sahabat Nabi shallallahu 'alaihi wasallam, jika salah seorang dari mereka memakai baju baru, dikatakatan kepadanya, \"Semoga tahan lama hingga Allah menggantinya dengan yang baru (yakni do`a panjang umur).\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isa bin Yunus] dari [Al Jurairi] dengan sanad yang sama. Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Muhammad bin Dinar] dari [Al Jurairi] dengan sanad dan makna hadits yang sama. Abu Dawud berkata, \" [Abdul Wahhab Ats Tsaqafi] tidak menyebutkan dalam sanadnya nama Abu Sa'id dan [Hammad bin Salamah]. Ia menyebutkan dari [Al Jurairi], dari [Abul 'Ala], dari Nabi shallallahu 'alaihi wasallam.\" Abu Dawud berkata, \"Hammad bin Salamah dan Ats Tsaqafi sumber periwayatan keduanya adalah satu.\""},"3391":{"ar":"حَدَّثَنَا نُصَيْرُ بْنُ الْفَرَجِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ يَعْنِي ابْنَ أَبِي أَيُّوبَ عَنْ أَبِي مَرْحُومٍ عَنْ سَهْلِ بْنِ مُعَاذِ بْنِ أَنَسٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَكَلَ طَعَامًا ثُمَّ قَالَ الْحَمْدُ لِلَّهِ الَّذِي أَطْعَمَنِي هَذَا الطَّعَامَ وَرَزَقَنِيهِ مِنْ غَيْرِ حَوْلٍ مِنِّي وَلَا قُوَّةٍ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ قَالَ وَمَنْ لَبِسَ ثَوْبًا فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي كَسَانِي هَذَا الثَّوْبَ وَرَزَقَنِيهِ مِنْ غَيْرِ حَوْلٍ مِنِّي وَلَا قُوَّةٍ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَا تَأَخَّرَ","id":"Telah menceritakan kepada kami [Nushair Ibnul Faraj] berkata, telah menceritakan kepada kami [Abdullah bin Yazid] berkata, telah menceritakan kepada kami [Sa'id] -yaitu Ibnu Abu Ayyub- dari [Abu Marhum] dari [Sahl bin Mu'adz bin Anas] dari [Bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memakan makanan kemudian membaca doa; 'ALHAMDULILLAHIL LADZII ATH'AMANII HADZA ATH THA'AAMA WA RAZAQANIIHI MIN GHAIRI HAULIN MINNI WA LAA QUWWATIN (Segala puji bagi Allah yang telah memberikan makanan ini kepadaku sebagai rizki, tanpa daya dan kekuatan dariku). ' Maka akan diampuni dosanya yang lalu dan yang akan datang. Dan barangsiapa memakai baju lalu membaca doa; 'ALHAMDULILLAHIL LADZII KASAANII HADZA ATS TSAUBA WA RAZAQANIIHI MIN GHAIRI HAULIN MINNI WA LAA QUWWATIN (Segala puji bagi Allah yang telah memberikan pakaian ini kepadaku sebagai rizki, tanpa daya dan kekuatan dariku). ' Maka akan diampuni dosanya yang lalu dan yang akan datang.\""},"3392":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ الْجَرَّاحِ الْأَذَنِيُّ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا إِسْحَقُ بْنُ سَعِيدٍ عَنْ أَبِيهِ عَنْ أُمِّ خَالِدٍ بِنْتِ خَالِدِ بْنِ سَعِيدِ بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِكِسْوَةٍ فِيهَا خَمِيصَةٌ صَغِيرَةٌ فَقَالَ مَنْ تَرَوْنَ أَحَقُّ بِهَذِهِ فَسَكَتَ الْقَوْمُ فَقَالَ ائْتُونِي بِأُمِّ خَالِدٍ فَأُتِيَ بِهَا فَأَلْبَسَهَا إِيَّاهَا ثُمَّ قَالَ أَبْلِي وَأَخْلِقِي مَرَّتَيْنِ وَجَعَلَ يَنْظُرُ إِلَى عَلَمٍ فِي الْخَمِيصَةِ أَحْمَرَ أَوْ أَصْفَرَ وَيَقُولُ سَنَاهْ سَنَاهْ يَا أُمَّ خَالِدٍ وَسَنَاهْ فِي كَلَامِ الْحَبَشَةِ الْحَسَنُ","id":"Telah menceritakan kepada kami [Ishaq Ibnul Jarrah Al Adzani] berkata, telah menceritakan kepada kami [Abu An Nadhr] berkata, telah menceritakan kepada kami [Ishaq bin Sa'id] dari [Bapaknya] dari [Ummu Khalid binti Khalid bin Sa'id bin Al Ash] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah diberi kain yang ada renda suteranya. Lalu beliau bersabda: \"Menurut kalian siapa yang paling berhak untuk mendapat kain ini?\", orang-orang pun diam. Beliau lalu bersabda: \"Datangkanlah Ummu Khalid kepadaku.\" Beliau lantas memberikan kain tersebut dan memakaikannya kepadanya. Setelah itu beliau bersabda: 'Semoga tahan lama hingga Allah menggantinya dengan yang baru (panjang umur). ' -dua kali-. Beliau kemudian melihat tanda berwarna merah atau kuning yang ada pada kain bersulam sutera tersebut, beliau bersabda: \"Wahai Ummu Khalid, sanah, sanah.\" Sanah menurut bahasa orang orang habasyah artinya adalah; bagus, bagus.\""},"3393":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عَبْدِ الْمُؤْمِنِ بْنِ خَالِدٍ الْحَنَفِيِّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْكَانَ أَحَبُّ الثِّيَابِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقَمِيصَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Abdul Mukmin bin Khalid Al Hanafi] dari [Abdullah bin Buraidah] dari [Ummu Salamah] ia berkata, \"Pakaian yang paling disukai oleh Rasulullah shallallahu 'alaihi wasallam adalah gamis.\""},"3394":{"ar":"حَدَّثَنَا زِيَادُ بْنُ أَيُّوبَ حَدَّثَنَا أَبُو تُمَيْلَةَ قَالَ حَدَّثَنِي عَبْدُ الْمُؤْمِنِ بْنُ خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ عَنْ أُمِّ سَلَمَةَ قَالَتْلَمْ يَكُنْ ثَوْبٌ أَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ قَمِيصٍ","id":"Telah menceritakan kepada kami [Ziyad bin Ayyub] berkata, telah menceritakan kepada kami [Abu Tumailah] ia berkata; telah menceritakan kepadaku [Abdul Mukmin bin Khalid] dari [Abdullah bin Buraidah] dari [Bapaknya] dari [Ummu Salamah] ia berkata, \"Tidak ada pakaian yang paling disukai oleh Rasulullah shallallahu 'alaihi wasallam selain gamis.\""},"3395":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ عَنْ أَبِيهِ عَنْ بُدَيْلِ بْنِ مَيْسَرَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ أَسْمَاءَ بِنْتِ يَزِيدَ قَالَتْكَانَتْ يَدُ كُمِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الرُّسْغِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] dari [Bapaknya] dari [Budail bin Maisarah] dari [Syahr bin Hausyab] dari [Asma binti Yazid] ia berkata, \"Lengan baju Rasulullah shallallahu 'alaihi wasallam hingga sebatas pergelangan tangan.\""},"3396":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَيَزِيدُ بْنُ خَالِدِ بْنِ مَوْهَبٍ الْمَعْنَى أَنَّ اللَّيْثَ يَعْنِي ابْنَ سَعْدٍ حَدَّثَهُمْ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ أَنَّهُ قَالَقَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْبِيَةً وَلَمْ يُعْطِ مَخْرَمَةَ شَيْئًا فَقَالَ مَخْرَمَةُ يَا بُنَيَّ انْطَلِقْ بِنَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقْتُ مَعَهُ قَالَ ادْخُلْ فَادْعُهُ لِي قَالَ فَدَعَوْتُهُ فَخَرَجَ إِلَيْهِ وَعَلَيْهِ قِبَاءٌ مِنْهَا فَقَالَ خَبَأْتُ هَذَا لَكَ قَالَ فَنَظَرَ إِلَيْهِ زَادَ ابْنُ مَوْهَبٍ مَخْرَمَةُ ثُمَّ اتَّفَقَا قَالَ رَضِيَ مَخْرَمَةُ قَالَ قُتَيْبَةُ عَنْ ابْنِ أَبِي مُلَيْكَةَ لَمْ يُسَمِّهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Yazid bin Khalid bin Mauhab] secara makna, bahwa [Al Laits] -yaitu Ibnu Sa'd- menceritakan kepada mereka, dari [Abdullah bin Ubaidullah bin Abu Mulaikah] dari [Al Miswar bin Makhramah] Bahwasanya ia berkata, \"Rasulullah shallallahu 'alaihi wasallam membagi-bagikan Aqbiyah (semacam surban), namun beliau tidak memberikan sesuatu pun kepada Makhramah. Maka Makhramah pun berkata, \"Wahai anakku, ikutlah aku menemui Rasulullah shallallahu 'alaihi wasallam.\" Lalu aku ikut pergi bersamanya. Beliau bersabda, \"Masuk, dan panggilkan ia kepadaku.\" Aku lalu memanggil Makhramah, dan Rasulullah keluar menemui Makhramah dengan membawa Aqbiyah. Beliau bersabda: \"Sengaja aku sembunyikan ini untuk kamu.\" Al Miswar berkata, \"Lalu Makhramah melihat Aqbiyah tersebut dan setuju.\" Al Miswar berkata, \"Makhramah telah ridha.\" Qutaibah berkata dari Ibnu Abu Mulaikah, \"Ia tidak menamainya.\""},"3397":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو عَوَانَةَ ح و حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ عِيسَى عَنْ شَرِيكٍ عَنْ عُثْمَانَ بْنِ أَبِي زُرْعَةَ عَنْ الْمُهَاجِرِ الشَّامِيِّ عَنْ ابْنِ عُمَرَ قَالَ فِي حَدِيثِ شَرِيكٍ يَرْفَعُهُ قَالَمَنْ لَبِسَ ثَوْبَ شُهْرَةٍ أَلْبَسَهُ اللَّهُ يَوْمَ الْقِيَامَةِ ثَوْبًا مِثْلَهُ زَادَ عَنْ أَبِي عَوَانَةَ ثُمَّ تُلَهَّبُ فِيهِ النَّارُحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ قَالَ ثَوْبَ مَذَلَّةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] berkata, telah menceritakan kepada kami [Abu Awanah]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Muhammad] -yaitu Ibnu Isa- dari [Syarik] dari [Utsman bin Abu Zur'ah] dari [Al Muhajir Asy Syami] dari [Ibnu Umar] perawi berkata: dalam hadits Syarik yang ia marfu'kan ia berkata, \"Barangsiapa memakai baju kemewahan (karena ingin dipuji), maka pada hari kiamat Allah akan mengenakan untuknya baju semisal. Ia menambahkan dari Abu Awanah, \"lalu akan dilahab oleh api neraka.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Awanah] ia berkata, \"Yaitu baju kehinaan.\""},"3398":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ ثَابِتٍ حَدَّثَنَا حَسَّانُ بْنُ عَطِيَّةَ عَنْ أَبِي مُنِيبٍ الْجُرَشِيِّ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَشَبَّهَ بِقَوْمٍ فَهُوَ مِنْهُمْ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Abu An Nadhr] berkata, telah menceritakan kepada kami ['Abdurrahman bin Tsabit] berkata, telah menceritakan kepada kami [Hassan bin Athiyah] dari [Abu Munib Al Jurasyi] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bertasyabuh dengan suatu kaum, maka ia bagian dari mereka.\" "},"3399":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ الرَّمْلِيُّ وَحُسَيْنُ بْنُ عَلِيٍّ قَالَا حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ أَبِيهِ عَنْ مُصْعَبِ بْنِ شَيْبَةَ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ مِرْطٌ مُرَحَّلٌ مِنْ شَعَرٍ أَسْوَدَو قَالَ حُسَيْنٌ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا","id":"Telah menceritakan kepada kami [Yazid bin Khalid bin Yazid bin Abdullah bin Mauhab Ar Ramli] dan [Husain bin Ali] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Zaidah] dari [Bapaknya] dari [Mush'ab bin Syaibah] dari [Shafiyah binti Syaibah] dari ['Aisyah radliallahu 'anha] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam keluar dengan mengenakan kain wool bergambar dari bulu berwarna hitam.\" Husain berkata, \"Yahya bin Zakariya telah menceritakan kepada kami.\""},"3400":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْعَلَاءِ الزُّبَيْدِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ عَقِيلِ بْنِ مُدْرِكٍ عَنْ لُقْمَانَ بْنِ عَامِرٍ عَنْ عُتْبَةَ بْنِ عَبْدٍ السُّلَمِيِّ قَالَاسْتَكْسَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَسَانِي خَيْشَتَيْنِ فَلَقَدْ رَأَيْتُنِي وَأَنَا أَكْسَى أَصْحَابِي","id":"Telah menceritakan kepada kami [Ibrahim bin Al 'Ala` Az Zubaidi] berkata, telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Aqil bin Mudrik] dari [Luqman bin Amir] dari [Utbah bin Abd As Sulami] ia berkata, \"Aku minta pakaian kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memberiku kain tipis yang bersulam wool, dan aku lihat seakan aku adalah orang yang paling bagus bajunya di antara sahabatku.\""},"3401":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَبِي بُرْدَةَ قَالَقَالَ لِي أَبِي يَا بُنَيَّ لَوْ رَأَيْتَنَا وَنَحْنُ مَعَ نَبِيِّنَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَصَابَتْنَا السَّمَاءُ حَسِبْتَ أَنَّ رِيحَنَا رِيحُ الضَّأْنِ","id":"Telah menceritakan kepada kami [Amru bin Aun] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Qatadah] dari [Abu Burdah] ia berkata, \" [Bapakku] berkata kepadaku, \"Wahai anakku, jika engkau lihat keadaan kami saat bersama Nabi kami shallallahu 'alaihi wasallam yang saat itu terguyur air hujan, maka engkau akan mengira bahwa bau badan kami adalah bau badan kambing.\""},"3402":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْ��َرَنَا عُمَارَةُ بْنُ زَاذَانَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ مَلِكَ ذِي يَزَنَ أَهْدَى إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلَّةً أَخَذَهَا بِثَلَاثَةٍ وَثَلَاثِينَ بَعِيرًا أَوْ ثَلَاثٍ وَثَلَاثِينَ نَاقَةً فَقَبِلَهَا","id":"Telah menceritakan kepada kami [Amru bin Aun] berkata, telah mengabarkan kepada kami [Umarah bin Zadzan] dari [Tsabit] dari [Anas bin Malik] berkata, \"bahwasanya raja dzi yazan memberi hadiah Rasulullah shallallahu 'alaihi wasallam perhiasan yang ia beli seharga tiga puluh tiga unta jantan, atau tiga puluh tiga unta betina, lalu beliau menerimanya.\""},"3403":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ الْحَارِثِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى حُلَّةً بِبِضْعَةٍ وَعِشْرِينَ قَلُوصًا فَأَهْدَاهَا إِلَى ذِي يَزَنَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Ali bin Zaid] dari [Ishaq bin Abdullah bin Al Harits] berkata, \"Rasulullah shallallahu 'alaihi wasallam membeli perhiasan seharga lebih dari tiga belas qalush (unta betina yang telah remaja), lalu beliau menghadiahkannya kepada Dzi Yadzan.\""},"3404":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا مُوسَى حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ الْمَعْنَى عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي بُرْدَةَ قَالَدَخَلْتُ عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَأَخْرَجَتْ إِلَيْنَا إِزَارًا غَلِيظًا مِمَّا يُصْنَعُ بِالْيَمَنِ وَكِسَاءً مِنْ الَّتِي يُسَمُّونَهَا الْمُلَبَّدَةَ فَأَقْسَمَتْ بِاللَّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُبِضَ فِي هَذَيْنِ الثَّوْبَيْنِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musa] berkata, telah menceritakan kepada kami [Sulaiman] -yakni Ibnul Mughirah- secara makna, dari [Humaid bin Hilal] dari [Abu Burdah] ia berkata, \"Aku masuk menemui ['Aisyah] radliallahu 'anha, lalu ia keluar dengan membawa kain sarung tebal buatan Yaman dan kain yang mereka namakan Al Mulabbadah. Kemudian ia bersumpah atas nama Allah, bahwa Rasulullah shallallahu 'alaihi wasallam meninggal saat mengenakan dua kain tersebut.\""},"3405":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ أَبُو ثَوْرٍ الْكَلْبِيُّ حَدَّثَنَا عُمَرُ بْنُ يُونُسَ بْنِ الْقَاسِمِ الْيَمَامِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا أَبُو زُمَيْلٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبَّاسٍ قَالَ لَمَّا خَرَجَتْ الْحَرُورِيَّةُ أَتَيْتُ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ فَقَالَ ائْتِ هَؤُلَاءِ الْقَوْمَ فَلَبِسْتُ أَحْسَنَ مَا يَكُونُ مِنْ حُلَلِ الْيَمَنِ قَالَ أَبُو زُمَيْلٍ وَكَانَ ابْنُ عَبَّاسٍ رَجُلًا جَمِيلًا جَهِيرًا قَالَ ابْنُ عَبَّاسٍ فَأَتَيْتُهُمْ فَقَالُوا مَرْحَبًا بِكَ يَا ابْنَ عَبَّاسٍ مَا هَذِهِ الْحُلَّةُقَالَ مَا تَعِيبُونَ عَلَيَّ لَقَدْ رَأَيْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسَنَ مَا يَكُونُ مِنْ الْحُلَلِقَالَ أَبُو دَاوُد اسْمُ أَبِي زُمَيْلٍ سِمَاكُ بْنُ الْوَلِيدِ الْحَنَفِيُّ","id":"Telah menceritakan kepada kami [Ibrahim bin Khalid Abu Tsaur Al Kalbi] berkata, telah menceritakan kepada kami [Umar bin Yunus bin Al Qasim Al Yamami] berkata, telah menceritakan kepada kami [Ikrimah bin Ammar] berkata, telah menceritakan kepada kami [Abu Zumail] berkata, telah menceritakan kepadaku [Abdullah bin Abbas] ia berkata, \"Ketika orang-orang Haruri keluar, aku menemui Ali radliallahu 'anhu. Lalu ia berkata, 'Datangilah orang-orang (Haruri) itu. ' Maka aku mengenakan pakaian terbaik yang dimiliki bangsa Yaman.\" Abu Zumail berkata, \"Ibnu Abbas adalah seorang laki-laki yang sangat tampan dan enak dipandang. Ibnu Abbas berkata, \"Lantas aku mendatangi orang-orang itu, mereka berkata, \"Selamat datang wahai Ibnu Abbas, ini pakaian apa!\" Ibnu Abbas menjawab, \"Kenapa kalian mencelaku! Sungguh, aku pernah melihat Rasulullah shallallahu 'alaihi wasallam mengenakan pakaian yang sangat bagus.\" Abu Dawud berkata, \"Abu Zumail nama aslinya adalah Simak Ibnul Walid Al Hanafi.\""},"3406":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدٍ الْأَنْمَاطِيُّ الْبَصْرِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ الرَّازِيُّ ح و حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ الرَّازِيُّ حَدَّثَنَا أَبِي أَخْبَرَنِي أَبِي عَبْدُ اللَّهِ بْنُ سَعْدٍ عَنْ أَبِيهِ سَعْدٍ قَالَرَأَيْتُ رَجُلًا بِبُخَارَى عَلَى بَغْلَةٍ بَيْضَاءَ عَلَيْهِ عِمَامَةُ خَزٍّ سَوْدَاءُ فَقَالَ كَسَانِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَهَذَا لَفْظُ عُثْمَانَ وَالْإِخْبَارُ فِي حَدِيثِهِ","id":"Telah menceritakan kepada kami [Utsman bin Muhammad Al Anmathi Al Bashari] berkata, telah menceritakan kepada kami ['Abdurrahman bin Abdullah Ar Razi]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Ahmad bin 'Abdurrahman Ar Razi] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah mengabarkan kepadaku bapakku [Abdullah bin Sa'd] dari bapaknya [Sa'd] ia berkata, \"Di Bukhara aku melihat [seorang laki-laki] di atas bighal putih mengenakan imamah (semacam surban yang lilitkan pada kepala) hitam bersulam sutera, laki-laki itu lantas berkata, \"Rasulullah shallallahu 'alaihi wasallam mengenakanku imamah ini.\" Ini adalah lafadz Utsman dalam haditsnya. "},"3407":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ نَجْدَةَ حَدَّثَنَا بِشْرُ بْنُ بَكْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ قَالَ حَدَّثَنَا عَطِيَّةُ بْنُ قَيْسٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ غَنْمٍ الْأَشْعَرِيَّ قَالَ حَدَّثَنِي أَبُو عَامِرٍ أَوْ أَبُو مَالِكٍ وَاللَّهِ يَمِينٌ أُخْرَى مَا كَذَّبَنِيأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَكُونَنَّ مِنْ أُمَّتِي أَقْوَامٌ يَسْتَحِلُّونَ الْخَزَّ وَالْحَرِيرَ وَذَكَرَ كَلَامًا قَالَ يُمْسَخُ مِنْهُمْ آخَرُونَ قِرَدَةً وَخَنَازِيرَ إِلَى يَوْمِ الْقِيَامَةِقَالَ أَبُو دَاوُد وَعِشْرُونَ نَفْسًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ أَكْثَرُ لَبِسُوا الْخَزَّ مِنْهُمْ أَنَسٌ وَالْبَرَاءُ بْنُ عَازِبٍ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Najdah] berkata, telah menceritakan kepada kami [Bisyr bin Bakr] dari ['Abdurrahman bin Yazid bin Jabir] ia berkata; telah menceritakan kepada kami [Athiyah bin Qais] ia berkata; Aku mendengar ['Abdurrahman bin Ghanm Al Asy'ari] ia berkata; telah menceritakan kepadaku Abu Amir atau [Abu Malik] -demi Allah- ia tidak mendustaiku bahwasanya ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Benar-benar akan ada dari umatku orang-orang yang menghalalkan sutera.\" Lalu ia menyebutkan redaksi lain, beliau bersabda: \"Salah seorang dari mereka diubah menjadi kera dan babi hingga hari kiamat.\" Abu Dawud menyebutkan, \"Ada dua puluh orang atau lebih dari sahabat Rasulullah shallallahu 'alaihi wasallam mengenakan sutera, salah seorang di antara mereka adalah Anas dan Al bara bin Azib.\""},"3408":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَأَى حُلَّةَ سِيَرَاءَ عِنْدَ بَابِ الْمَسْجِدِ تُبَاعُ فَقَالَ يَا رَسُولَ اللَّهِ لَوْ اشْتَرَيْتَ هَذِهِ فَلَبِسْتَهَا يَوْمَ الْجُمُعَةِ وَلِلْوَفْدِ إِذَا قَدِمُوا عَلَيْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَلْبَسُ هَذِهِ مَنْ لَا خَلَاقَ لَهُ فِي الْآخِرَةِ ثُمَّ جَاءَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا حُلَلٌ فَأَعْطَى عُمَرَ بْنَ الْخَطَّابِ مِنْهَا حُلَّةً فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ كَسَوْتَنِيهَا وَقَدْ قُلْتَ فِي حُلَّةِ عُطَارِدَ مَا قُلْتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَمْ أَكْسُكَهَا لِتَلْبَسَهَا فَكَسَاهَا عُمَرُ بْنُ الْخَطَّابِ أَخًا لَهُ مُشْرِكًا بِمَكَّةَحَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ وَعَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ بِهَذِهِ الْقِصَّةِ قَالَ حُلَّةُ إِسْتَبْرَقٍ وَقَالَ فِيهِ ثُمَّ أَرْسَلَ إِلَيْهِ بِجُبَّةِ دِيبَاجٍ وَقَالَ تَبِيعُهَا وَتُصِيبُ بِهَا حَاجَتَكَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Nafi'] dari [Abdullah bin Umar] berkata, \"Umar Ibnul Khaththab melihat kain bersulam sutera di jual depan pintu masjid. Umar lalu berkata, \"Wahai Rasulullah, sekiranya saja engkau membeli kain ini, sehingga engkau bisa memakainya di hari jum'at dan saat menerima utusan jika datang kepadamu.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Hanyasanya yang mengenakan ini adalah orang-orang yang tidak akan mendapatkan bagian di akhirat.\" Setelah itu didatangkan kepada Rasulullah shallallahu 'alaihi wasallam beberapa potong kain sutera, beliau lantas memberikan sepotong darinya kepada Umar Ibnul Khaththab. Umar lalu bertanya, \"Wahai Rasulullah, kenapa engkau berikan ini kepadaku, padahal engkau telah berkata tentang sutera sebagaimana yang engkau katakan!\" Rasulullah shallallahu 'alaihi wasallam kemudian menjawab: \"Aku berikan itu kepadamu bukan untuk engkau pakai.\" Umar Ibnul Khaththab pun mengenakan kain tersebut untuk saudara laki-lakinya yang masih musyrik di Makkah.\" Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yunus] dan [Amru Ibnul Harits] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [Bapaknya] dengan kisah beriku, ia berkata, \"Dengan kain sutera, \" dan ia menyebutkan dalam hadits tersebut, \"Lalu beliau mengirimkan jubbah (selendang) sutera kepada Umar.\" Beliau kemudian bersabda: \"Juallah ini, dan gunakanlah hasil penjualannya untuk memenuhi kebutuhanmu.\""},"3409":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ قَالَكَتَبَ عُمَرُ إِلَى عُتْبَةَ بْنِ فَرْقَدٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْحَرِيرِ إِلَّا مَا كَانَ هَكَذَا وَهَكَذَا أُصْبُعَيْنِ وَثَلَاثَةً وَأَرْبَعَةً","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] berkata, telah menceritakan kepada kami [Ashim Al Ahwal] dari [Abu Utsman An Nahdi] ia berkata, \" [Umar] menulis surat kepada Utbah bin Farqad, bahwa Nabi shallallahu 'alaihi wasallam melarang kain sutera kecuali sekian dan sekian. Yakni sekadar dua jari, atau tiga jari, atau empat jari.\""},"3410":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عَوْنٍ قَالَ سَمِعْتُ أَبَا صَالِحٍ يُحَدِّثُ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَأُهْدِيَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُلَّةُ سِيَرَاءَ فَأَرْسَلَ بِهَا إِلَيَّ فَلَبِسْتُهَا فَأَتَيْتُهُ فَرَأَيْتُ الْغَضَبَ فِي وَجْهِهِ وَقَالَ إِنِّي لَمْ أُرْسِلْ بِهَا إِلَيْكَ لِتَلْبَسَهَا وَأَمَرَنِي فَأَطَرْتُهَا بَيْنَ نِسَائِي","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Aun] ia berkata; Aku mendengar [Abu Shalih] menceritakan dari [Ali radliallahu 'anhu] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam diberi hadiah kain sutera, beliau lalu mengirimkannya kepadaku, maka aku pun memakainya. Setelah itu aku mendatangi beliau, tetapi aku melihat pada wajah beliau tanda kemarahan. Beliau bersabda: \"Aku mengirimkan itu kepadamu bukan untuk engkau pakai.\" Beliau pun memerintahkan kepadaku (untuk memberikan kepada orang lain), sehingga kain itu aku bagikan untuk para perempuanku.\""},"3411":{"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبْسِ الْقَسِّيِّ وَعَنْ لُبْسِ الْمُعَصْفَرِ وَعَنْ تَخَتُّمِ الذَّهَبِ وَعَنْ الْقِرَاءَةِ فِي الرُّكُوعِحَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ يَعْنِي الْمَرْوَزِيَّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا قَالَ عَنْ الْقِرَاءَةِ فِي الرُّكُوعِ وَالسُّجُودِ حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بِهَذَا زَادَ وَلَا أَقُولُ نَهَاكُمْ","id":"Telah menceritakan kepada kami [Al Qa'nabi] dari [Malik] dari [Nafi'] dari [Ibrahim bin Abdullah bin Hunain] dari [Bapaknya] dari [Ali bin Abu Thalib] radliallahu 'anhu, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakai kain yang bersulam sutera, kain yang dicelup dengan warna kuning, memakai cincin emas dan membaca Al-Qur'an saat rukuk.\" Telah menceritakan kepada kami [Ahmad bin Muhammad] -yaitu Al Marwazi- berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibrahim bin Abdullah bin Hunain] dari [Bapaknya] dari [Ali bin Abu Thalib] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam dengan redaksi hadits seperti ini. Ali berkata: \".. (beliau melarang) membaca Al-Qur'an saat rukuk dan sujud\", Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Muhammad bin Amru] dari [Ibrahim bin Abdullah] dengan lafadz seperti ini dengan menambahkan, \"Dan aku tidak mengatakan 'beliau melarang kalian' (maksudnya; Muhammad bin Amru menambahkan dalam riwayatnya bahwa Ali berkata; Rasulullah Shallahu 'Alaihi Wasallam melarangku dan aku tidak berkata beliau melarang kalian).\""},"3412":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ مَلِكَ الرُّومِ أَهْدَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتُقَةً مِنْ سُنْدُسٍ فَلَبِسَهَا فَكَأَنِّي أَنْظُرُ إِلَى يَدَيْهِ تَذَبْذَبَانِ ثُمَّ بَعَثَ بِهَا إِلَى جَعْفَرٍ فَلَبِسَهَا ثُمَّ جَاءَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَمْ أُعْطِكَهَا لِتَلْبَسَهَا قَالَ فَمَا أَصْنَعُ بِهَا قَالَ أَرْسِلْ بِهَا إِلَى أَخِيكَ النَّجَاشِيِّ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Ali bin Zaid] dari [Anas bin Malik] berkata, \"Raja Rum memberi haidah kepada Nabi shallallahu 'alaihi wasallam berupa farwah (sejenis jubah) sutera, lalu beliau mengenakannya. Seakan aku melihat tangan nabi bergerak-gerak (mengkibas), beliau lalu mengirimkan jubah itu kepada Ja'far, hingga ia pun memakainya. Ketika Ja'far datang kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Aku berikan itu kepadamu bukan untuk engkau pakai!\" Ja'far bertanya, \"Lalu apa yang harus aku lakukan terhadap jubah itu?\" beliau menjawab: \"Kirimkanlah kepada saudaramu, raja Najasyi.\""},"3413":{"ar":"حَدَّثَنَا مَخْلَدُ بْنُ خَالِدٍ حَدَّثَنَا رَوْحٌ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا أَرْكَبُ الْأُرْجُوَانَ وَلَا أَلْبَسُ الْمُعَصْفَرَ وَلَا أَلْبَسُ الْقَمِيصَ الْمُكَفَّفَ بِالْحَرِيرِ قَالَ وَأَوْمَأَ الْحَسَنُ إِلَى جَيْبِ قَمِيصِهِ قَالَ وَقَالَ أَلَا وَطِيبُ الرِّجَالِ رِيحٌ لَا لَوْنَ لَهُ أَلَا وَطِيبُ النِّسَاءِ لَوْنٌ لَا رِيحَ لَهُقَالَ سَعِيدٌ أُرَهُ قَالَ إِنَّمَا حَمَلُوا قَوْلَهُ فِي طِيبِ النِّسَاءِ عَلَى أَنَّهَا إِذَا خَرَجَتْ فَأَمَّا إِذَا كَانَتْ عِنْدَ زَوْجِهَا فَلْتَطَّيَّبْ بِمَا شَاءَتْ","id":"Telah menceritakan kepada kami [Makhlad bin Khalid] berkata, telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Sa'id bin Abu Arubah] dari [Qatadah] dari [Al Hasan] dari [Imran bin Hushain] bahwa Nabi Allah shallallahu 'alaihi wasallam bersabda: \"Aku tidak akan memakai alas pelana yang berwarna merah, dan tidak pula kain yang dicelup dengan warna kuning serta tidak akan memakai kain yang bersulam sutera (pada lengannya).\" Imran berkata, \"Lalu Hasan berisyarat pada saku bajunya.\" Imran berkata, \"beliau lalu bersabda: \"Ketahuilah, minyak wangi bagi laki-laki itu beraroma tetapi tidak berwarna, sedangkan minyak wangi bagi wanita itu berwarna tetapi tidak beraroma.\" Sa'id berkata, \"Menurutku bahwa ucapan beliau tentang minyak wangi wanita itu dipahami dalam kondisi saat ia keluar rumah, adapaun jika wanita itu sedang bersama suaminya, maka ia boleh mengenakan wewangian sesuka hatinya.\""},"3414":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدِ بْنِ عَبْدِ اللَّهِ بْنِ مَوْهَبٍ الْهَمْدَانِيُّ أَخْبَرَنَا الْمُفَضَّلُ يَعْنِي ابْنَ فَضَالَةَ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ الْقِتْبَانِيِّ عَنْ أَبِي الْحُصَيْنِ يَعْنِي الْهَيْثَمَ بْنَ شَفِيٍّ قَالَخَرَجْتُ أَنَا وَصَاحِبٌ لِي يُكْنَى أَبَا عَامِرٍ رَجُلٌ مِنْ الْمَعَافِرِ لِنُصَلِّيَ بِإِيلْيَاءَ وَكَانَ قَاصُّهُمْ رَجُلٌ مِنْ الْأَزْدِ يُقَالُ لَهُ أَبُو رَيْحَانَةَ مِنْ الصَّحَابَةِ قَالَ أَبُو الْحُصَيْنِ فَسَبَقَنِي صَاحِبِي إِلَى الْمَسْجِدِ ثُمَّ رَدِفْتُهُ فَجَلَسْتُ إِلَى جَنْبِهِ فَسَأَلَنِي هَلْ أَدْرَكْتَ قَصَصَ أَبِي رَيْحَانَةَ قُلْتُ لَا قَالَ سَمِعْتُهُيَقُولُ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَشْرٍ عَنْ الْوَشْرِ وَالْوَشْمِ وَالنَّتْفِ وَعَنْ مُكَامَعَةِ الرَّجُلِ الرَّجُلَ بِغَيْرِ شِعَارٍ وَعَنْ مُكَامَعَةِ الْمَرْأَةِ الْمَرْأَةَ بِغَيْرِ شِعَارٍ وَأَنْ يَجْعَلَ الرَّجُلُ فِي أَسْفَلِ ثِيَابِهِ حَرِيرًا مِثْلَ الْأَعَاجِمِ أَوْ يَجْعَلَ عَلَى مَنْكِبَيْهِ حَرِيرًا مِثْلَ الْأَعَاجِمِ وَعَنْ النُّهْبَى وَرُكُوبِ النُّمُورِ وَلُبُوسِ الْخَاتَمِ إِلَّا لِذِي سُلْطَانٍقَالَ أَبُو دَاوُد الَّذِي تَفَرَّدَ بِهِ مِنْ هَذَا الْحَدِيثِ ذِكْرُ الْخَاتَمِ","id":"Telah menceritakan kepada kami [Yazid bin Khalid bin Abdullah bin Mauhab Al Hamdani] berkata, telah mengabarkan kepadaku [Al Mufadhdhal] -yaitu Ibnu Fadhalah- dari [Ayyasy bin Abbas Al Qitbani] dari [Abu Al Hushain] -yaitu Al Haitsam bin Syafi ia berkata, \"Aku dan seorang sahabatku yang dipanggil dengan nama [Abu Amir], seorang laki-laki dari Al Ma'afir, keluar untuk melaksanakan shalat di Illiya. Mereka (penduduk setempat) mempunyai penasihat seorang laki-laki dari Al Azdi, ia biasa dipanggil dengan nama Abu raihanah, seorang sahabat Nabi.\" Abu Al Hushain berkata, \"Sahabatku tersebut mendahuluiku datang ke masjid, lalu aku menyusul dari belakang dan duduk di sisinya. Ia lantas bertanya kepadaku, \"Apakah kamu mendengar cerita [Abu Raihanah]?\" Aku menjawab, \"Tidak.\" Ia berkata, \"Aku mendengar dia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dari sepuluh hal; mengikir gigi, membuat tato, mencabut alis, seorang laki-laki tidur dengan laki-laki lain dalam satu selimut tanpa ada kain pembatas, seorang wanita tidur dengan wanita lain dalam satu selimut tanpa ada kain pembatas, seorang laki-laki yang menambahi sutera pada bagian bawah kainnya seperti orang 'ajam (bukan arab), atau menjadikan pada kain di bagian pundaknya berupa sutera seperi orang 'ajam. Beliau juga melarang dari merampas harta orang lain, memakai kulit macan, dan mamakai cincin kecuali penguasa.\" Abu Dawud berkata \" yang membuat hadits ini menyendiri dan berbeda dengan hadits lainnya adalah penyebutan lafadh; 'dan memakai cincin\". "},"3415":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا رَوْحٌ حَدَّثَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ عَبِيدَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَنُهِيَ عَنْ مَيَاثِرِ الْأُرْجُوَانِ","id":"Telah menceritakan kepada kami [Yahya bin Habib] berkata, telah menceritakan kepada kami [Rauh] berkata, telah menceritakan kepada kami [Hisyam] dari [Muhammad] dari [Abidah] dari [Ali radliallahu 'anhu] ia berkata, \"Telah dilarang pemakaian alas penala yang terbuat dari sulaman sutera.\""},"3416":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ هُبَيْرَةَ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ لُبْسِ الْقَسِّيِّ وَالْمِيثَرَةِ الْحَمْرَاءِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] dan [Muslim bin Ibrahim] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Hubairah] dari [Ali radliallahu 'anhu] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarangku memakai cincin emas, memakai kain yang bersulam sutera dan alas pelana yang berwarna merah.\""},"3417":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ الزُّهْرِيُّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي خَمِيصَةٍ لَهَا أَعْلَامٌ فَنَظَرَ إِلَى أَعْلَامِهَا فَلَمَّا سَلَّمَ قَالَ اذْهَبُوا بِخَمِيصَتِي هَذِهِ إِلَى أَبِي جَهْمٍ فَإِنَّهَا أَلْهَتْنِي آنِفًا فِي صَلَاتِي وَأْتُونِي بِأَنْبِجَانِيَّتِهِقَالَ أَبُو دَاوُد أَبُو جَهْمٍ بْنُ حُذَيْفَةَ مِنْ بَنِي عَدِيِّ بْنِ كَعْبِ بْنِ غَانِمٍ حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ فِي آخَرِينَ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ نَحْوَهُ وَالْأَوَّلُ أَشْبَعُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Ibrahim bin Sa'd] berkata, telah menceritakan kepada kami [Ibnu Syihab Az Zuhri] dari [Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat menggunakan kain yang ada gambarnya. Beliau lalu melihat gambar pada kainnya, selesai salam beliau bersabda: \"Bawalah kainku ini kepada Abu Jahm, sesungguhnya ia telah mengganggu shalatku, lalu bawalah kepadaku kainnya yang tidak bergambar.\" Abu Dawud berkata, \"Abu Jahm bin Khudzaifah berasal dari bani Adi bin Ka'b bin Ghanim.\" Dan telah menceritakan kepada kami [Utsman bin Abu Syaibah] dalam hadis-hadis lain, (mereka katakan), telah menceritakan kepada kami [Sufyan] dari [Azzuhri] dari ['Urwah] dari [Aisyah] dengan redaksi semisal namun hadis pertama lebih komplit. "},"3418":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْمُغِيرَةُ بْنُ زِيَادٍ حَدَّثَنَا عَبْدُ اللَّهِ أَبُو عُمَرَ مَوْلَى أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَرَأَيْتُ ابْنَ عُمَرَ فِي السُّوقِ اشْتَرَى ثَوْبًا شَأْمِيًّا فَرَأَى فِيهِ خَيْطًا أَحْمَرَ فَرَدَّهُ فَأَتَيْتُ أَسْمَاءَ فَذَكَرْتُ ذَلِكَ لَهَا فَقَالَتْ يَا جَارِيَةُ نَاوِلِينِي جُبَّةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْرَجَتْ جُبَّةَ طَيَالِسَةٍ مَكْفُوفَةَ الْجَيْبِ وَالْكُمَّيْنِ وَالْفَرْجَيْنِ بِالدِّيبَاجِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Al Mughirah bin Ziyad] berkata, telah menceritakan kepada kami [Abdullah Abu Umar] mantan budak (yang telah dimerdekakan oleh) [Asma binti Abu Bakr], ia berkata, \"Ibnu Umar membeli kain Syam yang padanya terdapat warna merah, lalu ia mengembalikannya. Maka aku mendatangi Asma dan aku ceritakan hal itu kepadanya. Asma lalu berkata, \"Wahai jariah, bawalah kemari jubah (semacam selendang) Rasulullah shallallahu 'alaihi wasallam.\" Pembantu perempuan itu lalu mengeluarkan jubah tebal yang masing masing dari tepi kantong, dan kedua lengan baju, serta kedua tepi belahan bajunya dari jenis sutera. "},"3419":{"ar":"حَدَّثَنَا ابْنُ نُفَيْلٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا خُصَيْفٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّمَا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الثَّوْبِ الْمُصْمَتِ مِنْ الْحَرِيرِ فَأَمَّا الْعَلَمُ مِنْ الْحَرِيرِ وَسَدَى الثَّوْبِ فَلَا بَأْسَ بِهِ","id":"Telah menceritakan kepada kami [Ibnu Nufail] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Khushaif] dari [Ikrimah] dari [Ibnu Abbas] ia berkata, \"Hanyasanya yang Rasulullah shallallahu 'alaihi wasallam larang adalah kain yang murni dari sutera, adapun jika itu berupa gambar atau benangnya saja, maka tidaklah mengapa.\""},"3420":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا عِيسَى يَعْنِي ابْنَ يُونُسَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَرَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَلِلزُّبَيْرِ بْنِ الْعَوَّامِ فِي قُمُصِ الْحَرِيرِ فِي السَّفَرِ مِنْ حِكَّةٍ كَانَتْ بِهِمَا","id":"Telah menceritakan kepada kami [An Nufail] berkata, telah menceritakan kepada kami [Isa] -yaitu Ibnu Yunus- dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Anas] ia berkata, \"Dalam suatu perjalanan Rasulullah shallallahu 'alaihi wasallam memberi keringanan kepada 'Abdurrahman bin Auf dan Zubair Ibnul Awwam untuk mengenakan baju sutera karena sakit gatal yang mereka derita.\""},"3421":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي أَفْلَحَ الْهَمْدَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ زُرَيْرٍ يَعْنِي الْغَافِقِيَّ أَنَّهُ سَمِعَ عَلِيَّ بْنَ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُإِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ حَرِيرًا فَجَعَلَهُ فِي يَمِينِهِ وَأَخَذَ ذَهَبًا فَجَعَلَهُ فِي شِمَالِهِ ثُمَّ قَالَ إِنَّ هَذَيْنِ حَرَامٌ عَلَى ذُكُورِ أُمَّتِي","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Aflah Al Hamdani] dari [Abdullah bin Zurair] -yaitu Al Aghafiqi- Bahwasanya ia mendengar [Ali bin Abu Thalib radliallahu 'anhu] berkata, \"Rasulullah shallallahu 'alaihi wasallam pernah mangambil sutera lalu meletakkannya pada sisi kanannya, dan mengambil emas lalu meletakkannya pada sisi kirinya. Kemudian beliau bersabda: \"Sesugguhnya dua barang ini haram bagi umatku yang laki-laki.\""},"3422":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ وَكَثِيرُ بْنُ عُبَيْدٍ الْحِمْصِيَّانِ قَالَا حَدَّثَنَا بَقِيَّةُ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ حَدَّثَهُأَنَّهُ رَأَى عَلَى أُمِّ كُلْثُومٍ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُرْدًا سِيَرَاءَ قَالَ وَالسِّيَرَاءُ الْمُضَلَّعُ بِالْقَزِّ","id":"Telah menceritakan kepada kami [Amru bin Utsman] dan [Katsir bin Ubaid] -keduanya dari Himsha, mereka berkata; telah menceritakan kepada kami [Baqiyyah] dari [Az Zubaidiy] dari [Az Zuhri] dari [Anas bin Malik] Bahwasanya ia menceritakan kepadanya, bahwa ia pernah melihat Ummu Kultsum binti Rasulullah shallallahu 'alaihi wasallam mengenakan belerudu dari sutera. Anas berkata, \"Siyara adalah sulaman sutera yang melintang.\""},"3423":{"ar":"حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أَحْمَدَ يَعْنِي الزُّبَيْرِيَّ حَدَّثَنَا مِسْعَرٌ عَنْ عَبْدِ الْمَلِكِ بْنِ مَيْسَرَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرٍ قَالَكُنَّا نَنْزِعُهُ عَنْ الْغِلْمَانِ وَنَتْرُكُهُ عَلَى الْجَوَارِيقَالَ مِسْعَرٌ فَسَأَلْتُ عَمْرَو بْنَ دِينَارٍ عَنْهُ فَلَمْ يَعْرِفْهُ","id":"Telah menceritakan kepada kami [Nashr bin Ali] berkata, telah menceritakan kepada kami [Abu Ahmad] -yaitu Az Zubairi- berkata, telah menceritakan kepada kami [Mis'ar] dari [Abdul Malik bin Maisarah] dari [Amru bin Dinar] dari [Jabir] ia berkata, \"Kami mengambilnya (sutra) dari anak laki-laki, tetapi kami biarkan untuk para gadis.\" Mis'ar berkata, \"Aku lalu menanyakannya kepada Amru bin Dinar tentang hal itu, namun ia tidak mengetahuinya.\""},"3424":{"ar":"حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ الْأَزْدِيُّ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ قُلْنَا لِأَنَسٍ يَعْنِي ابْنَ مَالِكٍ أَيُّ اللِّبَاسِ كَانَ أَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ أَعْجَبَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْحِبَرَةُ","id":"Telah menceritakan kepada kami [Hudbah bin Khalid Al Azdi] berkata, telah menceritakan kepada kami [Hammam] dari [Qatadah] ia berkata, \"Kami berkata kepada [Anas] -maksudnya Anas Ibnu Malik-, \"Baju apa yang paling disukai atau dikagumi oleh Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab, \"Kain hibarah (yaitu kain halus yang berasal dari yaman menurut orang-orang yaman ini adalah kain terbaik).\""},"3425":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَسُوا مِنْ ثِيَابِكُمْ الْبَيَاضَ فَإِنَّهَا مِنْ خَيْرِ ثِيَابِكُمْ وَكَفِّنُوا فِيهَا مَوْتَاكُمْ وَإِنَّ خَيْرَ أَكْحَالِكُمُ الْإِثْمِدُ يَجْلُو الْبَصَرَ وَيُنْبِتُ الشَّعْرَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Abdullah bin Utsman bin Khustaim] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pakailah warna putih untuk pakaian kalian, sebab ia sebaik-baik pakaian untuk kalian. Dan kafanilah orang-orang yang meninggal dari kalian dengannya. Dan sebaik-baik celak kalian adalah Al Itsmid, ia dapat mempertajam pandangan dan menumbuhkan rambut.\""},"3426":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا مِسْكِينٌ عَنْ الْأَوْزَاعِيِّ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ عَنْ وَكِيعٍ عَنْ الْأَوْزَاعِيِّ نَحْوَهُ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَى رَجُلًا شَعِثًا قَدْ تَفَرَّقَ شَعْرُهُ فَقَالَ أَمَا كَانَ يَجِدُ هَذَا مَا يُسَكِّنُ بِهِ شَعْرَهُ وَرَأَى رَجُلًا آخَرَ وَعَلْيِهِ ثِيَابٌ وَسِخَةٌ فَقَالَ أَمَا كَانَ هَذَا يَجِدُ مَاءً يَغْسِلُ بِهِ ثَوْبَهُ","id":"Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Miskin] dari [Al Auza'i]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dari [Waki'] dari [Al Auza'i] seperti itu, dari [Hassan bin Athiah] dari [Muhammad Ibnul Munkadir] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mendatangi kami, lalu beliau melihat seorang laki-laki yang rambutnya acak-acakkan. Maka beliau bersabda: \"Tidakkah orang ini mendapatkan sesuatu yang dapat digunakan untuk merapikan rambutnya?\" kemudian beliau juga mendapati seorang laki-laki yang bajunya kotor, beliau bersabda: \"Tidakkah orang ini mendapatkan air hingga ia dapat mencuci bajunya?\""},"3427":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَوْبٍ دُونٍ فَقَالَ أَلَكَ مَالٌ قَالَ نَعَمْ قَالَ مِنْ أَيِّ الْمَالِ قَالَ قَدْ آتَانِي اللَّهُ مِنْ الْإِبِلِ وَالْغَنَمِ وَالْخَيْلِ وَالرَّقِيقِ قَالَ فَإِذَا آتَاكَ اللَّهُ مَالًا فَلْيُرَ أَثَرُ نِعْمَةِ اللَّهِ عَلَيْكَ وَكَرَامَتِهِ","id":"Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Abu Ishaq] dari [Abu Al Ahwash] dari [Bapaknya] ia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam dengan baju yang lusuh. Maka beliau bertanya: \"Apakah engkau mempunyai harta?\" Ia menjawab, \"Ya.\" beliau bertanya lagi: \"Harta apa saja?\" ia menjawab, \"Allah telah memberiku unta, kambing, kuda dan budak.\" Beliau bersabda: \"Jika Allah memberimu harta maka tampakkanlah wujud dari nikimat-Nya dan pemberian-Nya itu pada dirimu.\""},"3428":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُحَمَّدٍ عَنْ زَيْدٍ يَعْنِي ابْنَ أَسْلَمَأَنَّ ابْنَ عُمَرَ كَانَ يَصْبُغُ لِحْيَتَهُ بِالصُّفْرَةِ حَتَّى تَمْتَلِئَ ثِيَابُهُ مِنْ الصُّفْرَةِ فَقِيلَ لَهُ لِمَ تَصْبُغُ بِالصُّفْرَةِ فَقَالَ إِنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْبُغُ بِهَا وَلَمْ يَكُنْ شَيْءٌ أَحَبُّ إِلَيْهِ مِنْهَا وَقَدْ كَانَ يَصْبُغُ ثِيَابَهُ كُلَّهَا حَتَّى عِمَامَتَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] berkata, telah menceritakan kepada kami [Abdul Aziz] -maksudnya Abdul Aziz Ibnu Muhammad- dari [Zaid] -maksudnya Zaid bin Aslam- ia berkata, \" [Ibnu Umar] pernah mewarnai janggutnya dengan warna kuning (waras dan za'faran) hingga bajunya penuh dengan warna kuning. Lalu dikatakan kepadanya, \"Kenapa engkau celup dengan warna kuning?\" Ia menjawab, \"Karena aku melihat Rasulullah shallallahu 'alaihi wasallam mencelup dengan warna itu, dan tidak ada sesuatu yang beliau sukai kecuali warna itu. Bahkan beliau memberi warna pakian dan surbannya dengan warna itu.\""},"3429":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ إِيَادٍ حَدَّثَنَا إِيَادٌ عَنْ أَبِي رِمْثَةَ قَالَانْطَلَقْتُ مَعَ أَبِي نَحْوَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَيْتُ عَلَيْهِ بُرْدَيْنِ أَخْضَرَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Ubaidullah] -maksudnya Ubaidullah bin Iyad- berkata, telah menceritakan kepada kami [Iyad] dari [Abu Rimtsah] ia berkata, \"Aku bersama bapakku pergi menemui Nabi shallallahu 'alaihi wasallam, lalu aku melihat beliau mengenakan dua kain beludru berwarna hijau.\""},"3430":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا هِشَامُ بْنُ الْغَازِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَهَبَطْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ ثَنِيَّةٍ فَالْتَفَتَ إِلَيَّ وَعَلَيَّ رَيْطَةٌ مُضَرَّجَةٌ بِالْعُصْفُرِ فَقَالَ مَا هَذِهِ الرَّيْطَةُ عَلَيْكَ فَعَرَفْتُ مَا كَرِهَ فَأَتَيْتُ أَهْلِي وَهُمْ يَسْجُرُونَ تَنُّورًا لَهُمْ فَقَذَفْتُهَا فِيهِ ثُمَّ أَتَيْتُهُ مِنْ الْغَدِ فَقَالَ يَا عَبْدَ اللَّهِ مَا فَعَلَتْ الرَّيْطَةُ فَأَخْبَرْتُهُ فَقَالَ أَلَا كَسَوْتَهَا بَعْضَ أَهْلِكَ فَإِنَّهُ لَا بَأْسَ بِهِ لِلنِّسَاءِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Isa bin Yunus] berkata, telah menceritakan kepada kami [Hisyam Ibnul Ghaz] dari [Amru bin Syu'aib] dari [bapaknya] dari [Kakeknya] ia berkata, \"Kami bersama Rasulullah shallallahu 'alaihi wasallam turun dari lembah Tsaniah, lalu beliau melihatku mengenakan kain tipis yang dicelup dengan warna kuning. Maka beliau bersabda: \"Kenapa kain tipis ini ada padamu!\" aku paham bahwa beliau tidak menyukainya, maka aku kembali menemui keluargaku yang sedang menyalakan tungku, sehingga kain itu aku masukkan ke dalamnya. Kesokan harinya aku datang menemui Nabi, beliau bertanya: \"Wahai Abdullah, apa yang engkau lakukan dengan kain tipis milikmu itu?\" aku lalu mengabarkan hal yang telah aku lakukan kepada beliau. Beliau pun bersabda: \"Kenapa tidak engkau berikan ke salah satu isterimu, karena itu tidak apa-apa untuk mereka.\""},"3431":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ الْحِمْصِيُّ حَدَّثَنَا الْوَلِيدُ قَالَ قَالَ هِشَامٌ يَعْنِي ابْنَ الْغَازِالْمُضَرَّجَةُ الَّتِي لَيْسَتْ بِمُشَبَّعَةٍ وَلَا الْمُوَرَّدَةُ","id":"Telah menceritakan kepada kami [Amru bin Utsman Al Himshi] berkata, telah menceritakan kepada kami [Al Walid] ia berkata, \" [Hisyam] -maksudnya hisyam bin Al Ghaz- berkata, \"yang dimaksud dengan al mudharrajah (kain yang dicelup dengan warna merah) adalah; yang tidak sempurna warna merahnya (penuh kemerahannya) serta tidak warna mawar.\""},"3432":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُثْمَانَ الدِّمَشْقِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ عَيَّاشٍ عَنْ شُرَحْبِيلَ بْنِ مُسْلِمٍ عَنْ شُفْعَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ قَالَرَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو عَلِيٍّ اللُّؤْلُؤِيُّ أُرَاهُ وَعَلَيَّ ثَوْبٌ مَصْبُوغٌ بِعُصْفُرٍ مُوَرَّدٌ فَقَالَ مَا هَذَا فَانْطَلَقْتُ فَأَحْرَقْتُهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَ��َيْهِ وَسَلَّمَ مَا صَنَعْتَ بِثَوْبِكَ فَقُلْتُ أَحْرَقْتُهُ قَالَ أَفَلَا كَسَوْتَهُ بَعْضَ أَهْلِكَقَالَ أَبُو دَاوُد رَوَاهُ ثَوْرٌ عَنْ خَالِدٍ فَقَالَ مُوَرَّدٌ وَطَاوُسٌ قَالَ مُعَصْفَرٌ","id":"Telah menceritakan kepada kami [Muhammad bin Utsman Ad Dimasyqi] berkata, telah menceritakan kepada kami [Isma'il bin Ayyas] dari [Syurahbil bin Muslim] dari [Syuf'ah] dari [Abdullah bin Amru bin Al Ash] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melihatku, -Abu Ali Al Lu`lu`I menyebutkan-, \"menurutku beliau melihat aku mengenakan kain yang dicelup dengan warna kuning. Maka beliau bersabda: \"Apa-apaan ini!\" Aku lalu pergi dan membakar kain tersebut. Nabi shallallahu 'alaihi wasallam lalu bertanya lagi: \"Apa yang engkau lakukan dengan kain milikmu?\" Aku menjawab, \"Kain itu aku bakar.\" Beliau bersabda: \"Kenapa tidak engkau berikan untuk sebagian isterimu?\" Abu Dawud berkata, \" [Tsaur] meriwayatkannya dari [Khalid], ia mengatakan, \"warna mawar\" sedangkan [Thawus] mengatakan; \"warna kuning.\""},"3433":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حُزَابَةَ حَدَّثَنَا إِسْحَقُ يَعْنِي ابْنَ مَنْصُورٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي يَحْيَى عَنْ مُجَاهِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَمَرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ عَلَيْهِ ثَوْبَانِ أَحْمَرَانِ فَسَلَّمَ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Huzabah] berkata, telah menceritakan kepada kami [Ishaq] -maksudnya Ishaq bin manshur- berkata, telah menceritakan kepada kami [Isra'il] dari [Abu Yahya] dari [Mujahid] dari [Abdullah bin Amru] ia berkata, \"Seorang laki-laki yang mengenakan dua kain berwarna merah lewat di depan Nabi shallallahu 'alaihi wasallam seraya mengucapkan salam, namun Nabi shallallahu 'alaihi wasallam tidak menjawab salamnya.\""},"3434":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَخْبَرَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ يَعْنِي ابْنَ كَثِيرٍ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ رَجُلٍ مِنْ بَنِي حَارِثَةَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رَوَاحِلِنَا وَعَلَى إِبِلِنَا أَكْسِيَةً فِيهَا خُيُوطُ عِهْنٍ حُمْرٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أَرَى هَذِهِ الْحُمْرَةَ قَدْ عَلَتْكُمْ فَقُمْنَا سِرَاعًا لِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نَفَرَ بَعْضُ إِبِلِنَا فَأَخَذْنَا الْأَكْسِيَةَ فَنَزَعْنَاهَا عَنْهَا","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala`] berkata, telah mengabarkan kepada kami [Abu Usamah] dari [Al Walid] -maksudnya Al Walid bin Katsir- dari [Muhammad bin Amru bin Atha] dari [Seorang laki-laki dari bani Haritsah] dari [Rafi' bin Khadij] ia berkata, \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, lalu Rasulullah shallallahu 'alaihi wasallam melihat unta-unta kami terdapat kain dari bulu yang berwarna merah. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"kenapa aku melihat warna merah rata pada kalian??.\" Lalu kami segera bangkit karena ucapan Rasulullah shallallahu 'alaihi wasallam tersebut hingga menyebabkan sebagian unta-unta kami lari. Kemudian kami mengambil dan melepas kain merah dari unta-unta tersebut.\""},"3435":{"ar":"حَدَّثَنَا ابْنُ عَوْفٍ الطَّائِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ حَدَّثَنِي أَبِي قَالَ ابْنُ عَوْفٍ الطَّائِيُّ وَقَرَأْتُ فِي أَصْلِ إِسْمَعِيلَ قَالَ حَدَّثَنِي ضَمْضَمٌ يَعْنِي ابْنَ زُرْعَةَ عَنْ شُرَيْحِ بْنِ عُبَيْدٍ عَنْ حَبِيبِ بْنِ عُبَيْدٍ عَنْ حُرَيْثِ بْنِ الْأَبَحِّ السَّلِيحِيِّ أَنَّ امْرَأَةً مِنْ بَنِي أَسَدٍ قَالَتْكُنْتُ يَوْمًا عِنْدَ زَيْنَبَ امْرَأَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَصْبُغُ ثِيَابًا لَهَا بِمَغْرَةٍ فَبَيْنَا نَحْنُ كَذَلِكَ إِذْ طَلَعَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَى الْمَغْرَةَ رَجَعَ فَلَمَّا رَأَتْ ذَلِكَ زَيْنَبُ عَلِمَتْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَرِهَ مَا فَعَلَتْ فَأَخَذَتْ فَغَسَلَتْ ثِيَابَهَا وَوَارَتْ كُلَّ حُمْرَةٍ ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجَعَ فَاطَّلَعَ فَلَمَّا لَمْ يَرَ شَيْئًا دَخَلَ","id":"Telah menceritakan kepada kami [Ibnu Auf Ath Tha`i] berkata, telah menceritakan kepada kami [Muhammad bin Isma'il] berkata, telah menceritakan kepadaku [Bapakku]. [Ibnu Auf Ath Tha`I] berkata, \"Aku membaca dalam buku [Isma'il] berkata; telah menceritakan kepadaku [Dhamdham] -maksudnya Dhamdham bin Zur'ah- dari [Syuraih bin Ubaid] dari [Habib bin Ubaid] dari [Huraits bin Al Abah As Salihi] berkata, \" [Seorang wanita] bani Asad berkata, \"Suatu hari aku berada di sisi Zainab isteri Rasulullah shallallahu 'alaihi wasallam sedang kami mewarnai baju miliknya dengan lumpur merah. Maka ketika kami sedang melakukan hal itu, Rasulullah shallallahu 'alaihi wasallam muncul di hadapan kami. Dan ketika Zainab melihat hal itu, ia mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam tidak menyukai perbuatannya. Maka ia pun mengambil kain bajunya untuk dicuci dan menghilangkan semua warna merah yang ada. Setelah itu Rasulullah shallallahu 'alaihi wasallam datang kembali, ketika beliau tidak melihat (warna merah itu lagi), beliau masuk ke dalam rumah.\""},"3436":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ النَّمَرِيُّ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُ شَعْرٌ يَبْلُغُ شَحْمَةَ أُذُنَيْهِ وَرَأَيْتُهُ فِي حُلَّةٍ حَمْرَاءَ لَمْ أَرَ شَيْئًا قَطُّ أَحْسَنَ مِنْهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar An Namri] berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Bara] ia berkata, \"Rambut Rasulullah shallallahu 'alaihi wasallam panjangnya hingga daun telinga, aku pernah melihat beliau mengenakan pakian berwarna merah, dan aku tidak pernah melihat seseorang yang lebih bagus dari beliau.\""},"3437":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِلَالِ بْنِ عَامِرٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى يَخْطُبُ عَلَى بَغْلَةٍ وَعَلَيْهِ بُرْدٌ أَحْمَرُ وَعَلِيٌّ رَضِيَ اللَّهُ عَنْهُ أَمَامَهُ يُعَبِّرُ عَنْهُ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hilal bin Amir] dari [Bapaknya] ia berkata, \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam berkhutbah di Mina di atas bighal, beliau mengenakan selendang beludru berwarna merah, sementara Ali radliallahu 'anhu berada di depannya sebagai penerjemah.\""},"3438":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْصَنَعْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُرْدَةً سَوْدَاءَ فَلَبِسَهَا فَلَمَّا عَرَقَ فِيهَا وَجَدَ رِيحَ الصُّوفِ فَقَذَفَهَا قَالَ وَأَحْسِبُهُ قَالَ وَكَانَ تُعْجِبُهُ الرِّيحُ الطَّيِّبَةُ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Hammam] dari [Qatadah] dari [Mutahrrif] dari ['Aisyah radliallahu 'anha] ia berkata, \"Aku membuatkan Rasulullah shallallahu 'alaihi wasallam selendang berwarna hitam, lalu beliau memakainya. Saat berkeringat, beliau mendapati bau wool (bulu kambing) hingga beliau pun membuangnya.\" perawi berkata, \"Aku mengira bahwa ia (Mutharrif) mengatakan, \"Rasulullah menyukai bau wangi.\""},"3439":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُحَمَّدٍ الْقُرَشِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ عُبَيْدَةَ أَبِي خِدَاشٍ عَنْ أَبِي تَمِيمَةَ الْهُجَيْمِيِّ عَنْ جَابِرٍ يَعْنِي ابْنَ سُلَيْمٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْتَبٍ بِشَمْلَةٍ وَقَدْ وَقَعَ هُدْبُهَا عَلَى قَدَمَيْهِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Muhammad Al Qurasyi] berkata, telah menceritakan kepada kami [Hammad bin Salamah] berkata, telah mengabarkan kepada kami [Yunus bin Ubaid] dari [Ubaidah Abu Khidasy] dari [Abu Tamimah Al Hujaimi] dari [Jabir bin Sulaim] ia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam, beliau waktu itu sedang duduk ihtiba (duduk di atas bokong dan mendekap kedua lututnya menempel dada) dengan selimut, sementara ujung selimutnya mengenai kedua telapak kakinya.\""},"3440":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ وَمُسْلِمُ بْنُ إِبْرَاهِيمَ وَمُوسَى بْنُ إِسْمَعِيلَ قَالُوا حَدَّثَنَا حَمَّادٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَامَ الْفَتْحِ مَكَّةَ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] dan [Muslim bin Ibarahim] dan [Musa bin Isma'il] mereka berkata; telah menceritakan kepada kami [Hammad] dari [Abu Az Zubair] dari [Jabir] berkata, \"Rasulullah shallallahu 'alaihi wasallam masuk saat pembukaan (penaklukan) kota Makkah dengan mengenakan imamah (surban yang lilitkan kepala) berwarna hitam.\""},"3441":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ مُسَاوِرٍ الْوَرَّاقِ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ قَدْ أَرْخَى طَرَفَهَا بَيْنَ كَتِفَيْهِ","id":"Telah menceritakan kepada kami [Al Hasan bin Ali] berkata, telah menceritakan kepada kami [Abu Usamah] dari [Musawir Al Warraq] dari [Ja'far bin Amru bin Huraits] dari [Bapaknya] ia berkata, \"Aku melihat Nabi shallallahu 'alaihi wasallam di atas mimbar mengenakan surban berwarna hitam, sementara ujungnya menjuntai pada dua pundaknya.\""},"3442":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ الثَّقَفِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ رَبِيعَةَ حَدَّثَنَا أَبُو الْحَسَنِ الْعَسْقَلَانِيُّ عَنْ أَبِي جَعْفَرِ بْنِ مُحَمَّدِ بْنِ عَلِيِّ بْنِ رُكَانَةَ عَنْ أَبِيهِأَنَّ رُكَانَةَ صَارَعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَرَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُكَانَةُ وَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَرْقُ مَا بَيْنَنَا وَبَيْنَ الْمُشْرِكِينَ الْعَمَائِمُ عَلَى الْقَلَانِسِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id Ats Tsaqafi] berkata, telah menceritakan kepada kami [Muhammad bin Rabi'ah] berkata, telah menceritakan kepada kami [Abu Al Hasan Al Asqalani] dari [Abu Ja'far bin Muhammad bin Ali bin Rukanah] dari [Bapaknya] berkata, \"Rukanah pernah menggulat (membanting) Nabi shallallahu 'alaihi wasallam, lalu Nabi shallallahu 'alaihi wasallam ganti membanting rukanah. [Rukanah] berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Perbedaan antara kita dengan orang-orang musyrik adalah diletakkannya imamah (semacam surban yang dililitkan di kepala) di atas peci.\""},"3443":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا عُثْمَانُ بْنُ عُثْمَانَ الْغَطَفَانِيُّ حَدَّثَنَا سُلَيْمَانُ بْنُ خَرَّبُوذَ حَدَّثَنِي شَيْخٌ مِنْ أَهْلِ الْمَدِينَةِ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ يَقُولُعَمَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَدَلَهَا بَيْنَ يَدَيَّ وَمِنْ خَلْفِي","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] -mantan budak bani Hasyim- berkata, telah menceritakan kepada kami [Utsman Al Ghathafani] berkata, telah menceritakan kepada kami [Sulaiman bin Kharrabudz] berkata, telah menceritakan kepadaku [Syaikh] -dari Madinah- ia berkata, \"Aku mendengar ['Abdurrahman bin Auf] berkata, \"Rasulullah shallallahu 'alaihi wasallam memasangkan imamah untukku, lalu beliau menjuntaikan ujung-ujungnya ke bagian depan dan belakangku.\""},"3444":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لِبْسَتَيْنِ أَنْ يَحْتَبِيَ الرَّجُلُ مُفْضِيًا بِفَرْجِهِ إِلَى السَّمَاءِ وَيَلْبَسُ ثَوْبَهُ وَأَحَدُ جَانِبَيْهِ خَارِجٌ وَيُلْقِي ثَوْبَهُ عَلَى عَاتِقِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] berkata, telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang dua cara berpakaian; seorang laki-laki berihtiba (duduk di atas bokong dan mendekap kedua lutut menempel dada) dengan membiarkan auratnya (kemaluan) menghadap ke langit. Dan memakai pakaian dengan satu sisi dibiarkan terbuka, lalu menyelempangkan bajunya ke pundak.\""},"3445":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّمَّاءِ وَعَنْ الِاحْتِبَاءِ فِي ثَوْبٍ وَاحِدٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang Ash Shama (membungkus seluruh tubuh tanpa ada celah untuk tangan keluar) dan berihtiba (duduk di atas bokong dan mendekap kedua lutut menempel dada) dengan satu kain.\""},"3446":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ وَأَحْمَدُ بْنُ يُونُسَ قَالَا حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا عُرْوَةُ بْنُ عَبْدِ اللَّهِ قَالَ ابْنُ نُفَيْلٍ ابْنُ قُشَيْرٍ أَبُو مَهَلٍ الْجُعْفِيُّ حَدَّثَنَا مُعَاوِيَةُ بْنُ قُرَّةَ حَدَّثَنِي أَبِي قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَهْطٍ مِنْ مُزَيْنَةَ فَبَايَعْنَاهُ وَإِنَّ قَمِيصَهُ لَمُطْلَقُ الْأَزْرَارِ قَالَ فَبَايَعْتُهُ ثُمَّ أَدْخَلْتُ يَدَيَّ فِي جَيْبِ قَمِيصِهِ فَمَسِسْتُ الْخَاتَمَقَالَ عُرْوَةُ فَمَا رَأَيْتُ مُعَاوِيَةَ وَلَا ابْنَهُ قَطُّ إِلَّا مُطْلِقَيْ أَزْرَارِهِمَا فِي شِتَاءٍ وَلَا حَرٍّ وَلَا يُزَرِّرَانِ أَزْرَارَهُمَا أَبَدًا","id":"Telah menceritakan kepada kami [An Nufail] dan [Ahmad bin Yunus] keduanya berkata; telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Urwah bin Abdullah]. Ibnu An Nufail bin Qusyair Abu Mahl Al Ju'fi berkata, telah menceritakan kepada kami [Mu'awiyah bin Qurrah] berkata, telah menceritakan kepadaku [Bapakku] ia berkata, \"Aku mendatangi Rasulullah shallallahu 'alaihi wasallam di antara kumpulan orang-orang Muzainah, lalu kami berbaiat kepadanya. Dan baju beliau tidak berkancing. Perawi berkata, \"Aku berbaiat kepada beliau beliau, lalu aku masukkan tanganku ke dalam saku baju beliau hingga aku dapat menyentuh setempel (tanda kenabian).\" Urwah berkata, \"Aku tidak pernah melihat Mu'awiyah dan anaknya kecuali membiarkan kancing bajunya terbuka, mereka tidak pernah menutup kancing bajunya, baik saat musim dingin atau musim panas.\""},"3447":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ قَالَ قَالَ الزُّهْرِيُّ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَابَيْنَا نَحْنُ جُلُوسٌ فِي بَيْتِنَا فِي نَحْرِ الظَّهِيرَةِ قَالَ قَائِلٌ لِأَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُقْبِلًا مُتَقَنِّعًا فِي سَاعَةٍ لَمْ يَكُنْ يَأْتِينَا فِيهَا فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنَ فَأُذِنَ لَهُ فَدَخَلَ","id":"Telah menceritakan kepada kami [Muhammad bin Dawud bin Sufyan] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] ia berkata; [Az Zuhri] berkata; [Urwah] berkata, \" ['Aisyah radliallahu 'anha] berkata, \"Ketika kami sedang duduk di rumah kami di siang hari, seseorang berkata kepada Abu Bakar radliallahu 'anhu, \"Ini adalah Rasulullah shallallahu 'alaihi wasallam, beliau datang dengan menutup kepala dan sebagian wajahnya di waktu yang tidak biasanya beliau datang ke rumah kami. Rasulullah shallallahu 'alaihi wasallam lalu datang seraya meminta izin (kepada Abu Bakar), beliau lalu diizinkan dan masuk.\""},"3448":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ أَبِي غِفَارٍ حَدَّثَنَا أَبُو تَمِيمَةَ الْهُجَيْمِيُّ وَأَبُو تَمِيمَةَ اسْمُهُ طَرِيفُ بْنُ مُجَالِدٍ عَنْ أَبِي جُرَيٍّ جَابِرِ بْنِ سُلَيْمٍ قَالَرَأَيْتُ رَجُلًا يَصْدُرُ النَّاسُ عَنْ رَأْيِهِ لَا يَقُولُ شَيْئًا إِلَّا صَدَرُوا عَنْهُ قُلْتُ مَنْ هَذَا قَالُوا هَذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ عَلَيْكَ السَّلَامُ يَا رَسُولَ اللَّهِ مَرَّتَيْنِ قَالَ لَا تَقُلْ عَلَيْكَ السَّلَامُ فَإِنَّ عَلَيْكَ السَّلَامُ تَحِيَّةُ الْمَيِّتِ قُلْ السَّلَامُ عَلَيْكَ قَالَ قُلْتُ أَنْتَ رَسُولُ اللَّهِ قَالَ أَنَا رَسُولُ اللَّهِ الَّذِي إِذَا أَصَابَكَ ضُرٌّ فَدَعَوْتَهُ كَشَفَهُ عَنْكَ وَإِنْ أَصَابَكَ عَامُ سَنَةٍ فَدَعَوْتَهُ أَنْبَتَهَا لَكَ وَإِذَا كُنْتَ بِأَرْضٍ قَفْرَاءَ أَوْ فَلَاةٍ فَضَلَّتْ رَاحِلَتُكَ فَدَعَوْتَهُ رَدَّهَا عَلَيْكَ قَالَ قُلْتُ اعْهَدْ إِلَيَّ قَالَ لَا تَسُبَّنَّ أَحَدًا قَالَ فَمَا سَبَبْتُ بَعْدَهُ حُرًّا وَلَا عَبْدًا وَلَا بَعِيرًا وَلَا شَاةً قَالَ وَلَا تَحْقِرَنَّ شَيْئًا مِنْ الْمَعْرُوفِ وَأَنْ تُكَلِّمَ أَخَاكَ وَأَنْتَ مُنْبَسِطٌ إِلَيْهِ وَجْهُكَ إِنَّ ذَلِكَ مِنْ الْمَعْرُوفِ وَارْفَعْ إِزَارَكَ إِلَى نِصْفِ السَّاقِ فَإِنْ أَبَيْتَ فَإِلَى الْكَعْبَيْنِ وَإِيَّاكَ وَإِسْبَالَ الْإِزَارِ فَإِنَّهَا مِنْ الْمَخِيلَةِ وَإِنَّ اللَّهَ لَا يُحِبُّ الْمَخِيلَةَ وَإِنْ امْرُؤٌ شَتَمَكَ وَعَيَّرَكَ بِمَا يَعْلَمُ فِيكَ فَلَا تُعَيِّرْهُ بِمَا تَعْلَمُ فِيهِ فَإِنَّمَا وَبَالُ ذَلِكَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Abu Ghifar] berkata, telah menceritakan kepada kami [Abu Tamimah Al Hujaimi] -dan Abu Tamimah namanya adalah Tharif bin Mujalid- dari [Abu Jurai Jabir bin Sulaim] ia berkata, \"Aku melihat seorang laki-laki yang fikirannya dijadikan sandaran oleh orang banyak, dan ia tidak mengatakan sesuatu kecuali orang-orang akan mengikutinya. Aku lalu bertanya, \"Siapakah dia?\" orang-orang menjawab, \"Ini adalah Rasulullah shallallahu 'alaihi wasallam.\" maka aku pun berkata, 'Wahai Rasulullah, 'Alaika As Salam (semoga keselamatan bersamamu) ' wahai Rasulullah, sebanyak dua kali. Beliau bersabda: \"Jangan engkau ucapkan 'Alaika As Salam', karena 'Alaika As Salam adalah penghormatan dan salam untuk mayit. Tetapi ucapkanlah 'As Salamu 'Alaika'.\" Jabir bin Sulaim berkata, \"Aku lalu bertanya, \"Apakah engkau utusan Allah?\" beliau menjawab: \"Ya, aku adalah utusan Allah, Dzat yang jika engkau tertimpa musibah, lalu engkau berdoa kepada-Nya, maka Dia akan menghilangkannya darimu. Jika kamu tertimpa paceklik, lalu engkau berdoa maka Dia akan menumbuhkan (tanaman) bagi kamu. Jika engkau berada di suatu tempat yang luas hingga kendaraanmu hilang, lalu engkau berdoa kepada-Nya, maka Dia akan mengembalikannya kepadamu.\" Jabir bin Sulaim berkata, \"Lalu aku berkata, \"Berilah kami perjanjian.\" Beliau bersabda: \"Jangan sekali-kali engaku cela orang lain.\" Jabir bin Sulaim berkata, \"Setelah itu aku tidak pernah mencela seorang pun; orang merdeka atau budak, unta atau kambing.\" Beliau bersabda lagi: \"Janganlah engkau remehkan perkara ma'ruf, berbicaralah kepada saudaramu dengan wajah yang penuh senyum dan berseri, sebab itu bagian dari perkara yang ma'ruf. Angkatlah sarungmu hingga setengah betis, jika tidak maka hingga kedua mata kaki. Dan janganlah engkau julurkan sarungmu karena itu bagian dari sifat sombong, sesungguhnya Allah tidak menyukai sifat sombong. Jika ada seseorang yang mencela dan memakimu karena cela yang ia ketahui darimu, maka janganlah engkau balas memaki karena cela yang engkau ketahui padanya, karena hal itu akan memberatkannya (pada hari kiamat).\""},"3449":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَرَّ ثَوْبَهُ خُيَلَاءَ لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ فَقَالَ أَبُو بَكْرٍ إِنَّ أَحَدَ جَانِبَيْ إِزَارِي يَسْتَرْخِي إِنِّي لَأَتَعَاهَدُ ذَلِكَ مِنْهُ قَالَ لَسْتَ مِمَّنْ يَفْعَلُهُ خُيَلَاءَ","id":"Telah menceritakan kepada kami [An Nufail] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Musa bin Uqbah] dari [Salim bin Abdullah] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjulurkan kainnya karena sombong, maka Allah tidak akan melihatnya pada hari kiamat.\" Abu Bakar berkata, \"Sesungguhnya salah satu ujung pakaianku ada yang menjulur, padahal aku telah berjanji untuk tidak melakukannya!\" beliau bersabda: \" kamu bukan termasuk orang yang melakukannya karena sombong.\""},"3450":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى عَنْ أَبِي جَعْفَرٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَبَيْنَمَا رَجُلٌ يُصَلِّي مُسْبِلًا إِزَارَهُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَتَوَضَّأْ فَذَهَبَ فَتَوَضَّأَ ثُمَّ جَاءَ فَقَالَ اذْهَبْ فَتَوَضَّأْ فَقَالَ لَهُ رَجُلٌ يَا رَسُولَ اللَّهِ مَا لَكَ أَمَرْتَهُ أَنْ يَتَوَضَّأَ ثُمَّ سَكَتَّ عَنْهُ قَالَ إِنَّهُ كَانَ يُصَلِّي وَهُوَ مُسْبِلٌ إِزَارَهُ وَإِنَّ اللَّهَ لَا يَقْبَلُ صَلَاةَ رَجُلٍ مُسْبِلٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Aban] berkata, telah menceritakan kepada kami [Yahya] dari [Abu Ja'far] dari [Atha bin Yasar] dari [Abu Hurairah] ia berkata, \"Ketika ada seorang laki-laki yang shalat sambil menjulurkan kainnya, Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Pergi dan berwudhulah.\" Laki-laki itu lantas pergi berwudhu kemudian kembali lagi, namun beliau tetap bersabda: \"Pergi dan berwudhulah.\" Lalu ada seorang laki-laki bertanya kepada beliau, \"Wahai Rasulullah, ada apa denganmu, engkau suruh dia berwudhu kemudian engkau diamkan?\" beliau menjawab, \"Laki-laki itu shalat dengan menjulurkan kain sarungnya, padahal Allah tidak menerima shalat seseorang yang menjulurkan kain sarungnya.\""},"3451":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ عَلِيِّ بْنِ مُدْرِكٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ ثَلَاثَةٌ لَا يُكَلِّمُهُمْ اللَّهُ وَلَا يَنْظُرُ إِلَيْهِمْ يَوْمَ الْقِيَامَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ قُلْتُ مَنْ هُمْ يَا رَسُولَ اللَّهِ قَدْ خَابُوا وَخَسِرُوا فَأَعَادَهَا ثَلَاثًا قُلْتُ مَنْ هُمْ يَا رَسُولَ اللَّهِ خَابُوا وَخَسِرُوا فَقَالَ الْمُسْبِلُ وَالْمَنَّانُ وَالْمُنَفِّقُ سِلْعَتَهُ بِالْحَلِفِ الْكَاذِبِ أَوْ الْفَاجِرِحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ سُلَيْمَانَ بْنِ مُسْهِرٍ عَنْ خَرَشَةَ بْنِ الْحُرِّ عَنْ أَبِي ذَرٍّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَالْأَوَّلُ أَتَمُّ قَالَ الْمَنَّانُ الَّذِي لَا يُعْطِي شَيْئًا إِلَّا مَنَّهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Ali bin Mudrik] dari [Abu Zur'ah bin Amru bin Jarir] dari [Kharasyah Ibnul Hur] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ada tiga golongan yang tidak dilihat oleh Allah dan tidak dibersihkan dosanya pada hari kiamat serta bagi mereka siksa yang pedih.\" Aku bertanya, \"Siapa mereka itu ya Rasulullah? Sungguh sia-sia dan meruginya mereka!? Beliau mengulangi perkataan itu hingga tiga kali, aku bertanya lagi, \"Siapa mereka itu ya Rasulullah? Sungguh sia-sia dan meruginya mereka!? beliau menjawab: \"Mereka adalah orang yang menjulurkan kainnya, orang yang mengungkit-ungkit pemberiannya dan orang yang melariskan dagangannya dengan sumpah palsu.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Al A'masy] dari [Sulaiman bin Mushir] dari [Kharasyah Ibnul Hur] dari [Abu Dzar] dari Nabi shallallahu 'alaihi wasallam, sebagaimana dalam hadits ini. Namun riwayat yang pertama lebih sempurna, Abu Dzar berkata, \"Al Mannan adalah orang yang tidak memberikan sesuatu kecuali mengharap pengembalian.\""},"3452":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو عَامِرٍ يَعْنِي عَبْدَ الْمَلِكِ بْنَ عَمْرٍو حَدَّثَنَا هِشَامُ بْنُ سَعْدٍ عَنْ قَيْسِ بْنِ بِشْرٍ التَّغْلِبِيِّ قَالَ أَخْبَرَنِي أَبِي وَكَانَ جَلِيسًا لِأَبِي الدَّرْدَاءِ قَالَكَانَ بِدِمَشْقَ رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَالُ لَهُ ابْنُ الْحَنْظَلِيَّةِ وَكَانَ رَجُلًا مُتَوَحِّدًا قَلَّمَا يُجَالِسُ النَّاسَ إِنَّمَا هُوَ صَلَاةٌ فَإِذَا فَرَغَ فَإِنَّمَا هُوَ تَسْبِيحٌ وَتَكْبِيرٌ حَتَّى يَأْتِيَ أَهْلَهُ فَمَرَّ بِنَا وَنَحْنُ عِنْدَ أَبِي الدَّرْدَاءِ فَقَالَ لَهُ أَبُو الدَّرْدَاءِ كَلِمَةً تَنْفَعُنَا وَلَا تَضُرُّكَ قَالَ بَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً فَقَدِمَتْ فَجَاءَ رَجُلٌ مِنْهُمْ فَجَلَسَ فِي الْمَجْلِسِ الَّذِي يَجْلِسُ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِرَجُلٍ إِلَى جَنْبِهِ لَوْ رَأَيْتَنَا حِينَ الْتَقَيْنَا نَحْنُ وَالْعَدُوُّ فَحَمَلَ فُلَانٌ فَطَعَنَ فَقَالَ خُذْهَا مِنِّي وَأَنَا الْغُلَامُ الْغِفَارِيُّ كَيْفَ تَرَى فِي قَوْلِهِ قَالَ مَا أُرَاهُ إِلَّا قَدْ بَطَلَ أَجْرُهُ فَسَمِعَ بِذَلِكَ آخَرُ فَقَالَ مَا أَرَى بِذَلِكَ بَأْسًا فَتَنَازَعَا حَتَّى سَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سُبْحَانَ اللَّهِ لَا بَأْسَ أَنْ يُؤْجَرَ وَيُحْمَدَ فَرَأَيْتُ أَبَا الدَّرْدَاءِ سُرَّ بِذَلِكَ وَجَعَلَ يَرْفَعُ رَأْسَهُ إِلَيْهِ وَيَقُولُ أَنْتَ سَمِعْتَ ذَلِكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولُ نَعَمْ فَمَا زَالَ يُعِيدُ عَلَيْهِ حَتَّى إِنِّي لَأَقُولُ لَيَبْرُكَنَّ عَلَى رُكْبَتَيْهِ قَالَ فَمَرَّ بِنَا يَوْمًا آخَرَ فَقَالَ لَهُ أَبُو الدَّرْدَاءِ كَلِمَةً تَنْفَعُنَا وَلَا تَضُرُّكَ قَالَ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُنْفِقُ عَلَى الْخَيْلِ كَالْبَاسِطِ يَدَهُ بِالصَّدَقَةِ لَا يَقْبِضُهَا ثُمَّ مَرَّ بِنَا يَوْمًا آخَرَ فَقَالَ لَهُ أَبُو الدَّرْدَاءِ كَلِمَةً تَنْفَعُنَا وَلَا تَضُرُّكَ قَالَ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الرَّجُلُ خُرَيْمٌ الْأَسَدِيُّ لَوْلَا طُولُ جُمَّتِهِ وَإِسْبَالُ إِزَارِهِ فَبَلَغَ ذَلِكَ خُرَيْمًا فَعَجِلَ فَأَخَذَ شَفْرَةً فَقَطَعَ بِهَا جُمَّتَهُ إِلَى أُذُنَيْهِ وَرَفَعَ إِزَارَهُ إِلَى أَنْصَافِ سَاقَيْهِ ثُمَّ مَرَّ بِنَا يَوْمًا آخَرَ فَقَالَ لَهُ أَبُو الدَّرْدَاءِ كَلِمَةً تَنْفَعُنَا وَلَا تَضُرُّكَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّكُمْ قَادِمُونَ عَلَى إِخْوَانِكُمْ فَأَصْلِحُوا رِحَالَكُمْ وَأَصْلِحُوا لِبَاسَكُمْ حَتَّى تَكُونُوا كَأَنَّكُمْ شَامَةٌ فِي النَّاسِ فَإِنَّ اللَّهَ لَا يُحِبُّ الْفُحْشَ وَلَا التَّفَحُّشَقَالَ أَبُو دَاوُد وَكَذَلِكَ قَالَ أَبُو نُعَيْمٍ عَنْ هِشَامٍ قَالَ حَتَّى تَكُونُوا كَالشَّامَةِ فِي النَّاسِ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] berkata, telah menceritakan kepada kami [Abu Amir] -maksudnya Abdul Malik bin Amru- berkata, telah menceritakan kepada kami [Hisyam bin Sa'd] dari [Qais bin Bisyr At Taghlibi] ia berkata; telah mengabarkan kepadaku [Bapakku] -ia adalah teman dekatnya Abu Darda`- ia berkata, \"Di Damasykus ada seorang laki-laki dari sahabat Nabi shallallahu 'alaihi wasallam yang bernama [Ibnu Al Hanzhaliyah]. Ia seorang laki-laki yang suka menyendiri, jarang sekali ia bersama orang-orang, ia selalu sibuk dengan shalat. Jika shalat telah selesai ia sibuk dengan tasbih dan takbir hingga ia kembali ke rumah. Suatu kali ia lewat saat kami sedang berada di sisi Abu Darda, Abu Darda lantas berkata kepadanya dengan suatu ucapan yang bermanfaat bagi kami dan tidak bermadharat bagi kamu. Ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutus ekspedisi, sekembalinya ekspedisi itu, seorang laki-laki dari mereka duduk di tempat duduk yang biasa Rasulullah shallallahu 'alaihi wasallam pakai untuk duduk. Lalu ia berkata kepada laki-laki yang ada di sisinya, \"Sekiranya engkau melihat kami saat berhadapan dengan musuh. lantas ia -maksudnya dirinya- mengambil tombaknya dan menghunjamkannya ke salah seorang musuh dan berujar -dengan maksud mengejek- 'Silahkan kau cabut tombakku, aku anak bani ghifar yang masih belia'. Maka bagaimana komentarmu tentang ucapannya? -Maksudnya; ucapan ejekan 'Silahkan kau cabut tombakku, aku anak bani ghifar yang masih belia! - Kawan yang di sampingnya menjawab, 'Aku tak punya pendapat kecuali bahwa pahalanya telah musnah! '. Komentarnya tadi sempat didengar yang lain sehingga ia mengajukan protes 'Menurutku ucapan seperti itu tidak masalah!. Kedua orang ini larut dalam pertikaian hingga Rasulullah mendengar keributannya. Rasul berujar 'Subhanallah, ucapan seperti itu tidak masalah, dan ia tetap akan mendapat ganjaran dan pujian! '. Lantas kulihat Abu darda' terlihat riang hingga ia mengangkat kepalanya kepada orang itu dan berkomentar, 'Benarkah, kau mendengar hal itu dari Rasulullah! '. Ia menjawab, 'Iya'. Abu Darda berulang-ulang mengajukan pertanyaannya hingga aku berkata dalam hati, andaikan ia lipat kedua lututnya' (maksudnya disudahi). Qais berkata, \"Suatu hari ada seseorang melewati kami, lantas Abu Darda berkata kepadanya dengan suatu ucapan yang bermanfaat bagi kami dan tidak bermadharat bagi kamu. Abu Darda berkata, \"Rasulullah pernah berujar kepada kami: “Orang yang memberi nafkah kepada kuda di jalan Allah seperti seseorang yang membentangkan tangannya untuk sedekah dan tidak pernah menahannya.\" Dihari yang lain, seseorang melewati kami, lantas Abu Darda berkata kepadanya dengan suatu ucapan yang bermanfaat bagi kami dan tidak bermadharat bagi kamu. Abu Darda berkata, Rasulullah Shallallahu 'alaihi wasallam bersabda: 'Sebaik-baik orang adalah Khuraim Al-asadi, sekiranya ia tidak memanjangkan rambutnya sampai bahu dan memanjangkan kain hingga melewati mata kaki'. Ucapan Nabi ini menjadikan Khuraim bergegas mengambil pisau. Ia potong rambutnya hingga sebatas kedua telinganya dan ia naikkan kainnya hingga pertengahan betisnya. Di hari lain ada seorang lewat, lantas Abu darda' berkata kepadanya dengan suatu ucapan yang bermanfaat bagi kami dan tidak bermadharat bagi kamu. Abu Darda berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kalian akan menemui sahabat-sahabat kalian, maka rapikanlah pelana kendaraan kalian, rapikan pakaian kalian, hingga seolah-olah kalian manusia-manusia istimewa di tengah-tengah manusia, sebab Allah tidak suka keburukan dan tindakan-tindakan yang mencerminkan keburukan.” Abu Daud berkata; begitu juga Abu Nuaim berkata dari Hisyam dengan redaksi; 'Hingga kalian seolah-olah sosok-sosok istimewa di tengah-tengah manusia'."},"3453":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَعِيلَ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا هَنَّادٌ يَعْنِي ابْنَ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ الْمَعْنَى عَنْ عَطَاءِ بْنِ السَّائِبِ قَالَ مُوسَى عَنْ سَلْمَانَ الْأَغَرِّ وَقَالَ هَنَّادٌ عَنْ الْأَغَرِّ أَبِي مُسْلِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَ هَنَّادٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ عَزَّ وَجَلَّ الْكِبْرِيَاءُ رِدَائِي وَالْعَظَمَةُ إِزَارِي فَمَنْ نَازَعَنِي وَاحِدًا مِنْهُمَا قَذَفْتُهُ فِي النَّارِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] berkata, telah menceritakan kepada kami [Hammad]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Hannad] -maksudnya Hannad bin As Sari- dari [Abu Al Ahwash] secara makna, dari [Atha bin As Saib] berkata; [Musa] berkata; dari [Salman Al Aghar]. [Hannad] berkata dari [Al Aghar Abu Muslim] dari [Abu Hurairah]. [Hannad] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Azza Wa Jalla berfirman: 'Kesombongan adalah selendang-Ku, kebesaran adalah sarung-Ku, barangsiapa mengambil salah satu dari keduanya dari-Ku, maka ia akan Aku lemparkan ke dalam neraka.\""},"3454":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي ابْنَ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَدْخُلُ الْجَنَّةَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ حَبَّةٍ مِنْ خَرْدَلٍ مِنْ كِبْرٍ وَلَا يَدْخُلُ النَّارَ مَنْ كَانَ فِي قَلْبِهِ مِثْقَالُ خَرْدَلَةٍ مِنْ إِيمَانٍقَالَ أَبُو دَاوُد رَوَاهُ الْقَسْمَلِيُّ عَنْ الْأَعْمَشِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] berkata, telah menceritakan kepada kami [Abu Bakr] -maksudnya Abu Bakr Ibnu Ayyasy- dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk surga orang yang dalam hatinya terdapat kesombongan sebesar biji sawi, dan tidak akan masuk ke dalam neraka orang yang dalam hatinya terdapat keimanan sebesar biji sawi.\" Abu Dawud berkata, \" [Al Qaslami] meriwayatkannya dari [Al A'masy] seperti hadits ini.\""},"3455":{"ar":"حَدَّثَنَا أَبُو مُوسَى مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا هِشَامٌ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رَجُلًا جَمِيلًا فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ حُبِّبَ إِلَيَّ الْجَمَالُ وَأُعْطِيتُ مِنْهُ مَا تَرَى حَتَّى مَا أُحِبُّ أَنْ يَفُوقَنِي أَحَدٌ إِمَّا قَالَ بِشِرَاكِ نَعْلِي وَإِمَّا قَالَ بِشِسْعِ نَعْلِي أَفَمِنْ الْكِبْرِ ذَلِكَ قَالَ لَا وَلَكِنَّ الْكِبْرَ مَنْ بَطِرَ الْحَقَّ وَغَمَطَ النَّاسَ","id":"Telah menceritakan kepada kami [Abu Musa Muhammad Ibnul Mutsanna] berkata, telah menceritakan kepada kami [Abdul Wahhab] berkata, telah menceritakan kepada kami [Hisyam] dari [Muhammad] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam -laki-laki itu seorang yang tampan- dan berkata, \"Wahai Rasulullah, aku menyukai keindahan, dan aku juga diberi keindahan sebagaimana yang engkau lihat, sampai-sampai aku tidak suka jika ada seseorang yang melebihiku -mungkin ia mengatakan, 'meskipun berupa sandal atau tali sandal'-, apakah itu bagian dari rasa sombong?\" Beliau menjawab: \"Tidak. Akan tetapi Sombong adalah menolak kebenaran dan meremehkan orang lain.\""},"3456":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْعَلَاءِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ قَالَسَأَلْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ عَنْ الْإِزَارِ فَقَال عَلَى الْخَبِيرِ سَقَطْتَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِزْرَةُ الْمُسْلِمِ إِلَى نِصْفِ السَّاقِ وَلَا حَرَجَ أَوْ لَا جُنَاحَ فِيمَا بَيْنَهُ وَبَيْنَ الْكَعْبَيْنِ مَا كَانَ أَسْفَلَ مِنْ الْكَعْبَيْنِ فَهُوَ فِي النَّارِ مَنْ جَرَّ إِزَارَهُ بَطَرًا لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al 'Ala bin 'Abdurrahman] dari [Bapaknya] ia berkata, \"Aku bertanya kepada [Abu Sa'id Al Khudri] tentang kain sarung, lalu ia berkata, \"Engkau bertanya kepada orang yang tepat. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kain sarung seorang muslim sebatas setengah betis, dan tidak berdosa antara batas setengah betis hingga dua mata kaki. Adapun apa yang ada di bawah kedua mata kaki adalah di neraka. Dan barangsiapa menjulurkan kain sarungnya karena sombong, maka Allah tidak akan melihatnya pada hari kiamat.\""},"3457":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ حَدَّثَنَا حُسَيْنٌ الْجُعْفِيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي رَوَّادٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْإِسْبَالُ فِي الْإِزَارِ وَالْقَمِيصِ وَالْعِمَامَةِ مَنْ جَرَّ مِنْهَا شَيْئًا خُيَلَاءَ لَمْ يَنْظُرْ اللَّهُ إِلَيْهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] berkata, telah menceritakan kepada kami [Husain Al Ju'fi] dari [Abdul Aziz bin Abu Rawwad] dari [Salim bin Abdullah] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Isbal (menjulurkan kain) itu ada pada sarung, baju dan surban. Siapa yang memanjangkan salah satu darinya karena sombong, maka Allah tidak akan melihatnya kelak pada hari kiamat.\""},"3458":{"ar":"حَدَّثَنَا هَنَّادٌ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ أَبِي الصَّبَّاحِ عَنْ يَزِيدَ بْنِ أَبِي سُمَيَّةَ قَالَ سَمِعْتُ ابْنَ عُمَرَ يَقُولُمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْإِزَارِ فَهُوَ فِي الْقَمِيصِ","id":"Telah menceritakan kepada kami [Hannad] berkata, telah menceritakan kepada kami [Ibnul Mubarak] dari [Abu Ash Shabbah] dari [Yazid bin Abu Sumayyah] ia berkata; Aku mendengar [Ibnu Umar] berkata, \"Apa yang Rasulullah shallallahu 'alaihi wasallam sabdakan dalam (isbalnya) sarung maka juga berlaku pada gamis.\""},"3459":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ مُحَمَّدِ بْنِ أَبِي يَحْيَى قَالَ حَدَّثَنِي عِكْرِمَةُأَنَّهُ رَأَى ابْنَ عَبَّاسٍ يَأْتَزِرُ فَيَضَعُ حَاشِيَةَ إِزَارِهِ مِنْ مُقَدَّمِهِ عَلَى ظَهْرِ قَدَمَيْهِ وَيَرْفَعُ مِنْ مُؤَخَّرِهِ قُلْتُ لِمَ تَأْتَزِرُ هَذِهِ الْإِزْرَةَ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتَزِرُهَا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Muhammad bin Abu Yahya] ia berkata; telah menceritakan kepadaku [Ikrimah] Bahwasanya ia pernah melihat [Ibnu Abbas] mengenakan sarung, ia meletakkan ujung sarungnya mulai dari arah depan hingga ujung telapak kakinya dengan meninggikan bagian belakang. Aku lalu bertanya, \"Kenapa engkau memakai sarung seperti ini?\" ia menjawab, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam memakai sarung seperti ini.\""},"3460":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ لَعَنَ الْمُتَشَبِّهَاتِ مِنْ النِّسَاءِ بِالرِّجَالِ وَالْمُتَشَبِّهِينَ مِنْ الرِّجَالِ بِالنِّسَاءِ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz] berkata, telah menceritakan kepada kami [Bapakku] berkata, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, Bahwasanya beliau melakanat para wanita yang menyurupai laki-laki, dan melaknat laki-laki yang menyerupai wanita.\""},"3461":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا أَبُو عَامِرٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلَ يَلْبَسُ لِبْسَةَ الْمَرْأَةِ وَالْمَرْأَةَ تَلْبَسُ لِبْسَةَ الرَّجُلِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] berkata, telah menceritakan kepada kami [Abu Amir] dari [Sulaiman bin Hilal] dari [Suhail] dari [Bapaknya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat laki-laki yang memakai pakaian wanita dan wanita yang memakai pakaian laki-laki.\""},"3462":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ لُوَيْنٌ وَبَعْضُهُ قِرَاءَةً عَلَيْهِ عَنْ سُفْيَانَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَقِيلَ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا إِنَّ امْرَأَةً تَلْبَسُ النَّعْلَ فَقَالَتْ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلَةَ مِنْ النِّسَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Sulaiman Luwain] -dan sebagiannya dengan cara dibacakan kepadanya- dari [Sufyan] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] ia berkata, \"Dikatakan kepada ['Aisyah radliallahu 'anhu], \"Bagaimana dengan wanita yang memakai sandal?\" ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam melaknat wanita-wanita yang menyerupai laki-laki.\""},"3463":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا ذَكَرَتْ نِسَاءَ الْأَنْصَارِ فَأَثْنَتْ عَلَيْهِنَّ وَقَالَتْ لَهُنَّ مَعْرُوفًا وَقَالَتْ لَمَّا نَزَلَتْ سُورَةُ النُّورِ عَمِدْنَ إِلَى حُجُورٍ أَوْ حُجُوزٍ شَكَّ أَبُو كَامِلٍ فَشَقَقْنَهُنَّ فَاتَّخَذْنَهُ خُمُرًا","id":"Telah menceritakan kepada kami [Abu Kamil] berkata, telah menceritakan kepada kami [Abu Awanah] dari [Ibrahim bin Muhajir] dari [Shafiyah binti Syaibah] dari ['Aisyah radliallahu 'anha] Bahwasanya ia menyebut-nyebut wanita Anshar, ia memuji dan mengatakan kebaikan kepada mereka. 'Aisyah berkata, \"Ketika turun surat An Nuur, mereka masuk ke dalam kamar, atau tempat pakaian -Abu Kamil ragu-, lalu mereka membelah dan menjadikannya sebagai kerudung.\""},"3464":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ ابْنِ خُثَيْمٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْلَمَّا نَزَلَتْ{ يُدْنِينَ عَلَيْهِنَّ مِنْ جَلَابِيبِهِنَّ }خَرَجَ نِسَاءُ الْأَنْصَارِ كَأَنَّ عَلَى رُءُوسِهِنَّ الْغِرْبَانَ مِنْ الْأَكْسِيَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Ibnu Tsaur] dari [Ma'mar] dari [Ibnu Khutsaim] dari [Shafiyah binti Syaibah] dari [Ummu Salamah] ia berkata, \"Ketika turun ayat: '(Hendaklah mereka mengulurkan jilbabnya) ', wanita-wanita Anshar keluar seakan di atas kepala mereka ada burung gagak -karena tertutup kerudung hitam-.\""},"3465":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ ح و حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْمَهْرِيُّ وَابْنُ السَّرْحِ وَأَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ قَالُوا أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي قُرَّةُ بْنُ عَبْدِ الرَّحْمَنِ الْمَعَافِرِيُّ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْيَرْحَمُ اللَّهُ نِسَاءَ الْمُهَاجِرَاتِ الْأُوَلَ لَمَّا أَنْزَلَ اللَّهُ{ وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَى جُيُوبِهِنَّ }شَقَقْنَ أَكْنَفَ قَالَ ابْنُ صَالِحٍ أَكْثَفَ مُرُوطِهِنَّ فَاخْتَمَرْنَ بِهَاحَدَّثَنَا ابْنُ السَّرْحِ قَالَ رَأَيْتُ فِي كِتَابِ خَالِي عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ بِإِسْنَادِهِ وَمَعْنَاهُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Sulaiman bin Dawud Al Mahri] dan [Ibnu As Sarh] dan [Ahmad bin Sa'id Al Hamdani] mereka berkata; telah mengabarkan kepada kami [Ibnu Wahb] berkata; telah mengabarkan kepadaku [Qurrah bin 'Abdurrahman Al Ma'arifi] dari [Ibnu Syihab] dari [Urwah bin Az Zubair] dari ['Aisyah] radliallahu 'anha, Bahwasanya ia pernah berkata, \"Semoga Allah merahmati wanita-wanita muhajirat (wanita-wanita yang berhijrah ke Madinah) yang terdahulu, ketika Allah menurunkan ayat: (Dan hendaklah mereka menutupkan kerudung ke dadanya..), mereka memotong (kain) lengan, [Ibnu Shalih] menyebutkan, \"(mereka memotong) kelebihan kain mereka untuk menutupi wajah mereka.\" Telah menceritakan kepada kami [Ibnu As Sarh] ia berkata, \"Aku melihat dalam buku [pamanku]; dari [Uqail] dari [Ibnu Syihab] dengan sanad dan maknanya.\""},"3466":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ كَعْبٍ الْأَنْطَاكِيُّ وَمُؤَمَّلُ بْنُ الْفَضْلِ الْحَرَّانِيُّ قَالَا حَدَّثَنَا الْوَلِيدُ عَنْ سَعِيدِ بْنِ بَشِيرٍ عَنْ قَتَادَةَ عَنْ خَالِدٍ قَالَ يَعْقُوبُ ابْنُ دُرَيْكٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ أَسْمَاءَ بِنْتَ أَبِي بَكْرٍ دَخَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهَا ثِيَابٌ رِقَاقٌ فَأَعْرَضَ عَنْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ يَا أَسْمَاءُ إِنَّ الْمَرْأَةَ إِذَا بَلَغَتْ الْمَحِيضَ لَمْ تَصْلُحْ أَنْ يُرَى مِنْهَا إِلَّا هَذَا وَهَذَا وَأَشَارَ إِلَى وَجْهِهِ وَكَفَّيْهِقَالَ أَبُو دَاوُد هَذَا مُرْسَلٌ خَالِدُ بْنُ دُرَيْكٍ لَمْ يُدْرِكْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا","id":"Telah menceritakan kepada kami [Ya'qub bin Ka'b Al Anthaki] dan [Muammal Ibnul Fadhl Al Harrani] keduanya berkata; telah menceritakan kepada kami [Al Walid] dari [Sa'id bin Basyir] dari [Qatadah] dari [Khalid] berkata; Ya'qub bin Duraik berkata dari ['Aisyah radliallahu 'anha], bahwa Asma binti Abu Bakr masuk menemui Rasulullah shallallahu 'alaihi wasallam dengan mengenakan kain yang tipis, maka Rasulullah shallallahu 'alaihi wasallam pun berpaling darinya. Beliau bersabda: \"Wahai Asma`, sesungguhnya seorang wanita jika telah baligh tidak boleh terlihat darinya kecuali ini dan ini -beliau menunjuk wajah dan kedua telapak tangannya-.\" Abu Dawud berkata, \"Ini hadits mursal. Khalid bin Duraik belum pernah bertemu dengan 'Aisyah radliallahu 'anha.\""},"3467":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَابْنُ مَوْهَبٍ قَالَا حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ أُمَّ سَلَمَةَ اسْتَأْذَنَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحِجَامَةِ فَأَمَرَ أَبَا طَيْبَةَ أَنْ يَحْجُمَهَاقَالَ حَسِبْتُ أَنَّهُ قَالَ كَانَ أَخَاهَا مِنْ الرَّضَاعَةِ أَوْ غُلَامًا لَمْ يَحْتَلِمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Ibnu Mauhab] keduanya berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] berkata, \"Bahwasanya Ummu Salamah memohon izin kepada Rasulullah shallallahu 'alaihi wasallam untuk berbekam, maka beliau menyuruh Abu Thaibah untuk membekamnya.\" Perawi berkata, \"Aku mengira bahwa Jabir mengatakan, \"Abu Thaibah adalah saudara persusuan Ummu Salamah, atau ia mengatakan, \"anak kecil yang belum mimpi basah (balig).\""},"3468":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو جُمَيْعٍ سَالِمُ بْنُ دِينَارٍ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى فَاطِمَةَ بِعَبْدٍ كَانَ قَدْ وَهَبَهُ لَهَا قَالَ وَعَلَى فَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا ثَوْبٌ إِذَا قَنَّعَتْ بِهِ رَأْسَهَا لَمْ يَبْلُغْ رِجْلَيْهَا وَإِذَا غَطَّتْ بِهِ رِجْلَيْهَا لَمْ يَبْلُغْ رَأْسَهَا فَلَمَّا رَأَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَلْقَى قَالَ إِنَّهُ لَيْسَ عَلَيْكِ بَأْسٌ إِنَّمَا هُوَ أَبُوكِ وَغُلَامُكِ","id":"Telah menceritakan kepada kami [Muhammad bin Isa] berkata, telah menceritakan kepada kami [Abu Jumai' Salim bin Dinar] dari [Tsabit] dari [Anas] berkata, \"Nabi shallallahu 'alaihi wasallam membawa seorang budak untuk Fatimah yang beliau hibahkan kepadanya.\" Anas berkata, \"Fatimah radliallahu 'anha mempunyai kain yang jika ia tutupkan kepala maka kakinya terlihat, dan jika ia tutupkan kaki maka kepalanya terlihat. Ketika Nabi shallallahu 'alaihi wasallam melihat hal itu beliau bersabda: \"Tidak ada masalah bagimu, sebab ini adalah bapak dan budakmu.\""},"3469":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا مُحَمَّدُ بْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ وَهِشَامِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ يَدْخُلُ عَلَى أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُخَنَّثٌ فَكَانُوا يَعُدُّونَهُ مِنْ غَيْرِ أُولِي الْإِرْبَةِ فَدَخَلَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا وَهُوَ عِنْدَ بَعْضِ نِسَائِهِ وَهُوَ يَنْعَتُ امْرَأَةً فَقَالَ إِنَّهَا إِذَا أَقْبَلَتْ أَقْبَلَتْ بِأَرْبَعٍ وَإِذَا أَدْبَرَتْ أَدْبَرَتْ بِثَمَانٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أَرَى هَذَا يَعْلَمُ مَا هَاهُنَا لَا يَدْخُلَنَّ عَلَيْكُنَّ هَذَا فَحَجَبُوهُحَدَّثَنَا مُحَمَّدُ بْنُ دَاوُدَ بْنِ سُفْيَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ بِمَعْنَاهُ حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ بِهَذَا الْحَدِيثِ زَادَ وَأَخْرَجَهُ فَكَانَ بِ��لْبَيْدَاءِ يَدْخُلُ كُلَّ جُمْعَةٍ يَسْتَطْعِمُ حَدَّثَنَا مَحْمُودُ بْنُ خَالِدٍ حَدَّثَنَا عُمَرُ عَنْ الْأَوْزَاعِيِّ فِي هَذِهِ الْقِصَّةِ فَقِيلَ يَا رَسُولَ اللَّهِ إِنَّهُ إِذَنْ يَمُوتُ مِنْ الْجُوعِ فَأَذِنَ لَهُ أَنْ يَدْخُلَ فِي كُلِّ جُمْعَةٍ مَرَّتَيْنِ فَيَسْأَلُ ثُمَّ يَرْجِعُ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] berkata, telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] dari [Az Zuhri] dan [Hisyam bin Urwah] dari [Urwah] dari ['Aisyah] radliallahu 'anha, ia berkata, \"Seorang laki-laki (banci) masuk menemui isteri-isteri Nabi shallallahu 'alaihi wasallam, dan para sahabat menganggapnya sebagai Ghairu Ulil Irbah (orang-orang yang tidak punya nafsu kepada wanita). Suatu ketika Nabi shallallahu 'alaihi wasallam masuk menemui kami sementara laki-laki banci itu bersama isteri-isteri beliau seraya mensifati wanita dengan berkata; 'Wanita itu jika menghadap ke depan maka ia menghadap dengan empat (lipatan), dan jika menghadap ke belakang maka ia menghadap dengan delapan (lipatan) '. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, aku melihat orang ini (banci) mengetahui apa yang ada pada wanita, maka jangan sekali-kali ia masuk menemui kalian.\" Mereka pun akhirnya memakai hijab.\" Telah menceritakan kepada kami [Muhammad bin Dawud bin Sufyan] berkata, telah menceritakan kepada kami [Abdurrazaq] berkata, telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Urwah] dari ['Aisyah] secara makna. Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Urwah] dari ['Aisyah] dengan hadits ini.. dengan tambahan, \"Nabi shallallahu 'alaihi wasallam mengeluarkan laki-laki (banci) itu ke padang pasir, dan datang setiap hari jum'at untuk mencari makan.\" Telah menceritakan kepada kami [Mahmud bin Khalid] berkata, telah menceritakan kepada kami [Umar] dari [Al Auza'i] -dalam kisah ini-, dikatakan, \"Wahai Rasulullah, bagaimana jika laki-laki (banci itu) mati kelaparan?\" beliau lalu memberinya izin untuk masuk dua kali setiap hari jum'at untuk minta makan, kemudian kembali lagi.\"Ket; lipatan maksudnya, wanita yang gemuk jika dilihat dari arah perut maka akan terlihat dua lipatan -setiap lipatan ada dua sisi- yang ada diperutnya, sementara jika dilihat dari arah punggung maka akan terlihat empat lipatan yang memiliki delapan sisi. Dan ini hanya terjadi pada wanita yang gemuk. "},"3470":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ الْمَرْوَزِيُّ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ أَبِيهِ عَنْ يَزِيدَ النَّحْوِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ{ وَقُلْ لِلْمُؤْمِنَاتِ يَغْضُضْنَ مِنْ أَبْصَارِهِنَّ }الْآيَةَ فَنُسِخَ وَاسْتَثْنَى مِنْ ذَلِكَ{ وَالْقَوَاعِدُ مِنْ النِّسَاءِ اللَّاتِي لَا يَرْجُونَ نِكَاحًا }الْآيَةَ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad Al Marwazi] berkata, telah menceritakan kepada kami [Ali Ibnul Husain bin Waqid] dari [Bapaknya] dari [Yazid An Nahwi] dari [Ikrimah] dari [Ibnu Abbas] berkata, \"Tentang ayat: (Katakanlah kepada wanita yang beriman, 'Hendaklah mereka menahan pandangannya..) ' telah dihapus, namun ada yang dikecualikan: '(dan wanita-wanita tua yang telah terhenti (dari haid dan mengandung), yang tidak ingin kawin (lagi)..) '.\""},"3471":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي نَبْهَانُ مَوْلَى أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ قَالَتْكُنْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ مَيْمُونَةُ فَأَقْبَلَ ابْنُ أُمِّ مَكْتُومٍ وَذَلِكَ بَعْدَ أَنْ أُمِرْنَا بِالْحِجَابِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجِبَا مِنْهُ فَقُلْنَا يَا رَسُولَ اللَّهِ أَلَيْسَ أَعْمَى لَا يُبْصِرُنَا وَلَا يَعْرِفُنَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَعَمْيَاوَانِ أَنْتُمَا أَلَسْتُمَا تُبْصِرَانِهِقَالَ أَبُو دَاوُد هَذَا لِأَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاصَّةً أَلَا تَرَى إِلَى اعْتِدَادِ فَاطِمَةَ بِنْتِ قَيْسٍ عِنْدَ ابْنِ أُمِّ مَكْتُومٍ قَدْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِفَاطِمَةَ بِنْتِ قَيْسٍ اعْتَدِّي عِنْدَ ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ رَجُلٌ أَعْمَى تَضَعِينَ ثِيَابَكِ عِنْدَهُ","id":"Telah menceritakan kepada kami [Muhammad Ibnul 'Ala`] berkata, telah menceritakan kepada kami [Ibnul Mubarak] dari [Yunus] dari [Az Zuhri] ia berkata; telah menceritakan kepadaku [Nabhan] -mantan budak (yang telah dimerdekakan oleh) Ummu Salamah- dari [Ummu Salamah] ia berkata, \"Aku berada di sisi Rasulullah shallallahu 'alaihi wasallam ketika Maimunah sedang bersamanya. Lalu masuklah Ibnu Ummi Maktum -yaitu ketika perintah hijab telah turun-. Maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Berhijablah kalian berdua darinya.\" Kami bertanya, \"Wahai Rasulullah, bukankah ia buta sehingga tidak bisa melihat dan mengetahui kami?\" Nabi shallallahu 'alaihi wasallam balik bertanya: \"Apakah kalian berdua buta? Bukankah kalian berdua dapat melihat dia?\" Abu Dawud berkata, \"Ini hanya khusus untuk isteri-isteri Nabi shallallahu 'alaihi wasallam, tidakkah engkau lihat bagaimana Fatimah binti Qais di sisi Ibnu Ummi Maktum! Nabi shallallahu 'alaihi wasallam pernah berkata kepada Fatimah binti Qais, 'Bukalah hijabmu di sisi Ibnu Ummi Maktum, sebab ia adalah seorang laki-laki buta, maka tidak mengapa engkau letakkan pakaianmu di sisinya.\""},"3472":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمَيْمُونِ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا زَوَّجَ أَحَدُكُمْ عَبْدَهُ أَمَتَهُ فَلَا يَنْظُرْ إِلَى عَوْرَتِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Ibnul Maimun] berkata, telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian menikahkan budak lelakinya dengan budak wanitanya, maka janganlah ia melihat aurat budak wanita tersebut.\""},"3473":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنِي دَاوُدُ بْنُ سَوَّارٍ الْمُزَنِيُّ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا زَوَّجَ أَحَدُكُمْ خَادِمَهُ عَبْدَهُ أَوْ أَجِيرَهُ فَلَا يَنْظُرْ إِلَى مَا دُونَ السُّرَّةِ وَفَوْقَ الرُّكْبَةِقَالَ أَبُو دَاوُد وَصَوَابُهُ سَوَّارُ بْنُ دَاوُدَ الْمُزَنِيُّ الصَّيْرَفِيُّ وَهِمَ فِيهِ وَكِيعٌ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] berkata, telah menceritakan kepada kami [Waki'] berkata, telah menceritakan kepadaku [Dawud bin Sawwar Al Muzani] dari [Amru bin Syu'aib] dari [Bapaknya] dari [Kakeknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian menikahkan pembantunya (budak wanita) dengan budak laki-lakinya atau pekerjanya, maka janganlah ia melihat apa yang ada di bawah pusar dan di atas lutut.\" Abu Dawud berkata, \"Yang benar adalah Sawwar bin Dawud Al Muzani Ash Shairafi, namun Waki' masih merasa ragu.\""},"3474":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ وَهْبٍ مَوْلَى أَبِي أَحْمَدَ عَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَهِيَ تَخْتَمِرُ فَقَالَ لَيَّةً لَا لَيَّتَيْنِقَالَ أَبُو دَاوُد مَعْنَى قَوْلِهِ لَيَّةً لَا لَيَّتَيْنِ يَقُولُ لَا تَعْتَمُّ مِثْلَ الرَّجُلِ لَا تُكَرِّرُهُ طَاقًا أَوْ طَاقَيْنِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] berkata, telah menceritakan kepada kami ['Abdurrahman]. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Habib bin Abu Tsabit] dari [Wahb] -mantan budak (yang telah dimerdekakan oleh) Abu Ahmad- dari [Ummu Salamah] Bahwasanya Nabi shallallahu 'alaihi wasallam pernah masuk menemuinya, sementara ia sedang mengenakan kerudung. Maka beliau bersabda: \"Lilitkanlah sekali saja, jangan dua kali lilitan.\" Abu Dawud berkata; \"Makna sabda Nabi, 'Lilitkanlah sekali saja, jangan dua kali lilitan' adalah janganlah engkau seperti lelaki memakai imamah (surban yang dililitkan pada kepala), jangan engkau ulangi berkali-kali.\""},"3475":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَأَحْمَدُ بْنُ سَعِيدٍ الْهَمْدَانِيُّ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنَا ابْنُ لَهِيعَةَ عَنْ مُوسَى بْنِ جُبَيْرٍ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبَّاسٍ حَدَّثَهُ عَنْ خَالِدِ بْنِ يَزِيدَ بْنِ مُعَاوِيَةَ عَنْ دِحْيَةَ بْنِ خَلِيفَةَ الْكَلْبِيِّ أَنَّهُ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَبَاطِيَّ فَأَعْطَانِي مِنْهَا قُبْطِيَّةً فَقَالَ اصْدَعْهَا صَدْعَيْنِ فَاقْطَعْ أَحَدَهُمَا قَمِيصًا وَأَعْطِ الْآخَرَ امْرَأَتَكَ تَخْتَمِرُ بِهِ فَلَمَّا أَدْبَرَ قَالَ وَأْمُرْ امْرَأَتَكَ أَنْ تَجْعَلَ تَحْتَهُ ثَوْبًا لَا يَصِفُهَاقَالَ أَبُو دَاوُد رَوَاهُ يَحْيَى بْنُ أَيُّوبَ فَقَالَ عَبَّاسُ بْنُ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Ahmad bin Amru bin As Sarh] dan [Ahmad bin Sa'id Al Hamdani] keduanya berkata; telah mengabarkan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepada kami [Ibnu Lahi'ah] dari [Musa bin Jubair] bahwa [Ubaidullah bin Abbas] menceritakan kepadanya dari [Khalid bin Yazid bin Mu'awiyah] dari [Dihyah bin Khalifah Al Kalbi] Bahwasanya ia berkata, \"Rasulullah shallallahu 'alaihi wasallam diberi beberapa potong kain Qubthiyah (kain mesir yang tipis dan berwarna putih), lalu memberikan satu potong kepadaku. Beliau bersabda: \"Bagilah menjadi dua bagian. Sebagian buatlah baju dan sebagian yang lain berikanlah kepada isterimu untuk dijadikan kerudung.\" Ketika telah berlalu, beliau berbalik dan bersabda: \"Perintahkanlah isterimu agar ia melapisi pada bagian bawahnya agar tidak membentuk tubuhnya.\" Abu Dawud berkata, \"Hadits ini diriwayatkan oleh [Yahya bin Ayyub], dan ia berkata; [Abbas bin Ubaidullah bin Abbas].\""},"3476":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي بَكْرِ بْنِ نَافِعٍ عَنْ أَبِيهِ عَنْ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ أَنَّهَا أَخْبَرَتْهُأَنَّ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ ذَكَرَ الْإِزَارَ فَالْمَرْأَةُ يَا رَسُولَ اللَّهِ قَالَ تُرْخِي شِبْرًا قَالَتْ أُمُّ سَلَمَةَ إِذًا يَنْكَشِفُ عَنْهَا قَالَ فَذِرَاعًا لَا تَزِيدُ عَلَيْهِحَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عِيسَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أُمِّ سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ قَالَ أَبُو دَاوُد رَوَاهُ ابْنُ إِسْحَقَ وَأَيُّوبُ بْنُ مُوسَى عَنْ نَافِعٍ عَنْ صَفِيَّةَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu Bakr bin Nafi'] dari [bapaknya] bahwasanya [Shafiyah binti Abu Ubaid] mengabarkan kepadanya, bahwa [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam berkata kepada Rasulullah shallallahu 'alaihi wasallam ketika beliau menyebutkan tentang kain sarung, \"Wahai Rasulullah, bagaimana dengan wanita?\" beliau menjawab: \"Lebihkanlah satu jengkal.\" Ummu Salamah berkata lagi, \"Bagaimana jika masih terlihat?\" beliau menjawab: \"Lebihkanlah satu hasta dan jangan lebih.\" Telah menceritakan kepada kami [Ibrahim bin Musa] berkata, telah mengabarkan kepada kami [Isa] dari [Ubaidullah] dari [Nafi'] dari [Sulaiman bin Yasar] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini.\" Abu Dawud berkata, \" [Ibnu Ishaq] dan [Ayyub bin Musa] juga menceritakan dari [Nafi'] dari [Shafiyah].\""},"3477":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ أَخْبَرَنِي زَيْدٌ الْعَمِّيُّ عَنْ أَبِي الصِّدِّيقِ النَّاجِيِّ عَنْ ابْنِ عُمَرَ قَالَرَخَّصَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُمَّهَاتِ الْمُؤْمِنِينَ فِي الذَّيْلِ شِبْرًا ثُمَّ اسْتَزَدْنَهُ فَزَادَهُنَّ شِبْرًا فَكُنَّ يُرْسِلْنَ إِلَيْنَا فَنَذْرَعُ لَهُنَّ ذِرَاعًا","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] berkata, telah mengabarkan kepadaku [Zaid Al 'Ammi] dari [Abu Ash Shiddiq An Naji] dari [Ibnu Umar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberi keringanan para Ummahatul Mukminin (isteri-isteri Nabi) untuk memanjangkan kain mereka satu jengkal, lalu mereka minta untuk ditambah dan beliau menambahkan satu jengkal lagi. Maka, mereka kemudian memanjangkan kainnya hingga satu hasta.\""},"3478":{"ar":"حَدَّثَنَا مُسَدَّدٌ وَوَهْبُ بْنُ بَيَانٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ وَابْنُ أَبِي خَلَفٍ قَالُوا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ مُسَدَّدٌ وَوَهْبٌ عَنْ مَيْمُونَةَ قَالَتْأُهْدِيَ لِمَوْلَاةٍ لَنَا شَاةٌ مِنْ الصَّدَقَةِ فَمَاتَتْ فَمَرَّ بِهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا دَبَغْتُمْ إِهَابَهَا وَاسْتَنْفَعْتُمْ بِهِ قَالُوا يَا رَسُولَ اللَّهِ إِنَّهَا مَيْتَةٌ قَالَ إِنَّمَا حُرِّمَ أَكْلُهَاحَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ بِهَذَا الْحَدِيثِ لَمْ يَذْكُرْ مَيْمُونَةَ قَالَ فَقَالَ أَلَا انْتَفَعْتُمْ بِإِهَابِهَا ثُمَّ ذَكَرَ مَعْنَاهُ لَمْ يَذْكُرْ الدِّبَاغَ","id":"Telah menceritakan kepada kami [Musaddad] dan [Wahb bin Bayan] dan [Utsman bin Abu Syaibah] dan [Ibnu Abu Khalaf] mereka berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] dari [Ibnu Abbas]. [Musaddad] dan [Wahb] berkata; dari [Maimunah] ia berkata, \"Pelayan kami mendapat hadiah seekor kambing, kemudian kambing itu mati. Ketika Nabi shallallahu 'alaihi wasallam melewatinya, beliau bersabda: \"Kenapa kalian tidak menyamak kulitnya hingga kalian dapat memanfaatkannya?\" orang-orang menjawab, \"Kambing itu telah mati.\" Beliau bersabda: \"Yang diharamkan itu memakannya.\" Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada kami [Yazid] berkata, telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] seperti hadits ini, namun ia tidak menyebut nama Maimunah. Ia berkata, \"Rasulullah bersabda: \"Kenapa kalian tidak memanfaatkan kulitnya?\" Ia lalu menyebutkan makna hadits tersebut, namun tidak menyebutkan kata 'menyamak'.\""},"3479":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ قَالَ مَعْمَرٌ وَكَانَ الزُّهْرِيُّيُنْكِرُ الدِّبَاغَ وَيَقُولُ يُسْتَمْتَعُ بِهِ عَلَى كُلِّ حَالٍقَالَ أَبُو دَاوُد لَمْ يَذْكُرْ الْأَوْزَاعِيُّ وَيُونُسُ وَعُقَيْلٌ فِي حَدِيثِ الزُّهْرِيِّ الدِّبَاغَ وَذَكَرَهُ الزُّبَيْدِيُّ وَسَعِيدُ بْنُ عَبْدِ الْعَزِيزِ وَحَفْصُ بْنُ الْوَلِيدِ ذَكَرُوا الدِّبَاغَ","id":"Telah menceritakan kepada kami [Muhammad bin Yahya bin Faris] berkata, telah menceritakan kepada kami [Abdurrazaq] ia berkata; [Ma'mar] berkata; [Az Zuhri] mengingkari bolehnya kulit yang disamak, ia mengatakan, \"Ia bisa dimanfaatkan dalam setiap keadaan.\" Abu Dawud berkata, \"Al Auza'I, Yunus dan Uqail dalam hadits Az Zuhri tidak menyebutkan kata 'samak'. Sedangkan Az Zubaidi, Sa'id bin Abdul Aziz dan Hafsh Ibnul Walid, mereka menyebutkan kata 'samak'.\""},"3480":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ وَعْلَةَ عَنْ ابْنِ عَبَّاسٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا دُبِغَ الْإِهَابُ فَقَدْ طَهُرَ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] berkata, telah mengabarkan kepada kami [Sufyan] dari [Zaid bin Aslam] dari ['Abdurrahman bin Wa'lah] dari [Ibnu Abbas] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kulit disamak, maka ia telah suci.\""},"3481":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ أُمِّهِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أَنْ يُسْتَمْتَعَ بِجُلُودِ الْمَيْتَةِ إِذَا دُبِغَتْ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Yazid bin Abdullah bin Qusaith] dari [Muhammad bin 'Abdurrahman bin Tsauban] dari [Ibunya] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk memanfaatkan kulit jika telah disamak.\""},"3482":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُوسَى بْنُ إِسْمَعِيلَ قَالَا حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ جَوْنِ بْنِ قَتَادَةَ عَنْ سَلَمَةَ بْنِ الْمُحَبَّقِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ أَتَى عَلَى بَيْتٍ فَإِذَا قِرْبَةٌ مُعَلَّقَةٌ فَسَأَلَ الْمَاءَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّهَا مَيْتَةٌ فَقَالَ دِبَاغُهَا طُهُورُهَا","id":"Telah menceritakan kepada kami [Hafsh bin Umar] dan [Musa bin Isma'il] keduanya berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Jaun bin Qatadah] dari [Salamah Ibnul Muhabbaq] berkata, \"Ketika perang Tabuk, Rasulullah shallallahu 'alaihi wasallam mendatangi sebuah rumah, lalu beliau menemukan sebuah wadah dari kulit yang digantung. Beliau kemudian minta diambilkan air dengan wadah tersebut, maka para sahabat pun berkata, \"Wahai Rasulullah, sesungguhnya wadah itu dari kulit bangkai!\" beliau bersabda: \"Penyamakannya telah menjadikan ia suci.\""},"3483":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو يَعْنِي ابْنَ الْحَارِثِ عَنْ كَثِيرِ بْنِ فَرْقَدٍ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكِ بْنِ حُذَافَةَ حَدَّثَهُ عَنْ أُمِّهِ الْعَالِيَةِ بِنْتِ سُبَيْعٍ أَنَّهَا قَالَتْكَانَ لِي غَنَمٌ بِأُحُدٍ فَوَقَعَ فِيهَا الْمَوْتُ فَدَخَلْتُ عَلَى مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهَا فَقَالَتْ لِي مَيْمُونَةُ لَوَ أَخَذْتِ جُلُودَهَا فَانْتَفَعْتِ بِهَا فَقَالَتْ أَوَ يَحِلُّ ذَلِكَ قَالَتْ نَعَمْ مَرَّ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رِجَالٌ مِنْ قُرَيْشٍ يَجُرُّونَ شَاةً لَهُمْ مِثْلَ الْحِمَارِ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَخَذْتُمْ إِهَابَهَا قَالُوا إِنَّهَا مَيْتَةٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُطَهِّرُهَا الْمَاءُ وَالْقَرَظُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepadaku [Amru] -yaitu Ibnul Harits- dari [Katsir bin Farqad] dari [Abdullah bin Malik bin Hudzafah] ia menceritakan kepadanya dari [ibunya yaitu Al 'Aliyah binti Subai'] Bahwasanya ia berkata, \"Aku mempunyai seekor kambing di gunung uhud, namun tiba-tiba ia mati. Lalu aku menemui [Maimunah] isteri Nabi shallallahu 'alaihi wasallam dan menceritakan hal itu kepadanya. Maimunah lantas berkata kepadaku, \"Kenapa tidak engkau ambil kulitnya hingga engkau bisa memanfaatkannya?\" Ia bertanya, \"Apakah itu boleh?\" Maimunah menjawab, \"Boleh. Suatu ketika beberapa laki-laki Quraisy melewati Rasulullah shallallahu 'alaihi wasallam dengan menyeret kambing mereka seperti keledai. Rasulullah shallallahu 'alaihi wasallam lalu berkata kepada mereka: \"Sekiranya kalian ambil kulitnya.\" Mereka berkata, \"Kambing itu telah mati.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Air dan Al Qarazh (daun dari jenis pohon yang biasa digunakan untuk menyamak) akan mensucikannya.\""},"3484":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ قَالَقُرِئَ عَلَيْنَا كِتَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَرْضِ جُهَيْنَةَ وَأَنَا غُلَامٌ شَابٌّ أَنْ لَا تَسْتَمْتِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] berkata, telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari ['Abdurrahman bin Abu Laila] dari [Abdullah bin Ukaim] ia berkata, \"Ketika kami sedang berada di Juhainah, buku Rasulullah shallallahu 'alaihi wasallam dibacakan kepada kami, dan waktu itu aku masih seorang bocah, yaitu: “Tidakkah kalian memanfaatkannya dengan menyamak kulitnya.”"},"3485":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا الثَّقَفِيُّ عَنْ خَالِدٍ عَنْ الْحَكَمِ بْنِ عُتَيْبَةَأَنَّهُ انْطَلَقَ هُوَ وَنَاسٌ مَعَهُ إِلَى عَبْدِ اللَّهِ بْنِ عُكَيْمٍ رَجُلٌ مِنْ جُهَيْنَةَ قَالَ الْحَكَمُ فَدَخَلُوا وَقَعَدْتُ عَلَى الْبَابِ فَخَرَجُوا إِلَيَّ فَأَخْبَرُونِي أَنَّ عَبْدَ اللَّهِ بْنَ عُكَيْمٍ أَخْبَرَهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى جُهَيْنَةَ قَبْلَ مَوْتِهِ بِشَهْرٍ أَنْ لَا تَنْتَفِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍقَالَ أَبُو دَاوُد قَالَ النَّضْرُ بْنُ شُمَيْلٍ يُسَمَّى إِهَابًا مَا لَمْ يُدْبَغْ فَإِذَا دُبِغَ لَا يُقَالُ لَه إِهَابٌ إِنَّمَا يُسَمَّى شَنًّا وَقِرْبَةً","id":"Telah menceritakan kepada kami [Muhammad bin Isma'il] -mantan budak bani Hasyim- berkata, telah menceritakan kepada kami [At Tsaqafi] dari [Khalid] dari [Al Hakam bin Utaibah] Bahwasanya ia dan beberapa orang menemui [Abdullah bin Ukaim] -seorang laki-laki dari Juhainah-. Al Hakam berkata, \"Mereka lalu masuk sementara aku duduk di depan pintu, kemudian mereka keluar menemuiku mengabarkan kepadaku bahwa Abdullah bin Ukaim telah mengabarkan kepada mereka, bahwa Rasulullah shallallahu 'alaihi wasallam telah menulis surat kepada orang-orang Juhainah sebulan sebelum beliau wafat, yaitu: \"Janganlah kalian memanfaatkan kulit atau tanduk bangkai.” Abu Daud berkata; An Nadhar bin Syumail mengatakan; \"dinamakan ihab (kulit bangkai) jika belum disamak, namun jika telah disamak maka tidak dinamakan lagi ihab (kulit bangkai), akan tetapi dinamakan griba (wadah dari kulit).”"},"3486":{"ar":"حَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ أَبِي الْمُعْتَمِرِ عَنْ ابْنِ سِيرِينَ عَنْ مُعَاوِيَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَرْكَبُوا الْخَزَّ وَلَا النِّمَارَقَالَ وَكَانَ مُعَاوِيَةُ لَا يُتَّهَمُ فِي الْحَدِيثِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَنَا أَبُو سَعِيدٍ قَالَ لَنَا أَبُو دَاوُدَ أَبُو الْمُعْتَمِرِ اسْمُهُ يَزِيدُ بْنُ طَهْمَانَ كَانَ يَنْزِلُ الْحِيَرَةَ","id":"Telah menceritakan kepada kami [Hannad bin As Sari] dari [Waki'] dari [Abu Al Mu'tamir] dari [Ibnu Sirin] dari [Mu'awiyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mengendarai dengan pelana dari sutera dan kulit harimau.\" Ia berkata, \"Mu'awiyah bukan termasuk orang-orang yang dituduh sebagai orang yang membuat-buat hadits dari Rasulullah shallallahu 'alaihi wasallam.\" Abu Sa'id berkata kepada kami, \"Abu Dawud berkata kepada kami, \"Abu Al Mu'tamir nama aslinya adalah Yazid bin Thahman, ia pernah singgah di daerah Al Hiyarah.\""},"3487":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا عِمْرَانُ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَصْحَبُ الْمَلَائِكَةُ رُفْقَةً فِيهَا جِلْدُ نَمِرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] berkata, telah menceritakan kepada kami [Abu Dawud] berkata, telah menceritakan kepada kami [Imran] dari [Qatadah] dari [Zurarah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Malaikat tidak akan menyertai rombongan yang di dalamnya terdapat kulit harimau.\""},"3488":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ الْحِمْصِيُّ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدٍ قَالَوَفَدَ الْمِقْدَامُ بْنُ مَعْدِي كَرِبَ وَعَمْرُو بْنُ الْأَسْوَدِ وَرَجُلٌ مِنْ بَنِي أَسَدٍ مِنْ أَهْلِ قِنَّسْرِينَ إِلَى مُعَاوِيَةَ بْنِ أَبِي سُفْيَانَ فَقَالَ مُعَاوِيَةُ لِلْمِقْدَامِ أَعَلِمْتَ أَنَّ الْحَسَنَ بْنَ عَلِيٍّ تُوُفِّيَ فَرَجَّعَ الْمِقْدَامُ فَقَالَ لَهُ رَجُلٌ أَتَرَاهَا مُصِيبَةً قَالَ ��َهُ وَلِمَ لَا أَرَاهَا مُصِيبَةً وَقَدْ وَضَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حِجْرِهِ فَقَالَ هَذَا مِنِّي وَحُسَيْنٌ مِنْ عَلِيٍّ فَقَالَ الْأَسَدِيُّ جَمْرَةٌ أَطْفَأَهَا اللَّهُ عَزَّ وَجَلَّ قَالَ فَقَالَ الْمِقْدَامُ أَمَّا أَنَا فَلَا أَبْرَحُ الْيَوْمَ حَتَّى أُغَيِّظَكَ وَأُسْمِعَكَ مَا تَكْرَهُ ثُمَّ قَالَ يَا مُعَاوِيَةُ إِنَّ أَنَا صَدَقْتُ فَصَدِّقْنِي وَإِنْ أَنَا كَذَبْتُ فَكَذِّبْنِي قَالَ أَفْعَلُ قَالَ فَأَنْشُدُكَ بِاللَّهِ هَلْ تَعْلَمُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبْسِ الذَّهَبِ قَالَ نَعَمْ قَالَ فَأَنْشُدُكَ بِاللَّهِ هَلْ تَعْلَمُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبْسِ الْحَرِيرِ قَالَ نَعَمْ قَالَ فَأَنْشُدُكَ بِاللَّهِ هَلْ تَعْلَمُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُبْسِ جُلُودِ السِّبَاعِ وَالرُّكُوبِ عَلَيْهَا قَالَ نَعَمْ قَالَ فَوَاللَّهِ لَقَدْ رَأَيْتُ هَذَا كُلَّهُ فِي بَيْتِكَ يَا مُعَاوِيَةُ فَقَالَ مُعَاوِيَةُ قَدْ عَلِمْتُ أَنِّي لَنْ أَنْجُوَ مِنْكَ يَا مِقْدَامُ قَالَ خَالِدٌ فَأَمَرَ لَهُ مُعَاوِيَةُ بِمَا لَمْ يَأْمُرْ لِصَاحِبَيْهِ وَفَرَضَ لِابْنِهِ فِي الْمِائَتَيْنِ فَفَرَّقَهَا الْمِقْدَامُ فِي أَصْحَابِهِ قَالَ وَلَمْ يُعْطِ الْأَسَدِيُّ أَحَدًا شَيْئًا مِمَّا أَخَذَ فَبَلَغَ ذَلِكَ مُعَاوِيَةُ فَقَالَ أَمَّا الْمِقْدَامُ فَرَجُلٌ كَرِيمٌ بَسَطَ يَدَهُ وَأَمَّا الْأَسَدِيُّ فَرَجُلٌ حَسَنُ الْإِمْسَاكِ لِشَيْئِهِ","id":"Telah menceritakan kepada kami [Amru bin Utsman bin Sa'id Al Himshi] berkata, telah menceritakan kepada kami [Baqiyyah] dari [Bahira] dari [Khalid] ia berkata, \" [Al Miqdam bin Ma'di Karib], Amru bin Al Aswad dan seorang laki-laki dari bani Asad, dari penduduk Qinnasrin datang kepada [Mu'awiyah bin Abu Sufyan]. Mu'awiyah lalu berkata kepada Al Miqdam, \"Tidakkah kamu tahu bahwa Al Hasan bin Ali telah wafat?\" Al Miqdam pun mengucapkan istirja' (ucapan inna lillahi wa inna ilaihi raaji'uun). Lalu ada seorang laki-laki berkata kepadanya, \"Apakah kamu menganggapnya sebagai musibah?\" Al Miqdam balik berkata, \"Kenapa aku tidak menganggapnya sebagai musibah, padahal ia adalah orang yang pernah berada dalam pangkuan Rasulullah shallallahu 'alaihi wasallam? beliau juga telah bersabda: \"Ini (Hasan) dariku, dan Husain dari Ali.\" Al Asadi lantas berkata, \"Bara api ini (Hasan) telah Allah matikan (kalimat untuk membuat Mu'awiyah senang).\" Maka Al Miqdam pun berkata, \"Pada hari ini aku tidak akan bisa gembira sehingga aku dapat membuatmu marah, dan akan aku perdengarkan kepadamu sesuatu yang membuatmu benci.\" Kemudian ia berkata, \"Wahai Mu'awiyah! Jika aku benar maka benarkanlah, dan jika aku dusta maka dustakanlah aku.\" Mu'awiyah berkata, \"Akan aku lakukan.\" Al Miqdam lalu berkata, \"Aku bersumpah kepada Allah atas kamu, tidakkah kamu tahu bahwa Rasulullah shallallahu 'alaihi wasallam melarang untuk mengenakan emas?\" Mu'awiyah menjawab, \"Benar.\" Al Miqdam berkata, \"Aku bersumpah kepada Allah atas kamu, tidakkah kamu tahu bahwa Rasulullah shallallahu 'alaihi wasallam melarang mengenakan sutera?\" Mu'awiyah menjawab, \"Benar.\" Al Miqdam berkata, \"Aku bersumpah kepada Allah atas kamu, tidakkah kamu tahu bahwa Rasulullah shallallahu 'alaihi wasallam melarang mengenakan kulit binatang buas dan mengendarainya?\" Mu'awiyah menjawab, \"Benar.\" Al Miqdam berkata, \"Wahai Mu'awiyah, demi Allah semua ini telah aku lihat di rumahmu!\" Al Miqdam berkata, \"Wahai Al Miqdam, aku tahu bahwa aku tidak akan selamat dari kamu.\" Khalid berkata, \"Mu'awiyah memerintahkan (untuk memberikan sesuatu) yang belum pernah ia perintahkan kepada dua sahabatnya, dan ia juga memberikan kepada anak Al Miqdam sebanyak dua ratus (dinar). Maka Al Miqdam membagikannya kepada kawan-kawannya, tetapi ia tidak memberikan kepada Al Asadi sedikit pun dari apa yang ia ambil. Hal ini kemudian dilaporkan kepada Mu'awiyah hingga ia berkata, \"Al Miqdam itu seorang yang mulia lagi dermawan, adapun Al Asadi adalah orang baik tetapi pelit.\""},"3489":{"ar":"حَدَّثَنَا مُسَدَّدُ بْنُ مُسَرْهَدٍ أَنَّ يَحْيَى بْنَ سَعِيدٍ وَإِسْمَعِيلَ بْنَ إِبْرَاهِيمَ حَدَّثَاهُمْ الْمَعْنَى عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ بْنِ أُسَامَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ جُلُودِ السِّبَاعِ","id":"Telah menceritakan kepada kami [Musaddad bin Musarhad] bahwa [Yahya bin Sa'id] dan [Isma'il bin Ibrahim] keduanya menceritakan kepada mereka secara makna, dari [Sa'id bin Abu Arubah] dari [Qatadah] dari [Abu Al Malih bin Usamah] dari [Bapaknya] berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang memakai kulit binatang buas.\""},"3490":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ الْبَزَّازُ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَالَ أَكْثِرُوا مِنْ النِّعَالِ فَإِنَّ الرَّجُلَ لَا يَزَالُ رَاكِبًا مَا انْتَعَلَ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shabbah Al Bazzaz] berkata, telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari [Musa bin Uqbah] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, beliau lalu bersabda: \"Perbanyaklah mengenakan sandal, karena seseorang masih disebut pengendara selama ia mengenakan sandal.\""},"3491":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ نَعْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَهَا قِبَالَانِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Anas] bahwa sandal Nabi shallallahu 'alaihi wasallam mempunyai dua tali (sandal).\""},"3492":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَبُو يَحْيَى أَخْبَرَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْتَعِلَ الرَّجُلُ قَائِمًا","id":"Telah menceritakan kepada kami [Muhammad bin Abdurrahim Abu Yahya] berkata, telah mengabarkan kepada kami [Abu Ahmad Az Zubairi] berkata, telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melarang seorang mengenakan sandal sambil berdiri.\""},"3493":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَمْشِي أَحَدُكُمْ فِي النَّعْلِ الْوَاحِدَةِ لِيَنْتَعِلْهُمَا جَمِيعًا أَوْ لِيَخْلَعْهُمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang dari kalian memakai satu sandal. Hendaklah ia memakai semuanya atau melepaskan semuanya.\""},"3494":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا انْقَطَعَ شِسْعُ أَحَدِكُمْ فَلَا يَمْشِ فِي نَعْلٍ وَاحِدَةٍ حَتَّى يُصْلِحَ شِسْعَهُ وَلَا يَمْشِ فِي خُفٍّ وَاحِدٍ وَلَا يَأْكُلْ بِشِمَالِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid Ath Thayalisi] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika tali sandal salah seorang dari kalian putus maka janganlah ia berjalan dengan mengenakan satu sandal hingga membetulkannya, dan jangan pula berjalan dengan satu khuf (sepatu, slop), serta jangan makan dengan tangan kiri.\""},"3495":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى حَدَّثَنَا عبْدُ اللَّهِ بْنُ هَارُونَ عَنْ زِيَادِ بْنِ سَعْدٍ عَنْ أَبِي نَهِيكٍ عَنْ ابْنِ عَبَّاسٍ قَالَمِنْ السُّنَّةِ إِذَا جَلَسَ الرَّجُلُ أَنْ يَخْلَعَ نَعْلَيْهِ فَيَضَعَهُمَا بِجَنْبِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] berkata, telah menceritakan kepada kami [Shofwan bin Isa] berkata, telah menceritakan kepada kami [Abdullah bin Harun] dari [Ziyad bin Sa'd] dari [Abu Nahik] dari [Ibnu Abbas] ia berkata, \"Termasuk dari sunah adalah, jika seseorang duduk hendaklah ia melepas kedua sandalnya dan meletakkan di sebelahnya.\""},"3496":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا انْتَعَلَ أَحَدُكُمْ فَلْيَبْدَأْ بِالْيَمِينِ وَإِذَا نَزَعَ فَلْيَبْدَأْ بِالشِّمَالِ وَلْتَكُنْ الْيَمِينُ أَوَّلَهُمَا يَنْتَعِلُ وَآخِرَهُمَا يَنْزِعُ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian mengenakan sandal hendaklah memulai dari sebelah kanan, jika ingin melepas hendaklah dari sebelah kiri. Maka, jadikanlah sebelah kanan pertama kali saat mengenakan dan terakhir kali saat melepas.\""},"3497":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ وَمُسلِمُ بْنُ إِبْرَاهِيمَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ الْأَشْعَثِ بْنِ سُلَيْمٍ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ التَّيَمُّنَ مَا اسْتَطَاعَ فِي شَأْنِهِ كُلِّهِ فِي طُهُورِهِ وَتَرَجُّلِهِ وَنَعْلِهِ قَالَ مُسْلِمٌ وَسِوَاكِهِ وَلَمْ يَذْكُرْ فِي شَأْنِهِ كُلِّهِقَالَ أَبُو دَاوُد رَوَاهُ عَنْ شُعْبَةَ مُعَاذٌ وَلَمْ يَذْكُرْ سِوَاكَهُ","id":"Telah menceritakan kepada kami [Hafsh bin Umar] dan [Muslim bin Ibrahim] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Asy'ats bin Sulaim] dari [Bapaknya] dari [Masruq] dari ['Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam senang memulai dari yang sebelah kanan dalam setiap perbuatan yang dilakukannya, semampu mungkin; baik dalam bersuci, menyisir dan memakai sandal.\" Muslim menyebutkan, \"dan dalam bersiwaknya, \" tetapi ia tidak menyebutkan, 'setiap perbuatan yang dilakukannya'. Abu Dawud berkata, \" [Mu'adz] menceritakannya dari [Syu'bah], tetapi ia tidak menyebutkan dalam bersiwaknya'.\""},"3498":{"ar":"حَدَّثَنَا النُّفَيْلِيُّ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا لَبِسْتُمْ وَإِذَا تَوَضَّأْتُمْ فَابْدَءُوا بِأَيَامِنِكُمْ","id":"Telah menceritakan kepada kami [An Nufaili] berkata, telah menceritakan kepada kami [Zuhair] berkata, telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian mengenakan (baju) atau berwudhu, maka mulailah dari yang sebelah kanan.\""},"3499":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ خَالِدٍ الْهَمْدَانِيُّ الرَّمْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ أَبِي هَانِيءٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَذَكَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفُرُشَ فَقَالَ فِرَاشٌ لِلرَّجُلِ وَفِرَاشٌ لِلْمَرْأَةِ وَفِرَاشٌ لِلضَّيْفِ وَالرَّابِعُ لِلشَّيْطَانِ","id":"Telah menceritakan kepada kami [Yazid bin Khalid Al Hamdani Ar Ramli] berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Abu Hani`] dari [Abu 'Abdurrahman Al Hubuli] dari [Jabir bin Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang ranjang tidur, beliau bersabda: \"Satu ranjang untuk seorang laki-laki, satu ranjang untuk wanita, satu ranjang untuk tamu, dan yang keempat adalah untuk setan.\""},"3500":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْجَرَّاحِ عَنْ وَكِيعٍ عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ فَرَأَيْتُهُ مُتَّكِئًا عَلَى وِسَادَةٍ زَادَ ابْنُ الْجَرَّاحِ عَلَى يَسَارِهِقَالَ أَبُو دَاوُد رَوَاهُ إِسْحَقُ بْنُ مَنْصُورٍ عَنْ إِسْرَائِيلَ أَيْضًا عَلَى يَسَارِهِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] berkata, telah menceritakan kepada kami [Waki']. (dalam jalur lain disebutkan) Telah menceritakan kepada kami [Abdullah Ibnul Jarrah] dari [Waki'] dari [Isra'il] dari [Simak] dari [Jabir bin Samurah] ia berkata, \"Aku masuk menemui Nabi shallallahu 'alaihi wasallam di rumahnya, dan aku melihat beliau duduk bersandar di atas bantal.\" [Ibnul Jarrah] menambahkan, \"Sebelah kirinya.\" Abu Dawud berkata, \" [Ishaq bin Manshur] meriwayatkannya dari [Isra'il] juga dengan lafadz, 'Sebelah kirinya'.\""}};
